-- Poems batch 146
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ecf6c8ad-a101-4652-96a6-68a1672d6ba3','嶺南荔枝不可寄遠龍眼新熟輒以五百顆奉晦叔或可與伯逢共一酌也  其一','張栻','宋','宋诗','song-poetry','','[]','荔子如今尚典刑，秋林圓實著嘉名。',32,'全唐诗/poet.song.150000.json','["荔子如今尚典刑，秋林圓實著嘉名。", "雖無赬玉南風面，却耐筠籠千里行。"]'),
('548f3dde-4d23-4429-b2e5-e5579c22c2b1','嶺南荔枝不可寄遠龍眼新熟輒以五百顆奉晦叔或可與伯逢共一酌也  其二','張栻','宋','宋诗','song-poetry','','[]','手自封題寄故人，聊將風味赴詩唇。',32,'全唐诗/poet.song.150000.json','["手自封題寄故人，聊將風味赴詩唇。", "千年尚憶唐羌疏，不汙華清驛騎塵。"]'),
('8948ce16-ea4e-4a4f-b7d0-7a167a673f0a','壽定叟弟  其一','張栻','宋','宋诗','song-poetry','','[]','聞說清朝對紫宸，君王側席屢咨詢。',32,'全唐诗/poet.song.150000.json','["聞說清朝對紫宸，君王側席屢咨詢。", "惟應民瘼開陳切，故遣分符驗撫循。"]'),
('39e59af8-5f68-4956-9eb6-039c4de05fb5','壽定叟弟  其二','張栻','宋','宋诗','song-poetry','','[]','聞說嚴人愛貳車，呻吟赴愬頼携扶。',32,'全唐诗/poet.song.150000.json','["聞說嚴人愛貳車，呻吟赴愬頼携扶。", "從今充擴應無倦，千里疲民待子蘇。"]'),
('30b84ace-3f24-4444-86a1-019206d3083f','壽定叟弟  其三','張栻','宋','宋诗','song-poetry','','[]','聞說年來更老成，清心寡欲厭紛紜。',32,'全唐诗/poet.song.150000.json','["聞說年來更老成，清心寡欲厭紛紜。", "固知造物有深意，端享修齡看策勳。"]'),
('5e17f73d-79fe-481d-9968-9c0d0f7cba5e','壽定叟弟  其四','張栻','宋','宋诗','song-poetry','','[]','秋風想已治歸裝，吾亦扁舟具碧湘。',32,'全唐诗/poet.song.150000.json','["秋風想已治歸裝，吾亦扁舟具碧湘。", "世味祇應諳歷遍，何如兄弟對方床。"]'),
('9b4eaf06-e7f2-4925-87cc-dba540bff03c','壽定叟弟  其五','張栻','宋','宋诗','song-poetry','','[]','年年桂綻菊開時，長憶芳樽共一巵。',32,'全唐诗/poet.song.150000.json','["年年桂綻菊開時，長憶芳樽共一巵。", "請誦周人和樂句，全勝三歎陟岡詩。"]'),
('7e8a680d-fadd-4bfc-9f42-73703dd191b7','丙申至前五日復坐南窗憶去年詩又成兩章  其一','張栻','宋','宋诗','song-poetry','','[]','依然紅日照窗楣，還是去年消息時。',32,'全唐诗/poet.song.150000.json','["依然紅日照窗楣，還是去年消息時。", "妙理不須尋轍迹，只於生處驗新知。"]'),
('258edcb4-c548-4405-b5c4-6f87526efd5a','丙申至前五日復坐南窗憶去年詩又成兩章  其二','張栻','宋','宋诗','song-poetry','','[]','新晴物物有春意，正值一陽來復時。',32,'全唐诗/poet.song.150000.json','["新晴物物有春意，正值一陽來復時。", "變化無窮俱是易，探原密處起乾知。"]'),
('37e59aee-750d-494a-8d84-e46ebfa34d1c','題雉山禊亭','張栻','宋','宋诗','song-poetry','','[]','一曲清江正可憐，隔江新竹露娟娟。',32,'全唐诗/poet.song.150000.json','["一曲清江正可憐，隔江新竹露娟娟。", "好風成我曲肱夢，起看飛雲度碧天。"]'),
('5ae7d254-4844-4049-b0c4-a1f768413fd6','夢乘大舸卧泛江湖波濤甚壯醒乃悟其爲雨因成小詩','張栻','宋','宋诗','song-poetry','','[]','平生得意白鷗外，歲晚歸心鴻鴈俱。',32,'全唐诗/poet.song.150000.json','["平生得意白鷗外，歲晚歸心鴻鴈俱。", "蕉葉雨聲喧曉枕，夢成風楫泛江湖。"]'),
('0601c8be-ce20-4fd4-876f-277e75575721','南嶽庵僧寄上封新茶風味甚高薄暮分送韓廷玉李嵩老','張栻','宋','宋诗','song-poetry','','["\u8861\u5c71"]','浮甌雪色喜初嘗，中有祝融風露香。',32,'全唐诗/poet.song.150000.json','["浮甌雪色喜初嘗，中有祝融風露香。", "徑欲與君同晤賞，短檠清夜正相望。"]'),
('32a792ef-452b-4ad9-b969-b8d9d72f3e5f','跋王介甫遊鍾山圖','張栻','宋','宋诗','song-poetry','','[]','林影溪光靜自如，蕭疎短鬢獨騎馿。',32,'全唐诗/poet.song.150000.json','["林影溪光靜自如，蕭疎短鬢獨騎馿。", "可能胸次都無事，擬向山中更著書。"]'),
('e4779b88-6c84-4f41-87d7-5dd0edfe76a7','歲晚烹試小春建茶','張栻','宋','宋诗','song-poetry','','[]','陽月藏春妙莫窺，靈芽粟粒露全機。',32,'全唐诗/poet.song.150000.json','["陽月藏春妙莫窺，靈芽粟粒露全機。", "煮泉獨啜寒窗夜，已覺東風天際歸。"]'),
('dd98df28-895e-4ddc-ad67-77497612a2f1','昨過漕臺庭前荼䕷盛開已而詹體仁海棠和章及此因用前韻賦兩章  其一','張栻','宋','宋诗','song-poetry','','[]','玉立春深雪不如，生香透骨雪應無。',32,'全唐诗/poet.song.150000.json','["玉立春深雪不如，生香透骨雪應無。", "莫遣飄零雜塵土，芬芳留入碧琳腴。"]'),
('69139568-511b-4637-9b42-2c06b55cf065','昨過漕臺庭前荼䕷盛開已而詹體仁海棠和章及此因用前韻賦兩章  其二','張栻','宋','宋诗','song-poetry','','[]','紛紛花片逐風飛，綠幄藏春自一奇。',32,'全唐诗/poet.song.150000.json','["紛紛花片逐風飛，綠幄藏春自一奇。", "不入時人紅紫眼，却須我輩與題詩。"]'),
('662b066e-9466-4b2a-a64b-99c4a93fd125','所思亭海棠初開折贈兩使者將以小詩  其一','張栻','宋','宋诗','song-poetry','','[]','未須比擬紅深淺，更莫平章香有無。',32,'全唐诗/poet.song.150000.json','["未須比擬紅深淺，更莫平章香有無。", "過雨夕陽樓上看，千花容有此膚腴。"]'),
('6f53a390-8336-4868-a12a-440283aac23c','所思亭海棠初開折贈兩使者將以小詩  其二','張栻','宋','宋诗','song-poetry','','[]','東風著物本無私，紅入花梢特地奇。',32,'全唐诗/poet.song.150000.json','["東風著物本無私，紅入花梢特地奇。", "想得霜臺春思滿，一枝聊遣博新詩。"]'),
('260f5849-d9b0-419f-81f6-7263583ea23f','廖憲送牡丹用海棠韻復走筆戲和之  其一','張栻','宋','宋诗','song-poetry','','[]','綠葉滿園風雨餘，君家花事嶺中無。',32,'全唐诗/poet.song.150000.json','["綠葉滿園風雨餘，君家花事嶺中無。", "眼明見此復三歎，京洛名園憶上腴。"]'),
('7cfc1f79-bdee-4146-90eb-43dc5ea8e51f','廖憲送牡丹用海棠韻復走筆戲和之  其二','張栻','宋','宋诗','song-poetry','','[]','報答春光須著語，年來老我不能奇。',32,'全唐诗/poet.song.150000.json','["報答春光須著語，年來老我不能奇。", "風前娟好有餘態，未必此花如此詩。"]'),
('fa11a6d6-e904-415a-975b-69b876c2d773','定叟弟頻寄黄蘗仰山新芽嘗口占小詩適災患亡聊久不得遣寄今日方能寫此  其一','張栻','宋','宋诗','song-poetry','','[]','瘴雨昏昏梅子黄，午窗歸夢一繩床。',32,'全唐诗/poet.song.150000.json','["瘴雨昏昏梅子黄，午窗歸夢一繩床。", "江南雲腴忽到眼，中有吾家棠棣香。"]'),
('cbb15112-09bb-440c-ac86-28f2f8969bbd','定叟弟頻寄黄蘗仰山新芽嘗口占小詩適災患亡聊久不得遣寄今日方能寫此  其二','張栻','宋','宋诗','song-poetry','','[]','集雲峯頂風霜飽，黄蘗洲前水石清。',32,'全唐诗/poet.song.150000.json','["集雲峯頂風霜飽，黄蘗洲前水石清。", "不入貢包供玉食，祇應山澤擅高名。"]'),
('bb8fd518-2907-4ecd-ad3d-a971091fa44f','益陽南境松杉夾道鬰然父老相傳忠定張公爲邑時所植也其間亦有既剪而復生者作詩屬來者護持之','張栻','宋','宋诗','song-poetry','','[]','夾道松杉半老蒼，前賢餘澤未應忘。',32,'全唐诗/poet.song.150000.json','["夾道松杉半老蒼，前賢餘澤未應忘。", "君看直幹連雲起，豈但當年蔽芾棠。"]'),
('fca29a2d-58be-4b4a-8312-996a3fe335df','登楚野亭見張舍人題字','張栻','宋','宋诗','song-poetry','','[]','英豪自昔多遺恨，人物于今正渺然。',32,'全唐诗/poet.song.150000.json','["英豪自昔多遺恨，人物于今正渺然。", "來訪舍人題字處，淡煙莎草滿平川。"]'),
('0a68f9cc-10e3-4c4b-bacd-8d6ac1fc1c01','城南雜詠二十首 納湖','張栻','宋','宋诗','song-poetry','','[]','原原錫潭水，匯此南城陰。',24,'全唐诗/poet.song.150000.json','["原原錫潭水，匯此南城陰。", "岸花有開落，水盈無淺深。"]'),
('ec1cc75d-c724-4e32-b752-a200d65f9879','城南雜詠二十首 東渚','張栻','宋','宋诗','song-poetry','','[]','團團凌風桂，宛在水之東。',24,'全唐诗/poet.song.150000.json','["團團凌風桂，宛在水之東。", "月色穿林影，却下碧波中。"]'),
('5d45b618-afe5-41af-ac25-917caca0204f','城南雜詠二十首 詠歸橋','張栻','宋','宋诗','song-poetry','','[]','四序有佳趣，今古蓋共茲。',24,'全唐诗/poet.song.150000.json','["四序有佳趣，今古蓋共茲。", "橋邊獨微吟，回首忘所之。"]'),
('f30ad12e-f11a-46ca-997f-8c3b8d08657e','城南雜詠二十首 船齋','張栻','宋','宋诗','song-poetry','','[]','窗低蘆葦秋，便有江湖思。',24,'全唐诗/poet.song.150000.json','["窗低蘆葦秋，便有江湖思。", "久已倦垂綸，游魚不須避。"]'),
('82b05192-c578-4b4d-9ffa-fd69d79ea8bf','城南雜詠二十首 麗澤','張栻','宋','宋诗','song-poetry','','[]','長哦伐木篇，佇立以望子。',24,'全唐诗/poet.song.150000.json','["長哦伐木篇，佇立以望子。", "日暮飛鳥歸，門前長春水。"]'),
('84f567a4-753e-4f64-a3db-4b91c440320d','城南雜詠二十首 蘭澗','張栻','宋','宋诗','song-poetry','','[]','藝蘭北澗側，澗曲風紆餘。',24,'全唐诗/poet.song.150000.json','["藝蘭北澗側，澗曲風紆餘。", "願言植根固，芬芳長慰予。"]'),
('5e5da9f3-7b1a-4c7b-8e28-8be98f217a96','城南雜詠二十首 山齋','張栻','宋','宋诗','song-poetry','','[]','疊石小崢嶸，修篁高下生。',24,'全唐诗/poet.song.150000.json','["疊石小崢嶸，修篁高下生。", "地偏人迹罕，古井轆轤鳴。"]'),
('0d709017-4175-4853-a547-c25581a0297c','城南雜詠二十首 書樓','張栻','宋','宋诗','song-poetry','','[]','高樓出林杪，中有千載書。',24,'全唐诗/poet.song.150000.json','["高樓出林杪，中有千載書。", "昔人不可見，倚檻意何如。"]'),
('f727e2c8-2568-484f-81fc-5fce47c33556','城南雜詠二十首 蒙軒','張栻','宋','宋诗','song-poetry','','[]','開軒僅尋丈，水竹亦蕭疎。',24,'全唐诗/poet.song.150000.json','["開軒僅尋丈，水竹亦蕭疎。", "客來須起敬，題榜了翁書。"]'),
('efdbdc0b-7dac-48c9-a6f4-b99a7c85826e','城南雜詠二十首 石瀨','張栻','宋','宋诗','song-poetry','','[]','流泉自清寫，觸石短長鳴。',24,'全唐诗/poet.song.150000.json','["流泉自清寫，觸石短長鳴。", "窮年竹根底，和我讀書聲。"]'),
('1ef169db-c957-46ca-9e23-654446d252be','城南雜詠二十首 卷雲亭','張栻','宋','宋诗','song-poetry','','[]','雲生山氣佳，雲卷山色靜。',24,'全唐诗/poet.song.150000.json','["雲生山氣佳，雲卷山色靜。", "隠几亦何心，此意相與永。"]'),
('e0e2ef12-f2da-4853-b4f4-2f092235ca10','柳堤','張栻','宋','宋诗','song-poetry','','[]','前年種垂柳，已復如許長。',24,'全唐诗/poet.song.150000.json','["前年種垂柳，已復如許長。", "長條莫攀折，留待映滄浪。"]'),
('3e983776-4be8-4cc3-8ae5-dde7aa9f69b4','柳堤 月榭','張栻','宋','宋诗','song-poetry','','[]','危闌明倒影，面面湧金波。',24,'全唐诗/poet.song.150000.json','["危闌明倒影，面面湧金波。", "何處無佳月，惟應此地多。"]'),
('8eec62dc-685a-48c8-9a5b-22a0ea7bf6aa','柳堤 濯清亭','張栻','宋','宋诗','song-poetry','','[]','芙蓉豈不好，濯濯清漣漪。',24,'全唐诗/poet.song.150000.json','["芙蓉豈不好，濯濯清漣漪。", "采之不盈把，怊悵暮忘饑。"]'),
('96658e0d-88a5-4226-abbf-5c6fd4ad5bf4','柳堤 西嶼','張栻','宋','宋诗','song-poetry','','[]','繫舟西岸邊，幅巾自來去。',24,'全唐诗/poet.song.150000.json','["繫舟西岸邊，幅巾自來去。", "島嶼花木深，蟬鳴不知處。"]'),
('29801232-5220-4fc1-a777-e28e3cab784e','柳堤 琮琤谷','張栻','宋','宋诗','song-poetry','','[]','幽谷竹成陰，懸流著石清。',24,'全唐诗/poet.song.150000.json','["幽谷竹成陰，懸流著石清。", "不妨風月夕，來此聽琮琤。"]'),
('0af9c54e-23f6-4f53-8474-8808e0e3ca14','柳堤 梅堤','張栻','宋','宋诗','song-poetry','','[]','亭亭堤上梅，歷歷波間影。',24,'全唐诗/poet.song.150000.json','["亭亭堤上梅，歷歷波間影。", "歲晚憶夫君，寂寞煙渚靜。"]'),
('9c580a24-3167-44cd-9cfd-659f51e8a659','柳堤 聽雨舫','張栻','宋','宋诗','song-poetry','','[]','風吹渡頭雨，摵摵蓬上聲。',24,'全唐诗/poet.song.150000.json','["風吹渡頭雨，摵摵蓬上聲。", "欣然會心處，端復與誰評。"]'),
('9c8fd42d-c36b-48d9-9dba-6eb542326f80','柳堤 采菱舟','張栻','宋','宋诗','song-poetry','','[]','散策下亭阿，水清魚可數。',24,'全唐诗/poet.song.150000.json','["散策下亭阿，水清魚可數。", "却上采菱舟，乘風過南浦。"]'),
('b17e9643-a116-4ef8-8435-9f7293b57006','柳堤 南阜','張栻','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','湘水接洞庭，秋山見遥碧。',24,'全唐诗/poet.song.150000.json','["湘水接洞庭，秋山見遥碧。", "南阜時一登，搔首意無斁。"]'),
('26713ab9-aac3-44d6-8542-30868faa371c','游嶽尋梅不獲和元晦韻','張栻','宋','宋诗','song-poetry','','[]','眼看飛雪灑千林，更著寒溪水淺深。',32,'全唐诗/poet.song.150000.json','["眼看飛雪灑千林，更著寒溪水淺深。", "應有梅花連夜發，却煩詩句寫愁襟。"]'),
('0e5a6594-5e84-479f-b559-9206d88bc075','十三日晨起霜晴用定王臺韻賦此','張栻','宋','宋诗','song-poetry','','[]','晴嵐開嶽鎮，雲雨斷陽臺。',48,'全唐诗/poet.song.150000.json','["晴嵐開嶽鎮，雲雨斷陽臺。", "日出寒光迥，川平秀色回。", "興隨天際鴈，詩寄嶺頭梅。", "盛事它年說，憑君記玉杯。"]'),
('96a2c9b7-97d5-4d69-bd64-9166aac1908e','用元晦定王臺韻','張栻','宋','宋诗','song-poetry','','[]','珍重南山路，驅羸幾度來。',48,'全唐诗/poet.song.150000.json','["珍重南山路，驅羸幾度來。", "未登喬嶽頂，空說妙高臺。", "曉霧層層歛，奇峯面面開。", "山間元自樂，澤畔不須哀。"]'),
('d458850a-c864-4f22-b7a0-4726d0d92f53','馬上口占','張栻','宋','宋诗','song-poetry','','[]','向來一雪壓霾昏，曉跨征鞍傍水村。',32,'全唐诗/poet.song.150000.json','["向來一雪壓霾昏，曉跨征鞍傍水村。", "七十二峯俱玉立，巍然更覺祝融尊。"]'),
('d2098db9-61fa-429e-8124-0d42feb861ad','馬上舉韓退之語口占','張栻','宋','宋诗','song-poetry','','[]','擾擾人心隨渺茫，更於底處問穹蒼。',32,'全唐诗/poet.song.150000.json','["擾擾人心隨渺茫，更於底處問穹蒼。", "今朝開霽君知否，春到無邊花草香。"]'),
('a6fbb8d0-c0e6-4037-a146-7439cd4e2453','和朱元晦韻','張栻','宋','宋诗','song-poetry','','[]','一見瓊山眼爲青，馬蹄不覺渡沙汀。',32,'全唐诗/poet.song.150000.json','["一見瓊山眼爲青，馬蹄不覺渡沙汀。", "如今誰是王摩詰，爲寫清新入畫屏。"]'),
('1080716a-0394-4350-8417-f00d1d49b53d','登山有作','張栻','宋','宋诗','song-poetry','','[]','上頭壁立起千尋，下列羣峯次第深。',32,'全唐诗/poet.song.150000.json','["上頭壁立起千尋，下列羣峯次第深。", "兀兀籃輿自吟詠，白雲流水此時心。"]'),
('faa9e79d-4d8f-4a0c-ae41-e7d6aa66b6cb','和元晦馬跡橋','張栻','宋','宋诗','song-poetry','','[]','便請行從馬跡橋，何須乘鶴簉叢霄。',32,'全唐诗/poet.song.150000.json','["便請行從馬跡橋，何須乘鶴簉叢霄。", "殷勤底事登臨去，不爲山僧苦見招。"]'),
('083dcce9-ef0f-4729-acd6-5af964ef9946','方廣道中半嶺少憩','張栻','宋','宋诗','song-poetry','','[]','半嶺籃輿小駐肩，眼中已覺渺雲煙。',32,'全唐诗/poet.song.150000.json','["半嶺籃輿小駐肩，眼中已覺渺雲煙。", "山頭更盡無窮境，非是人間別有天。"]'),
('dfdc6f72-568d-43e5-8cd3-2703c349473b','道中景物甚勝吟賞不暇因復作此','張栻','宋','宋诗','song-poetry','','[]','支筇石壁聽溪聲，却看雲山萬疊新。',32,'全唐诗/poet.song.150000.json','["支筇石壁聽溪聲，却看雲山萬疊新。", "總是詩情吟不徹，一時分付與吾人。"]'),
('21483a94-0430-416c-9cce-661a69235d38','崖邊積雪取食清甚賦此','張栻','宋','宋诗','song-poetry','','[]','陰崖積雪射寒光，入齒清甘得味嘗。',32,'全唐诗/poet.song.150000.json','["陰崖積雪射寒光，入齒清甘得味嘗。", "應是山神知客意，故將瓊液沃詩腸。"]'),
('95e32440-83b8-4b73-9bba-7e888a594362','和元晦後洞山口晚賦','張栻','宋','宋诗','song-poetry','','[]','石裂長藤瘦，山圍野路深。',48,'全唐诗/poet.song.150000.json','["石裂長藤瘦，山圍野路深。", "寒溪千古思，喬木四時陰。", "更得尋幽侶，何妨擁鼻吟。", "笑看雲出岫，誰是此無心。"]'),
('5601a972-19da-4a01-8a95-ec22e19dee2d','和元晦雪壓竹韻','張栻','宋','宋诗','song-poetry','','[]','山行景物總清奇，知費山翁幾許詩。',32,'全唐诗/poet.song.150000.json','["山行景物總清奇，知費山翁幾許詩。", "雪急風號聯騎日，月明霜凈倚闌時。"]'),
('6f0e0f2c-84ab-48fa-bd63-a286cbdede8c','和元晦懷定叟戲作','張栻','宋','宋诗','song-poetry','','[]','路入青山小作程，每逢佳處憶吾人。',32,'全唐诗/poet.song.150000.json','["路入青山小作程，每逢佳處憶吾人。", "山林朝市休關念，認取臨深履薄身。"]'),
('67a4acce-3383-4bb1-bc0f-220011a27ec1','方廣聖燈','張栻','宋','宋诗','song-poetry','','[]','陰壑傳聞炯夜燈，幾人高閤費追尋。',32,'全唐诗/poet.song.150000.json','["陰壑傳聞炯夜燈，幾人高閤費追尋。", "山間光景祇常事，堪笑塵寰萬種心。"]'),
('d5895440-9441-44bd-9887-6f166ff568a8','賦羅漢果','張栻','宋','宋诗','song-poetry','','["\u897f\u6e56"]','黄實累累本自芳，西湖名字著諸方。',32,'全唐诗/poet.song.150000.json','["黄實累累本自芳，西湖名字著諸方。", "里稱勝母吾常避，珍重山僧自煮湯。"]'),
('539439a1-32cf-40bb-b120-3f2b7890dc62','和元晦詠畫壁','張栻','宋','宋诗','song-poetry','','[]','松杉夾路自清陰，溪水有源誰復尋。',32,'全唐诗/poet.song.150000.json','["松杉夾路自清陰，溪水有源誰復尋。", "忽見畫圖開四壁，悠然端亦慰予心。"]'),
('fb0e844b-9462-4fb9-a779-18282c8b6afe','和元晦方廣版屋','張栻','宋','宋诗','song-poetry','','[]','葺蓋非陶埴，年深自碧差。',24,'全唐诗/poet.song.150000.json','["葺蓋非陶埴，年深自碧差。", "如何亂心曲，不忍誦秦詩。"]'),
('a4888fdd-5f31-475b-b5c6-5b2dc927600f','和擇之賦泉聲','張栻','宋','宋诗','song-poetry','','[]','試問今宵澗底聲，何如三歎有餘音。',32,'全唐诗/poet.song.150000.json','["試問今宵澗底聲，何如三歎有餘音。", "堂中衲子還知否，月白風清底處尋。"]'),
('a886929e-8d67-417d-977b-209e578492dc','和擇之賦霜月','張栻','宋','宋诗','song-poetry','','[]','月華明潔好霜天，遥指層城幾暮煙。',32,'全唐诗/poet.song.150000.json','["月華明潔好霜天，遥指層城幾暮煙。", "妙意此時誰與寄，美人湘水隔娟娟。"]'),
('89dcfb70-87ff-480a-b3fd-d1962043b284','和擇之賦枯木','張栻','宋','宋诗','song-poetry','','[]','陰崖虎豹露鬚牙，元是枯槎著蘚花。',32,'全唐诗/poet.song.150000.json','["陰崖虎豹露鬚牙，元是枯槎著蘚花。", "不向明堂支萬祀，玄冬苦節未須誇。"]'),
('fc0f637a-b7f4-4c97-a3fc-615ad05d8dfa','聞方廣長老化去有作','張栻','宋','宋诗','song-poetry','','[]','夜入精藍意自真，上方一笑政清新。',32,'全唐诗/poet.song.150000.json','["夜入精藍意自真，上方一笑政清新。", "山僧忽復隨流水，可惜平生未了身。"]'),
('ced2ad04-907f-437c-b462-a14ab02f8dce','賦蓮花峰','張栻','宋','宋诗','song-poetry','','[]','玉井峯頭十丈蓮，天寒日暮更清妍。',32,'全唐诗/poet.song.150000.json','["玉井峯頭十丈蓮，天寒日暮更清妍。", "不須重詠洛神賦，便可同賡雲錦篇。"]'),
('676c3f78-179e-4f1b-979c-2c132d1f86b1','和元晦詠雪','張栻','宋','宋诗','song-poetry','','[]','兀坐竹輿穿澗壑，仰看石徑接煙霞。',32,'全唐诗/poet.song.150000.json','["兀坐竹輿穿澗壑，仰看石徑接煙霞。", "是間故有春消息，散作千林瓊玉花。"]'),
('2057746d-f218-4601-af97-8eaadbb2279a','自方廣過高臺','張栻','宋','宋诗','song-poetry','','[]','兩寺清聞磬，羣峯石作城。',48,'全唐诗/poet.song.150000.json','["兩寺清聞磬，羣峯石作城。", "風生雲影亂，猿嘯月華明。", "香火遠公社，江湖鷗鳥盟。", "是中俱不著，俯仰見平生。"]'),
('0f2a5156-8fb8-40fa-8879-4f7fe27b8660','賦石廩峰','張栻','宋','宋诗','song-poetry','','[]','巋然高廩倚晴天，獨得佳名自古傳。',32,'全唐诗/poet.song.150000.json','["巋然高廩倚晴天，獨得佳名自古傳。", "多謝山中出雲氣，人間長與作豐年。"]'),
('dd7f2de4-18dc-4cf4-8238-c27f3ae089b5','道傍殘火溫酒有作','張栻','宋','宋诗','song-poetry','','[]','陰崖衝雪寒膚裂，野路燃薪春意回。',32,'全唐诗/poet.song.150000.json','["陰崖衝雪寒膚裂，野路燃薪春意回。", "旋暖提壺傾濁酒，陶然絕勝夜堂杯。"]'),
('615837c1-265e-4aeb-96ee-1a47057b4932','和元晦林間殘雪之韻','張栻','宋','宋诗','song-poetry','','[]','眼中光潔盡瓊瑶，未覺鬰藍宮殿遥。',32,'全唐诗/poet.song.150000.json','["眼中光潔盡瓊瑶，未覺鬰藍宮殿遥。", "石壁長林冰筯落，鏘然玉佩響層霄。"]'),
('92a4778b-c370-4119-8d0b-6b3e1e166496','和擇之看雪','張栻','宋','宋诗','song-poetry','','[]','嶽背三冬雪，真同不夜城。',48,'全唐诗/poet.song.150000.json','["嶽背三冬雪，真同不夜城。", "野雲何晃蕩，澗水助空明。", "行橐多新句，青山有舊盟。", "堂堂身世事，渠謾說三生。"]'),
('2f8e8d55-1c97-46e1-a32f-d804bd9099a7','和擇之福巖回望嶽市','張栻','宋','宋诗','song-poetry','','[]','回首塵寰去渺然，山中別是一風煙。',32,'全唐诗/poet.song.150000.json','["回首塵寰去渺然，山中別是一風煙。", "好乘晴色上高頂，要看清霜明月天。"]'),
('8e96bd03-7b92-4648-96d4-2c319441b31c','福巖讀張湖南舊詩','張栻','宋','宋诗','song-poetry','','[]','茲遊奇絕平生事，只欠瀛仙冰雪姿。',32,'全唐诗/poet.song.150000.json','["茲遊奇絕平生事，只欠瀛仙冰雪姿。", "元是經行題品地，却從山際誦新詩。"]'),
('60257242-ddcd-40e6-b870-6d0487e9ac86','和擇之登祝融峰口占','張栻','宋','宋诗','song-poetry','','[]','祝融高處好，拂石坐林端。',48,'全唐诗/poet.song.150000.json','["祝融高處好，拂石坐林端。", "雲夢從渠小，乾坤本自寬。", "回眸增浩蕩，出語覺高寒。", "明日重來看，寧應取次還。"]'),
('5b4013df-f5a2-4045-bb09-6e41bd51b2ae','和元晦晚霞','張栻','宋','宋诗','song-poetry','','[]','早來雪意遮空碧，晚喜晴霞散綺紅。',32,'全唐诗/poet.song.150000.json','["早來雪意遮空碧，晚喜晴霞散綺紅。", "便可懸知明旦事，一輪明月快哉風。"]'),
('0e4174ef-0b53-4066-a0b8-dd17e3098ca5','過高臺獲信老詩集','張栻','宋','宋诗','song-poetry','','[]','蕭然僧榻碧雲端，細讀君詩夜未闌。',32,'全唐诗/poet.song.150000.json','["蕭然僧榻碧雲端，細讀君詩夜未闌。", "門外蒼松霜雪裏，比君佳處讓高寒。"]'),
('cabf4b9f-8a3b-4400-80ac-f8ea46f1c8e5','和元晦贈上封長老','張栻','宋','宋诗','song-poetry','','[]','上方元自好，一榻有餘清。',48,'全唐诗/poet.song.150000.json','["上方元自好，一榻有餘清。", "祇趁晨鐘起，寧聞山鳥聲。", "高僧足幽事，野客富詩情。", "試問峯頭景，今朝作麽生。"]'),
('24bf3a62-e5e4-455f-8b89-ba480e83ab28','和元晦醉下祝融','張栻','宋','宋诗','song-poetry','','[]','雲氣飄飄御晚風，笑談噓吸滿心胸。',32,'全唐诗/poet.song.150000.json','["雲氣飄飄御晚風，笑談噓吸滿心胸。", "須臾歛盡還空碧，露出天邊無數峯。"]'),
('ea09184e-81c9-4dac-892c-ebc7209a0812','和元晦十六日下山之韻','張栻','宋','宋诗','song-poetry','','[]','歸袂隨雲起，籃輿趁雪明。',48,'全唐诗/poet.song.150000.json','["歸袂隨雲起，籃輿趁雪明。", "山僧苦留客，世故却關情。", "小倚枯藤杖，聊聽絕澗聲。", "如何山下客，一笑已來迎。"]'),
('51e5b764-b5a8-40a5-b5cf-9679138b3d4d','和擇之韻','張栻','宋','宋诗','song-poetry','','[]','山中好景年年在，人事多端日日新。',32,'全唐诗/poet.song.150000.json','["山中好景年年在，人事多端日日新。", "不向青山生戀著，祇緣身世總非真。"]'),
('b4cf0dd9-77e7-48d9-9dce-b4e26915640c','和擇之韻','張栻','宋','宋诗','song-poetry','','[]','舊說峯頭寺，真成杖屨來。',48,'全唐诗/poet.song.150000.json','["舊說峯頭寺，真成杖屨來。", "却尋泥路滑，更喜野雲堆。", "寒積三冬雪，陽生九地雷。", "城中幾親友，爲說看山回。"]'),
('aa4c6106-c91a-4023-8f4f-bf8bd44ccaa3','題曾氏山園十一詠 尚絅堂','張栻','宋','宋诗','song-poetry','','[]','昔人爲己學，深旨妙隠微。',24,'全唐诗/poet.song.150000.json','["昔人爲己學，深旨妙隠微。", "三復尚絅章，服膺願無違。"]'),
('169a700a-f5f0-4d6e-9152-d19ba410b26e','題曾氏山園十一詠 夕陽臺','張栻','宋','宋诗','song-poetry','','[]','日暮天無風，岸巾夕陽中。',24,'全唐诗/poet.song.150000.json','["日暮天無風，岸巾夕陽中。", "回首發遐想，明月已升東。"]'),
('4674374e-6469-4ccb-b2c9-353a20462a0b','題曾氏山園十一詠 橘沜','張栻','宋','宋诗','song-poetry','','[]','我家湘水濱，年年賦徠服。',24,'全唐诗/poet.song.150000.json','["我家湘水濱，年年賦徠服。", "君家百畝田，晚歲千樹綠。"]'),
('d05df4e4-40e4-4c6a-a327-addc085fdf57','題曾氏山園十一詠 霜傑','張栻','宋','宋诗','song-poetry','','[]','種松苦難長，松長還耐久。',24,'全唐诗/poet.song.150000.json','["種松苦難長，松長還耐久。", "莫作目前思，但種門前柳。"]'),
('4119be9d-53cb-4481-8ff0-9cf6ba2a8505','題曾氏山園十一詠 菊隠','張栻','宋','宋诗','song-poetry','','[]','不肯競桃李，甘心同艾蒿。',24,'全唐诗/poet.song.150000.json','["不肯競桃李，甘心同艾蒿。", "德人一題品，愈覺風味高。"]'),
('eeaaf4d6-7fa0-4605-8e81-1e9b5e5cf0db','題曾氏山園十一詠 君子亭','張栻','宋','宋诗','song-poetry','','[]','嘉蓮秉嘉質，解后逢賞音。',24,'全唐诗/poet.song.150000.json','["嘉蓮秉嘉質，解后逢賞音。", "翁豈玩物者，寄意一何深。"]'),
('b969e158-6a63-4587-a2de-931d7ccc3a69','題曾氏山園十一詠 蓼步','張栻','宋','宋诗','song-poetry','','[]','扁舟橫薄莫，渺渺蓼知秋。',24,'全唐诗/poet.song.150000.json','["扁舟橫薄莫，渺渺蓼知秋。", "家山有江湖，何必賦遠遊。"]'),
('9a06dfec-d919-4646-850f-73ab5ee8e61d','題曾氏山園十一詠 北山','張栻','宋','宋诗','song-poetry','','[]','南山煙雨霏，北山風露多。',24,'全唐诗/poet.song.150000.json','["南山煙雨霏，北山風露多。", "衣沾非所惜，屨濕知如何。"]'),
('85c291d8-9ae0-4ce3-906b-9cbae867310e','題曾氏山園十一詠 梅沼','張栻','宋','宋诗','song-poetry','','[]','寒梅只自芳，野水有餘清。',24,'全唐诗/poet.song.150000.json','["寒梅只自芳，野水有餘清。", "山空歲云暮，妙意相發明。"]'),
('9ba728cb-04bb-4baf-a18d-5e353e7bb16c','題曾氏山園十一詠 桃花塢','張栻','宋','宋诗','song-poetry','','[]','花開山與明，花落水流去。',24,'全唐诗/poet.song.150000.json','["花開山與明，花落水流去。", "行人欲尋源，只在山深處。"]'),
('ac3e52ba-c8b3-458c-9a06-f6d2da3291c7','題曾氏山園十一詠 吟風橋','張栻','宋','宋诗','song-poetry','','[]','橋邊風月佳，俯仰有餘思。',24,'全唐诗/poet.song.150000.json','["橋邊風月佳，俯仰有餘思。", "無忘履冰心，方識吟風意。"]'),
('ab9cb523-da12-4293-9cc4-b75700a20f20','昨日與周伯壽別終夕雨小詩追路','張栻','宋','宋诗','song-poetry','','[]','夜雨虛簷響徹明，地蒸衣潤欲生雲。',32,'全唐诗/poet.song.150000.json','["夜雨虛簷響徹明，地蒸衣潤欲生雲。", "想君渚路頻回首，我亦書窗倍憶君。"]'),
('71121955-29c2-4b16-a32a-9d48757e2dad','自西園登山','張栻','宋','宋诗','song-poetry','','[]','日光射崖冰雪色，風壑傳響松龍吟。',32,'全唐诗/poet.song.150000.json','["日光射崖冰雪色，風壑傳響松龍吟。", "但忻耳目得所遇，不覺山高幾許尋。"]'),
('5a127e45-4baf-44d5-b4a2-a221e09ca65c','十五日再登祝融峰用臺字韻','張栻','宋','宋诗','song-poetry','','[]','今朝風日霽，共約再登臺。',48,'全唐诗/poet.song.150000.json','["今朝風日霽，共約再登臺。", "人在雲端上，僧從天際回。", "巖頭風戛竹，林畔雪欺梅。", "濁酒消寒氣，無妨飲數杯。"]'),
('ee214474-19d8-4d88-8a71-d281aa009356','方廣寺睡覺','張栻','宋','宋诗','song-poetry','','[]','僧舍孤衾寄此情，莊生夢破曉鐘聲。',32,'全唐诗/poet.song.150000.json','["僧舍孤衾寄此情，莊生夢破曉鐘聲。", "浮漚蹤跡原無定，惆悵西風一夜清。"]'),
('fc875ad1-9ea2-4adb-b655-1a53caaf4f16','胡丈廣仲與范伯崇自嶽市來同登絕頂舉酒極談得聞比日講論之樂','張栻','宋','宋诗','song-poetry','','[]','久憩珠林寺，高軒自遠來。',48,'全唐诗/poet.song.150000.json','["久憩珠林寺，高軒自遠來。", "攜朋上喬嶽，載酒到瓊臺。", "論道吟心樂，吟詩笑眼開。", "遥觀松柏樹，風韻有餘哀。"]'),
('4b9832e3-100b-4fea-ad48-630a07503561','春日西興道中  其一','張栻','宋','宋诗','song-poetry','','[]','短短菰蒲綠未齊，河洲水暖鴈行低。',32,'全唐诗/poet.song.150000.json','["短短菰蒲綠未齊，河洲水暖鴈行低。", "歸時須趁春光淺，待得春深意却迷。"]'),
('5899d405-2770-4596-a99c-6b30b73605cb','春日西興道中  其二','張栻','宋','宋诗','song-poetry','','[]','江梅已過杏花初，尚怯餘寒著萼疎。',32,'全唐诗/poet.song.150000.json','["江梅已過杏花初，尚怯餘寒著萼疎。", "待得重來幾枝在，半隨蝶翅半蜂鬚。"]'),
('79370fbd-94fd-4159-b13c-22e51fb49f78','春日西興道中  其三','張栻','宋','宋诗','song-poetry','','[]','岸容山意兩溶溶，便是東皇第一功。',32,'全唐诗/poet.song.150000.json','["岸容山意兩溶溶，便是東皇第一功。", "春色平鋪人不見，却將醉眼認繁紅。"]'),
('46befc94-9dca-45f3-816c-8899ca8b8ad2','春日西興道中  其四','張栻','宋','宋诗','song-poetry','','[]','一川曉色鷺分去，兩岸烟花鶑带來。',32,'全唐诗/poet.song.150000.json','["一川曉色鷺分去，兩岸烟花鶑带來。", "徑欲卜居從釣叟，綠楊缺處竹門開。"]'),
('fff91c86-5c30-4646-a584-fb96006f8b3c','春日西興道中  其五','張栻','宋','宋诗','song-poetry','','[]','簷鐸無聲鳥語稀，徑深鐘梵出花遲。',32,'全唐诗/poet.song.150000.json','["簷鐸無聲鳥語稀，徑深鐘梵出花遲。", "日長徧遶溪南寺，未信東風屬酒旗。"]'),
('db0b7e98-a6f4-4527-a21a-6d75ebd050ca','晚春','張栻','宋','宋诗','song-poetry','','[]','捲地狂風殿晚春，落花蓋水欲成雲。',32,'全唐诗/poet.song.150000.json','["捲地狂風殿晚春，落花蓋水欲成雲。", "向人不改舊時面，只有蒼官無此君。"]'),
('1277b33e-59be-458a-8960-8323add97a3e','晚望','張栻','宋','宋诗','song-poetry','','[]','獨上荒亭數過帆，橫林疎處見蒼灣。',32,'全唐诗/poet.song.150000.json','["獨上荒亭數過帆，橫林疎處見蒼灣。", "固知不入豪華眼，送與鳬鷗自在看。"]'),
('0222fa79-ae35-4548-a3cd-9d1ee7220e98','八詠樓有感','張栻','宋','宋诗','song-poetry','','[]','仲舒舊事無人記，家令風流一世傾。',32,'全唐诗/poet.song.150000.json','["仲舒舊事無人記，家令風流一世傾。", "天下何曾識真吏，古來幾許尚虛名。"]'),
('a6471de1-a338-4feb-aaaa-af4cc6ee0243','遊絲','張栻','宋','宋诗','song-poetry','','[]','遊絲浩蕩醉春光，倚頼微風故故長。',32,'全唐诗/poet.song.150000.json','["遊絲浩蕩醉春光，倚頼微風故故長。", "幾度鶑聲留欲住，又隨飛絮過東牆。"]'),
('642f7be2-a679-4697-b59d-8626bc0a0886','題劉氏綠映亭  其一','張栻','宋','宋诗','song-poetry','','[]','凉葉翻翻不受塵，芒鞋藤杖及清晨。',32,'全唐诗/poet.song.150000.json','["凉葉翻翻不受塵，芒鞋藤杖及清晨。", "開簾小放前溪入，澄綠光中獨岸巾。"]'),
('21d2752b-8c0e-497c-ae11-a33137f59b32','題劉氏綠映亭  其二','張栻','宋','宋诗','song-poetry','','[]','鷺浴魚跳在鏡屏，摇青浮碧太鮮明。',32,'全唐诗/poet.song.150000.json','["鷺浴魚跳在鏡屏，摇青浮碧太鮮明。", "牆東種得陰成幄，隔葉看來却有情。"]'),
('946bb51f-0d15-4373-8d72-22ac2f61c2a9','大雲巖','張栻','宋','宋诗','song-poetry','','[]','平地起突兀，頹然若負龜。',48,'全唐诗/poet.song.150000.json','["平地起突兀，頹然若負龜。", "初疑斤斧鑿，安得此巧奇。", "乃知化工巧，精意運神機。", "巖深翠長滴，沖沖閲四時。"]'),
('cdd94b78-9c31-4dbf-8e0d-e28e14fa64c3','和故舊招館','張栻','宋','宋诗','song-poetry','','[]','牢落詩盟寒欲灰，非君懷抱若爲開。',32,'全唐诗/poet.song.150000.json','["牢落詩盟寒欲灰，非君懷抱若爲開。", "未闌樽酒論文意，拂榻應須有待來。"]'),
('ea6f03f9-e672-4115-9f96-9a4f6159b3eb','和友人夢游西山','張栻','宋','宋诗','song-poetry','','[]','故人疇昔隠西峰，野寺幽房一徑通。',64,'全唐诗/poet.song.150000.json','["故人疇昔隠西峰，野寺幽房一徑通。", "無復老僧談舊事，空餘修竹滿清風。", "夢中尋勝忘南北，句裏論心豈異同。", "我欲壁間題唱和，他年留得詫南公。"]'),
('ddf9ab0b-5ada-45ad-a031-73d60a9064e4','過上天竺寺','張栻','宋','宋诗','song-poetry','','[]','上竺諸天近，中林萬木低。',48,'全唐诗/poet.song.150000.json','["上竺諸天近，中林萬木低。", "迥超塵世外，恍入雪山西。", "忽漫參龍象，行將混鹿麋。", "何年釋簪紱，於此獨幽棲。"]'),
('ef5b31b4-8412-48f0-93ab-8807b2097115','荆湖望月','張栻','宋','宋诗','song-poetry','','["\u8861\u5c71"]','浩浩湖之源，迤邐衡山下。',60,'全唐诗/poet.song.150000.json','["浩浩湖之源，迤邐衡山下。", "有月來中天，明珠千斛瀉。", "澂澈一塵無，交輝清不夜。", "嗟彼泉下人，逝莫挽逸駕。", "惟有不死心，清光徧華夏。"]'),
('4043864c-a79c-4746-84e7-bfeb981ca991','登嶽麓赫曦臺聯句','張栻','宋','宋诗','song-poetry','','[]','泛舟長沙渚，振策湘山岑。',48,'全唐诗/poet.song.150000.json','["泛舟長沙渚，振策湘山岑。", "煙雲渺變化，宇宙窮高深。", "懷古壯士志，憂時君子心。", "寄言塵中客，莽蒼誰能尋。"]'),
('a4b03503-50df-4e70-bd9f-86d0a73a2525','落梅','張栻','宋','宋诗','song-poetry','','[]','清溪南畔小橋東，落月紛紛水映紅。',64,'全唐诗/poet.song.150000.json','["清溪南畔小橋東，落月紛紛水映紅。", "五夜客愁花片裏，一年春事角聲中。", "歌殘玉樹人何在，舞破香衫曲未終。", "却憶孤山醉歸路，馬蹏殘雪襯春風。"]'),
('7357181b-9888-4810-a2b6-902a252f1f88','句','張栻','宋','宋诗','song-poetry','','[]','郴山足奇變，其水復清美。',12,'全唐诗/poet.song.150000.json','["郴山足奇變，其水復清美。"]'),
('1b6a6f3c-995c-47e6-a3a6-51d9f8808d66','和陶淵明二十首  其一','陳造','宋','宋诗','song-poetry','','[]','作計憂患場，賢聖頗中之。',60,'全唐诗/poet.song.150000.json','["作計憂患場，賢聖頗中之。", "淮鄉酒價賤，希復獨醒時。", "齒髮變今昔，撫己屬負茲。", "清坐挹飲客，辭費未免疑。", "客歡我怡然，此戒何妨持。"]'),
('20890e8f-783b-4587-8fc4-0a00c54cbdb1','和陶淵明二十首  其二','陳造','宋','宋诗','song-poetry','','[]','壯歲銳著述，瞢欲藏名山。',48,'全唐诗/poet.song.150000.json','["壯歲銳著述，瞢欲藏名山。", "中間忽自哂，聒聒厭多言。", "棄置杯中樂，雕鎪耗歲年。", "不知百歲後，何益空名傳。"]'),
('4c36ed81-578e-4c86-bd29-43e1e59a1558','和陶淵明二十首  其三','陳造','宋','宋诗','song-poetry','','[]','薄俗不難化，君子要得情。',60,'全唐诗/poet.song.150000.json','["薄俗不難化，君子要得情。", "善政良易孚，循良本無名。", "一從吏海邑，我暇民樂生。", "穽填虎自避，心冥鷗不驚。", "且了飽飯課，不問報政成。"]'),
('66ebed21-61cd-42f4-b148-646c6f2cb76f','和陶淵明二十首  其四','陳造','宋','宋诗','song-poetry','','[]','不念建德遊，枉作心奮飛。',72,'全唐诗/poet.song.150000.json','["不念建德遊，枉作心奮飛。", "一溺狂泉飲，坐受人所悲。", "吾樂有餘地，醉鄉真可依。", "酹觴初問塗，嗽醪便知歸。", "棄置近藥裹，改絃計扶衰。", "歡趣固自若，誰謂志願違。"]'),
('352d7f59-fe63-4ce3-a56c-02fb64cc7ff6','和陶淵明二十首  其五','陳造','宋','宋诗','song-poetry','','[]','捐金得嘉旨，舉室更笑喧。',60,'全唐诗/poet.song.150000.json','["捐金得嘉旨，舉室更笑喧。", "老子舊小戶，醉帽每先偏。", "即今省酒費，或辦歸買山。", "吏隠有定趣，縣債當亟還。", "乘流遇坎止，畢世佩此言。"]'),
('55eb7ec3-057b-4bb9-8c7a-b81b892984f1','和陶淵明二十首  其六','陳造','宋','宋诗','song-poetry','','[]','張竦詆陳遵，彼此竟誰是。',48,'全唐诗/poet.song.150000.json','["張竦詆陳遵，彼此竟誰是。", "徐公今似優，昔行未容毀。", "中年覆觴過，畏病乃能爾。", "兒輩無真見，縕袍賢錦綺。"]'),
('62b8e9e2-2bd6-463a-ba24-01c1f2c71010','和陶淵明二十首  其七','陳造','宋','宋诗','song-poetry','','[]','海鄉亦好春，紅紫紛蕤英。',61,'全唐诗/poet.song.150000.json','["海鄉亦好春，紅紫紛蕤英。", "黄鳥托庭柯，啁异常如有情。", "知我得碧濤，似勸花前傾。", "豈知好飲客，靜坐耐耳鳴。", "茹津拆紅泥，鯨吸看後生。"]'),
('a9eeb55f-e2fa-4d2d-a810-c34eac239d97','和陶淵明二十首  其八','陳造','宋','宋诗','song-poetry','','[]','骯髒老眉面，豈是趨世資。',60,'全唐诗/poet.song.150000.json','["骯髒老眉面，豈是趨世資。", "謬著百僚底，躄躠彊折枝。", "深知才用短，敢謂時命奇。", "歸耕不顧計，更問婚娶爲。", "何向不貧賤，肯爲寸祿羈。"]'),
('cb8866bd-5652-4386-98ca-4314ed5b3295','和陶淵明二十首  其九','陳造','宋','宋诗','song-poetry','','[]','公朝不遺才，蕩蕩天門開。',96,'全唐诗/poet.song.150000.json','["公朝不遺才，蕩蕩天門開。", "雜遝盡奇士，騰凌舒壯懷。", "有客尋遂初，與時自作乖。", "脫粟傲肉食，官居當巖棲。", "東州拜璽書，西州迎芝泥。", "夫也商聲謳，滿屋金石諧。", "詩書孰踐履，簿領甘沉迷。", "平生獨往願，萬牛挽莫回。"]'),
('710c1b7f-6ff2-46bd-987c-f58f4102e05d','和陶淵明二十首  其一○','陳造','宋','宋诗','song-poetry','','[]','自公有至樂，詩卷還坐隅。',60,'全唐诗/poet.song.150000.json','["自公有至樂，詩卷還坐隅。", "得句一吐之，嬉然忘窮塗。", "百世一俯仰，萬象付馳驅。", "吟情當飲興，其樂皆有餘。", "役心聲利場，咄咄彼何居。"]'),
('30357a4e-db00-498b-93a8-e53732dabffd','和陶淵明二十首  其一一','陳造','宋','宋诗','song-poetry','','[]','卯金穿窬雄，典午盜有道。',72,'全唐诗/poet.song.150000.json','["卯金穿窬雄，典午盜有道。", "當時附炎人，忍耻稱國老。", "延之終代北，范粲車上槁。", "矯矯竹林儁，麴糵豈真好。", "陶公諸公右，烱若橫道寶。", "不就酣湎逝，亦恐自標表。"]'),
('f63b2a99-6157-4e53-8630-883b7c6ccf67','和陶淵明二十首  其一二','陳造','宋','宋诗','song-poetry','','[]','訪書酒誥空，揚子浪傷時。',72,'全唐诗/poet.song.150000.json','["訪書酒誥空，揚子浪傷時。", "頌德譽大人，劉伶頗費辭。", "人生意行耳，暇復商略茲。", "用己律世人，一信起千疑。", "規規滯所然，在物寧非欺。", "我心受風舟，漂然隨所之。"]'),
('9c777723-0221-464c-bdfc-4a8f9bda4779','和陶淵明二十首  其一三','陳造','宋','宋诗','song-poetry','','[]','人生無賢愚，彼是皆夢境。',60,'全唐诗/poet.song.150000.json','["人生無賢愚，彼是皆夢境。", "矻矻迷所求，冥冥睡未醒。", "此心方放紛，息念乃要領。", "衝風有驚波，揠苗無佳穎。", "夢覺悵今昔，吾其默自炳。"]'),
('13c299ea-2b1c-4575-a178-b54cce9036ef','和陶淵明二十首  其一四','陳造','宋','宋诗','song-poetry','','[]','暇日坐北窗，好風竹間至。',60,'全唐诗/poet.song.150000.json','["暇日坐北窗，好風竹間至。", "楚騷偶到眼，開卷已心醉。", "愛君君子心，湛身抑其次。", "自靖各所安，苟難豈所貴。", "非渠工語言，誰遣忘肉味。"]'),
('7c178bf7-5ce1-4795-bf78-4bc67d76dddf','和陶淵明二十首  其一五','陳造','宋','宋诗','song-poetry','','[]','憒憒綺紈兒，客或大其宅。',60,'全唐诗/poet.song.150000.json','["憒憒綺紈兒，客或大其宅。", "長公抱胸奇，所向有削迹。", "窮達吁可驚，賢否乃什百。", "請君勿此計，計之當浮白。", "九品寧用評，四并良可惜。"]'),
('42e9b3bb-5662-4158-a167-d262628cc87f','和陶淵明二十首  其一六','陳造','宋','宋诗','song-poetry','','[]','細閲史氏書，宛若身所經。',72,'全唐诗/poet.song.150000.json','["細閲史氏書，宛若身所經。", "夢錄以命之，過影紀虧成。", "一堯間十秦，寒暑倏變更。", "我起千歲後，遊心於大庭。", "俛仰海塵揚，鼓舞天籟鳴。", "紛紛閲過前，表立俱志情。"]'),
('bcc6ed19-1e86-4e16-9f89-fe3160e8d8c1','和陶淵明二十首  其一七','陳造','宋','宋诗','song-poetry','','[]','達觀無畦畛，自狹叔季風。',48,'全唐诗/poet.song.150000.json','["達觀無畦畛，自狹叔季風。", "典書有佳釀，飲徒常眼中。", "彼醉我俱適，未覺介勝通。", "剛制免寂寥，政復人得弓。"]'),
('93d21362-334f-4e58-b439-87ce0b78adc5','和陶淵明二十首  其一八','陳造','宋','宋诗','song-poetry','','[]','少從師友間，雅意效一得。',60,'全唐诗/poet.song.150000.json','["少從師友間，雅意效一得。", "中年彈塵冠，欲起復回惑。", "初無輔時具，吾責良易塞。", "即今禹紹舜，羣俊萃王國。", "臣猶自知之，環省每愍默。"]'),
('876e22ee-cac0-4586-bec8-be7d7c73014c','和陶淵明二十首  其一九','陳造','宋','宋诗','song-poetry','','[]','昔人蟻壤遊，方復詫貴仕。',84,'全唐诗/poet.song.150000.json','["昔人蟻壤遊，方復詫貴仕。", "回首辭窮約，投分感知己。", "鄰鼓驚邊隅，得無豢養耻。", "戰酣日爲却，血尸三百里。", "推枕視窗日，前事皆可紀。", "向來心營營，乃始得真止。", "彼此誰賢愚，所持那足恃。"]'),
('890457b2-7d84-4740-ac0b-b926f7a5462d','和陶淵明二十首  其二○','陳造','宋','宋诗','song-poetry','','[]','陶翁出宰縣，徑去亦天真。',120,'全唐诗/poet.song.150000.json','["陶翁出宰縣，徑去亦天真。", "閑居詩成集，古雅仍深醇。", "坡翁訪赤壁，臨流雙鬢新。", "小袖補衮手，千篇準過秦。", "兩翁閲當世，眇若毫端塵。", "熙豐望義熙，愛君最忠勤。", "向非與道俱，寧爾著語親。", "自我誦遺編，行身少知津。", "敢忘炷爐香，亦復墊雨巾。", "鼎鼎蓋棺前，期無愧斯人。"]'),
('b2753494-2b8a-4cd0-bcbc-4914bb732f3b','書法蟹方後','陳造','宋','宋诗','song-poetry','','[]','放麑念號鳴，易牛憐觳觫。',144,'全唐诗/poet.song.150000.json','["放麑念號鳴，易牛憐觳觫。", "仁心誰獨無，天機或待觸。", "悠悠寄宇宙，往往狥口腹。", "君子一飽適，庖事不到目。", "寧知刀俎間，宛轉無聲哭。", "空蜚與土穴，暴殄無遺育。", "況此佳風味，世肯貸爾族。", "炳炬擒爬沙，免介薦膏馥。", "向來橫戈怒，不救摇牙酷。", "醤浴酒拍浮，方法忍抄錄。", "躁擾至絕命，耳聞痛在肉。", "淡茹吾能事，晚食媚山蔌。"]'),
('e092768c-a719-435c-963e-0699325272fc','寄二孫 嶤','陳造','宋','宋诗','song-poetry','','[]','憶昔初抱孫，雙鬢颯已秋。',144,'全唐诗/poet.song.150000.json','["憶昔初抱孫，雙鬢颯已秋。", "眼看與我長，歲月如許遒。", "我以薄宦西，汝爲守舍留。", "夢輒來後前，歲律欻再周。", "想今與迺父，長我更半頭。", "天姿粹而溫，整整靜不浮。", "六經如取携，八面自優遊。", "落筆動萬言，頗能如翁不。", "如翁何足道，抗志須前修。", "良匠有妙斲，惰農無厚收。", "彼哉碌碌者，不源而計流。", "吾言不虛往，過是夫何求。"]'),
('82d2be85-0c8e-42a0-b0e2-35d043918d3c','寄二孫 扆','陳造','宋','宋诗','song-poetry','','[]','阿泰幼儻碭，勢若泛駕馬。',144,'全唐诗/poet.song.150000.json','["阿泰幼儻碭，勢若泛駕馬。", "暫別已束髮，折節殊曩者。", "誦書口瀾翻，晝夜曾不捨。", "課肯犯雪供，筆亦揮汗把。", "才地校優劣，不在阿儒下。", "平時於方兄，眇視真土苴。", "念翁少年日，爲學不餘暇。", "混俗類疎放，秉心迺儒雅。", "兒今頗肖吾，解笑時苟且。", "師匠求有餘，好書不外假。", "緬懷螢雪邊，力倍功更寡。", "可用吾季孟，直輩古班賈。"]'),
('e41852f4-30fb-4876-ab9f-a9825bd07857','苦旱六首  其一','陳造','宋','宋诗','song-poetry','','[]','旱氣乘炎熇，觸耳仍怨咨。',48,'全唐诗/poet.song.150000.json','["旱氣乘炎熇，觸耳仍怨咨。", "九重正宵旰，解顔定何時。", "書生身世憂，寧止八口饑。", "可復河朔醉，欲賡云漢詩。"]'),
('bd51f694-7a7f-42b3-a895-8ebd9a8fe9f9','苦旱六首  其二','陳造','宋','宋诗','song-poetry','','[]','雨師久退藏，風伯恣吹鼓。',48,'全唐诗/poet.song.150000.json','["雨師久退藏，風伯恣吹鼓。", "蓊然西郊雲，離合太熒侮。", "及茲一汛灑，頗亦清袢暑。", "幾占魚鱗天，僅得龍尾雨。"]'),
('aa4870a8-7724-4c43-8c06-942c3332f6c1','苦旱六首  其三','陳造','宋','宋诗','song-poetry','','[]','我雖甓社居，有田不瀕湖。',48,'全唐诗/poet.song.150000.json','["我雖甓社居，有田不瀕湖。", "漫漫湖水長，奈此田中枯。", "携文客邊侯，劣可輸殘租。", "黧瘁不識飽，愧爾耕田夫。"]'),
('95b2009d-2e78-4463-be65-7db057c310bd','苦旱六首  其四','陳造','宋','宋诗','song-poetry','','[]','枯旱歲十九，無若今歲酷。',48,'全唐诗/poet.song.150000.json','["枯旱歲十九，無若今歲酷。", "日色雖許赤，苗心尚餘綠。", "舉觴勸睡龍，雄飛勝雌伏。", "作意收桑榆，前愆儻容贖。"]'),
('08e41eb5-ab14-4fb4-b105-3ff1e2ce0069','苦旱六首  其五','陳造','宋','宋诗','song-poetry','','[]','蒼生惜死所，倚須數寸澤。',48,'全唐诗/poet.song.150000.json','["蒼生惜死所，倚須數寸澤。", "連朝油雲度，空勞問雨色。", "豐歉恐數然，造物莫爲力。", "定知天屢陰，爲爾動悽惻。"]'),
('a7bb7c06-43c0-4e39-afb2-b369b844c719','苦旱六首  其六','陳造','宋','宋诗','song-poetry','','[]','頻年忍流移，猶幸稊稗熟。',48,'全唐诗/poet.song.150000.json','["頻年忍流移，猶幸稊稗熟。", "稊稗亦已無，何以填饑腹。", "時方迫凍餒，勢恐瞢榮辱。", "儻無意外憂，根蘗猶可斸。"]'),
('92c438aa-2e0a-4106-99b6-4e010cff8b16','馬上見賣白蓮者三首  其一','陳造','宋','宋诗','song-poetry','','[]','引息度奇暑，風日正交戰。',72,'全唐诗/poet.song.150000.json','["引息度奇暑，風日正交戰。", "淮鄉六月春，嫣然擔頭見。", "香凝素囊拆，濕餘清露泫。", "豐膚專正色，一忠百佞賤。", "祝融迺司花，慰我紅塵面。", "買歸一盃適，得共黄葵薦。"]'),
('d8416900-fa25-4323-8dc2-5ae3c293f810','馬上見賣白蓮者三首  其二','陳造','宋','宋诗','song-poetry','','[]','東蕩百頃寬，滿蕩蓮結花。',72,'全唐诗/poet.song.150000.json','["東蕩百頃寬，滿蕩蓮結花。", "孤村蓮蕩西，茅茨吾所家。", "年年紅紫盡，爲春留芳華。", "酒船墮雲錦，歌棹凌瑞霞。", "只今鄉閭夢，不道身風沙。", "把花但三嗅，對酒長咨嗟。"]'),
('b4a1d68b-a26a-45ae-98e6-40f1300ff967','馬上見賣白蓮者三首  其三','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東蕩花清晨，西湖渺無津。',72,'全唐诗/poet.song.150000.json','["東蕩花清晨，西湖渺無津。", "凉荷引天遠，極目粧面新。", "鳴榔與鼓枻，彼豈尋芳人。", "香風漂我舟，領略不及賓。", "當時賞花句，興在迹已陳。", "歌似冰玉友，花面俱迴春。"]'),
('2d5c987e-1a5d-4635-9f30-3c2ccb83d535','蔡秀才求予所作記作詩贈之時蔡移居','陳造','宋','宋诗','song-poetry','','[]','古人四壁居，今人猶歎息。',72,'全唐诗/poet.song.150000.json','["古人四壁居，今人猶歎息。", "蔡子携百指，亦自無四壁。", "分絕檳榔求，未斷文字癖。", "此行誰知己，所向盡艱食。", "予文久自知，不作杯水直。", "方君忍饑雷，可語寧此石。"]'),
('4f14ed53-619b-47d8-bf9c-ac0ab260714a','彭尉焚巢二首  其一','陳造','宋','宋诗','song-poetry','','[]','彭家柳邊堂，江色潤書畫。',120,'全唐诗/poet.song.150000.json','["彭家柳邊堂，江色潤書畫。", "迺公根柢學，衣傳自心會。", "唾手勳業餘，探妙文字外。", "區區青紫計，韋子豈君配。", "神物護揮毫，而不告成壞。", "赫炎卷地過，椽瓦了無在。", "頼是堂間書，萬軸腹中載。", "迺公洞天理，否傾則爲泰。", "向來薦才名，開口取猜怪。", "從今柳先生，頗爲參元快。"]'),
('e309380c-7b18-4dad-bad2-d86744d5891d','彭尉焚巢二首  其二','陳造','宋','宋诗','song-poetry','','[]','迺翁五車讀，弓劍初一命。',120,'全唐诗/poet.song.150000.json','["迺翁五車讀，弓劍初一命。", "九十歸田園，顔丹眼如鏡。", "客來不告倦，筆落有餘勁。", "霜嚴草花落，松柏獨也正。", "吾憐盼與札，徐閲襄昭定。", "濟美竟寂寞，陳編漫輝映。", "翁家戲綵郎，足繼賢業盛。", "雄詞逼王楊，奧學窺韓孟。", "援今校古昔，兩翁猶此病。", "今段天試君，處此要以靜。"]'),
('58b0027b-b455-4be1-b7e4-710047527659','次韻章舜舉','陳造','宋','宋诗','song-poetry','','[]','天孫望河鼓，杳眇河西東。',144,'全唐诗/poet.song.150000.json','["天孫望河鼓，杳眇河西東。", "參旗映天梁，欻作秋夕逢。", "人生風馬牛，未害心期同。", "章侯大雅士，抱負難形容。", "平生萬卷讀，會意春冰融。", "小遲風雲期，未剖琳瑯胸。", "我頃誦清句，神馳水朝宗。", "識面勝聞名，論文得新功。", "烱彼如意珠，來自仙者宮。", "徑作君苗焚，執筆吾熱中。", "荒學顧何取，目昏鬢已童。", "惟應得石友，天用慰塗窮。"]'),
('0e63e8d8-38a7-43ea-98da-84724268ad89','再用前韻贈鹽城四士','陳造','宋','宋诗','song-poetry','','[]','行李小槃薄，海西裨海東。',144,'全唐诗/poet.song.150000.json','["行李小槃薄，海西裨海東。", "交情半新故，生世有遇逢。", "從我二三子，草木臭味同。", "業工畫眉嫵，飾此冰雪容。", "高軒一再過，向我作春融。", "陳侯犀一角，錦腸星斗胸。", "章侯金百鍊，學派傳正宗。", "楊侯較諸楊，朝墨收儁功。", "王郎天地間，合侍明光宮。", "我老一無可，短翼羣蜚中。", "樽酒剪銀燭，詩錦佩奚童。", "寬破十日留，文律得細窮。"]'),
('23d88d49-38d7-4820-b260-025107bfa2aa','次韻王解元賃地築屋','陳造','宋','宋诗','song-poetry','','[]','饑麟不落毛，士生常百憂。',156,'全唐诗/poet.song.150000.json','["饑麟不落毛，士生常百憂。", "何人金爲埒，振客不待求。", "之子磊磈胸，貯書不貯愁。", "焉知奉二老，百指借岸舟。", "方耐冷侵骨，未暇吟掉頭。", "目前帡幪託，急於溫飽謀。", "詩來愬窮狀，讀想寒颼颼。", "我亦寄別巢，其拙真病鳩。", "每慙烏所瞻，更羨鶑出幽。", "君看沉沉者，生不譚軻丘。", "可食忘嗟來，至寶忌暗投。", "天地吾蘧廬，此理君信不。", "爲親儻可屈，三返無宜休。"]'),
('e5f366eb-fb00-4231-a50a-9509a08b4f3d','次韻章時可','陳造','宋','宋诗','song-poetry','','[]','般門難呈拙，仰屋方自咎。',144,'全唐诗/poet.song.150000.json','["般門難呈拙，仰屋方自咎。", "詩肩卓兩峰，因君笑今又。", "袖手非不佳，拜賜良獨厚。", "翩翩王公孫，肝肺衷繪繡。", "向來傳新作，價欲擅文囿。", "妙語再墮前，吟玩忘昏晝。", "江濤駭澎湃，風竹聆疎瘦。", "足我學古心，如飲得美酎。", "氣無寒郊寒，派續後山後。", "采采葩華林，羣芳釀孤茂。", "錯刀合瓊瑶，內索慙寡陋。", "肯如周人朴，唾去不一嗅。"]'),
('52d47aeb-e046-4d70-8240-4d674cbb95c7','贈施都正三首  其一','陳造','宋','宋诗','song-poetry','','[]','嚴嚴神仙居，不受世塵涴。',48,'全唐诗/poet.song.150000.json','["嚴嚴神仙居，不受世塵涴。", "棲身白玉壺，眼凈詎容唾。", "主人敬愛客，馬秣僕不餓。", "洗心爐薰前，容了舊經課。"]'),
('5cfd2eb8-e1ab-486b-9a01-cd5280e581fa','贈施都正三首  其二','陳造','宋','宋诗','song-poetry','','[]','雨窗舞晦明，風竹作騷屑。',48,'全唐诗/poet.song.150000.json','["雨窗舞晦明，風竹作騷屑。", "斷無思歸夢，人境兩清絕。", "道人氣金玉，妙論挾冰雪。", "未須金鼎丹，始可黑霜髮。"]'),
('5ff909b9-0715-4e02-a2f8-3c0eb26a0bfb','贈施都正三首  其三','陳造','宋','宋诗','song-poetry','','[]','欲觀芸芸初，當求根極地。',48,'全唐诗/poet.song.150000.json','["欲觀芸芸初，當求根極地。", "古今貉一丘，貴賤魚千里。", "纖雲翳太空，玄珠在深水。", "安得數年閑，與師商榷此。"]'),
('699fffeb-26cb-4fa6-be9d-4a9ab262849f','次潘德久韻','陳造','宋','宋诗','song-poetry','','[]','沉沉王侯居，列屋皆妖妍。',96,'全唐诗/poet.song.150000.json','["沉沉王侯居，列屋皆妖妍。", "性斧糜春葱，日詫歌舞筵。", "孰知山澤儒，超然廣文氈。", "野花供嫵媚，山月獻連娟。", "潘郎真吾徒，常加視後鞭。", "居無鮑生馬，紅粉風蓬旋。", "張公爲石奴，處仲政復賢。", "繼今看遠業，賤子當留年。"]'),
('c26f1c63-0c99-457e-9960-0f873fd38e75','次韻章茂深安撫見寄','陳造','宋','宋诗','song-poetry','','[]','引領數仞牆，坐歷幾秋仲。',120,'全唐诗/poet.song.150000.json','["引領數仞牆，坐歷幾秋仲。", "西風度凝香，稍羞文字供。", "使君今退之，一眄士輕重。", "碩德金玉文，天畀爲吾宋。", "鄙夫老世紛，萬事曲肱夢。", "向來竊膏馥，編綴飽吟諷。", "此詩含古意，羣騷之橘頌。", "理窟有餘地，猶許一醉共。", "名卿璧一雙，豪士笛三弄。", "侍公眼生纈，聊目歸鴻送。"]'),
('132000c3-4619-41c3-9555-ba363021a83f','七月附米舟之浙中作','陳造','宋','宋诗','song-poetry','','[]','白蟲散如蛆，黑蟲聚如蟻。',120,'全唐诗/poet.song.150000.json','["白蟲散如蛆，黑蟲聚如蟻。", "循緣仍咂齧，欲寐復九起。", "吾舟玉爲粒，生此果何理。", "神奇作臭腐，秋暑况如燬。", "人生託洪爐，一飽蓋分爾。", "臨流念彫年，胡迺置身此。", "笑口忽唶惋，曼膚或瘡痏。", "隄防費應俗，情僞良不美。", "短籬護松菊，吾歸殊可喜。", "錐刀詫朋儕，嗟爾商販子。"]'),
('fa6d1566-dded-480f-9a56-939c1a1b920a','召伯停舟辟雨','陳造','宋','宋诗','song-poetry','','[]','窗度荷芰風，舟艤鴛鴦浦。',96,'全唐诗/poet.song.150000.json','["窗度荷芰風，舟艤鴛鴦浦。", "落帆憩篙師，辟此白淙雨。", "長征取愜快，留滯不云苦。", "適喜縣麻勢，爲盪鑠石暑。", "去年舟繫柳，卧看虹飲渚。", "龍公會事發，尚記跳珠語。", "崎嶇不諧俗，似爲龍所予。", "一盃酬新凉，開瓶先酹汝。"]'),
('0958c625-39b0-4f5c-937e-ccf3ccb9539b','過樊村','陳造','宋','宋诗','song-poetry','','[]','襄鄂二千里，何啻三百灣。',72,'全唐诗/poet.song.150000.json','["襄鄂二千里，何啻三百灣。", "風色九順逆，左往復右還。", "舟行已三日，沿流不作艱。", "即今蒼煙面，猶是泊處山。", "信次有定期，曲直了不關。", "聊可供戲事，輕橈與回環。"]'),
('94023cb3-b366-42bb-9fa8-784ecc632feb','呂城待閘得陳魏二生晤語','陳造','宋','宋诗','song-poetry','','[]','呂城望奔牛，道里不作遠。',96,'全唐诗/poet.song.150000.json','["呂城望奔牛，道里不作遠。", "徙倚不容前，奈此河流淺。", "窘步客懷惡，癡坐僕夫倦。", "班荆得兩生，晤語忘旦晚。", "文卷得細披，湯餠亦粗辦。", "生須朋從樂，時亦慰連蹇。", "長吟行路難，回首偶耕願。", "卜鄰儻君等，老我幸無怨。"]'),
('76b62515-958f-4476-af2e-a6982aa9b08b','贈楊伯時','陳造','宋','宋诗','song-poetry','','[]','璧月無纖翳，冰壺不受塵。',120,'全唐诗/poet.song.150000.json','["璧月無纖翳，冰壺不受塵。", "西京子雲裔，有官居士身。", "今代龐德公，淑質秉大雅。", "生事一丘壑，龍鳳拜床下。", "緒餘辨官業，膏馥付爾曹。", "詩聲華岳重，士論錫山高。", "京塵逆旅中，初喜識芝宇。", "鄙語愧呈拙，有底極推許。", "漂流當定居，久計浙西東。", "他年結詩社，未嫌後從公。"]'),
('41f2b029-966b-4c50-ac0a-32a18ce4aa66','送葉主簿楚州應錢帥之招','陳造','宋','宋诗','song-poetry','','[]','漢庭用少餘，無策銷外侮。',240,'全唐诗/poet.song.150000.json','["漢庭用少餘，無策銷外侮。", "充國七十翁，勝算定樽俎。", "夫君譚西北，萬里真目睹。", "諸將失投機，遽豈一二數。", "形勢可聚米，君王未借箸。", "江湖五十年，帝閽嚴九虎。", "後生不更事，兒戲議邊圉。", "圓方殊枘鑿，寂默忍羈旅。", "平生干霄氣，百吞不一吐。", "白眼閲流俗，閉口避爾汝。", "山陽文武資，幹國今吉甫。", "清嘯臨籌邊，志已無驕虜。", "經年虛代舍，須君作謀主。", "心嗤區區鄭，緩不省之武。", "盍思度外意，徑略紙上語。", "山陽吾未識，彷彿夢眉宇。", "斷知磊落人，衆棄能獨取。", "一巵勸臨分，三歎欲輕舉。", "抒君胸中奇，定作商應羽。", "還應訪隠淪，道我聽鷄舞。"]'),
('c4c0ff22-38e1-4cd4-8a13-6b2740c5aa07','次韻王解元','陳造','宋','宋诗','song-poetry','','[]','觀名計利心，惴惴日交戰。',180,'全唐诗/poet.song.150000.json','["觀名計利心，惴惴日交戰。", "洪濤探龍睡，赤手投虎圈。", "孰知青雲士，眼靜不汝眩。", "中年琴書趣，早歲林壑願。", "我無適時具，未敢厭寒遠。", "政須營一醉，尚喜春酒賤。", "前回所探花，撲蔌已如霰。", "把杯臨清池，纈影中流見。", "可須催歸語，且領提壺勸。", "向來眼中人，此客頗嘗見。", "兩王風流絕，聲名到朝彥。", "新句如破竹，脫手金丸轉。", "石交可忘年，時亦共酣醼。", "春來景物好，題品幾時遍。", "鶑花不無情，向君真自獻。"]'),
('38fc4ead-961e-4e43-a7a2-4ef260e4aa5f','贈錢郎中','陳造','宋','宋诗','song-poetry','','[]','刓方利祿媒，抱道俗不省。',240,'全唐诗/poet.song.150000.json','["刓方利祿媒，抱道俗不省。", "詩書工發冢，孰起世儒病。", "錢侯挺直節，蠻徼復蘭省。", "劍氣夜星明，鵰翮秋霜耿。", "上前論世務，萬乘爲首肯。", "平生中原慮，壯歲左符請。", "不作黄閣想，擬試白羽秉。", "孤忠當宁知，宏圖時宰領。", "羣兒須圓曲，謂可力勝命。", "彼此計乘除，得甓喪崇鼎。", "平生信所得，一鑑照萬境。", "幕中辭脂韋，客右進嚴冷。", "主簿聱牙伯，評俗怒生癭。", "令君强項翁，爭事不藏頴。", "但有周舍思，可無衛武警。", "我亦意行者，泥古志未逞。", "朝來聽名理，剪燭延落景。", "寸田殊易荒，有頼剔榛梗。", "效奇乏良策，汲深慙短綆。", "惟期佩公言，不墮頹俗穽。"]'),
('d950de5e-6d18-425d-a6c5-0f9d41eeb8e4','次王仲衡尚書鹿鳴宴韻','陳造','宋','宋诗','song-poetry','','[]','儒冠幾經秦，士貴始藝祖。',240,'全唐诗/poet.song.150000.json','["儒冠幾經秦，士貴始藝祖。", "英儁承上意，不止工造語。", "文風逮列聖，秀異彌博取。", "即今再太平，比屋務稽古。", "先生國元老，曩亦原夫舉。", "倚相能丘索，吉甫允文武。", "後生藉膏馥，掉臂雄藝圃。", "豈伊鄶無譏，敢睨大國楚。", "諸生觀國光，名欲簉龍虎。", "初非意敢料，顧爲公所與。", "蕙蘭侈芳筵，肴核富雕俎。", "酒行不待醉，闔坐喜欲舞。", "妙句韋白前，拭目嗟未睹。", "豪氣倏賈餘，舉舉陵天宇。", "懸知三千牘，去作虹霓吐。", "我坐廣文氈，勤拙初不補。", "看揮修月刃，穩送摶風羽。", "傳燈知道尊，食蔗記荼苦。", "明年公東歸，商衡傅巖雨。", "附翼偕渠儂，遠臣觀所主。"]'),
('e49b43d1-628c-4565-b166-f3bfc4667c74','再次韻謝王仲衡尚書薦章','陳造','宋','宋诗','song-poetry','','[]','禰生布衣兒，始未客黄祖。',240,'全唐诗/poet.song.150000.json','["禰生布衣兒，始未客黄祖。", "一鶚輕百鷙，名已騰薦語。", "跌宕噤不施，衆笑此何取。", "一賦出緒餘，已可光近古。", "先生傳正學，抱負幾文舉。", "名世昔退之，好善今衛武。", "汲引略權近，論薦及農圃。", "高義表一時，惡氛可消楚。", "俗方急梯媒，中表羊而虎。", "低顔下氣地，百請幾一與。", "代舍著衰翁，秋芹薦侯俎。", "泉甘困深汲，袖短妨妍舞。", "薦士不待求，昔聞乃今睹。", "傅毛可飛肉，矮屋俄廣宇。", "平生氣輪囷，非公向誰吐。", "小當工撫字，大或效遺補。", "長風初借便，振迅顧雙羽。", "未妨著書緣，人有譏自苦。", "朝來詩興動，毫端鳴急雨。", "夸似鱣堂生，頗見此賓主。"]'),
('8b271bcf-e61d-4676-8c4f-0e64cf2016ee','次王尚書韻呈石湖','陳造','宋','宋诗','song-poetry','','[]','聖經三百篇，凜凜詩鼻祖。',240,'全唐诗/poet.song.150000.json','["聖經三百篇，凜凜詩鼻祖。", "日月懸太空，不作雕篆語。", "可學不可議，仲尼親去取。", "變爲屈宋騷，刻畫已愧古。", "曹劉驥騄騁，沈鮑鴻鵠舉。", "并稱五字雄，繩墨蓋陵武。", "甫白壁萬仞，眎彼柳樊圃。", "又如曹邾鄭，屏息從晉楚。", "黄陳嗣前作，風壑嘯兩虎。", "公生四子後，相望心相與。", "溟渤無棄流，酸鹹或登俎。", "取源自聖經，長袖固善舞。", "清篇神所護，近句誰先睹。", "鄉來儀朝行，拱揖尊帝宇。", "出使辭氣振，前席情素吐。", "非公任安危，衮闕幾不補。", "歸來將詩壇，越笴傅之羽。", "陳黄伯仲爾，胡復用心苦。", "學力我枯涸，進冀濡教雨。", "首肯公不疑，更用詢季主。"]'),
('694858e5-a671-4349-ad39-23f80db7cd67','次前韻贈龔養正','陳造','宋','宋诗','song-poetry','','[]','淮鄉富奇髦，歛衽讓乃祖。',240,'全唐诗/poet.song.150000.json','["淮鄉富奇髦，歛衽讓乃祖。", "及今戶相矜，十襲藏妙語。", "遺澤有源水，豈直輪一取。", "夫君典刑在，落筆更醇古。", "白眼視公卿，矧肯睨豪舉。", "世味淡如水，進德吾孔武。", "四壁但圖史，一飽問場圃。", "修眉冰玉顔，初服仍楚楚。", "團蒲芥軒寂，索手繫雕虎。", "客來輒欣然，詩就寧漫與。", "自云窺官達，束身著高俎。", "肯思麒麟楦，强作沐猴舞。", "見笑寒如冰，如睫不自睹。", "君眼高一世，天光靜生宇。", "寓意文字間，軋軋繭緒吐。", "后皇急幽側，員闕多未補。", "當儀振鷺羣，亟下冥鴻羽。", "鄉來受廛地，幽屏良獨苦。", "蓬萊道家山，金碧上煙雨。", "反君招隠篇，長懷報明主。"]'),
('205dbdaf-dc16-4483-9782-c4891d4d814c','大雪復用前韻呈王尚書','陳造','宋','宋诗','song-poetry','','[]','密雪何自來，雨禰雲其祖。',240,'全唐诗/poet.song.150000.json','["密雪何自來，雨禰雲其祖。", "史臣紀上瑞，外此可無語。", "帝豈爲詩設，偏爲詩人取。", "梁園謝家庭，麗句傳今古。", "玄冥老更事，厥職甚脩舉。", "屬者甫見白，今者復接武。", "賦形想像殊，玉田瓊作圃。", "定知懷璧人，蹍足不向楚。", "天孫事遨嬉，開關叱九虎。", "剪冰幾何時，下土均付與。", "羣僊燕青冥，酒所未徹俎。", "狂撼白榆花，笑看風處舞。", "林巒带城堞，變滅眩所睹。", "安得鶴背游，一覽了九宇。", "頗煩孟光請，杯覆詩不吐。", "海圖拆曲折，兒女粗紉補。", "明年麥秋好，落磨收鵝羽。", "盍賡屢豐謠，少慰田家苦。", "嘉應自丘禱，不待書閔雨。", "飽飯對翻飛，此惠仍地主。"]'),
('24d33c84-0561-4895-8f62-d0cc91938230','祈雨齊雲樓','陳造','宋','宋诗','song-poetry','','[]','波凉魚初浮，露下蟬罷警。',144,'全唐诗/poet.song.150000.json','["波凉魚初浮，露下蟬罷警。", "胡床俯前池，妙意吾已領。", "主人絕俗姿，此地背塵境。", "霜華耿玉宇，璇漢轉金餠。", "桂娥不無情，與客閑弄影。", "紅妝擁千蓋，環坐殊秀整。", "盤珍供剝芡，水厄停煮茗。", "清譚略逕庭，快若客酲醒。", "不辭僕頻更，頗覺夜彌永。", "明朝雨一尺，重約追霽景。", "但恐閑麈尾，鼓吹閙蛙黽。", "適聽步虛聲，縹緲碧雲頂。"]'),
('52c01e82-752f-4139-94cb-4202c4cf03f0','次韻諸公清樾軒詩','陳造','宋','宋诗','song-poetry','','[]','塵中望青山，防有移文阻。',96,'全唐诗/poet.song.150000.json','["塵中望青山，防有移文阻。", "誦君清樾篇，頓忘三伏暑。", "想見松風底，樹羽仍設虡。", "山靈莫逆友，獻豈煩縞紵。", "招隠未容反，陳迹渠能序。", "詩翁麋鹿姿，窮不問唐舉。", "歸誅故山茅，吳鴈馮寄語。", "君寧山中人，居州定王所。"]'),
('4b833928-b89c-4519-a5b3-1d253c83c079','代羅大著遥題雲巢','陳造','宋','宋诗','song-poetry','','[]','高人玩世心，仕學有餘裕。',144,'全唐诗/poet.song.150000.json','["高人玩世心，仕學有餘裕。", "稍償俗間負，未忘塵外趣。", "結巢依莽蒼，泉石得佳處。", "牙籤三萬軸，遮眼豈云蠹。", "鳥哢巖作屏，翛然不移具。", "時招櫧山雲，蒼白繚窗戶。", "徑潤樹罩煙，庭虛月含霧。", "萬景供旦夕，與人美無度。", "園翁垂綸叟，或許陪杖屨。", "我亦漫仕者，雅志買山住。", "即今想像意，未辦魁傑句。", "他年登君巢，酒所尚容賦。"]'),
('fec11a97-5493-4cbd-a053-97919a5e52b5','次韻胡學長喜雨','陳造','宋','宋诗','song-poetry','','[]','胡君著述間，動作千載計。',288,'全唐诗/poet.song.150000.json','["胡君著述間，動作千載計。", "雅奧三百篇，挹取欲無藝。", "一源發至醇，萬象赴傲睨。", "平生笑此癖，論交惜晚歲。", "君詩信入神，我眼本無翳。", "屈膝邢娥前，酬贈慚醜戾。", "憶初拜雩壇，遽恐枵腹斃。", "徒然陰樞縱，寧止乾胏噬。", "敢徐救焚步，頗徇非鬼祭。", "端知世興道，密若有司契。", "神孚聖君德，家沐良牧惠。", "天人隔顯幽，論理不論勢。", "朝來望阡陌，白水漲天際。", "歌呼滿中田，不勉渠自勵。", "黍稌分後先，稂稗易耘薙。", "清泉向小歉，比屋念遺穧。", "饑飽巧相補，上帝亦已諦。", "老夫辦疊期，是恩良不細。", "僊曹有佳招，天閽不堅閉。", "長安粟一囊，或許引前例。", "不然買青山，補破仍茹糲。", "出處顧何心，一漚寓斯世。", "衆雛能稼穡，暇日訓孝悌。", "相望渺海涯，恩懃未渠替。"]'),
('fcb04893-8fe5-46cb-bafe-bfdfb799830d','贈鍾汝楫','陳造','宋','宋诗','song-poetry','','[]','坐窗雨蕭蕭，出戶泥活活。',240,'全唐诗/poet.song.150000.json','["坐窗雨蕭蕭，出戶泥活活。", "旅食向六旬，淫霖破七八。", "舊新佳客斷，局陋不可活。", "鍾郎卷銜袖，詩與人秀發。", "誦之未數紙，驟覺陰氛豁。", "壯如秋濤湧，清比哀玉戛。", "騷人詠香草，不足供採捋。", "詩人深堂奧，掉臂欲排闥。", "應接殊不暇，愧耻那容刷。", "正宜長聚集，慰我抱饑渴。", "不見動十日，有力苦見奪。", "轉頭二十年，夢覺幾電抹。", "我甘鼯五窮，子亦狼載跋。", "川增得深敬，外此本毫末。", "別語忽見諗，回腸隠膠葛。", "乘除等寒暑，休王有回斡。", "豫章出林遲，出乃千丈拔。", "天居五雲處，往矣儕俊傑。", "當念淮山陽，有人晞短髮。", "噬肯回葉舟，譚妙共蔬糲。"]'),
('3f3ca6b1-f505-444d-8903-5a7e22cfe186','題徐居士遯庵','陳造','宋','宋诗','song-poetry','','[]','世網誰所張，四彌天宇大。',144,'全唐诗/poet.song.150000.json','["世網誰所張，四彌天宇大。", "萬情本一機，矻矻同此在。", "徐君經世心，心乃超世外。", "趣靜緣有動，無顯奚用晦。", "姑爲辟俗去，示世無吾待。", "結庵定其遷，初不憚一再。", "容膝得勝處，外物了纖芥。", "有山自煙雲，有水可灌溉。", "百丈峙翠屏，千尋拖碧带。", "床頭三聖書，會意謝分挂。", "天山得要旨，肥遯元非內。", "此名扁此室，吾詩儻容配。"]'),
('783560ad-a42e-4788-a50f-c2690840bb1e','次韻徐秀才十首  其一','陳造','宋','宋诗','song-poetry','','[]','冷官卧漳濱，書奩漫棲埃。',48,'全唐诗/poet.song.150000.json','["冷官卧漳濱，書奩漫棲埃。", "餐魚芼瓠葉，局縮養不才。", "窮鬼不受送，與君作陳雷。", "將軍視將浼，夫豈餽無臺。"]'),
('b6ea0d33-a3de-43ff-8c18-d8c3a35c3881','次韻徐秀才十首  其二','陳造','宋','宋诗','song-poetry','','[]','杜陵將詩壇，受歃湊多士。',48,'全唐诗/poet.song.150000.json','["杜陵將詩壇，受歃湊多士。", "黄陳大其傳，券契密付委。", "徐君萬卷腹，詩作風雷起。", "春秋富有餘，著眼置餘子。"]'),
('7ada2ea4-c26d-4235-b551-b9bdaa9dd91b','次韻徐秀才十首  其三','陳造','宋','宋诗','song-poetry','','[]','向來孟浩然，醉眼高宇宙。',48,'全唐诗/poet.song.150000.json','["向來孟浩然，醉眼高宇宙。", "清詩落京師，蘇李欲束咮。", "蔗隴槎頭鯿，未覺黄金富。", "纖鈎餌蝦蠅，但取浮陽嗅。"]'),
('d202723e-02de-4e0a-8483-006d3791650a','次韻徐秀才十首  其四','陳造','宋','宋诗','song-poetry','','[]','翕赫公侯門，下客亦方聞。',48,'全唐诗/poet.song.150000.json','["翕赫公侯門，下客亦方聞。", "慘澹埃𡏖地，高賢絕通津。", "蠹書分此老，華國須奇文。", "渠觀有旁招，子行當冠軍。"]'),
('348b6c78-82b4-4adb-b095-1e6bc31be3d9','次韻徐秀才十首  其五','陳造','宋','宋诗','song-poetry','','[]','毅毅挂榻翁，孺子來如家。',48,'全唐诗/poet.song.150000.json','["毅毅挂榻翁，孺子來如家。", "長安聚蚊兒，車馬紛囂譁。", "裔孫會兩窮，韶顔映蒼華。", "長嘯敘孔李，驚翻籬角鴉。"]'),
('53c2cd4d-e508-4c8a-864b-afcfff413b1c','次韻徐秀才十首  其六','陳造','宋','宋诗','song-poetry','','[]','霄霏上冥鴻，山霧卧文豹。',48,'全唐诗/poet.song.150000.json','["霄霏上冥鴻，山霧卧文豹。", "餓鴟嚇腐鼠，啄啄詫飛趠。", "吾徒爲己學，欣慼置不校。", "小草或遠志，詭遇乃近效。"]'),
('23fcb077-a2d3-4808-92cc-2ed28423c031','次韻徐秀才十首  其七','陳造','宋','宋诗','song-poetry','','[]','鈎妙如悟禪，去瑕等居讎。',48,'全唐诗/poet.song.150000.json','["鈎妙如悟禪，去瑕等居讎。", "學詩得是法，善刀無全牛。", "脫手希代珍，願子毋輕投。", "衮衮譚項斯，愧非古人儔。"]'),
('dec846af-298f-4914-988e-9ceeba7fc71e','次韻徐秀才十首  其八','陳造','宋','宋诗','song-poetry','','[]','閲世難衣食，眼中子能賢。',48,'全唐诗/poet.song.150000.json','["閲世難衣食，眼中子能賢。", "萬像入吟筆，摹寫皆其天。", "蹇孑我荒學，一字不蘄傳。", "子家文章錄，得書或牽聯。"]'),
('d611e939-5165-41a3-b7e7-740b9ee32c90','次韻徐秀才十首  其九','陳造','宋','宋诗','song-poetry','','[]','釣湖鱠紅鱗，斸山飯黄獨。',48,'全唐诗/poet.song.150000.json','["釣湖鱠紅鱗，斸山飯黄獨。", "書生甘若飴，八珍不在目。", "出處有餘裕，贔屭營寸祿。", "一舟指三徑，不遠儻許復。"]'),
('137a1082-374c-4342-97d9-c8c88dba0fb7','次韻徐秀才十首  其一○','陳造','宋','宋诗','song-poetry','','[]','堂笑伊優登，米笑侏儒索。',48,'全唐诗/poet.song.150000.json','["堂笑伊優登，米笑侏儒索。", "見笑與笑人，等可付束閤。", "從俗心易波，矚理眼無膜。", "但求種秫田，歸療酒腸涸。"]'),
('eff48515-9c42-42c5-815f-2a1a53102574','次諸公詩韻','陳造','宋','宋诗','song-poetry','','[]','牆圍護風煙，簷影納紅綠。',168,'全唐诗/poet.song.150000.json','["牆圍護風煙，簷影納紅綠。", "城西百弓地，論價指和玉。", "滄浪取具體，輞川儼遺躅。", "年時得小憩，振衣休汗足。", "山靈不留人，定復厭棖觸。", "坐想散花女，深堂伴金粟。", "今年桃李月，僮馬幾裝束。", "竟成夢魂到，永歎春事促。", "此亦志願違，世有谿壑欲。", "似聞偕六逸，碧酒仍艷曲。", "風鶴羽人下，露花妃子浴。", "詩卷肯屬我，爲洗顔面俗。", "元亮晚耒耜，彌明舊符籙。", "可須白月前，熠熠度螢燭。"]'),
('21430494-e3dd-4c7e-9b24-7e0eb21150b2','八月晦試院中作','陳造','宋','宋诗','song-poetry','','[]','官居課程地，生有文字癖。',168,'全唐诗/poet.song.150000.json','["官居課程地，生有文字癖。", "誠知蟁負山，詎得辭此檄。", "嘉禾古多士，孰者非巨擘。", "老眼不待封，舊苦眩花隔。", "勿云石賈玉，箴失眸亦得。", "捧心若爲妍，竊鈇徒自匿。", "陸海貪窮搜，奇寶多偶獲。", "巧常昏金注，勇或便大敵。", "清醳聆鄒琴，款識辨周鬲。", "頗收半段槍，遐念連城璧。", "渠應悔羔袖，吾敢厭鷄肋。", "撫囊搴利穎，體國免素食。", "明朝羅客拜，定自百夫特。", "俗無拋磚惡，歸舟緩張席。"]'),
('4869ad66-b6c9-451b-90c4-35ca76e1b8d2','九月二日','陳造','宋','宋诗','song-poetry','','[]','燈火一樽酒，笑語亦固然。',48,'全唐诗/poet.song.150000.json','["燈火一樽酒，笑語亦固然。", "如何棘圍夜，憶歸不成眠。", "衰懷動多感，妻兒須眼前。", "人生四方志，誰遣霜覆顛。"]'),
('1537a1dc-fb45-434f-bfb6-acf56e3d5118','次韻袁憲閲兵許浦','陳造','宋','宋诗','song-poetry','','[]','皇澤泉及瀕，戎索均帝闕。',252,'全唐诗/poet.song.150000.json','["皇澤泉及瀕，戎索均帝闕。", "邊屯笳簫地，彎弓睨胡月。", "萬旅皆金繒，不待持閥閲。", "于時江流澌，極目雲閣雪。", "嬉嬉忘其寒，恩寵自稠疊。", "使星照海徼，天意不虛設。", "勞勤需摩拊，勇怯要旌別。", "除器有良楛，扣閽許陳列。", "古來分君憂，下敢謝薄劣。", "叱馭陵九折，摧鋒取三捷。", "况公經世才，翻浪海鯨掣。", "夷吾吾目中，江左佇茂烈。", "汾陽唐柱石，守器未應缺。", "銜命茲小試，鼓勇士眥裂。", "指揮用諸將，他日須此傑。", "聖君中興主，詔語一見决。", "治具有罅漏，詎容惜捫舌。", "兆眹貴先識，沉默真小節。", "鄙夫百僚底，欲隠尚不屑。", "幾登王公門，面醜辭易竭。", "向公又一鳴，當復笑燕說。"]'),
('47ceca02-ad8e-4871-bfff-1634088c466e','三月初晚晴寄高縉之三首  其一','陳造','宋','宋诗','song-poetry','','[]','東風掃積陰，殘雨不敢漂。',48,'全唐诗/poet.song.150000.json','["東風掃積陰，殘雨不敢漂。", "壞雲裂裳帛，倒挂磴嶺腰。", "鳥影不作暝，夕陽明山椒。", "安得上上頭，風露永清宵。"]'),
('79ab5912-1dff-4d65-961b-3e39a53281d8','三月初晚晴寄高縉之三首  其二','陳造','宋','宋诗','song-poetry','','[]','人家繡閨閑，湖上粧面新。',48,'全唐诗/poet.song.150000.json','["人家繡閨閑，湖上粧面新。", "湖山簫鼓中，魚鳥安得馴。", "山靈建飛雨，凈洗綺羅塵。", "即今隄邊柳，爲誰管殘春。"]'),
('4301afed-5e4f-4790-ab88-549d3c1cad0e','三月初晚晴寄高縉之三首  其三','陳造','宋','宋诗','song-poetry','','[]','曲欄倚青冥，萬井入指顧。',48,'全唐诗/poet.song.150000.json','["曲欄倚青冥，萬井入指顧。", "湖光漾明霞，照我凭欄處。", "森木倦鳥歸，遥空征鴻度。", "定知待月人，破竹有奇句。"]'),
('dac2c551-5c38-4307-9647-aade0bc2f34c','苦雨','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','有足不下樓，有耳祇聽雨。',72,'全唐诗/poet.song.150000.json','["有足不下樓，有耳祇聽雨。", "一日不可耐，忽忽彌旬所。", "軒蓋斷還往，尸居成獨語。", "日色似見慰，雲氣復如許。", "西湖梅柳月，裘馬趁簫鼓。", "細追他日夢，一笑念縛虎。"]'),
('6a0d73e1-6e10-4473-8391-14cc23be162d','再用前韻贈高縉之三首  其一','陳造','宋','宋诗','song-poetry','','[]','晴色與春違，香紅不餘漂。',48,'全唐诗/poet.song.150000.json','["晴色與春違，香紅不餘漂。", "出郭縱遠目，草長麥齊腰。", "詩來慰幽獨，吮諷芬蘭椒。", "招月作三益，庶用娛中宵。"]'),
('14ee8ac1-9788-4346-8ffb-b994924c09f1','再用前韻贈高縉之三首  其二','陳造','宋','宋诗','song-poetry','','[]','閉門雨兩月，君來無舊新。',48,'全唐诗/poet.song.150000.json','["閉門雨兩月，君來無舊新。", "白眼睨牢石，騫飛不受馴。", "落落含風松，紛紛棲睫塵。", "慚非修月手，向君和陽春。"]'),
('33e8794b-fe88-40ce-a4b4-a08f1562ecc3','再用前韻贈高縉之三首  其三','陳造','宋','宋诗','song-poetry','','[]','高郎客京華，好事有左顧。',48,'全唐诗/poet.song.150000.json','["高郎客京華，好事有左顧。", "儒林丈人行，乃得曳裾處。", "亦知短褐底，藴抱美無度。", "繼今數公間，可但傳新句。"]'),
('f0efb2ed-b37a-4b30-9580-9fd1b2b28766','謝袁起巖使君借貢院居  其一','陳造','宋','宋诗','song-poetry','','[]','書生歎漂流，卜築定何日。',48,'全唐诗/poet.song.150000.json','["書生歎漂流，卜築定何日。", "折腰爲斗升，問舍羨九一。", "諸公有好事，往往遂所乞。", "懸知許黔突，當復念容膝。"]'),
('2d8bce19-f1da-4f97-8565-3be452ae8771','謝袁起巖使君借貢院居  其二','陳造','宋','宋诗','song-poetry','','[]','火雲烘白晝，悠悠晝日長。',48,'全唐诗/poet.song.150000.json','["火雲烘白晝，悠悠晝日長。", "黄塵撲面去，行客汗反漿。", "老夫清夢起，開卷鉤北窗。", "微風入巾袂，世恐無此凉。"]'),
('c1db8c67-596d-4101-83d3-e14f6ac577f7','謝袁起巖使君借貢院居  其三','陳造','宋','宋诗','song-poetry','','[]','久晴忽一雨，爲洗暑氣煩。',48,'全唐诗/poet.song.150000.json','["久晴忽一雨，爲洗暑氣煩。", "斯人作欣慼，造物無怨恩。", "我方墮窮塗，獨能庇寒暄。", "公亦不自德，自笑煩於言。"]'),
('79bf15e7-76c8-49cd-8596-07ca9e36e1a1','謝袁起巖使君借貢院居  其四','陳造','宋','宋诗','song-poetry','','[]','槃薄蕭寺中，永嘆無客到。',48,'全唐诗/poet.song.150000.json','["槃薄蕭寺中，永嘆無客到。", "吾室自勃谿，粗免以饑告。", "及此蔭寬閒，好風日見勞。", "安得長者車，茶餠寫襟抱。"]'),
('aaf21e3e-d227-4b60-b6b8-06e054cf42f0','謝袁起巖使君借貢院居  其五','陳造','宋','宋诗','song-poetry','','[]','槐龍舞修影，頹景忽西沒。',48,'全唐诗/poet.song.150000.json','["槐龍舞修影，頹景忽西沒。", "空庭漾金波，坐待月東出。", "臨風思傳觴，沃此支離骨。", "開門拜嘉惠，正得杯中物。"]'),
('8002a1e0-e76d-42d3-8cb6-ae1771022d0e','寄題徐虞卿醒心亭','陳造','宋','宋诗','song-poetry','','[]','人間聲利場，疾馳不知反。',144,'全唐诗/poet.song.150000.json','["人間聲利場，疾馳不知反。", "營營計毫末，一益昧百損。", "徐侯大雅士，探道自其本。", "策勳虛明地，外累不待遣。", "出能同光塵，歸念寄蕭散。", "著亭得勝處，竹茂水清淺。", "亭中眎亭外，畏塗塵瞇眼。", "翛然得此心，萬化無餘藴。", "老我尚問津，人與室俱遠。", "向來卜鄰計，欲舞嘆袖短。", "會當尋此盟，蔬飯同茗椀。", "灑落無何遊，共閲世沈湎。"]'),
('8c925c63-8a80-4452-b574-b88f18a79ecd','餘姚飯','陳造','宋','宋诗','song-poetry','','[]','昨暮浴上虞，今晨飯餘姚。',96,'全唐诗/poet.song.150000.json','["昨暮浴上虞，今晨飯餘姚。", "官期有餘日，我行得逍遥。", "盤實剝芡芰，羹魚薦蘭椒。", "一飽老人事，茗飲亦復聊。", "捫腹每自愧，昔賢尚簞瓢。", "僧垣棲翠微，金碧煥山椒。", "龍泓甘可茹，塔鈴如見招。", "遲留本不惡，况復待晚潮。"]'),
('ba7f50df-6bdc-4d09-bdaa-1ef8bdc7c637','車堰牛','陳造','宋','宋诗','song-poetry','','[]','牛力輕萬鈞，性順異諸畜。',144,'全唐诗/poet.song.150000.json','["牛力輕萬鈞，性順異諸畜。", "有足不解踶，有角不皆觸。", "課日引耒耜，爲人給穀粟。", "私家憂闕食，公家要餘蓄。", "公私雖相須，置汝誰取足。", "柰何過堰客，行舟動千斛。", "挽牽亦諉汝，贔屭頸髀縮。", "扣角一勞之，不語對以腹。", "物生愧無用，懷安或非福。", "於人儻有益，厪身豈云酷。", "君看廟前牲，被繡飽蒭菽。", "膏血薦鼎俎，誰定悲觳觫。"]'),
('73cbabc4-0aa2-4bd4-9e27-a469ef02ac5d','舟行即事','陳造','宋','宋诗','song-poetry','','[]','昨日出曹娥，明日指慈溪。',96,'全唐诗/poet.song.150000.json','["昨日出曹娥，明日指慈溪。", "待潮舟爲膠，得潮舟若蜚。", "留滯復一快，計程元不遲。", "人生意失得，孰者乘除之。", "今屈昔已伸，彼贏此或虧。", "但可自適適，尚用悲喜爲。", "水伯愚弄人，政如造物兒。", "丈夫木作腸，渠輩未易知。"]'),
('e5ab8967-e82c-4434-a092-e27e55b1e88a','餞寄定海交代','陳造','宋','宋诗','song-poetry','','[]','縣尹古子男，今不一錢直。',288,'全唐诗/poet.song.150000.json','["縣尹古子男，今不一錢直。", "低摧奉簡書，偵伺常屏息。", "白簡與按章，歲月供彈劾。", "當路雖所懼，姦民巧狙擊。", "吻間售蜂蠆，意外變白黑。", "防虞莫救過，彌縫或逃謫。", "政使有卓魯，未容置形迹。", "云何世難事，君不動聲色。", "編民翕風移，惡少且心革。", "田廬有笑歌，魑魅亦竄匿。", "斯人紀仁愛，幾磨南山石。", "政聲懿如此，僅免繩治厄。", "諸公蜚鶚書，犯嚴尚遺力。", "安得定海民，爲君灑薦墨。", "蘭臺傳循吏，採訪多失實。", "安得定海人，爲君秉直筆。", "嗟我吏隠者，志在山南北。", "身名萬金重，如博試此擲。", "頼今遺愛地，一一可矜式。", "政恐效西子，美顰得嘲劇。", "江皋一樽酒，聊挽朝天客。", "妙樂喧江浪，清譚倒理窟。", "盟言底遽寒，舟駛潮水急。", "西望念風義，感嘆徒至骨。"]'),
('214fd84e-be17-4ac8-a0de-465a81799ff0','復吳祕正五詩  其一','陳造','宋','宋诗','song-poetry','','[]','武陵邁往氣，當世隠一敵。',48,'全唐诗/poet.song.150000.json','["武陵邁往氣，當世隠一敵。", "揚眉諸公間，甘作遷客客。", "裔孫典刑在，磊落抱深識。", "我學謝柳州，顧肯睨門席。"]'),
('676441bf-859d-4173-9d7c-2a9cb903c6b1','復吳祕正五詩  其二','陳造','宋','宋诗','song-poetry','','[]','簿書阻從遊，人遠嗟室邇。',48,'全唐诗/poet.song.150000.json','["簿書阻從遊，人遠嗟室邇。", "胥徒怪坐忙，眉睫若爲喜。", "方賡于蒍于，忽誦子虛子。", "悠然得此心，外累蚊過耳。"]'),
('e7a95bc1-9da0-44f0-8c49-fc094fcf33d0','復吳祕正五詩  其三','陳造','宋','宋诗','song-poetry','','[]','我如不材材，自誑無用用。',48,'全唐诗/poet.song.150000.json','["我如不材材，自誑無用用。", "向來風月前，詩筆頗吟弄。", "低摧髮皓白，無與世輕重。", "枯株欲丹黄，因君彌自訟。"]'),
('1d135141-7a2d-4c7b-9482-04591e1dec5c','復吳祕正五詩  其四','陳造','宋','宋诗','song-poetry','','[]','作宰古尚教，宓齊但橫琴。',48,'全唐诗/poet.song.150000.json','["作宰古尚教，宓齊但橫琴。", "唐吏猶易爲，讀書或松林。", "一從來海瀕，琴書暗塵侵。", "俗有古今異，鞭扑違寸心。"]'),
('0d0c1aae-fef3-4eff-a588-49993f01343b','復吳祕正五詩  其五','陳造','宋','宋诗','song-poetry','','[]','君詩用功深，平處猶近古。',48,'全唐诗/poet.song.150000.json','["君詩用功深，平處猶近古。", "北斗燦繁星，拜賜詫兒女。", "亦思貂可續，中夜攪肺腑。", "攬鬚粲一笑，笑翁祗自苦。"]'),
('88a63617-7c20-4905-a587-5321643047aa','張丞見和次韻答之  其一','陳造','宋','宋诗','song-poetry','','[]','中年賦遠遊，羣僊謂匹敵。',48,'全唐诗/poet.song.150000.json','["中年賦遠遊，羣僊謂匹敵。", "朅來吏海隅，笑死鶴背客。", "昔人混屠酤，不取俗眼識。", "惟應赤城老，默許分半席。"]'),
('572a176c-ff43-4e2b-87ae-d2786da28962','張丞見和次韻答之  其二','陳造','宋','宋诗','song-poetry','','[]','故人十年別，牆宇今密邇。',48,'全唐诗/poet.song.150000.json','["故人十年別，牆宇今密邇。", "譚勝復詩工，排日有歡喜。", "所嗟連城璧，過詫窶人子。", "何况政術疎，一一頼提耳。"]'),
('752ea0cb-c25a-45dc-90be-78ed0d933210','張丞見和次韻答之  其三','陳造','宋','宋诗','song-poetry','','[]','我本山林人，娛老有日用。',48,'全唐诗/poet.song.150000.json','["我本山林人，娛老有日用。", "時須禽一戲，暇乃笛三弄。", "言償作縣責，顧敢寶所重。", "催科未妨拙，防速牙角訟。"]'),
('4423839d-3d5a-4f09-aba9-c6d2b1ee6c12','張丞見和次韻答之  其四','陳造','宋','宋诗','song-poetry','','[]','張陳舊莫逆，雅趣瑟和琴。',48,'全唐诗/poet.song.150000.json','["張陳舊莫逆，雅趣瑟和琴。", "器用異所宜，渠觀與山林。", "朝來覽鏡笑，鬢雪無可侵。", "但辦摩衰眼，送君立班心。"]'),
('21121df0-d38f-4989-99c9-c43639e1b556','張丞見和次韻答之  其五','陳造','宋','宋诗','song-poetry','','[]','男兒鼎珍食，富貴倚稽古。',48,'全唐诗/poet.song.150000.json','["男兒鼎珍食，富貴倚稽古。", "不然東山車，穩載十眉女。", "可憐强項令，俗塵塞腸腑。", "端如溧陽尉，老訴食薺苦。"]'),
('30978e04-2dbd-4512-81d0-43763c44f7de','送李象山趨朝二首  其一','陳造','宋','宋诗','song-poetry','','[]','人將宰象山，蕭散目郎署。',144,'全唐诗/poet.song.150000.json','["人將宰象山，蕭散目郎署。", "即今撥煩手，蓄縮殆難措。", "鄰分銅鐵名，恐坐汙染故。", "髯君千日留，曾無疾頑怒。", "德孚俗風動，政洽民孺慕。", "過虞櫝中毀，穩下竿頭步。", "定川壯哉縣，瞢不揣鯫腐。", "虎鬚有危攬，羊腸無善御。", "彼此劇易間，霄壤計相去。", "滿懷血指羞，乏君斲輪具。", "鄰輝幾餘分，忽復失强助。", "歸舟不可挽，臨風悄延佇。"]'),
('8e76f883-49c7-4b03-86ad-8e2635c19f39','送李象山趨朝二首  其二','陳造','宋','宋诗','song-poetry','','[]','書肘詎容掣，箏柱不可膠。',144,'全唐诗/poet.song.150000.json','["書肘詎容掣，箏柱不可膠。", "付事多其防，職業自寂寥。", "頗思圓機士，細苛舉綱條。", "宰邑古難之，茹苦耐煎熬。", "百抑不一揚，推波益驚濤。", "由來法愈密，祇爲下所操。", "一饑驅我出，銅墨强折腰。", "捩翅著籠中，側睨鵬沖霄。", "平生有知己，持橐貳銓曹。", "君來定倒屣，道我不自聊。", "願推變通術，霧雨均枯焦。", "而况代舍舊，肯惜引手勞。"]'),
('e53cc6f7-a1db-4b84-bff5-20f39b6e5787','遊慈溪龍虎軒','陳造','宋','宋诗','song-poetry','','[]','坐曹可勝勞，出郭復行役。',144,'全唐诗/poet.song.150000.json','["坐曹可勝勞，出郭復行役。", "半年定海令，三度慈溪客。", "慈溪足勝處，山秀江繚碧。", "終然縈夢寐，遑此事遊歷。", "高軒閟龍虎，表表市闤側。", "得興不暇慵，徙倚且數刻。", "洞戶初推敲，階除旋登陟。", "向來攫怒勢，枯幹抱頑石。", "乃知名實間，未易膠今昔。", "尚喜詩翁碑，不受蒼蘚蝕。", "可但神所護，人未忘翁德。", "非使老眼明，斯遊竟無得。"]'),
('e3366fb7-e560-499b-9588-8b4468d5fc45','十二月二十六日趨府','陳造','宋','宋诗','song-poetry','','[]','誰謂一舍遠，不辦三餐趨。',144,'全唐诗/poet.song.150000.json','["誰謂一舍遠，不辦三餐趨。", "亭午縣市西，衙鼓府城隅。", "匹馬驚鳥去，指槌冰在須。", "北風挾霜氣，萬象付摧枯。", "想當折琴絃，未怪裂人膚。", "駝裘被甲如，是日有若無。", "客首不暇回，顧容少踟躇。", "出處不能同，勞逸爲之殊。", "龐翁馬少游，似非隠者徒。", "鄉居老躬耕，飽溫得自娛。", "婆娑銅墨間，盍亦省頭顱。", "蔉穮脫中熟，吾口良易餬。"]'),
('eee5fa6a-1b5b-4186-8210-f4b77eab2364','十二月二十七日趨慈溪','陳造','宋','宋诗','song-poetry','','[]','西風蜚江浪，江畔那容立。',144,'全唐诗/poet.song.150000.json','["西風蜚江浪，江畔那容立。", "霰花濺千尺，望望客衣濕。", "小舟艤兩三，人已鵝鴈集。", "側睨波洶洶，俯憐身岌岌。", "乘凌玩掀舞，生死付呼吸。", "前登爲回首，舟重巾𧥄𧥄。", "支徑不通車，車去如見縶。", "念此役夫苦，體我官事急。", "傍顧中夜還，得無僵仆泣。", "畀汝就甘寢，白飯亦周給。", "徇人多意外，自信寧不及。", "利物身每輕，睡覺况六十。"]'),
('f113ec66-1572-47e5-bda2-1d666f6c2ec2','次韻王省幹  其一','陳造','宋','宋诗','song-poetry','','[]','南橘合嘉頌，爲枳緣踰淮。',48,'全唐诗/poet.song.150000.json','["南橘合嘉頌，爲枳緣踰淮。", "黄濁轉眼涸，一昨瀰兩涯。", "志士抱根柢，千古容興懷。", "後生事蟲篆，蟻穴鏖檀槐。"]'),
('93a528f7-b107-417b-9304-6a20619f7a22','次韻王省幹  其二','陳造','宋','宋诗','song-poetry','','[]','一官初有祿，三月免無君。',48,'全唐诗/poet.song.150000.json','["一官初有祿，三月免無君。", "平時愛人學，蘄試百一分。", "習俗南北異，所見違所聞。", "致化要無倦，儒者貴長文。"]'),
('50affd9d-cdcc-42dc-9d5c-a9c2bacd0d49','次韻王省幹  其三','陳造','宋','宋诗','song-poetry','','[]','王侯文振奇，人作高山仰。',48,'全唐诗/poet.song.150000.json','["王侯文振奇，人作高山仰。", "世學方波頹，渠獨不流蕩。", "諸生畏雄驁，六藝厚涵養。", "遥知落詩筆，高像寄逸想。"]'),
('6c619192-82e3-4d4a-9fdc-cd39737c768e','次韻王省幹  其四','陳造','宋','宋诗','song-poetry','','[]','叔也過我門，往往接䍦倒。',48,'全唐诗/poet.song.150000.json','["叔也過我門，往往接䍦倒。", "惎以元亮止，終然劉伶禱。", "我此待鶱翔，夫合戒陵傲。", "惰遊置耕耘，曷怨鹵莽報。"]'),
('7fd2c566-73e0-48ee-8144-3bae55ee9867','次韻王省幹  其五','陳造','宋','宋诗','song-poetry','','[]','大匠成風手，器就不待模。',48,'全唐诗/poet.song.150000.json','["大匠成風手，器就不待模。", "老夫默自哂，堆豗守一隅。", "論交獨何幸，魚目儷明珠。", "他年君鄰牆，作意營一區。"]'),
('4d91e3b4-150f-4806-841d-5b7f30fbc74d','次韻張丞','陳造','宋','宋诗','song-poetry','','[]','政平民安之，不在書上考。',144,'全唐诗/poet.song.150000.json','["政平民安之，不在書上考。", "君看道傍樗，蒼雲蔭合抱。", "明時話英躔，佳氣指蓬島。", "孰知嵌巖幽，乃韞希代寶。", "張侯儒而吏，笞箠環臺皁。", "政聲載輿論，文價動諸老。", "學富食猶貧，志堅進不早。", "即今紫霄人，豈必皆橫草。", "亦知名煒燁，曾上薦士表。", "靜女家無媒，深閨自媚好。", "胡寧倚昌丰，濃抹且淡掃。", "會看邢娥前，妬婦付絕倒。"]'),
('0cefc552-b615-4b6d-b02a-21344b0686ff','謝制帥高卿剡四首  其一','陳造','宋','宋诗','song-poetry','','[]','宰邑非良才，朴拙瞢信己。',48,'全唐诗/poet.song.150000.json','["宰邑非良才，朴拙瞢信己。", "曾無補毫髮，粗不畏首尾。", "倚公造物手，襲璧護玷毀。", "世有百謫餘，觀旁首重稽。"]'),
('1ca5c752-1118-447d-a889-11f7c260b37d','謝制帥高卿剡四首  其二','陳造','宋','宋诗','song-poetry','','[]','薦書未及門，啅鵲拂人衣。',48,'全唐诗/poet.song.150000.json','["薦書未及門，啅鵲拂人衣。", "盥手衮字褒，祇遣顔忸怩。", "瑕瑜僅相償，葑菲終不遺。", "窮途石作腸，持用答恩私。"]'),
('acdd0500-4920-4ba9-bb7e-fa38ac2767c2','謝制帥高卿剡四首  其三','陳造','宋','宋诗','song-poetry','','[]','去年來甬東，旄倪喜動色。',48,'全唐诗/poet.song.150000.json','["去年來甬東，旄倪喜動色。", "公今畫船西，行路亦嗟惜。", "去來本何心，民自作欣慼。", "達人了世緣，八極付揮斥。"]'),
('dafccd64-5186-4b04-88bb-c66e4a74d1b6','謝制帥高卿剡四首  其四','陳造','宋','宋诗','song-poetry','','[]','論世究德業，先生處其全。',48,'全唐诗/poet.song.150000.json','["論世究德業，先生處其全。", "谹議可斷國，餘功猶護邊。", "此行雖暫屈，衮職正急賢。", "璽書起黄霸，摩眼待新年。"]'),
('972490e1-01e2-4c94-8de6-f29d6fd30fdb','次韻張守不欺堂','陳造','宋','宋诗','song-poetry','','[]','使君古醇儒，內視保良貴。',120,'全唐诗/poet.song.150000.json','["使君古醇儒，內視保良貴。", "芸芸鏡中影，了莫遁情僞。", "賦芧豈至術，機灌彼誰子。", "退食一堂間，百事反諸己。", "床敷但詩卷，庭砌亦屐齒。", "洞洞靈府閑，拳拳聖言畏。", "獨傳迂叟印，不作俯仰愧。", "何當拾級前，拱坐商略是。", "謦咳付元城，歸詠如闕里。", "從俗倦執熱，得意風雨會。"]'),
('8cbd2810-01a6-4f88-8475-874327fe1fd9','次韻不擾堂','陳造','宋','宋诗','song-poetry','','[]','取民狼走羊，勝之楚克庸。',168,'全唐诗/poet.song.150000.json','["取民狼走羊，勝之楚克庸。", "孰知號召初，已賦大小東。", "賢侯守此道，力若拔山雄。", "深堂玩閴寂，翠影環蒙籠。", "泛應得天遊，靜鎮副上衷。", "樂知前池魚，吟當北窗風。", "情寄埃𡏖外，俗自和氣中。", "高吟與傑作，鏗谹而舂容。", "無欲民自朴，契鑰今古同。", "即今美化孚，袖手自即功。", "坐令鞭蒲捐，寧遣馬力窮。", "我心偕郡人，會當志願從。", "新年鋒車南，帝渥看稠重。", "政聲潁川上，可庸不作公。"]'),
('2c72d580-6296-4b01-a9ac-e5c0aba725e5','宿雲巖山','陳造','宋','宋诗','song-poetry','','[]','名山邦域中，每嘆夢境隔。',144,'全唐诗/poet.song.150000.json','["名山邦域中，每嘆夢境隔。", "如何夏而春，共苦沽水厄。", "向來夢中山，真作緣雲升。", "夜氣與僧話，凜凜冰壺清。", "初宵潺淙聲，大慰望霓意。", "睡醒鐘魚鳴，猶是翻盆勢。", "不因官事驅，寧許山門留。", "况今浴種天，頓釋嗣歲憂。", "雨既副我禱，山亦入吾手。", "一旦二喜并，誰謂終不偶。", "涉世嗟聱牙，天頗憐其窮。", "更持靈臺香，歸謝淵德龍。"]'),
('da98f091-f720-40f1-b381-e8e386c48301','李伯成食甘豆粥和淵明詩分寄次韻','陳造','宋','宋诗','song-poetry','','[]','八珍較半菽，豐悴岐兩端。',120,'全唐诗/poet.song.150000.json','["八珍較半菽，豐悴岐兩端。", "志士傃所逢，心泰體亦安。", "李侯貧食粥，吾獨於此觀。", "竈婦不餘顰，鄰券有後還。", "顔帖孰嗣之，范叔可勝寒。", "破碓砂瓶前，蘭佩雜木難。", "堂堂五字律，鋩鍔凜莫干。", "不羨侏儒飽，寧追陋巷顔。", "挈瓶肯見分，特特扣荆關。", "讀詩良起予，投匕忘悲嘆。"]'),
('95ca2d6a-9660-485e-938d-37fe912ddcaf','次韻解樞幹二首  其一','陳造','宋','宋诗','song-poetry','','[]','我方首儒冠，頗亦易此人。',120,'全唐诗/poet.song.150000.json','["我方首儒冠，頗亦易此人。", "尚友卑自漢，讀書考先秦。", "士或暗鄭朴，識面蘄卜鄰。", "計疎志空勤，敝帚浪自珍。", "口前齊東語，瞢欲潤帝綸。", "學如村社醖，百醨間一醇。", "老蘗媚衰紅，飽閲姚魏春。", "顧慚誤題品，五字極清新。", "君才允文武，行矣拱帝宸。", "余年念桑榆，歸去儕編民。"]'),
('be1f5982-8f08-4d42-b47f-7ac9c23c9881','次韻解樞幹二首  其二','陳造','宋','宋诗','song-poetry','','[]','阿文鈍于學，莫計故新年。',120,'全唐诗/poet.song.150000.json','["阿文鈍于學，莫計故新年。", "向微他山錯，詎徹醯甕天。", "論交置才否，如君政自賢。", "爲導有源水，俾加視後鞭。", "譬彼千仞登，投足得攀緣。", "君生英衛家，造詣超儒先。", "餘論分吾兒，一一當手編。", "繄我液樠木，卧沙不受鎸。", "鵲音曉見諗，羣玉紛墮前。", "政使高紙價，敢蘄世儒傳。"]'),
('f06f6062-3235-482e-b7ed-0325073b5ecb','題張仲思孝友堂','陳造','宋','宋诗','song-poetry','','[]','筆端吐陽春，胸次著雲夢。',240,'全唐诗/poet.song.150000.json','["筆端吐陽春，胸次著雲夢。", "袖中匠石斤，規矩隨意中。", "君侯道藝樂，不許俗子共。", "深堂埃𡏖外，平日文字供。", "默對八窗靜，不但十年種。", "妙語落人間，一一萬金重。", "平反與進修，併作旨甘奉。", "只今衣五綵，頗亦笛三弄。", "何人侍板輿，觴豆燕羣從。", "鴒原春事繁，鴈影天宇空。", "傍睨梟雉呼，或作鄒魯閧。", "紛紛手翻覆，納納腹空洞。", "汲直合居中，器博滯近用。", "初計拔薤來，竟息憩棠訟。", "翛然擁書坐，竹風助吟諷。", "更聽雛鳳鳴，未妨蜚鴻送。", "今皇志復古，俗有後賓貢。", "斯文屬耆儒，夏屋况巨棟。", "江漢繼崧高，誰當第嘉誦。", "縣知尹吉甫，縮手辟張仲。"]'),
('d2057294-1e1e-466a-a5a4-0eae8113babf','次韻嚴文炳暫別歸吳門','陳造','宋','宋诗','song-poetry','','[]','白駒縶維之，君乃再歲住。',144,'全唐诗/poet.song.150000.json','["白駒縶維之，君乃再歲住。", "政如荷蓧翁，鷄黍止季路。", "得句推敲餘，每肯向予吐。", "平生識丁字，頗亦指佳處。", "只今妙著述，詎云工訓故。", "東陸方播和，南雲遽回顧。", "似聞漢諸公，交口河東賦。", "挽袖不轉頭，欻作翩鴻去。", "郡舍雖舊約，侯門有晚遇。", "可忘酒招携，况識棋勝負。", "老景樂事稀，春意駿足騖。", "無令歸驂前，怒風鏖花絮。"]'),
('a5164555-b734-49ce-b9da-ed77790016ca','再用才子富文華校讎天祿閣韻贈周教授  其一','陳造','宋','宋诗','song-poetry','','[]','仙人藤陰夢，金骨窖黄埃。',48,'全唐诗/poet.song.150000.json','["仙人藤陰夢，金骨窖黄埃。", "當年晁張雙，縮手推其才。", "陳編且千載，萬蟄聽春雷。", "偕公閑弔古，文遊但荒臺。"]'),
('ece00452-b3ee-4d9b-b525-7c5014bd5f05','再用才子富文華校讎天祿閣韻贈周教授  其二','陳造','宋','宋诗','song-poetry','','[]','步屧城脚園，蒼官拱綠士。',48,'全唐诗/poet.song.150000.json','["步屧城脚園，蒼官拱綠士。", "向來錦打圍，轉首就紛委。", "流光不貸客，感喟中夜起。", "肝腸舊輪囷，言賦子虛子。"]'),
('f3760eef-861d-49e4-9bf0-11a7e68395e3','再用才子富文華校讎天祿閣韻贈周教授  其三','陳造','宋','宋诗','song-poetry','','[]','胸涵陽秋筆，眼高古今宙。',48,'全唐诗/poet.song.150000.json','["胸涵陽秋筆，眼高古今宙。", "周子定可人，萬象棲一咮。", "眇睨紈綺郎，自詭多文富。", "世有九鼎珍，唾去不渠嗅。"]'),
('c19f0261-6ee7-429e-b7b9-e5ec9bce0dc1','再用才子富文華校讎天祿閣韻贈周教授  其四','陳造','宋','宋诗','song-poetry','','[]','窮途有快意，辟席得異聞。',48,'全唐诗/poet.song.150000.json','["窮途有快意，辟席得異聞。", "青天千萬里，翳日带煙雲。", "今者君子後，滿窺崔蔡文。", "當此陣堂堂，嘆我提孤軍。"]'),
('a50974f4-bb1f-4b90-9ffb-928877feac99','再用才子富文華校讎天祿閣韻贈周教授  其五','陳造','宋','宋诗','song-poetry','','[]','矻矻守枯策，頭童未起家。',48,'全唐诗/poet.song.150000.json','["矻矻守枯策，頭童未起家。", "居陋婦勃谿，食貧兒讙譁。", "養高有驁岸，戰勝無紛華。", "黔浴如可移，誰辨鵠與鴉。"]'),
('fa1be6f6-9aac-4e44-8aa6-81d7c9add732','再用才子富文華校讎天祿閣韻贈周教授  其六','陳造','宋','宋诗','song-poetry','','[]','徇物笑蠻觸，自守等毅豹。',48,'全唐诗/poet.song.150000.json','["徇物笑蠻觸，自守等毅豹。", "寸壤聞蚓吟，九萬觀鵬踔。", "孰知塵外士，戴目懶此校。", "營營彼誰子，磔蝟計微效。"]'),
('37454649-bcc2-4bab-8429-8d5e0e41bf82','再用才子富文華校讎天祿閣韻贈周教授  其七','陳造','宋','宋诗','song-poetry','','[]','審知才非充，敢怨言不讎。',48,'全唐诗/poet.song.150000.json','["審知才非充，敢怨言不讎。", "進乃隔九虎，退且辦十牛。", "向非食不足，此檄當徑投。", "黄馘漁樵翁，揣分吾其儔。"]'),
('36ef0f64-3537-4de7-a07d-28371ba3acd8','再用才子富文華校讎天祿閣韻贈周教授  其八','陳造','宋','宋诗','song-poetry','','[]','君家小阿韞，擇壻須才賢。',48,'全唐诗/poet.song.150000.json','["君家小阿韞，擇壻須才賢。", "我家小於菟，披霧欲窺天。", "鵲語燈著花，妙契默有傳。", "何當珠簾外，綵絲自相聯。"]'),
('68176a73-d740-4398-9244-dd81231837a3','再用才子富文華校讎天祿閣韻贈周教授  其九','陳造','宋','宋诗','song-poetry','','[]','萬木同一秋，松柏正也獨。',48,'全唐诗/poet.song.150000.json','["萬木同一秋，松柏正也獨。", "夫君閲流俗，塵過不留目。", "我昔甘曳裾，低首問宜祿。", "及今君子前，玩易愧頻復。"]'),
('41fb4dbb-6bf8-4f2e-a395-df7e092b4465','再用才子富文華校讎天祿閣韻贈周教授  其一○','陳造','宋','宋诗','song-poetry','','[]','假板未通班，此氣渠容索。',48,'全唐诗/poet.song.150000.json','["假板未通班，此氣渠容索。", "周友萬卷腹，小却石渠閣。", "培學虎出翼，息妄眼蛻膜。", "何當去爲霜，萬壑正枯涸。"]'),
('4267cf8a-fee1-4daf-8e1c-3ea993bd9d88','別俞君任通判三首  其一','陳造','宋','宋诗','song-poetry','','[]','客舍不宜久，黄塵翳衣纓。',96,'全唐诗/poet.song.150000.json','["客舍不宜久，黄塵翳衣纓。", "非君此解后，孰使老眼明。", "握手雜談笑，洗醆共濁清。", "已燼銅爐煙，倏聽丙夜更。", "清詩相勞苦，凜然見高情。", "珠璧眩璀璨，珩璜競鎗鏗。", "寧惟老眼明，亦使病骨輕。", "語離信所重，未敢促歸程。"]'),
('a4eed7bd-f8b3-4dbb-9157-5d63c2e93130','別俞君任通判三首  其二','陳造','宋','宋诗','song-poetry','','[]','一代石湖翁，韓歐或其儗。',96,'全唐诗/poet.song.150000.json','["一代石湖翁，韓歐或其儗。", "當時出門下，如君屈幾指。", "論定難爲才，我乃輩多士。", "椎成方未器，正頼君礲砥。", "師友繫魂夢，栩栩輒千里。", "驚見得此客，乾鵲預爲喜。", "一笑破千憂，天幸寧有此。", "石湖倏眼中，此翁真不死。"]'),
('5a4593e6-0dff-432d-8499-005e1ae1e9d6','別俞君任通判三首  其三','陳造','宋','宋诗','song-poetry','','[]','房陵望毗陵，計舍六十餘。',96,'全唐诗/poet.song.150000.json','["房陵望毗陵，計舍六十餘。", "今我從遠役，羨君方逸居。", "逸勞不足道，會合嗟愈疎。", "向來江南北，二年能幾書。", "殘山賸水地，詩題當不虛。", "得句茹不吐，思君定愁予。", "遡江日千里，豈無紅尾魚。", "交情儻未忘，與問今何如。"]'),
('d5f4c7c3-027a-43c4-a16c-9295ca713781','書隠靜寺壁','陳造','宋','宋诗','song-poetry','','[]','籃輿初半塗，飛雨欲無路。',120,'全唐诗/poet.song.150000.json','["籃輿初半塗，飛雨欲無路。", "到山臂屈伸，赫日照窗戶。", "山靈太孤介，深厭俗塵汙。", "雨似難客來，晴似推客去。", "書生林泉意，此癖端有素。", "俛眉紅塵中，正以五斗故。", "堇堇三徑資，渠須畢婚娶。", "出既非得已，歸亦奚早莫。", "他年五湖舟，何殊一杯渡。", "卷舒吾自由，誰招復誰拒。"]'),
('1ba9471d-d2d7-48cb-b8a4-6a0b8c06d04c','贈臧文仲四首  其一','陳造','宋','宋诗','song-poetry','','[]','青山玉所藴，下此翠鳳雙。',48,'全唐诗/poet.song.150000.json','["青山玉所藴，下此翠鳳雙。", "音含古韶濩，身非世文章。", "衆羽不敢睨，謂是聖時祥。", "有人摩老眼，側佇雲路翔。"]'),
('d0dc1db8-4099-4f52-b7ba-b98d024b5bec','贈臧文仲四首  其二','陳造','宋','宋诗','song-poetry','','[]','夫君根柢學，宜我屢即之。',48,'全唐诗/poet.song.150000.json','["夫君根柢學，宜我屢即之。", "罷馬取長道，顧肯過我爲。", "索寶黔婁家，怪君焉取斯。", "頗嘗見此客，且用詫吾兒。"]'),
('a540eabd-0285-4780-bad4-fc4674a325b2','贈臧文仲四首  其三','陳造','宋','宋诗','song-poetry','','[]','理以定故明，用智或成疎。',48,'全唐诗/poet.song.150000.json','["理以定故明，用智或成疎。", "芸芸自根求，一一皆我儲。", "饑糒渴須漿，水固不宜車。", "請君默自燭，是物誰欠餘。"]'),
('d8004a1c-b248-4563-bd03-ddc36b173c04','贈臧文仲四首  其四','陳造','宋','宋诗','song-poetry','','[]','始吾泛其觀，中吾固其守。',48,'全唐诗/poet.song.150000.json','["始吾泛其觀，中吾固其守。", "拳拳寶所重，世或輕敝帚。", "廐馬我所師，家鷄誰得有。", "此心如此用，煩君訂是否。"]'),
('9bb12e52-d85b-441b-b32d-695afe87f919','戒飲三詩  其一','陳造','宋','宋诗','song-poetry','','[]','毒痡痛受辛，斬刈憎暴秦。',120,'全唐诗/poet.song.150000.json','["毒痡痛受辛，斬刈憎暴秦。", "杜康與儀狄，賊物其罪均。", "商毒烈火炎，岐鎬方陽春。", "秦暴虓虎搏，歐粵無顰呻。", "二子起酒禍，古今同湛身。", "計實乃鴆葛，適口良甘醇。", "文錦覆深穽，病媒鬼之鄰。", "劋殺不遺迹，辛政猶爲仁。", "今子知所戒，浮俗豈其倫。", "生世千金軀，况復富席珍。"]'),
('731920c3-f189-4269-98a5-7142f6d87b7f','戒飲三詩  其二','陳造','宋','宋诗','song-poetry','','[]','中古避世者，或以飲自名。',120,'全唐诗/poet.song.150000.json','["中古避世者，或以飲自名。", "世網未易脫，顛眩寧其情。", "嗟哉竹林子，嚌茹日瓶甖。", "時既謝周漢，顧肯羨久生。", "中聖憐徐邈，種秫想淵明。", "卯金當塗高，委質吾顔頳。", "偕我偶盛時，生亦未易輕。", "况子淑茂資，天驥趣修程。", "論才應時須，挺志爲親榮。", "親言銘肺肝，盍師陶士衡。"]'),
('dfa230f5-cef3-4b08-9926-205e4769a6d0','戒飲三詩  其三','陳造','宋','宋诗','song-poetry','','[]','自我銘盤盂，覆盃遠麴糵。',120,'全唐诗/poet.song.150000.json','["自我銘盤盂，覆盃遠麴糵。", "人或安清修，身亦享黄髮。", "柰何悠悠者，沈酗無虛日。", "言之每逢怒，周誥存苦闕。", "狂悖貽世戒，氣血瞢中竭。", "持觴勸客意，彼肯獨夭折。", "投轄車鈐頸，抽腸擢其骨。", "交遊多若人，自重要勇决。", "關須太虛閉，交繼叔夜絕。", "毋興聖賢悲，濡首右臂折。"]'),
('78d3cc10-56c2-467f-a63c-a23ccd8285c1','邵伯阻風小泊贈送行諸公','陳造','宋','宋诗','song-poetry','','[]','長征每愛日，小泊未遻意。',120,'全唐诗/poet.song.150000.json','["長征每愛日，小泊未遻意。", "陰風自南北，客子聽軒輊。", "召棠望吾鄉，不作秦越異。", "船閣鴈鶩洲，人穿魚蝦市。", "相逢各吳語，知識十三四。", "水實不自買，海錯有佳饋。", "餞行餘十客，超俗見友義。", "笑譚寒谷春，爲我洗羈思。", "相與卧玉瓶，跋燭得微醉。", "老懷易作惡，別語毋動喙。"]'),
('c39886bb-1dd4-4b81-a16e-c6ebe26dccfe','次韻丁判院','陳造','宋','宋诗','song-poetry','','[]','丁侯袖詩來，容聽媧皇絃。',240,'全唐诗/poet.song.150000.json','["丁侯袖詩來，容聽媧皇絃。", "咀嚼冰齒頰，如漱錫谷泉。", "露花有餘姿，風漪自成紋。", "中含班傅香，夐絕郊島寒。", "汗流竟後塵，何有一字難。", "明月墮我側，盥誦喜欲顛。", "因君念漂零，俛仰追昔年。", "門間半面初，隄柳嘶晚蟬。", "寒暑機不停，奔騖履欲穿。", "客舍此相遇，把酒霜鴻天。", "男兒氣干霄，猶受稠人憐。", "似聞國士遇，度外置拘攣。", "渠信造物兒，賦予終奇偏。", "凌風謝垢濁，仙者一探丸。", "多肉彼下乘，更趠驊騮前。", "我老從斗祿，纖鱗潜重淵。", "饑火少見貸，歸志久已堅。", "自甘尺蠖屈，何與風鵬鶱。", "會看鶚書薦，領此雲錦篇。", "從今拭病目，長風駕蜚翰。"]'),
('3d003b51-f5b9-44a1-8c92-e3e17b469f44','泊瓜步','陳造','宋','宋诗','song-poetry','','[]','擁衾迎鑾曉，艤楫瓜步夜。',144,'全唐诗/poet.song.150000.json','["擁衾迎鑾曉，艤楫瓜步夜。", "問俗鄉音轉，束縕野宿乍。", "去家倏兼旬，取道逾三舍。", "江神雖世情，羈客忍陵藉。", "初趁風色好，忽復帆席卸。", "泊舟市區外，繫纜古柳下。", "遥聽波浪湧，未息妻孥怕。", "譙翁身世拙，衷貨迄未價。", "榮望絕臺閣，歸計盍桑柘。", "男兒四方志，肯與衰鬢謝。", "古人出處間，分取世俗訝。", "呼酒把譚麈，捫虱復王伯。"]'),
('860313e0-4782-4d4c-97c8-992770296fe2','魏帝廟','陳造','宋','宋诗','song-poetry','','[]','佛貍歲未卯，志欲吞宇縣。',168,'全唐诗/poet.song.150000.json','["佛貍歲未卯，志欲吞宇縣。", "當年江飲馬，腥血浸淮甸。", "無人飯耕牛，有井巢歸燕。", "至今閲遺史，爲汝空飲恨。", "緬想瓜步留，殺氣纏吳分。", "云何此山椒，遺像儼高殿。", "無乃甘事讎，吳俗昧所見。", "或復綿歷久，後嗣忘敵怨。", "冥漠彼有識，福汝吾敢信。", "君看趙與薛，狥國冒禍釁。", "魏侯繼前躅，長呼死白刃。", "胡不尸祝之，香火均遠近。", "豈但祈神休，抑使頑懦奮。", "誰令决從違，引手適我願。"]'),
('bfa81375-a1d4-4812-a9f4-335efc1c99a8','長蘆寺二首  其一','陳造','宋','宋诗','song-poetry','','[]','梁帝號用儒，顧有佞佛癖。',168,'全唐诗/poet.song.150000.json','["梁帝號用儒，顧有佞佛癖。", "區區泥其粗，佛者寧汝即。", "矯矯隻履翁，談妙塵可析。", "冀上一言契，何意水投石。", "瓶錫翩然逝，北去甘面壁。", "有道惡驚世，應俗肯留迹。", "一時起誕罔，千載受誑惑。", "至今利涉地，傳流何荒惚。", "渡江一葦爾，古今尚遺植。", "紛紛捕影徒，唱一和者百。", "遠渡有浮杯，行空或飛錫。", "至人果善幻，幾何異鬼蜮。", "世人墮邪蔽，狥虛不計實。", "我學謝傅韓，艤舟重唶唧。"]'),
('eb216839-d0fc-4262-9eea-a20ff0ad9802','長蘆寺二首  其二','陳造','宋','宋诗','song-poetry','','[]','昔年望長蘆，去江逾百步。',168,'全唐诗/poet.song.150000.json','["昔年望長蘆，去江逾百步。", "垣宇呀已缺，浮圖欹欲仆。", "僧徒噬肯留，日有沉溺懼。", "重來舒望眼，佛剎非故處。", "安衆得亢爽，定遷酬夙素。", "似聞瓶錫侶，復作醯蚋聚。", "居人禱蠶麥，行客乞泉布。", "營者肆夸侈，施者不顧慮。", "百堵煥金碧，奚翅復其故。", "往往豪儁人，四壁有未具。", "彼徒創寺意，取鎮湍濤怒。", "向來梵唄所，倏爲蛟螭據。", "在己不自保，誘俗說依怙。", "波流置不省，此理吾未諭。"]'),
('226a1c70-c116-472f-a532-6c8ef7a3c7eb','泊龍灣','陳造','宋','宋诗','song-poetry','','[]','小灣隠沙觜，沙外仍奔湍。',120,'全唐诗/poet.song.150000.json','["小灣隠沙觜，沙外仍奔湍。", "是間以龍名，信乃龍所蟠。", "浮煙澹寒鑑，斷岸圍清瀾。", "孰知面勢要，中有水府寬。", "我來艤倦楫，天水夜茫漫。", "狂飈吼薄暮，驚浪摧舊灘。", "鯨鱣碭厥居，渡鳥垂羽翰。", "孰睡不知曉，夢次聞平安。", "龍公自兼愛，况此行路難。", "何以答神休，幽佩紉蘅蘭。"]'),
('9524c5ed-ca80-4bae-bfd3-3ae7946ac039','龍灣看初日','陳造','宋','宋诗','song-poetry','','[]','江聲夜寂絕，江霧曉空濛。',120,'全唐诗/poet.song.150000.json','["江聲夜寂絕，江霧曉空濛。", "亂霞映淡日，隠隠空濛中。", "羲馭巧呈瑞，不與他時同。", "烱然玉奩靜，泛此瑛盤紅。", "分明三足烏，依微絳綃蒙。", "曾穹歛氛曀，幽壑舞魚龍。", "昇從海僊府，光射河伯宮。", "遥想麗帝闕，佳氣正鬰葱。", "鸞鷺同虎拜，三呼并神嵩。", "散人得壯觀，醉約持釣翁。"]'),
('ad6a47ec-69b6-44af-8a11-274cdb6c1722','舟中除夜','陳造','宋','宋诗','song-poetry','','[]','老境閲流光，翩若下坂車。',120,'全唐诗/poet.song.150000.json','["老境閲流光，翩若下坂車。", "除夜更深念，繫尾留去蛇。", "昔人老世故，亦復興此嗟。", "迫歲况羈旅，孤舟如泛槎。", "妻孥共蓬窗，偪側棲樹鴉。", "撥火話鄉國，悽愴雜笑譁。", "桃柏粗能具，爆竹知誰家。", "欻聽鷄鼓翼，尚看燈結花。", "遥知諸神曉，共正青帝衙。", "我亦東風前，坐待帆影斜。"]'),
('44318f50-b333-496e-be5c-60b52ce16d4c','草鞋夾','陳造','宋','宋诗','song-poetry','','[]','隆岸圍小河，紆鬰江之隩。',168,'全唐诗/poet.song.150000.json','["隆岸圍小河，紆鬰江之隩。", "初看一泓窄，旋望百頃淥。", "艅艎與下瀨，山屹復雲矗。", "自治貴不試，此舟江左腹。", "向來胡騎南，勢若撼坤軸。", "飛城截中流，羣孽頸爲縮。", "元兇坐自斃，犬羊僅還轂。", "千齡有機會，二豎方角逐。", "武剛環貔貅，突騎騖陵陸。", "古今常勝術，所投副所欲。", "神州久望望，廟算佇復復。", "區區計自保，膠柱難爲曲。", "客行寧賈胡，小泊遂信宿。", "撫事空三嘆，爲儒慚碌碌。"]'),
('ae2a79b7-651e-4d44-b794-8ad70dc3325f','泊慈湖北岸','陳造','宋','宋诗','song-poetry','','[]','坐覺江流平，漶漫裂三股。',168,'全唐诗/poet.song.150000.json','["坐覺江流平，漶漫裂三股。", "舟子告風橫，因循宿中浦。", "慈湖古戍近，猶復小江阻。", "漁翁家葦間，蝸舍無鄰伍。", "把酒訊三老，此寧泊舟所。", "諗我今昔異，解带無所苦。", "向來探丸徒，白晝猶旁午。", "一自尚書來，此輩凜刀俎。", "江山亙千里，有屋皆外戶。", "似聞襄江道，衽席過行旅。", "翳公舊威愛，平寧尚如許。", "兩地好經行，爲官喜欲舞。", "倒床鼻雷吼，夢破聞船鼓。", "受欺墮姑息，迂儒彼何取。"]'),
('dc145b4d-6531-46b7-9e36-961d34397173','泊府口','陳造','宋','宋诗','song-poetry','','[]','建鄴重東南，爰從吳晉後。',144,'全唐诗/poet.song.150000.json','["建鄴重東南，爰從吳晉後。", "鎮戍分淮江，心腹運臂肘。", "我舟歷陽岸，煙外見鍾阜。", "問名良賓實，南渡此其口。", "龍蟠虎踞地，永藉藩籬守。", "六朝或易之，戎馬輒騰蹂。", "鐵山此濟師，竟致凶渠走。", "扼吭儻得要，制敵果何有。", "設險務究本，不獨計山藪。", "任吏所宜擇，撫民所宜厚。", "孤生恤緯意，南望凝竚久。", "深愧行歌人，招邀話佳酒。"]'),
('6894c6f8-6ed9-4cbb-bd49-48e9e871a68c','采石渡','陳造','宋','宋诗','song-poetry','','[]','大江礙崇山，突起作湍悍。',144,'全唐诗/poet.song.150000.json','["大江礙崇山，突起作湍悍。", "采石天下險，揭厲誰敢玩。", "戈樓泊千艘，鋒旗麗天漢。", "昨憶辛巳秋，胡馬蜂蟻亂。", "敢觸貔虎怒，旋作狐鼠竄。", "繄此折其角，羣孽終內叛。", "孤亭試一登，明眼得奇觀。", "回首吾葉舟，已復艤沙岸。", "我犀不敢然，幽察神所憚。", "欻聽鉦鼓閧，戎事閲鵝鸛。", "折衝須武備，保治頼彊幹。", "鄙夫華封祝，泚筆亦其漫。"]'),
('563f3ee8-1e10-4ceb-b5eb-b69a4e40d7eb','上下驛磯','陳造','宋','宋诗','song-poetry','','[]','湖陰數里間，山麓矻兩磯。',216,'全唐诗/poet.song.150000.json','["湖陰數里間，山麓矻兩磯。", "磯麓突江出，禹功不及施。", "千古妨行舟，死生繫毫釐。", "我昔步磯上，雨歇暑氣微。", "驚湍下百尺，怒勢轟千鼙。", "尚憂坤軸動，無怪沙岸欹。", "蟄龍渠得安，過鳥翅欲垂。", "頭眩膽爲掉，坐嘆舟上兒。", "壯哉天下險，姦軌容抵巇。", "如身護風寒，要地此幾希。", "今來歲華暮，去舟良坦夷。", "人言水進退，寒暑分盛衰。", "古來設險守，亦有可易時。", "函谷與劍閣，秦漢嘗用之。", "人輕地亡重，正煩折箠笞。", "恃險無興國，興國須藩籬。", "帝王所取重，文武各攸司。", "險易倏變改，即磯餘可推。"]'),
('65b0497e-2ac9-401c-96f5-25a8b3d10137','蕪湖感舊','陳造','宋','宋诗','song-poetry','','[]','下帆同烏棲，掛帆逐鷄起。',120,'全唐诗/poet.song.150000.json','["下帆同烏棲，掛帆逐鷄起。", "但見蕪湖月，耿夜清如水。", "江左此壯縣，我昔舟屢艤。", "諸公各敬客，款曲豈今比。", "酒杯慣邀留，妓圍供燕喜。", "流連動十日，揮掃或千紙。", "舊遊想如昨，故交今餘幾。", "逝者泉壤隔，存者參辰似。", "浪憑楚些招，盍寄相思字。", "可能喚巫陽，且欲託雙鯉。"]'),
('9a7fb251-08a6-41dd-824a-8fbe2ec1c792','過繁昌','陳造','宋','宋诗','song-poetry','','[]','江山互映带，竹樹渺隠見。',144,'全唐诗/poet.song.150000.json','["江山互映带，竹樹渺隠見。", "居人江山閒，安處忘古縣。", "泊舟穴子初，舊觀儼自薦。", "𡻊山高攙雲，雲際抹深靛。", "慰我塵埃容，嘉此煙雨面。", "山脚慣奔走，尉曹分卑賤。", "縣人應指似，鬢改顔狀變。", "漂零渠未知，憂患嘗欲遍。", "俛仰二十年，轉眄閲蜚電。", "故人半在亡，在者或海甸。", "明朝理去楫，山影暝江練。", "安得人如山，來往長相見。"]'),
('a1104abf-9304-4760-b9a8-d96772e3ae0d','繁昌早發','陳造','宋','宋诗','song-poetry','','[]','客行固厪身，留滯如捩翼。',120,'全唐诗/poet.song.150000.json','["客行固厪身，留滯如捩翼。", "及茲祖禮竟，蓐食理帆席。", "風停浪未蟄，天曙月正白。", "版磯匯湍殺，荻港煙樹碧。", "杖策丁家洲，徙倚容少息。", "無酒問山店，憶鱸聽村笛。", "鳥烏啼松行，鴈鴇下沙磧。", "回柁投曲澳，又寄糝潭夕。", "情疎或易合，不作淮楚隔。", "累然槁項翁，軟語慰行役。"]'),
('4945077e-15b3-4bc5-9120-9e3117f20b4d','泊海子口','陳造','宋','宋诗','song-poetry','','[]','池口至海口，望望三舍外。',96,'全唐诗/poet.song.150000.json','["池口至海口，望望三舍外。", "辰發莫已到，回首西日在。", "風師肯憐客，祖道煩一嗌。", "我舟疑凌虛，楚山真歷塊。", "蜚鳥相讓疾，驚浪乃弗逮。", "窮塗坐局縮，頗嘗得此快。", "遄邁自本圖，闕供恐貽悔。", "未辦問村膠，且計具薪菜。"]'),
('1a24bb66-8ee3-49da-9c08-8929378b5d86','泊小姑山','陳造','宋','宋诗','song-poetry','','[]','楚山屹兩姑，我見乃其稚。',144,'全唐诗/poet.song.150000.json','["楚山屹兩姑，我見乃其稚。", "聞名詩卷間，識面客舟次。", "玉刻極端麗，簪植瞑蒼翠。", "娟月上天角，相與詫嫵媚。", "怒風將我西，未憗卜晚憩。", "山足舟可艤，山木纜可繫。", "山外正風波，獨此佳食寐。", "斷知有神物，主此勝絕地。", "明朝捐行橐，可無答神賜。", "白鵝雪爲肪，綠蟻香馥鼻。", "舟穩風又熟，無乃契神意。", "未暇訪彭郎，辭費辨非是。"]'),
('8afc0892-8967-4b60-915c-2ad4fe5c5f37','郭家洲','陳造','宋','宋诗','song-poetry','','[]','携兒上絕岸，微徑步蒙密。',216,'全唐诗/poet.song.150000.json','["携兒上絕岸，微徑步蒙密。", "人稀鳥烏樂，老屋幾百室。", "荒凉郭家洲，籬落映殘日。", "問俗得周旋，譍門頗倉卒。", "興衰今昔殊，郭姓尚十七。", "鄰里闕鹽茗，翁姬僅盥櫛。", "共說頻歲歉，平陸江浪沒。", "場圃或潭洞，椽栱行螾蛭。", "去秋微收爾，樵採取黔突。", "接耳多樂郊，一去恐兩失。", "吾邦有杜母，撫我不待乞。", "蠲租桑柘在，休役孫子佚。", "意使流殍無，寧後倉廥實。", "官今潯陽來，吏師那容失。", "書紳拜此賜，知我佐郡紱。", "古來裨肉食，多自蒭蕘出。", "必若窮吏道，孰先究民疾。", "剝膚快目前，吾固笑無術。"]'),
('8059745f-2792-4f01-b0e2-920e6783c2b5','富池廟','陳造','宋','宋诗','song-poetry','','[]','買香馬頭西，跂望富池口。',144,'全唐诗/poet.song.150000.json','["買香馬頭西，跂望富池口。", "我帆廟下卸，祇費一炊久。", "匆匆索冠裳，堇堇辦牲酒。", "所取薦蠲潔，不必須富厚。", "精魄我爲悚，勇節公則有。", "出門聞風聲，萬竅一呼吼。", "林摧巨木折，江驅雪山走。", "繫纜下窗坐，齋心念神佑。", "鄰舟瞢冒去，膽碎面黧黝。", "非今羞供留，例亦罹釁咎。", "交神不用卜，遲速示可否。", "噬將捨舟楫，望望終稽首。"]'),
('4de168b5-e790-4150-aacc-c3839c840946','離富池','陳造','宋','宋诗','song-poetry','','[]','江流寂無聲，明滅窗月曉。',120,'全唐诗/poet.song.150000.json','["江流寂無聲，明滅窗月曉。", "客枕歸夢餘，意先西蜚鳥。", "雪天信少風，翳面正繚繞。", "富池忽信次，肯羨雕鶻矯。", "向免犯險艱，神惠顧豈少。", "今晨有佳興，調笑向諸小。", "波平旗脚直，康莊馳騕褭。", "鱗鱗到座隅，健鵲啅林杪。", "人家積蘇間，山影橫練表。", "未成官縛去，得句吾事了。"]'),
('ad10a5ad-994e-48ff-9c2d-87d8e677497a','馬口','陳造','宋','宋诗','song-poetry','','[]','氛昏翳春曉，瞠目如受蒙。',168,'全唐诗/poet.song.150000.json','["氛昏翳春曉，瞠目如受蒙。", "停舟少須之，紅日碾高空。", "是時羣山間，積雪未肯融。", "巖霧不盡收，似角藻繪功。", "屏障莽回合，粉墨紛異同。", "嵌巖眩有無，草樹森玲瓏。", "皛皛瓊爲田，奕奕旆卷風。", "羃籬抹高頂，下乃卧玉龍。", "隠顯隨斷續，間簉成葱櫳。", "微漪湛不摇，一一縣鏡中。", "酒杯與詩筆，客次寧闕供。", "搴取不貲景，納我雲夢胸。", "一笑漂泊裏，孰謂吾塗窮。", "摩挱好東絹，世恐無此工。"]'),
('96c2ba0a-3c78-4feb-b359-fa4938139195','銀葫蘆','陳造','宋','宋诗','song-poetry','','[]','山水佳有餘，我與之周旋。',144,'全唐诗/poet.song.150000.json','["山水佳有餘，我與之周旋。", "江行已久矣，今復領其全。", "漾舟銀葫蘆，雪在春漸妍。", "素瓊間蒼玉，化工與雕鎸。", "屏圍無空缺，護此百頃天。", "圖畫別濃淡，粉墨生雲煙。", "人間有此境，定屬水府仙。", "先生嗜奇勝，久駐無由緣。", "命名失雅馴，吾意終慊然。", "玉鑑扁山石，取重須時賢。", "可無泊舟所，作亭近江壖。", "登臨付楚客，當有雲錦篇。"]'),
('3343ca78-7ddf-4a7d-a31c-4a98d8bc549b','回風磯','陳造','宋','宋诗','song-poetry','','[]','大江悠悠去，淥靜初演漾。',144,'全唐诗/poet.song.150000.json','["大江悠悠去，淥靜初演漾。", "山石齟齬之，湍險乃萬狀。", "君看回風磯，却畧不可上。", "椒石卧中江，與江作陂障。", "鏜沓匯石下，漰澎劇奔放。", "北磯屹對峙，其中過舟舫。", "水流作高下，咫尺便尋丈。", "我行返壑餘，坐想潢流漲。", "頹波次灩澦，如馬亦如象。", "攖觸寧完舟，奇禍此無妄。", "入峽與上瀧，艱惡偕叵量。", "下澤遵夷塗，回首一怊悵。"]'),
('bf1bdff5-7443-48a4-b03c-b0c24c9b1d9f','龍眼磯','陳造','宋','宋诗','song-poetry','','[]','誰謂石一拳，不作江流礙。',96,'全唐诗/poet.song.150000.json','["誰謂石一拳，不作江流礙。", "朝來揚帆西，瞥若驥歷塊。", "龍眼風火磯，培塿視華岱。", "似聞潢潦時，亦復鼓湍匯。", "鑿去本不難，奇巧禹所愛。", "其上嘉樹密，其側魚網曬。", "居惟羨漁鄉，復欲老犢背。", "西歸儻得此，庸敵七里瀨。"]'),
('57b390e4-e21f-4f08-a62e-d8f73af472d5','散花洲晚泊','陳造','宋','宋诗','song-poetry','','[]','畧眼毛山夾，枯涸不可留。',144,'全唐诗/poet.song.150000.json','["畧眼毛山夾，枯涸不可留。", "風帆劈箭去，遼海吹一漚。", "長年面死灰，死爭如赴仇。", "一飯六十里，幸泊散花洲。", "呼婦具盥櫛，命酒浣驚憂。", "我無資身策，老計餬口謀。", "勿云朝不坐，叱馭復何求。", "奔車非伯夷，覆舟無孔丘。", "薄德既謝此，身世付浮休。", "亦念三徑具，歸從沮溺遊。", "笑說今日快，擊轅爲渠謳。", "別留初熟酒，飲處酹陽侯。"]'),
('af70e563-243c-4fca-94c4-055fdd0b005b','庾樓','陳造','宋','宋诗','song-poetry','','[]','晉起不由德，亦坐崇清虛。',168,'全唐诗/poet.song.150000.json','["晉起不由德，亦坐崇清虛。", "陵夷莫挽回，後世猶受汙。", "庾非適用才，夷甫真其徒。", "樓以庾得名，而庾愎且迂。", "面勢瞰空闊，簷楹煥丹朱。", "遐想如不及，效尤無乃愚。", "風流與經濟，本自珉玉殊。", "空譚養虛譽，胎禍取炭塗。", "峻約火燎原，典午轅下駒。", "舉扇障蜚塵，王叟寧厚誣。", "狥名不既實，扁榜誰權輿。", "得興偕下僚，小節安足模。", "捍患識黄樓，仰高題景疎。", "于是復間然，吾言乃迂儒。"]'),
('c64854d7-55e2-48fb-8e52-76ea1e65f582','題六宜堂','陳造','宋','宋诗','song-poetry','','[]','昔人厭俗心，寧取無肉瘦。',168,'全唐诗/poet.song.150000.json','["昔人厭俗心，寧取無肉瘦。", "平時眼爲青，綠士須客右。", "立節自修竦，適用兼庇覆。", "君家所居堂，音響不待叩。", "千溝蔭百椽，一一渭川秀。", "公今王元之，好尚如授受。", "記樓賦此堂，異聲同一咮。", "心謀耳目適，所樂壹能副。", "昔人言外意，泥一乃百漏。", "拘拘六者間，見未脫科臼。", "我此小盤礴，萬境欻通透。", "徐步寒玉琤，長謠靈籟奏。", "主人信清絕，此君舊幽茂。", "并策超俗勳，醉墨點衫袖。"]'),
('e25cdac8-a160-4092-9859-7192a357be4a','次韻余司理','陳造','宋','宋诗','song-poetry','','[]','名分屬我輩，那容狥多可。',168,'全唐诗/poet.song.150000.json','["名分屬我輩，那容狥多可。", "勢由服勞屈，享以綦貴夥。", "積水須固防，易溢不難破。", "勸沮自有機，懲一警千箇。", "世儒略其本，顧詳獄犴課。", "彼頑工抵巇，未可援宥過。", "奸名犯具分，論罪不在大。", "吏姦易爲熾，士氣寧受挫。", "漏網容汝輩，厚顔向此座。", "新詩驚老眼，唱高信難和。", "向來搏虎手，老去但慵懦。", "近者勞阿買，金薤編玉唾。", "此詩尤傑出，氣有江山佐。", "揆予收新得，比君倍當賀。"]'),
('a335948f-700c-47c6-88d7-66bf5262ae10','禱雨福溪巖','陳造','宋','宋诗','song-poetry','','[]','我訪福溪巖，行行黍稌中。',144,'全唐诗/poet.song.150000.json','["我訪福溪巖，行行黍稌中。", "人家打麥罷，鄰里笑語同。", "迎官問來意，不信有藴隆。", "淙激田間泉，詰曲走青虹。", "此泉有餘用，此巖無闕供。", "福巖真福地，爲民保年豐。", "縹緲三花仙，蜿蜒千尺龍。", "翛然乞靈地，陪此超世翁。", "是巖既磨滅，是泉乃終窮。", "洪慈小决擇，妙化符鴻蒙。", "彼此猶屯膏，無乃坐怨恫。", "稽首貢此言，庶其鑒丹衷。"]'),
('871edb59-5a10-49f3-a04e-48357ce61ec9','近榆亭  其一','陳造','宋','宋诗','song-poetry','','[]','小亭園西偏，政復園取重。',48,'全唐诗/poet.song.150000.json','["小亭園西偏，政復園取重。", "扶疎百本木，自昔誰所種。", "敷舒曉霞爛，磊落金丸奉。", "城東詩客在，端許與此供。"]'),
('ca98da77-79b8-4b93-a6db-7fea9fb209be','近榆亭  其二','陳造','宋','宋诗','song-poetry','','[]','董老故自貧，但有滿林杏。',48,'全唐诗/poet.song.150000.json','["董老故自貧，但有滿林杏。", "別令雕虎守，探囊續人命。", "我老斷狡獪，昔人慵季孟。", "惟餘隠几地，可愈俗子病。"]'),
('c44ef3bd-9711-4fea-8c3f-21c44917a19a','近榆亭  其三','陳造','宋','宋诗','song-poetry','','[]','天亦積氣爾，種榆誰所傳。',48,'全唐诗/poet.song.150000.json','["天亦積氣爾，種榆誰所傳。", "人間自得得，何適而非仙。", "少陵健於辭，暇計然不然。", "長翁名亭意，繫影更可憐。"]'),
('fed93496-f08e-487b-82f8-689e70429cd6','近榆亭  其四','陳造','宋','宋诗','song-poetry','','[]','何年歲星精，夜辭天帝家。',48,'全唐诗/poet.song.150000.json','["何年歲星精，夜辭天帝家。", "幻爲頼鄉種，增賁別乘衙。", "似聞綵鳳舞，天風亂晨霞。", "尚當月林飲，一摻漁陽檛。"]'),
('ca34cec6-35d0-40e7-9aa3-0309c29ad133','近榆亭  其五','陳造','宋','宋诗','song-poetry','','[]','坐亭撚吟髭，搯抉了不近。',48,'全唐诗/poet.song.150000.json','["坐亭撚吟髭，搯抉了不近。", "詩來良爲吾，吮漱賸芳潤。", "遽令方丈屋，遶壁走虬蜃。", "何如嶺頭梅，題品得何遜。"]'),
('0fc08ff3-5ab9-4206-a145-4010c868e9ab','近榆亭  其六','陳造','宋','宋诗','song-poetry','','[]','摭華復食實，果部誰稱伯。',48,'全唐诗/poet.song.150000.json','["摭華復食實，果部誰稱伯。", "兄桃柰其弟，無若此眉白。", "三玄信殊稟，五沃擅嘉殖。", "藏核待東歸，分供橘奴帛。"]'),
('9dc4a03d-03dd-478c-8b5f-d039088cb5d6','近榆亭  其七','陳造','宋','宋诗','song-poetry','','[]','少日接爲構，無何了桑榆。',48,'全唐诗/poet.song.150000.json','["少日接爲構，無何了桑榆。", "邀食有餘地，何事須千奴。", "此亭與此木，到眼聊爲娛。", "五詩信睡語，定博君盧胡。"]'),
('49482774-2cac-4039-9e59-79376a45a4b7','答余司理','陳造','宋','宋诗','song-poetry','','[]','緬懷海縣遊，不作千山隔。',144,'全唐诗/poet.song.150000.json','["緬懷海縣遊，不作千山隔。", "雖償還俗債，茲復望霓厄。", "孰知赫曦中，欻有油雲升。", "六幕一汛掃，病骨如濯清。", "西山殷其雷，晚溽尚雨意。", "頗思雲巖宿，靜聽崩空勢。", "靈湫貝爲宮，龍伯肯小留。", "與翁寧兩心，當亦憂民憂。", "願龍噓爲霖，彍電歸袖手。", "免令山城民，議我拜土偶。", "千里飫玉粒，秉穗周困窮。", "牲肥酒如油，歲歲敬爲龍。"]'),
('6daf2c78-6727-4f11-9104-44363b6738a9','教授有詩再次韻','陳造','宋','宋诗','song-poetry','','[]','人間望晴雨，長若物所隔。',144,'全唐诗/poet.song.150000.json','["人間望晴雨，長若物所隔。", "虧成間十五，嘉穀信多厄。", "假手方寸丹，誠與爐煙升。", "風伯齟齬之，不容徹九清。", "玄雲起西北，似副祈禜意。", "驚飈鏖晚空，汛灑第末勢。", "寄聲主雨神，雲車盍小留。", "咄嗟澤枯槁，爲人消殷憂。", "輔帝凝太和，繫子一引手。", "如昔五三代，濟時須聖偶。", "詩壇我賤工，康莊自途窮。", "眩旋向良樂，并御天閑龍。"]'),
('c3ce8f23-b4c4-4ec5-aadf-63aa12464467','次韻余司理路監嶽','陳造','宋','宋诗','song-poetry','','[]','入山日正烈，出山雲忽濃。',192,'全唐诗/poet.song.150000.json','["入山日正烈，出山雲忽濃。", "身疑潤空青，旋覺霏雨濛。", "歸來坐良夜，淙瀉如崩空。", "縣知焦卷地，轉眼青芃芃。", "似聞移晚秧，竭蹷不暇慵。", "人計故新年，已判一倍豐。", "此惠究所自，無乃西山龍。", "澤物龍能之，叱使則天公。", "我行與雨會，僅殺顔發紅。", "地上螻蟻臣，渠敢貪天功。", "兩公壯藻思，表表千夫雄。", "新詩猥見予，拜賜豈所蒙。", "得意筆生春，狀物斤成風。", "生世有如願，兼得寧易逢。", "此詩自宮商，爲君絃枯桐。", "準擬鷄酒社，往和擊壤翁。"]'),
('22ac3c1a-6bb3-4956-a101-726daf34a4e0','和陶淵明歸田園居六詩  其一','陳造','宋','宋诗','song-poetry','','[]','一室類蜂房，爲食來窮山。',120,'全唐诗/poet.song.150000.json','["一室類蜂房，爲食來窮山。", "僅救饑火煎，跋履恐彫年。", "平生丘壑念，回首魚脫淵。", "鄉居何許家，菰茭滿中田。", "有兒可耕牧，枉滯章句間。", "昨日鵲啅餘，鴈書忽墮前。", "云集南蕩工，數竈騰青煙。", "書賣猶可市，前功戒頹顛。", "官業詎宜老，倦客志在閑。", "置書命鴟夷，心事今泰然。"]'),
('680a7f07-77ca-4754-b82e-e2ec88113492','和陶淵明歸田園居六詩  其二','陳造','宋','宋诗','song-poetry','','[]','良驥馳康莊，驤首輕韅鞅。',72,'全唐诗/poet.song.150000.json','["良驥馳康莊，驤首輕韅鞅。", "筋骨倏謝昔，得無伏櫪想。", "自審涎顙質，蹀躞欲奚往。", "如我合漁樵，奪煬忘幼長。", "資身本缺如，與世志空廣。", "老去傃所安，豈直樂榛莽。"]'),
('a1eaeb82-9735-4f30-8752-89e4b3e6b671','和陶淵明歸田園居六詩  其三','陳造','宋','宋诗','song-poetry','','[]','種禾摭其實，即穊乃可稀。',48,'全唐诗/poet.song.150000.json','["種禾摭其實，即穊乃可稀。", "儒吏瞢不長，竟爲老農歸。", "妻芸兒可犂，稱力食且衣。", "平生睎龐翁，此意今不違。"]'),
('267f8831-3072-4fa0-ac23-d1a0bdb202da','和陶淵明歸田園居六詩  其四','陳造','宋','宋诗','song-poetry','','[]','半生冒吏塵，初不一日娛。',96,'全唐诗/poet.song.150000.json','["半生冒吏塵，初不一日娛。", "往往清夜夢，翛然繫林墟。", "已辦二頃耕，更有三畝居。", "養魚近傳訣，種桑不論株。", "呼兒計曩昔，屈信果何如。", "不復首尾畏，形泰神裕餘。", "枝筇莎徑微，枕書竹牖虛。", "日用食眠爾，外此一事無。"]'),
('5c504336-0681-4499-ad3e-cd28064a538f','和陶淵明歸田園居六詩  其五','陳造','宋','宋诗','song-poetry','','[]','我慚曠達人，夢寐眷鄉曲。',60,'全唐诗/poet.song.150000.json','["我慚曠達人，夢寐眷鄉曲。", "十年仕楚越，政坐食不足。", "人皆詫善奕，舉世鮮識局。", "陶翁有高躅，迷塗炳明燭。", "於焉稅吾駕，作息課昏旭。"]'),
('5f984c59-b27a-44ef-a5cc-17b03e517473','和陶淵明歸田園居六詩  其六','陳造','宋','宋诗','song-poetry','','[]','把竿坐斜陽，跨牛出曉陌。',84,'全唐诗/poet.song.150000.json','["把竿坐斜陽，跨牛出曉陌。", "長謠柴桑詠，聊復自適適。", "梓里三鬴餘，鄰犬不吠夕。", "稼穡政使忙，樽酒取空隙。", "仙曹有知友，自揣無能役。", "經時雋英事，小人分耕績。", "成言君勿問，賣菜可求益。"]'),
('7c69fe26-8621-4700-869d-6019a12a0a70','病起四詩 一節食','陳造','宋','宋诗','song-poetry','','[]','醫經戒多食，書惡殄天物。',132,'全唐诗/poet.song.150000.json','["醫經戒多食，書惡殄天物。", "細茹取微足，衛生此其術。", "是銘當匕筯，况我已衰疾。", "胡爲冒所戒，一卧復十日。", "恙疴不虛生，一一自口實。", "大嚼健武事，欲强蒲柳質。", "行年踰知命，備歷世纖悉。", "山膚與水豢，嘗味幾十七。", "婪酣復不已，頤正昧終吉。", "昔人議四凶，饕餮乃其一。", "不見辟穀翁，曾是漢良弼。"]'),
('ba78e60d-06b4-4380-8319-8114d79c69c1','病起四詩 二止酒','陳造','宋','宋诗','song-poetry','','[]','少日良束脩，但識名教樂。',132,'全唐诗/poet.song.150000.json','["少日良束脩，但識名教樂。", "誰令憂患後，頗復近杯勺。", "嚚號或跳梁，扶携取諧謔。", "興來偶一適，事過含餘怍。", "向非病鼎至，或未悟狂藥。", "不知黍麥毒，終乃蓳葛若。", "腐腸自浸漸，履虺尚歌咢。", "覆觴吾已後，遽覺今勝昨。", "此衷天啟之，相予固不薄。", "卒歲辦僧過，茗粥安淡泊。", "時醉床頭經，妙意翔碧落。"]'),
('8cda40fe-7e01-41a8-9994-b930e3090d9c','病起四詩 三息念','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','祿位據極品，勳業垂不磨。',168,'全唐诗/poet.song.150000.json','["祿位據極品，勳業垂不磨。", "出從白馬肥，家有黄金多。", "世間貴富者，才德乃莫過。", "骨相審自知，甕盎哀駘他。", "一昔讀書史，志空慕丘軻。", "矻矻章句樂，所趣不及他。", "日月倏遷謝，如此定命何。", "知己初不無，腰金鳴玉珂。", "一旦逝水去，匪斧嗟不柯。", "揆材既樗櫟，揣分合澗薖。", "旌翻火馳餘，但有雙鬢皤。", "迨今要勇往，灌園仍養痾。", "石女自無兒，古井那解波。", "西湖佳風煙，久矣辦一蓑。"]'),
('7a0d8d33-03f2-4b55-bf85-6bc4e3c9ba35','病起四詩 四論報','陳造','宋','宋诗','song-poetry','','[]','我本扶犂手，爲儒父兄意。',144,'全唐诗/poet.song.150000.json','["我本扶犂手，爲儒父兄意。", "全家飽官廩，髮膚盡君賜。", "一念三稽首，報答迄未議。", "向來挹前修，謂可跬步至。", "即今頻頻食，空負堂堂志。", "尚當桑榆收，未可弁髦棄。", "柰何不自愛，生理冒所忌。", "致君榮吾親，環省已不冀。", "餘年猶視息，舊學有造詣。", "其次在立言，揆予敢辟是。", "於世粗有益，就死可無愧。", "噬將金玉女，凜凜戒失墜。"]'),
('afa65717-1a09-400c-a464-8166223b1181','題陳主管奧廣樓','陳造','宋','宋诗','song-poetry','','[]','卷舒樂天遊，仕宦甘吏隠。',96,'全唐诗/poet.song.150000.json','["卷舒樂天遊，仕宦甘吏隠。", "吾宗大雅士，爲學先究本。", "樓居盤礴地，超然寄妙藴。", "沉沉一機深，納納萬象泯。", "人方窺端倪，我自絕畦畛。", "胡寧山川麗，詩卷規束攟。", "彼哉狹且露，之世坐拘窘。", "瞢焉登斯樓，不博粲然囅。"]'),
('29e59e2c-9c22-4de1-9b18-f4e7bcea336f','題雍和堂','陳造','宋','宋诗','song-poetry','','[]','元功播萬有，洪纖各秀穎。',132,'全唐诗/poet.song.150000.json','["元功播萬有，洪纖各秀穎。", "一或疵癘之，槁乾例榛梗。", "是身儲至和，舉世乏妙領。", "粹然太丘裔，父子皆秀整。", "學自付衣鉢，刃不留綮肯。", "文字長少蘇，智趣大小耿。", "翛然詩禮庭，翩度脊令影。", "穆穆塤箎春，矯矯塵務屏。", "會看蟬嫣去，滋味調九鼎。", "彼哉夸毗子，肝膽作蛙黽。", "斯焉世宗師，胡不日三請。"]'),
('b97a9a9d-ebba-4ea0-8a78-d7f080d6fade','題通明堂','陳造','宋','宋诗','song-poetry','','[]','世儒困牆面，窒外由蔽中。',84,'全唐诗/poet.song.150000.json','["世儒困牆面，窒外由蔽中。", "一理有朝澈，八窗自玲瓏。", "公無末俗病，人識古賢風。", "照物鑑絕塵，與世雲行空。", "似聞虛白室，略與公心同。", "彼哉壞陂老，史語寧所蒙。", "吾知泚筆意，千載端爲公。"]'),
('e60ed464-1fcc-445b-bc85-7d3d14dce4e2','次韻余司理','陳造','宋','宋诗','song-poetry','','[]','一從荆楚役，八數昏旦星。',192,'全唐诗/poet.song.150000.json','["一從荆楚役，八數昏旦星。", "剸裁有瑣碎，觴詠無頻仍。", "世故未焚券，官曹方治經。", "客或嗤臞儒，下亦安聾丞。", "過日念知己，遠方空舊朋。", "持斧迺宗匠，歃血主文盟。", "天瓢賸挹注，風翼困凌乘。", "袖憐醉墨淄，眼爲故交青。", "招此窮鄉吏，闖彼小玉京。", "樽罍容吟噱，粉黛羅娉盈。", "理窟領新得，詩瓢傾舊盛。", "風前雕虎嘯，秋後寒蛩鳴。", "六花嚴堅陣，尺箠鏖罷兵。", "是翁信奇偉，小子慚奉承。", "攘善悖古訓，躗言防天刑。", "見推無異辭，君語吾未憑。"]'),
('dca21bb1-0e47-4395-8bd7-041957c4f28e','離伏龍','陳造','宋','宋诗','song-poetry','','[]','北風鏖屯雲，倦鳥白晝迷。',144,'全唐诗/poet.song.150000.json','["北風鏖屯雲，倦鳥白晝迷。", "篩爲縣麻雨，寒氣晚凄凄。", "何以贈行客，去路一尺泥。", "卒徒淖莫前，草棘取新蹊。", "可能辭滯留，十步九顛隮。", "窮我恐非天，問子誰見擠。", "少日憂患海，有眉未肯低。", "流年况衰病，縱死非孩提。", "戚欣何足云，壽夭久已齊。", "秀色浮嶺路，清音淙上溪。", "會心各姿態，捋須忘慘悽。", "山靈不無情，斬新獻詩題。"]'),
('88eb8c18-9f2d-4d3e-9ee4-11f00751c5fc','過八疊山','陳造','宋','宋诗','song-poetry','','[]','我從外朝來，嶮峭相連接。',120,'全唐诗/poet.song.150000.json','["我從外朝來，嶮峭相連接。", "巉絕不可上，孰與西八疊。", "車匪毛羽去，我豈猿猱捷。", "一步九頓仆，陟起正岌嶪。", "飛蘿攀恐斷，狠石高更躡。", "時方積雨後，沒骭泥涉涉。", "客居慣澤國，未到意先懾。", "呀如敵場赴，隸卒不敢怯。", "及此問次舍，猶覺口嚅囁。", "剪燭未渠寢，尚恐夢驚魘。"]'),
('2b61c81d-78c8-4592-86a1-5b128ee67b85','還家登悔來坡','陳造','宋','宋诗','song-poetry','','[]','下坡黐鴈墮，上坡風鷁退。',96,'全唐诗/poet.song.150000.json','["下坡黐鴈墮，上坡風鷁退。", "歷險雖末勢，未易忘嘆慨。", "散人吏隠心，下上不云悔。", "摩眼見南山，衆嶺莫謀大。", "雲陰巧蔽虧，日御頗隔閡。", "誰規山一凹，千室作闤闠。", "嵐影暝竹柏，吾廬良好在。", "言歸休吾勞，嘯詠山與對。"]'),
('d0d487d5-f396-4ca7-964c-6a8eb7bfff30','程帥和陶二詩見憶次韻','陳造','宋','宋诗','song-poetry','','[]','離合定有數，撫事尚忍言。',96,'全唐诗/poet.song.150000.json','["離合定有數，撫事尚忍言。", "憶掎枚鄒袂，遊從如兔園。", "堂堂繡衣老，凜凜雲錦篇。", "繄公笑譚爾，諷玩良超然。", "效顰徒區區，睎駕嗟無緣。", "登樓漫多感，漂泊類仲宣。", "窊石取供醉，孤子真次山。", "東望搔白首，不獨悲流年。"]'),
('9188cecd-9790-43b9-9cf9-cd0bbd6e7634','次程帥和陶詩韻','陳造','宋','宋诗','song-poetry','','[]','昔吾竊科第，正自學力勤。',120,'全唐诗/poet.song.150000.json','["昔吾竊科第，正自學力勤。", "雖從士夫後，祿已不及親。", "痛感韋經傳，敢忘擇孟鄰。", "念汝知策厲，燈夜仍鷄晨。", "立志忌作輟，惜陰計寸分。", "盍抽胸次陳，驅爲筆底春。", "解顔獻新得，眩眼釋嶠雲。", "鉏頭足膏腴，天人巧相因。", "奉親有如此，况予耐賤貧。", "誰今子不如，儷美須前人。"]'),
('a99ea8fc-3b9c-42d5-aa1a-96a879526d86','謝程帥袁制使  其一','陳造','宋','宋诗','song-poetry','','[]','昔人道與俱，物外一不假。',48,'全唐诗/poet.song.150000.json','["昔人道與俱，物外一不假。", "而我同是見，兼取及土苴。", "虛心超萬境，詩筆時一把。", "造詣豈二機，此秘知者寡。"]'),
('e6749dec-f6b7-433f-ae95-77ba89f97427','謝程帥袁制使  其二','陳造','宋','宋诗','song-poetry','','[]','還山念初願，老夫辦一物。',48,'全唐诗/poet.song.150000.json','["還山念初願，老夫辦一物。", "生平萬金産，自託五色筆。", "譬如十全醫，付此無妄疾。", "落紙亂蛇蚓，超然百憂失。"]'),
('61d9939b-75ea-40ce-8139-133763f4a354','謝程帥袁制使  其三','陳造','宋','宋诗','song-poetry','','[]','世人事夸毗，失得紛滅起。',48,'全唐诗/poet.song.150000.json','["世人事夸毗，失得紛滅起。", "回思少年日，失脚幾墮此。", "尚友千載人，得已吾徑已。", "高眠北窗風，賢否付一指。"]'),
('f6bef454-f693-43ec-bd93-618a844a3d56','謝程帥袁制使  其四','陳造','宋','宋诗','song-poetry','','[]','俗間若偪仄，有士能湛浮。',48,'全唐诗/poet.song.150000.json','["俗間若偪仄，有士能湛浮。", "任真自得得，與世不同憂。", "得閒書遮眼，覺倦書枕頭。", "不辭蠹魚誚，不貽牢豕羞。"]'),
('340273df-4658-441f-8cea-ff7c3f231f1a','謝程帥袁制使  其五','陳造','宋','宋诗','song-poetry','','[]','江左風流人，安石頗巨擘。',48,'全唐诗/poet.song.150000.json','["江左風流人，安石頗巨擘。", "絲竹不去耳，用逃憂患域。", "陶琴不須絃，我輩所矜式。", "設逢東山翁，兕觥與浮白。"]'),
('3cd9e5e4-32c0-4e1e-b9e6-66a065b827f5','謝程帥袁制使  其六','陳造','宋','宋诗','song-poetry','','[]','好書飛墮前，客有記衰賤。',48,'全唐诗/poet.song.150000.json','["好書飛墮前，客有記衰賤。", "蜀道六十舍，汗牛煩軺傳。", "端如枵腹人，品列睨嘉薦。", "常伯古賢風，凜凜眼中見。"]'),
('428140ea-298a-4aa3-8ce2-e96663fde326','謝程帥袁制使  其七','陳造','宋','宋诗','song-poetry','','[]','會青媲熊膽，入眼冰雪如。',48,'全唐诗/poet.song.150000.json','["會青媲熊膽，入眼冰雪如。", "疎雲放佳月，赤眚爲之除。", "自拭烏皮几，日課蠅頭書。", "政使堂下笑，矻矻糟粕餘。"]'),
('66b4d78b-b750-495e-99fb-87d0b6f11e5d','謝程帥袁制使  其八','陳造','宋','宋诗','song-poetry','','[]','豐約自定分，絲粟戒妄求。',48,'全唐诗/poet.song.150000.json','["豐約自定分，絲粟戒妄求。", "斯文寓理窟，多取誰汝尤。", "人間張長公，骯髒謝公侯。", "窮塗有樂地，投老容夷猶。"]'),
('e0ec9f1f-75a4-4e44-9df7-86d08a6359a8','謝程帥袁制使  其九','陳造','宋','宋诗','song-poetry','','[]','九死得此生，萬事遂成懶。',48,'全唐诗/poet.song.150000.json','["九死得此生，萬事遂成懶。", "惟餘坐進地，劣亦受推挽。", "交遊金玉人，畢力補疎短。", "詩書銜砭劑，陸續到老眼。"]'),
('de4e1f68-0e01-4d43-9fb9-bb3c9c3d54ea','謝程帥袁制使  其一○','陳造','宋','宋诗','song-poetry','','[]','一編用劉漢，誰似進履生。',48,'全唐诗/poet.song.150000.json','["一編用劉漢，誰似進履生。", "高吟謝世書，我嘗羨彌明。", "昭文倦袖手，此曲寧虧成。", "屠龍與澼洸，付渠自重輕。"]'),
('874c711c-a5b3-4dbb-9291-5b8aa2123b87','程帥以詩見慰用韻謝之','陳造','宋','宋诗','song-poetry','','[]','平時聯輝星，轉首食既月。',72,'全唐诗/poet.song.150000.json','["平時聯輝星，轉首食既月。", "誰能玄覽空，影事睨盈缺。", "老子一掬淚，未憗謝天合。", "生世岐高下，末路各一穴。", "莊生悟浮休，荀粲枉悲咽。", "公言敬書紳，聞道有先達。"]'),
('e188d228-d252-4f11-923f-cdab7816046d','梁廣文歸自襄陽作古樂章迎之  其一','陳造','宋','宋诗','song-poetry','','[]','自君之出矣，適我患禍初。',48,'全唐诗/poet.song.150000.json','["自君之出矣，適我患禍初。", "入門悼今昔，顧影憐畸孤。", "古有鼓盆達，自笑食蘗如。", "石交不在眼，勝談誰見娛。"]'),
('14b294ed-fc37-48a5-bcf6-6f04caa80005','梁廣文歸自襄陽作古樂章迎之  其二','陳造','宋','宋诗','song-poetry','','[]','自君之出矣，春意尚妖冶。',48,'全唐诗/poet.song.150000.json','["自君之出矣，春意尚妖冶。", "著我愁城中，轉首已中夏。", "豈無鼓吹具，塵筆置不把。", "亦欲鞭其慵，獨倡無和者。"]'),
('b0d11985-3c3f-4ef5-8030-8bc60a469016','梁廣文歸自襄陽作古樂章迎之  其三','陳造','宋','宋诗','song-poetry','','[]','自君之出矣，無心惜流光。',48,'全唐诗/poet.song.150000.json','["自君之出矣，無心惜流光。", "但記燕營巢，俄復蜂割房。", "煩君驗節物，可孤北窗凉。", "戎葵一笑粲，竹萌十尺强。"]'),
('31bf5795-0171-4a73-99da-7d7453b0f65b','梁廣文歸自襄陽作古樂章迎之  其四','陳造','宋','宋诗','song-poetry','','[]','自君之出矣，饑民日北首。',48,'全唐诗/poet.song.150000.json','["自君之出矣，饑民日北首。", "春從二天來，共拜更生手。", "未議解倒垂，促膝此何有。", "非君面揚榷，誰有筆端口。"]'),
('046d2d6e-e9f4-4215-8925-a1c044e687d8','次韻陸子高','陳造','宋','宋诗','song-poetry','','[]','一從別君來，圓缺幾望舒。',288,'全唐诗/poet.song.150000.json','["一從別君來，圓缺幾望舒。", "相與兄弟然，異姓殊厥居。", "向來帆歸船，欲去仍趦趄。", "平安可但已，擬憑雙鯉魚。", "兩地邈千里，二年能幾書。", "了知故人意，記憶猶勤渠。", "當君訪甓社，值我留南徐。", "參辰巧相避，終冀或起予。", "扣戶聽剝啄，果爾不作疎。", "屬者久契闊，茲焉不躊躇。", "甚欲挽袖留，扣子萬卷儲。", "子家老嗣宗，三賦陵相如。", "阿戎青出藍，萬壑赴歸墟。", "宸廷奉大對，百韞財一紓。", "有偕仲補衮，無取辛引裾。", "俯視漢諸公，彼餒此有餘。", "置之不吾即，欲刃捐礛䃴。", "南臺復西掖，高位爲誰虛。", "未須芹藻地，脫口鎗珮琚。", "平時交遊間，別酒慣攙袪。", "如君可畏敬，且復同鄉閭。", "求全待補劓，涉險資閑輿。", "滔滔多面朋，著眼增欷歔。", "視我若浼然，於君何頼與。"]'),
('e3d76373-98a9-4257-a628-a4bfa8693271','再次陸子高韻奉寄','陳造','宋','宋诗','song-poetry','','[]','孰能下書帷，潜心如仲舒。',288,'全唐诗/poet.song.150000.json','["孰能下書帷，潜心如仲舒。", "沒沒視息間，飽食仍懷居。", "紛華或交戰，進修顧趦趄。", "屹立視儕輩，未脫同隊魚。", "欲耕我無由，生計付束書。", "推卷了無得，每嗟吾負渠。", "日月駒隙過，撫事猶姑徐。", "衰晚時用少，倖直女駡予。", "拙憐官路澀，貧覺交情疎。", "沈沈王侯宅，進步終踟躕。", "所悲名不稱，暇計家無儲。", "一官劣自庇，晉如復摧如。", "犂頭足膏澤，良田本榛墟。", "洪鍾忍不扣，妙意誰爲紓。", "纖缺間衆美，狐裘羔爲裾。", "而我空無有，一饋九嘆餘。", "眼中今士龍，才業世舍諸。", "椽筆將精騎，詩來真擣虛。", "陳前眩錦繡，論報乏瑶琚。", "應以巴人歌，跼蹐疑見祛。", "逝將賣書去，近君營田閭。", "更僕懷韋編，課兒肩竹輿。", "有志竟未酬，南睇幾欷歔。", "愛我寧惡石，非子而誰與。"]'),
('17771d20-2b52-4b7c-8eff-e5e6602d1b36','感事十詩上李侍郎  其一','陳造','宋','宋诗','song-poetry','','[]','齊人石爲瓠，自視比金璧。',48,'全唐诗/poet.song.150000.json','["齊人石爲瓠，自視比金璧。", "鑽之不能竅，寶此果何益。", "人士爲己學，落落肯如石。", "當知井用汲，又惡匏不食。"]'),
('3b27ce16-1899-4dfd-8ccb-a28633e7a670','感事十詩上李侍郎  其二','陳造','宋','宋诗','song-poetry','','[]','客來自羅浮，遺我藥如粟。',48,'全唐诗/poet.song.150000.json','["客來自羅浮，遺我藥如粟。", "茹之三頓首，已覺顔如玉。", "飛浮日月傍，夜訪銀河宿。", "和氣均人寰，坐使年穀熟。"]'),
('b4504dc8-7956-492b-b921-b0000faea379','感事十詩上李侍郎  其三','陳造','宋','宋诗','song-poetry','','[]','鄰女德稱色，婉孌白玉溫。',72,'全唐诗/poet.song.150000.json','["鄰女德稱色，婉孌白玉溫。", "無資嫁未售，行媒不顧門。", "佩是親紉蘭，庭有手植萱。", "君子正求匹，不聘甘難婚。", "芳歲逝不留，苦節中彌敦。", "澗潦有遺采，此意與誰論。"]'),
('b3a95a7f-cfd5-4fba-8c51-d44016b3e216','感事十詩上李侍郎  其四','陳造','宋','宋诗','song-poetry','','[]','國工鑄良劍，髮白心志悴。',60,'全唐诗/poet.song.150000.json','["國工鑄良劍，髮白心志悴。", "晶熒淬歛餘，干莫并犀利。", "入匣蟄虬龍，落手懾魑魅。", "衛身未足道，適用在一試。", "樓蘭猶頡頏，顧汝豈虛器。"]'),
('5f554a31-0c97-4fe0-94b6-0ca71d95b3d6','感事十詩上李侍郎  其五','陳造','宋','宋诗','song-poetry','','[]','荆璞自楚寶，顧終雜土木。',72,'全唐诗/poet.song.150000.json','["荆璞自楚寶，顧終雜土木。", "和氏浪三獻，一身已再辱。", "小儒褐衣底，磊落幾荆玉。", "把玩坐蓬屋，和應笑遺俗。", "善價誰不懷，一辱詎可贖。", "吾亦笑和氏，葵猶衛其足。"]'),
('9ab98d20-5026-4e8f-bb9e-983ff80c7255','感事十詩上李侍郎  其六','陳造','宋','宋诗','song-poetry','','[]','伯夷困采薇，名不厠周亂。',72,'全唐诗/poet.song.150000.json','["伯夷困采薇，名不厠周亂。", "敬通可言命，四七拱炎漢。", "聖主方側席，士或槃薖澗。", "有斧苦無柯，古今同此嘆。", "大人世鳳麟，吐握豈云憚。", "么麽未足數，一官從浪漫。"]'),
('e9b87c68-0914-4b7d-9738-4352694dd3d0','感事十詩上李侍郎  其七','陳造','宋','宋诗','song-poetry','','[]','長松倚絕壑，高蘿纏綿之。',72,'全唐诗/poet.song.150000.json','["長松倚絕壑，高蘿纏綿之。", "蒼山屹半空，白雲相因依。", "揮策馬不前，自問此何時。", "聖賢運化樞，奇髦各騖馳。", "躑躅諸儒後，槁暴窮山爲。", "槃木貴有因，平心勿嗟咨。"]'),
('a10b5049-6821-4148-97ef-aa8dd26934f3','感事十詩上李侍郎  其八','陳造','宋','宋诗','song-poetry','','[]','燕君市駿心，一昔馳九野。',48,'全唐诗/poet.song.150000.json','["燕君市駿心，一昔馳九野。", "豈知千里足，近出鹽車下。", "臨風非一鳴，幾謂無識者。", "詳肉略之骨，曠古無善馬。"]'),
('dbba7eb6-f03b-477d-91b5-be71341f917d','感事十詩上李侍郎  其九','陳造','宋','宋诗','song-poetry','','[]','枉尋固已汙，索價則已欺。',72,'全唐诗/poet.song.150000.json','["枉尋固已汙，索價則已欺。", "人生功名念，舒卷自一時。", "榮辱取所適，窮達非敢知。", "及物儻在道，卑官亦可爲。", "咄咄厭矮屋，心無一日嬉。", "還應乘田翁，笑汝太矜持。"]'),
('7a3b64fe-81e7-4547-9b87-ac0a234007af','感事十詩上李侍郎  其一○','陳造','宋','宋诗','song-poetry','','[]','幽人一床書，不肯睨侯伯。',72,'全唐诗/poet.song.150000.json','["幽人一床書，不肯睨侯伯。", "領會有真樂，未厭四立壁。", "平日太玄經，看人五鹿客。", "今代元紫芝，獨未覘顔色。", "向來縈清夢，倏喜得親炙。", "一洗衰俗耻，滿腹志願畢。"]'),
('2a8c988d-fa1a-4108-aaef-3bd31396cc45','隠靜道中','陳造','宋','宋诗','song-poetry','','[]','晴日暝復出，煙雲尚飛浮。',144,'全唐诗/poet.song.150000.json','["晴日暝復出，煙雲尚飛浮。", "東風解人意，松間作颼飀。", "罷馬不用鞭，正愜道塗修。", "凉氣濯毛骨，百疾洒然瘳。", "縈紆草根泉，激激冰玉漱。", "籬頭薔薇花，娜娜新婦頭。", "空林人語寂，野鳥時啁啾。", "名山無窘步，春色况未休。", "盤礴翠微寺，判作三日留。", "曾非躭禪寂，聊此樂深幽。", "文移暫見貰，清境與心謀。", "晞髮五峰影，濯足雙澗流。"]'),
('6794c95c-faea-40aa-ae90-b67313c179f4','同陳宰黄簿游靈山八首宰云吾輩可謂忙裏偷閑苦中作樂以八字爲韻  其一','陳造','宋','宋诗','song-poetry','','[]','浮天大江白，發地羣山蒼。',48,'全唐诗/poet.song.150000.json','["浮天大江白，發地羣山蒼。", "江山環挹處，一鷲棲寶坊。", "偶從紅塵中，與客分僧床。", "却窺紅塵底，紛作磨蟻忙。"]'),
('439eed6f-e58b-46d3-8fc7-ba655056858a','同陳宰黄簿游靈山八首宰云吾輩可謂忙裏偷閑苦中作樂以八字爲韻  其二','陳造','宋','宋诗','song-poetry','','[]','精廬兩牛鳴，欲往輒復止。',48,'全唐诗/poet.song.150000.json','["精廬兩牛鳴，欲往輒復止。", "山靈應笑人，矻矻簿書裏。", "清辰陪詩翁，俗態方一洗。", "但恐煩移文，松檜負餘耻。"]'),
('f6e08c7f-6623-428b-a9cd-bebafcd5d8ef','同陳宰黄簿游靈山八首宰云吾輩可謂忙裏偷閑苦中作樂以八字爲韻  其三','陳造','宋','宋诗','song-poetry','','[]','令尹拯濟功，在處騰歌謳。',48,'全唐诗/poet.song.150000.json','["令尹拯濟功，在處騰歌謳。", "翛然伊洛意，副此招提游。", "一笑倥傯餘，政以先民憂。", "雖懷蔡侯靜，不作趙孟偷。"]'),
('5bd04140-06a1-48d6-a02e-272327dfc8f7','同陳宰黄簿游靈山八首宰云吾輩可謂忙裏偷閑苦中作樂以八字爲韻  其四','陳造','宋','宋诗','song-poetry','','[]','我雖裹章服，雅意耕寬閑。',48,'全唐诗/poet.song.150000.json','["我雖裹章服，雅意耕寬閑。", "著貂可採藥，拄笏或看山。", "白頭敲榜地，茲游破天慳。", "有興聊可歌，睡語不受刪。"]'),
('00ba49a9-20ab-4d3d-85f4-76761b102363','同陳宰黄簿游靈山八首宰云吾輩可謂忙裏偷閑苦中作樂以八字爲韻  其五','陳造','宋','宋诗','song-poetry','','[]','枕流未云清，食蘗不言苦。',48,'全唐诗/poet.song.150000.json','["枕流未云清，食蘗不言苦。", "老禪家翠微，風壑嘯一虎。", "碧眼照人天，金地漂花雨。", "千偈彈指頃，竟亦無剩語。"]'),
('1e7f3078-dcbf-45cb-a652-f1e7af167ad6','同陳宰黄簿游靈山八首宰云吾輩可謂忙裏偷閑苦中作樂以八字爲韻  其六','陳造','宋','宋诗','song-poetry','','[]','名山吾敢忘，獨往興易窮。',48,'全唐诗/poet.song.150000.json','["名山吾敢忘，獨往興易窮。", "勝游得勝士，杖屨凜生風。", "表表益者友，當求古人中。", "今世習鑿齒，前身黄石公。"]'),
('aa025eda-a6b2-4101-8a0d-b6efe7e6abdf','同陳宰黄簿游靈山八首宰云吾輩可謂忙裏偷閑苦中作樂以八字爲韻  其七','陳造','宋','宋诗','song-poetry','','[]','一代無爲翁，雅志屬丘壑。',48,'全唐诗/poet.song.150000.json','["一代無爲翁，雅志屬丘壑。", "至今玉雪句，爲山鎮不若。", "生平嵇生龍，何時令威鶴。", "弔古但三嘆，九原如可作。"]'),
('46991cd9-e64a-48dc-abc9-31925b7a1e2d','同陳宰黄簿游靈山八首宰云吾輩可謂忙裏偷閑苦中作樂以八字爲韻  其八','陳造','宋','宋诗','song-poetry','','[]','吾儕自由身，聲利爲纏索。',48,'全唐诗/poet.song.150000.json','["吾儕自由身，聲利爲纏索。", "不有山林幽，何以寬此縛。", "熏爐仍茗椀，鉤窗共盤礴。", "何必覩史天，是中差可樂。"]'),
('b55165eb-f974-4fc6-b5df-262c2224c38e','郡寮按樂飲趙判院有詩次其韻','陳造','宋','宋诗','song-poetry','','[]','簿書棼如絲，取樂得少空。',144,'全唐诗/poet.song.150000.json','["簿書棼如絲，取樂得少空。", "悠然杯勺興，藉此歌舞送。", "從事來官厨，醉不睡鄰甕。", "衣裳賸蘭澤，言議雜囂閧。", "人生醒忌獨，勝日飲須痛。", "向來韝上鷹，府公解其縱。", "先生作禪卧，肯以靜嗤動。", "形臞詩則昌，萬境供日用。", "文字與紅裙，寧非一理共。", "退之强分別，無乃夢中夢。", "絲竹娛中年，耐此髮種種。", "明當解予酲，酒德賡舊頌。"]'),
('80a42521-524d-4d38-ac11-a9907d853530','再過楊秀才莊','陳造','宋','宋诗','song-poetry','','[]','茆茨竹間見，竹根漱清流。',96,'全唐诗/poet.song.150000.json','["茆茨竹間見，竹根漱清流。", "翛然楊子宅，面勢崇山陬。", "開窗得小憩，忽復成再游。", "流光屬深省，昔扇今駝裘。", "主人中田宿，穡事方未休。", "譍門紫蘭兒，見客頗邀留。", "鷄黍要後約，行止寧前謀。", "攬轡茗事已，黄塵迷馬頭。"]'),
('8e4fd705-4a59-4b96-9760-4c9d41c95ced','張秀才復留爲作','陳造','宋','宋诗','song-poetry','','[]','郵城望繁川，渺莽天一陬。',168,'全唐诗/poet.song.150000.json','["郵城望繁川，渺莽天一陬。", "親知非不多，噬肯一來游。", "張侯我石友，前輩放一頭。", "逃俗火避濕，赴義鷹辭韝。", "窮谷喜足音，况接大雅流。", "前之翩然來，今復欣然留。", "茲非爲我歟，厚意胡宜酬。", "日邊有知己，崇論親冕旒。", "故人書沓來，擁麾淮上州。", "置彼肯就此，與世風馬牛。", "文字有至味，過從無珍羞。", "山院作僧過，竹靜荷氣浮。", "載下東野拜，幸貸別離憂。", "從渠夸毘子，見謂君何求。"]'),
('24fd0455-cfd8-4bca-a8ba-c9f2711d0a77','次韻臧秀才讀蘇集','陳造','宋','宋诗','song-poetry','','[]','自我得蘇集，玩閲幾忘年。',192,'全唐诗/poet.song.150000.json','["自我得蘇集，玩閲幾忘年。", "汲甘乏脩綆，適遠疲短牽。", "取一九不隨，望若終茫然。", "子齒始半我，用志超我先。", "晶熒出秀句，妙斲遺雕鎸。", "此翁深堂奧，駢闐誰敢專。", "潢汙置不云，學海須百川。", "怪子介且方，落筆盤走圓。", "子真蘇門徒，豈獨長短篇。", "平生修月手，不補衣履穿。", "秦黄晁張陳，衆星耿霜天。", "世儒昂其首，指似如登仙。", "子起斯人後，遊刃牛無全。", "邢娥望可知，衆女空丹鉛。", "何時班荆地，解我心懸懸。", "即今清夜夢，不止懷昔賢。"]'),
('7245bb49-4309-4cb8-9d10-7d6500fc1aff','送臧子與子儀之楚州告免解二首  其一','陳造','宋','宋诗','song-poetry','','[]','二臧如靜女，不受朱粉加。',96,'全唐诗/poet.song.150000.json','["二臧如靜女，不受朱粉加。", "尹姬望邢娥，宜著帝者家。", "向來揚蛾眉，衆喙怒以呀。", "指玉謝堅潔，擘肌起疵瑕。", "去汝忽若蛻，人與室俱遐。", "玉臺鏡如月，滿意事鉛華。", "九重訪娟麗，萬目看嫮姱。", "當使聽聽者，昂首七香車。"]'),
('666b18ff-c8e4-4c4b-a4a8-55000d7ec4df','送臧子與子儀之楚州告免解二首  其二','陳造','宋','宋诗','song-poetry','','[]','昭代論豪傑，崔侯允武文。',96,'全唐诗/poet.song.150000.json','["昭代論豪傑，崔侯允武文。", "小却折遐衝，厚用當致君。", "敷政極中和，殖學根典墳。", "士有砆玉岐，公自涇渭分。", "何人非教育，二臧實不羣。", "兩兩計偕去，名猶壅上聞。", "試袖于蒍歌，往拜劉將軍。", "心醉公瑾前，何待麴糵醺。"]'),
('82fa9b62-f7f8-4728-abcf-a8d9d062cbdc','寄陳用晦四首  其一','陳造','宋','宋诗','song-poetry','','[]','昭代儒者尊，青雲坦脩塗。',48,'全唐诗/poet.song.150000.json','["昭代儒者尊，青雲坦脩塗。", "即今子陳子，尚歌于蒍于。", "滿歲不自保，爾俗苦好誣。", "向來撫字工，督課有不如。"]'),
('abce5e9a-bcea-4778-955a-84be65eb92b4','寄陳用晦四首  其二','陳造','宋','宋诗','song-poetry','','[]','百謫孟公達，三絀柳下直。',48,'全唐诗/poet.song.150000.json','["百謫孟公達，三絀柳下直。", "今君向于湖，頗带遷逐色。", "府公酷好賢，要試心鐵石。", "此學祇現前，嗟傷定何益。"]'),
('7e1fa055-1126-4bf4-b4d4-a299d364ca03','寄陳用晦四首  其三','陳造','宋','宋诗','song-poetry','','[]','詩翁磊塊胸，大邑佳麗地。',48,'全唐诗/poet.song.150000.json','["詩翁磊塊胸，大邑佳麗地。", "瓊也領蝤蠐，懿也目秋水。", "清歌釂碧筩，粗足令公喜。", "醉呼翩欲仙，誰要卿料理。"]'),
('db2db162-92a6-4927-a0c6-a143fe79b7a8','寄陳用晦四首  其四','陳造','宋','宋诗','song-poetry','','[]','我初識蘇仙，談詩達旦夕。',48,'全唐诗/poet.song.150000.json','["我初識蘇仙，談詩達旦夕。", "君今與提衡，當復詫此客。", "一代紫微公，文采耀楚澤。", "歸來要同登，斲句慰英魄。"]'),
('5e6a3840-1b55-4c47-8136-0a0bd94064a7','次俞簿韻','陳造','宋','宋诗','song-poetry','','[]','昔賢識紫芝，不恨生叔季。',156,'全唐诗/poet.song.150000.json','["昔賢識紫芝，不恨生叔季。", "同寮得若人，襟宇極沖粹。", "相過鄙吝忘，滿抱昔賢意。", "傍睨褦襶兒，真堪裂人眥。", "棋枰消暇日，竹軒蔭疎翠。", "不作沮洳臨，纖鈎笑侯喜。", "愛此小泓渟，歷亂青鈿委。", "大篇副么荷，乞一仍得二。", "政須傳生徒，未暇藏篋笥。", "辭源深莫窮，歸牛定浮鼻。", "紫芝不詩鳴，較君同而異。", "游藝復友賢，老懷隨所寄。", "莫嗤學奕秋，更想鴻鵠至。"]'),
('482250ff-5136-4ab8-9dc7-d95df0562f74','檢旱望磕山','陳造','宋','宋诗','song-poetry','','[]','長塗并江沙，我行頗寂寥。',144,'全唐诗/poet.song.150000.json','["長塗并江沙，我行頗寂寥。", "登高望西南，羣山如湧潮。", "崩騰勢相排，又如羣馬驕。", "磕山乃孤峙，坐受羣山朝。", "雲斜復煙橫，助爾干碧霄。", "虛氣信所聚，神物不汝遥。", "有龍窟其趾，貝珠麗宮醮。", "豐凶執其柄，禱襘走黎苗。", "胡爲今茲旱，不能澤枯焦。", "史巫歲紛若，無乃徒囂囂。", "奔馳吾得辭，未救民腹枵。", "問龍當厚顔，深池卧逍遥。"]'),
('0d2fc82c-7273-44c5-b4e0-fdaa2cd8d4bf','三山磯','陳造','宋','宋诗','song-poetry','','[]','江頭數羣山，駢蹤各崢嶸。',96,'全唐诗/poet.song.150000.json','["江頭數羣山，駢蹤各崢嶸。", "茲山挺秀出，乃以三山名。", "三山戟拔立，離合煙雲橫。", "巨麓截水出，石轉爲微行。", "倒影射江北，陰森如未晴。", "盤渦觸岸去，勢若蛟龍爭。", "狹岸束洪流，突怒起不平。", "舟楫復往來，立者膽爲驚。"]'),
('f6fb106c-f56e-4197-bbfc-f5581ef36207','謝宋宰惠玉友麴方','陳造','宋','宋诗','song-poetry','','[]','夫子如周郎，即之疑飲醇。',192,'全唐诗/poet.song.150000.json','["夫子如周郎，即之疑飲醇。", "相從不踰歲，遽欲瀟湘秦。", "此生憂患餘，佽助嗟無幾。", "安得如公者，莫逆與終始。", "麴生到我室，奠贄心已傾。", "醖藉非俗輩，面作玉雪明。", "挹彼醇厚資，春意生戶牖。", "非公介其間，未易交此友。", "此友仙者流，勿藥氣自和。", "著我無何鄉，顧能蠲積痾。", "月團信佳人，業工敗人意。", "使我百慮攻，愁城不餘地。", "雖無叔夜書，泛交方自訟。", "平生一鮑子，世莫知管仲。", "悠然甘不懷，交道自久長。", "因渠念公他，端人更難忘。"]'),
('6c63e982-6a0d-4337-8b35-24f126214bd9','病起閑步','陳造','宋','宋诗','song-poetry','','[]','青女橫侵鬢，詎堪連日飲。',120,'全唐诗/poet.song.150000.json','["青女橫侵鬢，詎堪連日飲。", "黄媼不克家，倏伏半月枕。", "陰陽有酣戰，藥劑闕上品。", "衛生忘周防，內愧每流瀋。", "今朝步崇岡，晴日貸餘凜。", "江波縠動鏡，嶺雪印塗廩。", "竹間小梅花，幽香到襟衽。", "去春無幾日，鳥哢如見諗。", "酒瓢隨短轅，舊盟聊復寢。", "詩句酬物華，是口不容噤。"]'),
('e94c8af6-8264-44c7-a908-97698a4b8a51','示師文','陳造','宋','宋诗','song-poetry','','[]','樸樕已非材，骯髒遽成翁。',144,'全唐诗/poet.song.150000.json','["樸樕已非材，骯髒遽成翁。", "生無適時具，何向不涂窮。", "頼結文字緣，人士飽過從。", "三年尉山邑，趣操有同風。", "博古得二臧，秀發仍兩鍾。", "蔣侯厚本學，落筆語更工。", "我卜當塗居，薪米耐闕供。", "從渠得琢磨，遺汝不己豐。", "士生在知道，寡陋難言功。", "會理貴博觀，受物由虛中。", "潢汙不揚漪，大江日傾東。", "遲汝草靈光，一觴壽乃公。"]'),
('905a6fdf-e018-43a0-810a-321cba984f6c','辛丑春雪甚意有感','陳造','宋','宋诗','song-poetry','','[]','歲序各司存，雪神庀厥終。',288,'全唐诗/poet.song.150000.json','["歲序各司存，雪神庀厥終。", "度臘不成白，接春吹旱風。", "井脈青煙起，地毛黄埃蒙。", "東君借一怒，六合玄雲同。", "玉龍專獨夜，紵带縞長空。", "破曉欻三尺，山川積蘇中。", "宿麥頼一溉，園林潛動容。", "繄此玄冥事，春皇豈佻功。", "瘝官可辭責，代庖容非恭。", "風霜與暘雨，不時皆沴雺。", "即今雪擅春，何異雷鳴冬。", "方蘄焦槁息，未暇尤化工。", "緬懷虞周下，賢哲多不逢。", "權柄在掌握，秦越眎困窮。", "變故方沸渭，頃刻分吉凶。", "君子諉不謀，或非世用充。", "當知寸有長，琤琤即疇庸。", "鮒也肸土苴，顧能魯使東。", "鳶肩既歐刀，五孺各疏封。", "融約漫百數，不當劉係宗。", "稊稗實枵腹，常以歲不豐。", "奇疾待烏喙，參朮渠能攻。", "高位有不稱，坐令蛇爲龍。", "快意雖目前，道揆終厖茸。"]'),
('9089f733-d955-4854-b425-bdd613c3b9f9','答毛叔子','陳造','宋','宋诗','song-poetry','','[]','章甫不價越，澼洸或彊吳。',96,'全唐诗/poet.song.150000.json','["章甫不價越，澼洸或彊吳。", "事以適時重，投暗恐類愚。", "毛子抱高學，眇睨大小儒。", "過閲幾公卿，携文及吾廬。", "我窮劣識字，三讀起長吁。", "妙處未遽了，君意無乃孤。", "勸子俛從俗，青紫摘頷須。", "他時不朽託，一一世楷模。"]'),
('a02b71f8-9d4b-47e2-9c74-95dabd93393e','有嘆  其一','陳造','宋','宋诗','song-poetry','','[]','應事如應敵，收功端有素。',144,'全唐诗/poet.song.150000.json','["應事如應敵，收功端有素。", "詩乃隨景遷，預計幾膠柱。", "鼓吹月明秋，當時亦佳句。", "見卵求時夜，竟爲陰雲妬。", "想像蘄爲工，故智那用據。", "向來東遊意，夢境騷人賦。", "出郭带月行，過山衝雪去。", "風力馬欲却，寒氣鳥不度。", "舊擬忽新偶，自笑邯鄲步。", "與世甘數奇，失意資一悟。", "覆却從萬方，翛然隨所遇。", "吟情形前影，塵事風外絮。"]'),
('74f266c2-fccf-4f64-9e7f-49b7651a3eee','有嘆  其二','陳造','宋','宋诗','song-poetry','','[]','郊原二月天，節物屬丹素。',144,'全唐诗/poet.song.150000.json','["郊原二月天，節物屬丹素。", "山風欻雪花，野屋欲冰柱。", "破除酒邊興，截斷口前句。", "誰將萬玉妃，一一事嬌妬。", "東皇不無情，退縮自失據。", "史君文章家，客子舊能賦。", "茲游豈偶然，擬作袖手去。", "江梅孤舊約，桃花悵前度。", "漂忽幾何時，林影映沙步。", "層雲放曒日，瑩澈等僧悟。", "一笑百慮餘，如世有晚遇。", "預知詩及門，新語謝鹽絮。"]'),
('609be12c-86cc-4cf6-915e-af1ad3a712ee','王漕小燕玻璃分韻得路字','陳造','宋','宋诗','song-poetry','','[]','去年客京華，酷暑不可度。',168,'全唐诗/poet.song.150000.json','["去年客京華，酷暑不可度。", "時爲冷泉登，稅駕脫巾屨。", "風外雜佩鳴，松根一竇注。", "可聞不可挹，已足盪袢暑。", "朅來黄埃中，夢遶湖西路。", "寧知虎頭側，碧溜依紺宇。", "琤淙響琴筑，噴噀起霏霧。", "餘潤碧苔滋，照影紅葵嫮。", "凉氣濯毛骨，寒聲到樽俎。", "况陪持斧翁，觴詠澣塵慮。", "坐著錦囊生，歌煩桃葉女。", "向來湖西亭，聽泉渠須數。", "逼人灑清寒，如翁玉雪句。", "更喚泉間龍，爲霖下山去。"]'),
('f3f1659b-2831-4478-a137-37b4e1378798','送李監嶽二首  其一','陳造','宋','宋诗','song-poetry','','[]','李侯西州英，早著武士冠。',96,'全唐诗/poet.song.150000.json','["李侯西州英，早著武士冠。", "朅來淮上郡，鷄羣見翠鸞。", "清詩萬卷餘，脫手走銅丸。", "初聽耳目醒，再讀毛骨寒。", "解榻一甌茗，敢作粗官看。", "今者連日語，衮衮爲發難。", "中年可堪別，別君倍悲酸。", "書來有新句，政用驅愁端。"]'),
('c13248a6-130a-4f62-a2f3-03daeb0ed2ca','送李監嶽二首  其二','陳造','宋','宋诗','song-poetry','','[]','寥寥黄陳後，詩律日就卑。',96,'全唐诗/poet.song.150000.json','["寥寥黄陳後，詩律日就卑。", "京江一燈續，天乃不憗遺。", "念君從之遊，十年塤應箎。", "盡渠磋磨巧，况君粹美資。", "奪標快一得，不計弟子師。", "向來誦新作，格力欲并馳。", "扃戶玩明月，寒餓用一岐。", "及今辦一飽，無取空名垂。"]'),
('11ed7eee-228f-4a0c-9214-b4b131b203d4','次韻王漕燕玻璃','陳造','宋','宋诗','song-poetry','','[]','輕颸度翠密，碧溜下崚嶒。',48,'全唐诗/poet.song.150000.json','["輕颸度翠密，碧溜下崚嶒。", "飲處凌埃𡏖，談間忘鬰蒸。", "何物辟塵犀，墮我玉井冰。", "落手錦繡段，酬贈慙未能。"]'),
('dae85b15-b081-4599-9e76-9f6ff397ebcb','題五柳先生詩編年後二首  其一','陳造','宋','宋诗','song-poetry','','[]','淵明英傑氣，不減運甓翁。',96,'全唐诗/poet.song.150000.json','["淵明英傑氣，不減運甓翁。", "漫仕徑拂衣，高枕北窗風。", "平生經世意，蕭然詩卷中。", "卯金納大麓，正自竊鈇雄。", "妖雛自取死，遽敢貪天功。", "斯文未斲喪，吾道聊污隆。", "把菊得沉醉，直氣歛長虹。", "區區記隠德，史筆殊未公。"]'),
('9777b498-bec0-4773-abfb-d9b8a3a6960c','題五柳先生詩編年後二首  其二','陳造','宋','宋诗','song-poetry','','[]','邸報議麟經，卜書目羲易。',96,'全唐诗/poet.song.150000.json','["邸報議麟經，卜書目羲易。", "曲學暫雺曀，日月豈終蝕。", "陶翁詩百篇，優造雅頌域。", "九原不容作，妙意渠能測。", "今君語析塵，指示了皂白。", "定知泚筆人，斜川舊仙伯。", "毫釐無餘藴，領覽飽新得。", "言下悟未師，吟邊識圓澤。"]'),
('7de32796-0197-48bb-912d-cadae2385a62','次章房陵韻四首  其一','陳造','宋','宋诗','song-poetry','','[]','老驥挺高骨，彌耳塵中馳。',48,'全唐诗/poet.song.150000.json','["老驥挺高骨，彌耳塵中馳。", "鄰女嫁不售，泣向流黄機。", "與子落窮山，坐無適時姿。", "濠梁莞一笑，遊鱗噞風漪。"]'),
('952aaca6-d384-4163-8934-12b6101f6532','次章房陵韻四首  其二','陳造','宋','宋诗','song-poetry','','[]','詩法究源委，今古有正傳。',48,'全唐诗/poet.song.150000.json','["詩法究源委，今古有正傳。", "寥寥風騷後，誰定執此權。", "杜韓到黄陳，刃藏牛無全。", "愧我蟁負山，良夜卓兩肩。"]'),
('63414e73-b5b6-409a-847f-f66a15f4a316','次章房陵韻四首  其三','陳造','宋','宋诗','song-poetry','','[]','章子五車讀，詩外未一施。',48,'全唐诗/poet.song.150000.json','["章子五車讀，詩外未一施。", "清篇忽見屬，了不計吾誰。", "投暗率如此，世路宜暮遲。", "獨無牙曠手，並坐絃君詩。"]'),
('5c9a7d43-4068-4d24-a271-a4924df79470','次章房陵韻四首  其四','陳造','宋','宋诗','song-poetry','','[]','詩社有血指，鉛刀齒魚腸。',48,'全唐诗/poet.song.150000.json','["詩社有血指，鉛刀齒魚腸。", "橫江限一鎖，未易枝龍驤。", "山澤護我瑕，珠璧耀我箱。", "勝譚當不遺，茗果秋夜長。"]'),
('b6f0cf35-3e2f-4609-b8b9-89b6a22a5a14','再次韵  其一','陳造','宋','宋诗','song-poetry','','[]','咄咄嗟數奇，覤覤笑坐馳。',48,'全唐诗/poet.song.150000.json','["咄咄嗟數奇，覤覤笑坐馳。", "超然達觀士，顯晦用一機。", "夫君抱器業，軒豁見奇姿。", "付我舟一葉，緡絲漾清漪。"]'),
('cc330c76-c152-4fda-8d84-fe0372f6a583','再次韵  其二','陳造','宋','宋诗','song-poetry','','[]','覆觴課五升，秘訣不待傳。',48,'全唐诗/poet.song.150000.json','["覆觴課五升，秘訣不待傳。", "百里三萬家，優主師帥權。", "坐肉荒歲骨，豈但醫十全。", "高郎徑刺史，况論擔弛肩。"]'),
('e74ba3fa-8e81-4baf-b0df-8f221219c365','再次韵  其三','陳造','宋','宋诗','song-poetry','','[]','世人競捧心，妍醜西東施。',48,'全唐诗/poet.song.150000.json','["世人競捧心，妍醜西東施。", "揮斤得妙質，捨子吾從誰。", "所惜憂患餘，歸計不暇遲。", "繼今省幽獨，鴈足時新詩。"]'),
('3cfa1260-fedf-4a97-9735-3b72b0727981','再次韵  其四','陳造','宋','宋诗','song-poetry','','[]','平日四方念，見謂石作腸。',48,'全唐诗/poet.song.150000.json','["平日四方念，見謂石作腸。", "即今還家夢，絆驥首屢驤。", "不作垂橐嘆，藏書頗青箱。", "此燈可無傳，兒孫共翁長。"]'),
('f7cd6e06-5c23-468c-b936-e45cede55952','次韻梁教章宰喜雪  其一','陳造','宋','宋诗','song-poetry','','[]','袖手飛雪前，徒有風雅渴。',180,'全唐诗/poet.song.150000.json','["袖手飛雪前，徒有風雅渴。", "久親無言子，此興今莫遏。", "兩君壯藻思，詩柄專殺活。", "可須龍伯睡，驪珠乃平奪。", "長翁久荒廢，坐受兒女聒。", "愁城正合圍，醉鄉况禁謁。", "詩來起我敬，一嫡眇衆孽。", "此雪更此詩，清晤乃細閲。", "晶熒盤走圓，便旋玉爲屑。", "汛掃無惡氛，肯綮有妙割。", "解頤得匡鼎，和羹本商說。", "技癢吐復吞，正恐誚燕說。", "山城僧舍似，休務况佳節。", "可疎觸寒過，一笑卷蕉葉。", "作詩供捧腹，巴唱酬白雪。"]'),
('6c6e6624-f416-47f4-ad5f-8fec722a7e2d','次韻梁教章宰喜雪  其二','陳造','宋','宋诗','song-poetry','','[]','窮臘缺膏潤，何異客病渴。',180,'全唐诗/poet.song.150000.json','["窮臘缺膏潤，何異客病渴。", "龍伯供雪事，落勢不受遏。", "繽紛一再餘，旋報焦卷活。", "去年痛無年，回首氣尚奪。", "流亡何紛紛，哀訴良聒聒。", "爲民倒陳紅，擬效叫閽謁。", "繡衣肉骨手，大帚掃妖孽。", "貸金今可償，復許歲再閲。", "秦越作肥瘠，德人終不屑。", "協氣非挽回，何以救方割。", "想聞三白訊，把酒顔爲說。", "嗣歲屈指計，老農聚頭說。", "團欒飽餠飥，市鬻追時節。", "忍思狼狽初，草木茹根葉。", "苦樂倚伏間，此耻幸一雪。"]'),
('2fe0c7a5-47db-4f1a-8fa0-dcf0da566603','次韻梁教章宰喜雪  其三','陳造','宋','宋诗','song-poetry','','[]','平時豪飲興，人議老羌渴。',180,'全唐诗/poet.song.150000.json','["平時豪飲興，人議老羌渴。", "駿蹄就康莊，中有谿澗遏。", "俛仰三十年，僅作扶病活。", "樂事生無幾，造物忍見奪。", "謝安晚多感，正頼簫鼓聒。", "胡姬賣酒地，緬想不容謁。", "即今少年夢，尚苦法士孽。", "兩君詩酒豪，將壇最閥閲。", "左顧得投轄，勝譚看吐屑。", "雪天僕爲更，盤飯鮮粗割。", "共憐后山窮，塊處但禪說。", "一飽共此客，矜向鄰里說。", "問疾不厭頻，他費尚可節。", "官塗計離合，江海浮一葉。", "別期後歸燕，光陰等消雪。"]'),
('18abfdb9-6625-47fb-9f29-53d5fdd6a60b','遣興次前韻','陳造','宋','宋诗','song-poetry','','[]','斫水蘄斷流，捻鹽寧療渴。',180,'全唐诗/poet.song.150000.json','["斫水蘄斷流，捻鹽寧療渴。", "區區守荒學，籠鳥眩樊遏。", "向來麋鹿姿，祇可樵牧活。", "始其事誦數，魄似窮鬼奪。", "文字取憎疾，見謂蜩螗聒。", "回首輩行人，班劍或朝謁。", "方嗟沈带減，正坐河魚孽。", "分無青雲上，但有枯策閲。", "峩峩指頂地，羣口免騷屑。", "醪敷兒爲供，蜜脾手親割。", "敝帚非世用，槁梧取己說。", "非君莫逆者，此懷誰與說。", "反求每日誑，百行收一節。", "西來傾藁冊，又滿三百葉。", "暮年了無得，付子鏡中雪。"]'),
('30490722-0c0c-42d5-a881-e714441e3ec3','雪再次韻','陳造','宋','宋诗','song-poetry','','[]','卑官望雪心，有賦繼夢渴。',180,'全唐诗/poet.song.150000.json','["卑官望雪心，有賦繼夢渴。", "旱氣方兆朕，造物工式遏。", "山城窮陋地，民以牟麥活。", "即今稼事寶，趙璧還秦奪。", "忽訝天雲近，旋遭鳥烏聒。", "豐年得奇讖，賀詩簉佳謁。", "了知叶氣熏，人定銷天孽。", "老眼眩鹽絮，已不啻三閲。", "瓣香爲神報，無乃笑瑣屑。", "絕望羔酒醉，作意鷺股割。", "賞雪須佳客，生恐無此說。", "來年當更好，可但老農說。", "來春還家吟，要使君擊節。", "今朝泚筆否，浩蕩對雲葉。", "儻肯躡凌兢，黍椀更一雪。"]'),
('474290be-7281-4899-9fd9-a70cd93835b8','雪夜與師是棋次前韻','陳造','宋','宋诗','song-poetry','','[]','投醪士或醉，說梅人不渴。',180,'全唐诗/poet.song.150000.json','["投醪士或醉，說梅人不渴。", "窮途餘樂事，不受憂患遏。", "詩可供呻吟，棋亦識死活。", "朝來喜雪句，神藥胎可奪。", "一枰與兒晤，斷無市聲聒。", "既免沈舟諼，不作賭墅謁。", "指冷良易忍，眼花苦爲孽。", "疏置仍作罫，隨意略細閲。", "瓜葛勝負間，時亦近屑屑。", "策幾奇兵鏖，地比弱王割。", "吾非江左管，舐犢愈愛說。", "升沈作豐悴，今古無成說。", "家居鼓吹具，藉以保晚節。", "掀髯得一笑，爲汝倒蕉葉。", "袖手聽殘更，紅鱗曀晴雪。"]'),
('27c844d1-ebaa-489b-a0f6-62e42c6d1fa6','再次韻作招隠篇','陳造','宋','宋诗','song-poetry','','[]','我家五畝園，泉細地不渴。',180,'全唐诗/poet.song.150000.json','["我家五畝園，泉細地不渴。", "載酒噬肯遊，開門誰汝遏。", "典衣買花栽，種十八九活。", "繁華出荒穢，天巧容人奪。", "三徑紆曉步，兩部厭晴聒。", "長日岸幘嘯，看人曳裾謁。", "伸屈較倚伏，烜赫藏戾孽。", "蠻觸勝負間，吾老飽所閲。", "孰知花藥疇，細炷沈檀屑。", "此樂彼莫顧，渠愛我已割。", "微吟會心處，山鳥亦欣說。", "焉得喙三尺，佳處爲君說。", "秋蘭媚幽芳，野竹挺高節。", "當知陶一觴，可敵蕭八葉。", "駢來作螟蠃，獨立耿玉雪。"]'),
('4fac922d-a025-43cf-94d3-4f189db82a29','再次韻','陳造','宋','宋诗','song-poetry','','[]','人間十日雪，已潤夸父渴。',180,'全唐诗/poet.song.150000.json','["人間十日雪，已潤夸父渴。", "宿雲忽披靡，羲馭與抑遏。", "春從九地回，旋放牙甲活。", "主張披拂是，大塊司予奪。", "椒柏追時序，鼓吹聽曉聒。", "詩壇有同盟，辦作銜袖謁。", "得雪晴更佳，過是或爲孽。", "羣山半披剝，衆巧獻一閲。", "懸知兵吏集，不待鋪木屑。", "令尹活人手，小試牛刀割。", "廣文甘僻左，不肯事容說。", "與俗分樂事，盍以韻語說。", "獨慙長鬚送，不量好時節。", "要須百篇富，趁此梅未葉。", "正使領兕觥，快作湯沃雪。"]'),
('62082d32-18e2-4f7f-945e-cdff5e272065','再次韻','陳造','宋','宋诗','song-poetry','','[]','傳聞使者心，急士幾忍渴。',180,'全唐诗/poet.song.150000.json','["傳聞使者心，急士幾忍渴。", "廣文馬已秣，勢似不宜遏。", "長翁仕窮山，離索幾苟活。", "藉君忘幽獨，長恐有力奪。", "勸其少徐之，無謂險膚聒。", "吾儕冷如冰，雖坐慵造謁。", "渠儂夏畦譏，火馳自生孽。", "山城燈火夜，而况已再閲。", "佳人參辟辰，俗子眼中屑。", "一笑待休沐，官事罷剸割。", "期喪近絲竹，憂患偷愉說。", "古人惜中年，吾請用此說。", "爲君枝病軀，偕我酬令節。", "捐金裝玉梅，艤楫命桃葉。", "舊曲迄未試，把盃看翻雪。"]'),
('01f3c765-06d0-4312-a8d0-54c4b0420c4b','贈章宰','陳造','宋','宋诗','song-poetry','','[]','湯池潴巉巖，房祠踞穹隆。',240,'全唐诗/poet.song.150000.json','["湯池潴巉巖，房祠踞穹隆。", "向來偕君西，寒雨斜驚風。", "虛簷吞山川，悗若困樊籠。", "往來三十里，兀兀婦車中。", "頸方學縮鼈，眼不到飛鴻。", "迄今簿領前，老面潮羞紅。", "昨夕縣麻勢，子亦胡能東。", "如子亨衢人，不應分我窮。", "山靈兩介士，不屑陵原通。", "我輩吏塵涴，棖觸肯見容。", "高興未渠盡，佳節寧易逢。", "調琴家治具，竹堂小窗櫳。", "酬酢十客優，庖隸良易供。", "登山與聽雨，取醉政自同。", "玉友陪從事，共達吾深衷。", "逮今彊健時，數近玻璃鍾。", "丹杏正媚嫵，柳枝頗昌丰。", "古今共陳迹，春事尚匆匆。", "此歡不可失，此言儻見從。", "對花但忍渴，請看衰病翁。"]'),
('bd46be45-0a96-4c59-895f-ba910cb883bb','再次韻','陳造','宋','宋诗','song-poetry','','[]','谷巖蟄石燕，帝闕鎖豐隆。',240,'全唐诗/poet.song.150000.json','["谷巖蟄石燕，帝闕鎖豐隆。", "入懷疑有無，愜此靡微風。", "晴空寄望眼，已快鶴出籠。", "向來陰雨餘，缺然賢聖中。", "庭竹忽乾鵲，雲衢亦輕鴻。", "新詩照老眼，姱嫮欺羣紅。", "飛僊款幽寂，珩璜韻丁東。", "稠疊挹勝槩，孰謂吾天窮。", "花神憐客心，密密靈犀通。", "冗官况暇豫，令節聊從容。", "少徐泛觴醉，或有解佩逢。", "傾城試新粧，戶戶虛簾櫳。", "未用椽筆飛，坐詫十吏供。", "樂事易陳迹，此歎今古同。", "當時序蘭亭，一一言由衷。", "嘉會青帝惜，芳情吾輩鍾。", "繁香與麗人，相映媚以丰。", "瀝酒勸羲馭，西去忍匆匆。", "遲暮冀如願，百違今一從。", "瀾翻笑譚口，幾成呫嚅翁。"]'),
('c8d6c75b-f782-4c98-a172-d9335d1a864b','呈交代','陳造','宋','宋诗','song-poetry','','[]','雨行不轉首，豈即真良圖。',120,'全唐诗/poet.song.150000.json','["雨行不轉首，豈即真良圖。", "二年望鄉國，得歸不暇徐。", "徒隸悉此意，頗作竭蹷趨。", "衝泥傍險地，亦復歌載塗。", "使君卓旌旆，小燕留僧居。", "一盃酹龍公，庶或輔相予。", "捧觴未一再，霽色明桑榆。", "安寢俟清曉，辦裝無滯濡。", "有禱必其應，顯幽無乃拘。", "夸詡諱天幸，此理良自誣。"]'),
('ec276ae4-d556-46ce-a3c8-71b7816d3725','至喜鋪','陳造','宋','宋诗','song-poetry','','[]','外朝走馬息，險絕欲無路。',156,'全唐诗/poet.song.150000.json','["外朝走馬息，險絕欲無路。", "駔駿蹙萬蹄，勢若敵場赴。", "崩騰臨空曠，踠足此小駐。", "蕭然一驛傍，爲此數家聚。", "川城南山下，邑屋隨指顧。", "行人不勝喜，息駕始此處。", "跫然愀然意，南北分來去。", "我解房州印，初試歷險步。", "胡爲亦自得，不作罷爾慮。", "鄉心建瓴水，歸夢受風絮。", "殘年歸來引，他日遂初賦。", "是役固已勞，端復酬夙素。", "臨風搔白首，一笑飭徒御。"]'),
('319b3f87-03a6-4c28-bd42-8c82cdcbda03','報恩方丈小憩二首  其一','陳造','宋','宋诗','song-poetry','','[]','還家自欣然，小耐孥輩累。',48,'全唐诗/poet.song.150000.json','["還家自欣然，小耐孥輩累。", "老禪遽辟席，倦客容即次。", "仍將寒碧供，爲澣羈寓意。", "斷續饑龍吟，煜燿金鎖碎。"]'),
('bfc82cd2-c9c5-4233-bd0f-dafdb75ddff5','報恩方丈小憩二首  其二','陳造','宋','宋诗','song-poetry','','[]','石鼎無幾然，團蒲有餘藉。',48,'全唐诗/poet.song.150000.json','["石鼎無幾然，團蒲有餘藉。", "山嵐變寒凉，更挾清露下。", "月榦澹疎櫺，風枝語良夜。", "爲君賦招隠，自剔篝燈灺。"]'),
('0ec0535b-741b-4c52-8dfd-7c922a49d4d4','十詩謝廖計使  其一','陳造','宋','宋诗','song-poetry','','[]','二年仕窮山，書外睡作魔。',48,'全唐诗/poet.song.150000.json','["二年仕窮山，書外睡作魔。", "吹律黍爲茁，頼公有孰何。", "懸知登門初，大宅浮陽和。", "泛愛公自爾，小子何足多。"]'),
('2d30947f-c42b-4336-a5d6-b0bb976f6580','十詩謝廖計使  其二','陳造','宋','宋诗','song-poetry','','[]','平生書成癡，初不冀料理。',48,'全唐诗/poet.song.150000.json','["平生書成癡，初不冀料理。", "頹齡迫肺病，課此未云已。", "屠龍詫流俗，祿𨔤欲何以。", "閉目耐昏花，三嘆仍啟齒。"]'),
('aae1b9ae-2d13-409d-81d7-de8a1fd070de','十詩謝廖計使  其三','陳造','宋','宋诗','song-poetry','','[]','繡衣蓋代公，學力闖天造。',48,'全唐诗/poet.song.150000.json','["繡衣蓋代公，學力闖天造。", "千篇發幽秘，萬物困陵驁。", "攟收盡隨和，吾富無乃暴。", "小試推敲手，聊效桃李報。"]'),
('8360f219-dc5c-4ca9-9822-2f25453318e0','十詩謝廖計使  其四','陳造','宋','宋诗','song-poetry','','[]','偓佺地上仙，笙鶴不我遐。',48,'全唐诗/poet.song.150000.json','["偓佺地上仙，笙鶴不我遐。", "楚騷欲命僕，古詩無名家。", "晉當澤帝範，小却侈國華。", "本末計中外，倚須拜亨嘉。"]'),
('cf0771a3-ef47-44e4-b791-415cdda97f5b','十詩謝廖計使  其五','陳造','宋','宋诗','song-poetry','','[]','我生守荒學，意造無根蔕。',48,'全唐诗/poet.song.150000.json','["我生守荒學，意造無根蔕。", "時時寫所藴，致遠終恐泥。", "小勞斲鼻巧，霜風掃氛翳。", "一言可終身，萬金寧良惠。"]'),
('9c7cc037-b09c-4686-9cca-4f544058c6fd','十詩謝廖計使  其六','陳造','宋','宋诗','song-poetry','','[]','深井無淺汲，洪鍾須妙撞。',48,'全唐诗/poet.song.150000.json','["深井無淺汲，洪鍾須妙撞。", "揆公取士心，海若吞湖江。", "泓涵老昌黎，客或隴頭瀧。", "可待函丈扣，此心久已降。"]'),
('1ae7211c-0836-4d64-8a39-9497290ef4b0','十詩謝廖計使  其七','陳造','宋','宋诗','song-poetry','','[]','古今國士遇，揆我不盡無。',48,'全唐诗/poet.song.150000.json','["古今國士遇，揆我不盡無。", "頑鍾未容器，巧匠徒爲模。", "即今鶚書上，逮此鶴髮餘。", "但恐良夜夢，翩翾只江湖。"]'),
('7d3e13d6-d61b-4199-ac4a-2b92246657e9','十詩謝廖計使  其八','陳造','宋','宋诗','song-poetry','','[]','陸子木已拱，遺文空雋永。',48,'全唐诗/poet.song.150000.json','["陸子木已拱，遺文空雋永。", "鄭子爲米仕，縣廨縻簿領。", "聽公譚舊社，文陳鵝鸛整。", "離索我若斯，胡術謝榛梗。"]'),
('77d39b38-849e-4403-8d43-22e10c9fd9ba','十詩謝廖計使  其九','陳造','宋','宋诗','song-poetry','','[]','欲留苦滯淫，欲去復彷徨。',48,'全唐诗/poet.song.150000.json','["欲留苦滯淫，欲去復彷徨。", "卧漳仍登龍，兩心正交相。", "粲粲金玉人，納納錦繡腸。", "安得雲隨龍，意行即公傍。"]'),
('e33ad2b8-72d2-4e1b-bc95-26ef2df3e555','十詩謝廖計使  其一○','陳造','宋','宋诗','song-poetry','','[]','貧女信難昏，俗子每易忘。',48,'全唐诗/poet.song.150000.json','["貧女信難昏，俗子每易忘。", "文學公世師，一見遽倒囊。", "願公出調燮，容我濯滄浪。", "台躔五雲處，浩歌長相望。"]'),
('577d2c03-6d6f-4c9a-aa88-4cf752ef0664','涑口守風','陳造','宋','宋诗','song-poetry','','[]','辦舟留襄陽，辟風泊涑口。',144,'全唐诗/poet.song.150000.json','["辦舟留襄陽，辟風泊涑口。", "得行秋甲辰，初到夏癸酉。", "跛鼈已自慣，束髮至衰朽。", "坐是冥得喪，况復多病後。", "絕憐操舟兒，不惜脫穎手。", "顧瞻峴山亭，覿面可搴取。", "微風吹薄暮，霽景挂高柳。", "凉月欲略箕，陰氛尚侵斗。", "明朝起柂計，未敢決可否。", "身已不藉在，心自無何有。", "一事萌一意，但見掣君肘。", "擁書坐蓬窗，醉我不以酒。"]'),
('21f3be17-f4ed-4343-ac37-8e78a5b31b19','買薤','陳造','宋','宋诗','song-poetry','','[]','平日屠門嚼，因病不敢縱。',120,'全唐诗/poet.song.150000.json','["平日屠門嚼，因病不敢縱。", "園翁富薤畦，尚可羞此供。", "長白連嫩葉，雅稱鹽醯共。", "暖鬲號多益，斷下仍百中。", "醫經備收錄，詩老屢吟諷。", "韭齏葵作葅，未覺取世重。", "鷄壅謝稱帝，杞菊第賓從。", "佐我炊玉飽，食指免輕動。", "歸計三徑成，少辦百本種。", "指日筋骨强，報汝當抱甕。"]'),
('7a1decdd-d3ee-4be3-98e3-2793bbdfbbac','渡揚子','陳造','宋','宋诗','song-poetry','','[]','濤江吞天去，委此舟一葉。',96,'全唐诗/poet.song.150000.json','["濤江吞天去，委此舟一葉。", "前之恃勇往，微命幾顛跲。", "弱纜維復解，宿浪俄妥帖。", "北風不滿帆，晴空欲凌躡。", "淮人鄉情重，相爲細扶楫。", "浮玉瞥眼過，笑譚得利涉。", "窮塗有快意，十北收一捷。", "龍公不常喜，未用輕吾怯。"]'),
('8736b31d-fe3a-451d-85cc-711cbe015dfb','赤口灘','陳造','宋','宋诗','song-poetry','','[]','漢江多惡灘，赤口乃其最。',144,'全唐诗/poet.song.150000.json','["漢江多惡灘，赤口乃其最。", "前年將家上，正值江流殺。", "奔衖震溝𤱶，狼石森戟鐓。", "贔屭取進寸，一跌尋丈退。", "聞此尚痛定，躬履况兒輩。", "今者劈箭去，未覺有湍匯。", "一雨動三日，遠岸卷澎湃。", "向者險巇地，了不經眼界。", "三老笑相語，無復憂滯礙。", "路可屈指計，歸將平心待。", "窮塗偶快意，此惠莫謀大。", "龍公本何心，賤子多感慨。"]'),
('a1338dd6-8bae-4dc1-b786-41ab4f6413be','鴈汊東守風四首  其一','陳造','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','枉渚八日留，池口百里近。',96,'全唐诗/poet.song.150000.json','["枉渚八日留，池口百里近。", "東風翻白波，寸步不容進。", "如許天吳怒，頗訝地軸震。", "崩騰雪山飛，膽掉老眼暈。", "豈惟佐豪吟，更覺蘇宿疢。", "還家可指日，去意復小靳。", "遺體泰山重，瞢敢諉忠信。", "流坎隨所遇，遲速吾不問。"]'),
('eb6ab334-8004-444e-900b-e6a42b7750e3','鴈汊東守風四首  其二','陳造','宋','宋诗','song-poetry','','[]','蓬窗隔世塵，但有書滿床。',96,'全唐诗/poet.song.150000.json','["蓬窗隔世塵，但有書滿床。", "度日無與虞，日課一指彊。", "坐免鶩鴈聒，自詫肝肺香。", "奔驥踠足意，翛然吾自忘。", "賢否岐非是，狥己乃所望。", "溫故饜新得，但覺此味長。", "晚來砲車雲，翻空更漂揚。", "吾書未渠盡，更借燈燭光。"]'),
('975823af-be04-4ed5-be4e-5638fc969306','鴈汊東守風四首  其三','陳造','宋','宋诗','song-poetry','','[]','驚麋碭洪浸，何人矢麗龜。',96,'全唐诗/poet.song.150000.json','["驚麋碭洪浸，何人矢麗龜。", "遂令老病叟，珍毳及晚炊。", "野鹿敢伯仲，江鱘讓甘肥。", "淮人篤鄉義，賤乞等韭葵。", "向來無人境，沙漫水無涯。", "市聲不到耳，茭葦相因依。", "今無暴客虞，解衣候朝曦。", "厚味真過矣，安食如含飴。"]'),
('f819c6c5-11b8-4c22-995d-702bbe9bef28','鴈汊東守風四首  其四','陳造','宋','宋诗','song-poetry','','[]','東趣長風沙，移柂取空隙。',96,'全唐诗/poet.song.150000.json','["東趣長風沙，移柂取空隙。", "波頭蟄飛雪，幸矣不數刻。", "連延百家聚，俯瞰白沙磧。", "賣餠售蝦菜，傍舷忽絡繹。", "矧聞淮南音，眼中便鄉國。", "田翁顔甚溫，村酒釅堪喫。", "突兀戎官廨，戶柱相映赤。", "頗喜霜夜眠，更鼓聽歷歷。"]'),
('b7b3cd5b-7c8d-46a6-bd3c-c37c83a6b5f3','題解禹玉文卷後','陳造','宋','宋诗','song-poetry','','[]','平生解公子，器質美無度。',168,'全唐诗/poet.song.150000.json','["平生解公子，器質美無度。", "長加進學鞭，猶後趣時步。", "充腸笠澤書，脫手彈丸句。", "儕輩無爭衡，儒先有延譽。", "豈應如老夫，嘖嘖聲不遇。", "表表蠹齋翁，容易九原去。", "石交不在眼，頼子慰遲暮。", "新文爛錦繡，夫我何足赴。", "凜凜傳遠計，堂堂濟世具。", "葆愛今其時，自視要嬰孺。", "白璧不受塵，素絲易成汙。", "毋爲樗木散，寧作鐵硯鑄。", "良晨有逢年，逸足看取路。", "吾言信惡石，敢謂愛莫助。"]'),
('b7b984cf-48f1-4d18-9ae7-47a68e89c369','贈廣教主人  其一','陳造','宋','宋诗','song-poetry','','[]','七年走薄宦，重放湖上步。',120,'全唐诗/poet.song.150000.json','["七年走薄宦，重放湖上步。", "偕客憩鷲峰，訪僧得龍樹。", "瘦骨書作祟，餘年藥爲助。", "君技信精微，我疾判疑誤。", "多謝辦再往，一飽許復具。", "意偶俗物敗，行非山靈沮。", "定貽高人笑，竟墮塵事汙。", "似聞今參寥，近在西林住。", "擬掇茗果供，飽玩玉雪句。", "勝踐後五日，盟兼諗鷗鷺。"]'),
('2e1f8389-6505-47c2-bfcb-e8a070a965e0','贈廣教主人  其二','陳造','宋','宋诗','song-poetry','','[]','風雨破十九，可得閑餘步。',120,'全唐诗/poet.song.150000.json','["風雨破十九，可得閑餘步。", "畫舫連千百，排拶隄側樹。", "湖山墮空濛，於客信非助。", "前朝冒雨還，正爲初日誤。", "今者乘興往，不暇家治具。", "賞心有新愜，行計無舊沮。", "香塵紛羅綺，隠服耐此汙。", "鶑花殊未厭，烏兔渠小住。", "愛日擬秉燭，把酒先得句。", "上馬一回首，前灘下白鷺。"]'),
('38890e8e-1b6f-4d79-8778-e1f14f5f3d99','清明西湖再次韻','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','蘇公舊隄東，增築更千步。',120,'全唐诗/poet.song.150000.json','["蘇公舊隄東，增築更千步。", "右爲縈回溪，夾以葱青樹。", "晴湖映碧山，詩客獨多助。", "醉鄉赴新約，書癡悔前誤。", "况此好清明，酒果隨意具。", "向來計追歡，幾爲陰雨沮。", "今者成清遊，仍免俗子汙。", "斜陽不無情，似戀花柳住。", "春光念報答，襞牋須好句。", "此筆付此人，遊客半鴛鷺。"]'),
('b5d69350-cefe-4fdd-8570-54fddcee296f','旅館三適  其一','陳造','宋','宋诗','song-poetry','','[]','厥初木禾種，移殖雲水鄉。',96,'全唐诗/poet.song.150000.json','["厥初木禾種，移殖雲水鄉。", "粉之且縷之，一縷百尺彊。", "勻細繭吐緒，潔潤鵝截肪。", "吳儂方法殊，楚産可倚牆。", "嗟此玉食品，納我蔬蔌腸。", "匕筯動輒空，滑膩仍甘芳。", "豈惟僕飺餌，政復奴桄榔。", "即今弗洎感，頗思奉君王。"]'),
('5ce03931-542d-4c63-8535-2312b0ca2f8a','旅館三適  其二','陳造','宋','宋诗','song-poetry','','[]','雋永項上臠，紅嫩劣带膋。',96,'全唐诗/poet.song.150000.json','["雋永項上臠，紅嫩劣带膋。", "彼美大欄君，坐受羣毛朝。", "鼎湆走真味，正藉松炬燒。", "芼我銀絲窩，葱豉巧和調。", "堇塗非所宜，淑郁如蘭椒。", "腹腴但下隸，羶根合藤條。", "併填長翁腹，未覺喉牙摇。", "但訝大嚼餘，無補詩腸枵。"]'),
('1996407d-00ef-4657-bc45-095de5bddc8a','旅館三適  其三','陳造','宋','宋诗','song-poetry','','[]','佳齊肯見分，春意偕客至。',120,'全唐诗/poet.song.150000.json','["佳齊肯見分，春意偕客至。", "誰將清白名，言代碧香謚。", "起瀹饒磁甌，玩吮色香味。", "醍醐馥牙頰，沆瀣沃肺胃。", "桑落古宜城，不足偕品第。", "我病久不飲，此日欲小醉。", "快哉羈寓中，乃遣拜嘉惠。", "一盃先晨飯，欻作凌雲意。", "米飯薦燒豬，佳此三者備。", "飽足仍酣醺，眇睨人間世。"]'),
('a63ac2bd-c773-4539-85e6-1c1b48f8d10c','官務','陳造','宋','宋诗','song-poetry','','[]','磨陁爲官多，曉了未更歷。',144,'全唐诗/poet.song.150000.json','["磨陁爲官多，曉了未更歷。", "今世從仕者，萬口用一律。", "文桉日從事，鴈鶩竊投隙。", "自謀脫悔吝，初肯計易劇。", "追逮有踵接，符牒動山積。", "豈念南畝民，晷刻校日力。", "停犁聽上命，質衣供旅食。", "誰定老我師，黠民幾鬼蜮。", "締彼刀筆吏，表裏肆狙慝。", "柰何食肉人，立說與推激。", "此論儻不破，此弊終未息。", "揆予閲世熟，敢此諗在職。"]'),
('ae7e61e2-20c6-49c7-86b7-e0a3f76a1848','奔牛堰','陳造','宋','宋诗','song-poetry','','[]','挽舟下奔牛，挽丁已疲極。',120,'全唐诗/poet.song.150000.json','["挽舟下奔牛，挽丁已疲極。", "長衖此埭東，衖心齒砂礫。", "千指取寸進，贔屭山可拆。", "舟子提肺肝，舟材寧鐵石。", "即今揚塵處，劣計三百尺。", "時賢或興懷，僅費十夫力。", "往來日幾舟，孰者違此厄。", "爲人計安便，作吏戒徒食。", "斯人仍斯患，胡必須目擊。", "猶爲埭兵地，吾言竟何益。"]'),
('55b10f6a-6592-4e92-ae1c-b82cbf732e4c','呂城堰','陳造','宋','宋诗','song-poetry','','[]','堰西綠泱泱，堰東已膠盃。',120,'全唐诗/poet.song.150000.json','["堰西綠泱泱，堰東已膠盃。", "呂城校奔牛，客舟更遲回。", "嗟我爲貧仕，此路幾往來。", "厲翁市冠師，與我熟追陪。", "渠貧安無求，我困坐不才。", "三別二十年，鬢髮各摧頹。", "擬賡北山杞，倏笑南柯槐。", "惟翁未厭客，望影笑口開。", "生得數會面，升沈何有哉。", "相約飽飯過，世事付飛埃。"]'),
('0f6c1a08-3e79-4b3d-96e8-03a2dfd2c912','命書','陳造','宋','宋诗','song-poetry','','[]','命書唐濫觴，委源傳呂後。',168,'全唐诗/poet.song.150000.json','["命書唐濫觴，委源傳呂後。", "有倡莫爲遏，波蕩今不救。", "字育叵數計，八字詎所囿。", "甲子動垓億，舉一百萬漏。", "荒唐無稽據，誦言指休咎。", "柰何聰達人，頗復安此謬。", "懷刺曳長裾，偃蹇文士右。", "夸詡走干謁，薦墨不待叩。", "士有待濡沬，百請不一售。", "我昔遊江淮，知識間新舊。", "文士不到眼，此輩日交簉。", "辭章輕盃水，羨彼行橐富。", "鰓鰓問利祿，吾儒所深陋。", "自笑與世違，迂論取排詬。"]'),
('4071d516-4ffa-47fe-b6bc-b4f80f7ed14c','正學','陳造','宋','宋诗','song-poetry','','[]','政術自學術，君子惡其欺。',288,'全唐诗/poet.song.150000.json','["政術自學術，君子惡其欺。", "道學不容僞，世以僞用之。", "向來濂溪翁，粹然時所師。", "光風與霽月，取重前輩詞。", "兩程從之遊，流變已受疑。", "應世頗拘謭，自立如矜持。", "何人傳其粗，矯訐取世資。", "口中誠敬語，掎袂挹惠夷。", "其行則市井，跖屩差所爲。", "危坐悄長默，覆此庸蚩蚩。", "經正盛時事，怪女尚抵巇。", "秉畀幸一旦，嘉穀去稗稊。", "正士鴛鴻集，古學星日垂。", "江湖隠淪客，有見真管窺。", "爾輩受排拫，似亦無孑遺。", "得無奇英士，失脚遂磷緇。", "用過賢用功，取璧忘小疵。", "願引抆拭手，免興失時悲。", "願分斗升祿，少救併日饑。", "闢以周孔塗，正以孟韓規。", "嵬瑣審辟就，譸張慙昨非。", "六通而四達，恢若隆古時。", "治道貴去甚，世變須防微。", "吾言或可錄，敢用告採詩。"]'),
('8c4033e6-4877-487d-a4b3-64c456a261ca','財昏','陳造','宋','宋诗','song-poetry','','[]','師昏古所辭，財昏今不耻。',204,'全唐诗/poet.song.150000.json','["師昏古所辭，財昏今不耻。", "傳祀合二姓，古者貴由禮。", "四德五可外，貨賄亦末爾。", "民風日就頹，捨此爭校彼。", "媒氏未到眼，聘資問有幾。", "傾篋指金錢，交券搴租米。", "東家女未笄，儀矩無可紀。", "已聞歸有日，資送耀鄰里。", "西家女三十，閉戶事麻枲。", "四壁漏風霜，行媒無留趾。", "坐貧失行期，趣富瞢貪鄙。", "流弊例不免，其源實此起。", "多約或少酬，暫譽甘長毀。", "坐令親舊歡，詭譎變狐鬼。", "何况性習間，貧富岐臧否。", "土俗未易挽，人情大不媺。", "悠悠何足道，吾以諗君子。"]'),
('522990eb-6a9d-4b0b-92ae-cf74d2b161c0','聽政','陳造','宋','宋诗','song-poetry','','[]','爲政貴中和，偏徇古無取。',168,'全唐诗/poet.song.150000.json','["爲政貴中和，偏徇古無取。", "無心斯善應，奸譽乃其蠹。", "柰何聞見間，往往用心誤。", "扶弱抑其彊，古或垂此譽。", "世異俗且殊，處今猶徇故。", "曲直本不昧，彊弱豈所據。", "君子不此恤，情僞溷丹素。", "富室被剝朘，日有貧窶慮。", "士夫受加陵，悔不齒編戶。", "羸弊取必勝，玉色吞氣去。", "不知世富室，如母子所怙。", "不知意定向，未語機已露。", "傳繼用一律，抱寃莫赴愬。", "用是致和氣，南首問燕路。"]'),
('d7d0f369-9625-4464-a5b3-fe9fcb59c375','錢弊','陳造','宋','宋诗','song-poetry','','[]','爲家重牆垣，爲民須貨殖。',204,'全唐诗/poet.song.150000.json','["爲家重牆垣，爲民須貨殖。", "揚廬國北戶，東南頼控扼。", "淮民魚米餘，百貨仰殊域。", "用銅防外泄，用鐵乃奇畫。", "一利伏一弊，救弊要得策。", "持貨貿官券，捨此莫衣食。", "錢貨天下用，鐵乃限南北。", "坐令兩淮民，塊處斷貿易。", "計鐵取券直，十纔收六七。", "朝賢愛淮民，此困盍矜恤。", "銅鐵均國寶，通變豈無術。", "近甸視遠地，未可岐畛域。", "况今苦倒垂，倚待振焚溺。", "緣江八郡爾，雜用顧何失。", "官券朝北來，淮俗暮安宅。", "即今私鑄斷，胡尚膠今昔。", "吾貧復淮人，計勢不容默。"]'),
('6148ecbd-12a6-438d-ab41-835e37a7baf9','次韻林郎中相送北歸','陳造','宋','宋诗','song-poetry','','[]','銖兩作低昂，舉世皆此心。',96,'全唐诗/poet.song.150000.json','["銖兩作低昂，舉世皆此心。", "羨君松柏操，不受霜雪侵。", "向來車笠誓，歲寒迄能尋。", "骯髒吾何取，振拔意彌深。", "天才有賢否，宦路岐昇沈。", "鼎貴聽新渥，疊來當好音。", "我草賀緘處，碧溪映青林。", "祝公小婆娑，未宜輕分陰。"]'),
('b2a23619-1d34-4461-a047-d4b1781a78a5','次韻楊宰','陳造','宋','宋诗','song-poetry','','[]','淮俗日就薄，識者頗借憂。',240,'全唐诗/poet.song.150000.json','["淮俗日就薄，識者頗借憂。", "天變不徒然，旱暵將誰尤。", "日來聞見同，比屋聲悲愀。", "令君不鄙夷，疋馬走道周。", "似聞疄隴間，蟄蟄霰雨稠。", "課功撲燎餘，準粟秉庾收。", "一斃迺百孳，皁堅肥螟蟊。", "服勞豈容已，善後良未謀。", "即君論才諝，爲邦似求由。", "佩蘭扈玄蘺，所向多暗投。", "世賢劉係宗，芥視東家丘。", "方將解倒垂，未遑賦歸休。", "橫前觴深淵，君其萬斛舟。", "願天開老眼，一雨洗歎愁。", "旄倪飫菽粟，羈罷安田疇。", "探丸等和扁，沈痾灑然瘳。", "我亦民之一，擔石略不留。", "遭罹本自致，未敢忘反求。", "詩來念賢勞，效顰聊殺羞。", "孰視援溺手，不計輸幾籌。"]'),
('72508e3f-53c0-4486-8a3d-b4812916cd94','送羊侯因簡崔帥一首','陳造','宋','宋诗','song-poetry','','[]','遊宦何許佳，解印還故鄉。',204,'全唐诗/poet.song.150000.json','["遊宦何許佳，解印還故鄉。", "舊國仍舊都，別去未始忘。", "一旦吾眼中，怡然得徜徉。", "釣處它日梁，樹是兒時桑。", "扶携擁道周，老倪皆壺漿。", "官簿有高下，此樂均未央。", "羊侯萬金將，文武擅兩長。", "稜威肅貔虎，談兵厲冰霜。", "小作漳濱卧，斗飯方健强。", "胡爲倚秋風，歸思歌慨慷。", "似聞山陽郊，迓者立堵牆。", "湖蟹九月肥，社酒千室香。", "海舶來麋䴥，江戶送鱒魴。", "舉白作鯨吸，羅幙同春陽。", "樂事有如此，夙志今始償。", "我袖如椽筆，落紙煙雲翔。", "自今小晝錦，爲君記新堂。"]'),
('bb3831ff-b76e-43a8-8257-4dfef4bb36b1','題陳守宰仁和無倦堂二首  其一','陳造','宋','宋诗','song-poetry','','[]','仲尼治道師，今古誰造閫。',144,'全唐诗/poet.song.150000.json','["仲尼治道師，今古誰造閫。", "公與由也果，有得非二本。", "爲政貴無倦，聖語要自反。", "吾宗宰仁和，條教仰瓴建。", "吟對千挺竹，日課五升飯。", "膠擾付冰解，隠幽莫形遯。", "器資銅百鍊，心地蘭九畹。", "人絕懸魚續，自詭割鷄偃。", "秉心寧作輟，提耳悟頑諼。", "豈伊不可耐，據以爲益損。", "譬如歲豐凶，良農守穮蔉。", "功名自民庸，君子計歲晚。"]'),
('d2b653f9-7ef8-4548-8aaa-26ccea989c10','題陳守宰仁和無倦堂二首  其二','陳造','宋','宋诗','song-poetry','','[]','陳侯昔爲邑，鼓舞輦轂民。',144,'全唐诗/poet.song.150000.json','["陳侯昔爲邑，鼓舞輦轂民。", "爾來佐淮郡，喜詫有脚春。", "例滿徯志望，正繄不已純。", "帖焉受馴擾，初豈煩令申。", "撫臨不云倦，依然舊持循。", "終始秉厚德，邇遐沐深仁。", "報政已捐日，設施方日新。", "羣蠹繼革熄，千棟成逡巡。", "向來簡齋僊，九德罄忱恂。", "長源無涸流，盍嘗究所因。", "一印妙心傳，千載挹聖真。", "此學不勝用，企公嗣前塵。"]'),
('2ede0f2f-3a3d-4e90-88ee-3a43cde1e581','次韻楊宰','陳造','宋','宋诗','song-poetry','','[]','有薪尚濕惡，有穀未舂簸。',120,'全唐诗/poet.song.150000.json','["有薪尚濕惡，有穀未舂簸。", "病客正牢落，急雪忽蜚墮。", "枵腹亟問炊，曲身可欠火。", "簷隙納璀璨，座隅紛碎瑣。", "繽漂纔一瞬，彌滿已四野。", "慨念菜茹農，負愧吾顔赭。", "人同忍朝饑，神亦輟秋社。", "吾村劣收穫，猶幸了眼下。", "嗷嗷聞見間，久已絕貸假。", "何人發陳紅，倚待由也果。"]'),
('85da5213-cfde-4ee0-a4da-90f9bc1dd598','次韻楊宰對雪有感','陳造','宋','宋诗','song-poetry','','[]','生世波上舟，高下隨掀簸。',120,'全唐诗/poet.song.150000.json','["生世波上舟，高下隨掀簸。", "樓閣或藩溷，風花聽飛墮。", "榮利計圭黍，光陰付膏火。", "胡不養弘大，而顧蹈嵬瑣。", "君看前宵雪，積玉曉覆野。", "朝陽麗山川，湛碧仍眩赭。", "簿書辦官事，酒炙趁村社。", "長翁取意適，吾策未云下。", "優服作貴賤，觀傍了真假。", "平生招隠詩，尋盟逮今果。"]'),
('e5be0db8-fc18-43cc-9a81-ee982ddbfbd3','贈張德恭','陳造','宋','宋诗','song-poetry','','[]','少日試推敲，未脫蜂鶴病。',192,'全唐诗/poet.song.150000.json','["少日試推敲，未脫蜂鶴病。", "世間十全手，噬肯愛三請。", "即今悔少作，草草生氣盛。", "逢人忍脩縮，拜手博是正。", "往往掉其臂，百叩不一應。", "贔屭仰前修，萎憊不能勁。", "從君父子遊，似頗識蹊徑。", "使君唾隋珠，枚叟每後乘。", "郎君撞烟樓，楚珩復相映。", "兩豪五字律，萬象一清鏡。", "賸馥副羣趨，餘風振不競。", "郵城望迎鑾，未敢憚奔命。", "向來從渠後，無乃瑩吾聽。", "回省多岐亡，滿冀一語訂。", "此篇尤愛我，見推乃見警。", "政使元白前，向君亦脩敬。"]'),
('09b22afc-8319-4770-8560-e6a357dd28f7','次韻張守阻冰','陳造','宋','宋诗','song-poetry','','[]','清篇方鼎來，强韻不可柰。',120,'全唐诗/poet.song.150000.json','["清篇方鼎來，强韻不可柰。", "膽掉久未定，如守上瀧柂。", "渾厚出綺麗，平談含頓挫。", "正始嘆不嗣，黄初君突過。", "想當舟陷泥，勢若右旋磨。", "河神要好句，待君顔一破。", "我行阻重壩，倍費客炊火。", "邗溝塵欲揚，人步溝尾汊。", "一雨濯旱枯，此惠誰所假。", "生世天不人，孰者可弔賀。"]'),
('6be864f2-7c2c-40fb-993f-98e854469d47','遊北山','陳造','宋','宋诗','song-poetry','','[]','有客可與遊，闕酒得無病。',180,'全唐诗/poet.song.150000.json','["有客可與遊，闕酒得無病。", "豈意四從事，過我不待請。", "洗杓挹風度，免慙林花盛。", "公學此味如，渾厚兼醇正。", "公量虛谷如，有來良善應。", "肯分兵厨瀝，少佐筆力勁。", "罷營杖頭錢，徐取松間徑。", "登臨舊能賦，七發踵枚乘。", "此興老未衰，西日尚餘映。", "風怒雷再鼓，雲破天一鏡。", "山花下野鳥，詩題一堪命。", "府公文章伯，聲稱聳羣聽。", "明朝倒錦囊，非是庶所訂。", "豈伊綵鳳鳴，而聆露鶴警。", "定知謝東山，凡百易子敬。"]'),
('97718e6d-7c23-4a17-b7d9-d42a89778b2a','再次韻','陳造','宋','宋诗','song-poetry','','[]','當臘可折絃，羣植不告病。',192,'全唐诗/poet.song.150000.json','["當臘可折絃，羣植不告病。", "春令宜畫一，驟寒乃奇請。", "淙潺急雨後，摧拉北風盛。", "倚戶頸爲縮，引望立不正。", "下窗斷過逢，袖手謝酬應。", "坐嘆花信遲，陡怯弓力勁。", "今朝晴色好，呼童掃幽徑。", "客子踏青約，久許陪驂乘。", "逶迤望北山，巷柳俄蔭映。", "乾鵲語紅樹，遊鯈噞明鏡。", "平時詩酒社，賈勇與春競。", "即今鶑花前，欺客頗方命。", "擊轅歌于蒍，寧入俚耳聽。", "喧靜交戰間，詩老儻能訂。", "寓物不流物，古語方自警。", "追隨黄白郎，不擬繆爲敬。"]'),
('5d175202-8a60-4918-b10f-d8c2e0176750','吳節推趙楊子曹器遠趙子野携具用韻謝之','陳造','宋','宋诗','song-poetry','','[]','平日從俊遊，寂寂坐多病。',192,'全唐诗/poet.song.150000.json','["平日從俊遊，寂寂坐多病。", "犯床漫飛埃，瑶笙罷重請。", "昔遊喜復到，風物他日盛。", "坡恐名燕支，樓亦詫端正。", "新交間舊友，氣合宮羽應。", "譚麈冰霜厲，筆陣鵝鸛勁。", "吏隠分樂地，與世不好徑。", "拔貧辦一歡，挾貴輕百乘。", "四豪載酒過，講德珠璧映。", "歌奏雲近人，舞罷鸞顧鏡。", "酬酢忘主賓，笑語似紛競。", "朱樓識阿盼，白酒醉師命。", "明朝耐殘酲，江聲醒幽聽。", "此樂謫仙後，同異君試訂。", "四豪成風手，可但隻字警。", "我投詩社名，拜手敢貌敬。"]'),
('3a9158ae-4618-45c3-b04c-914d55ba14f2','再次敬字韻','陳造','宋','宋诗','song-poetry','','[]','陰風摧行車，欻作三日病。',192,'全唐诗/poet.song.150000.json','["陰風摧行車，欻作三日病。", "使君敬愛客，重此折簡請。", "碧香駢柔嘉，虛辱禮意盛。", "老衰已不支，節候况失正。", "寒事動奸時，暖氣久未應。", "積雨遷厥怒，密雪佐其勁。", "新詩挽春色，墮我桃李徑。", "飄蕭尋芳興，亟問果下乘。", "把君珠兩兩，後照仍前映。", "重燒見火浣，百鍊乃寶鏡。", "折箠敵可笞，歌風楚不競。", "讀檄且觀濤，壽我無有命。", "舊聞句通神，瘧鬼褫魄聽。", "援君起廢手，直用古賢訂。", "笑送夢中豎，子行良機警。", "亦笑齊東翁，口舌邀客敬。"]'),
('b639c166-ad2c-4b5b-a86b-695abdaf5f3d','再次韻張簿','陳造','宋','宋诗','song-poetry','','[]','生世詩作癖，頗坐艱局病。',192,'全唐诗/poet.song.150000.json','["生世詩作癖，頗坐艱局病。", "當前成風手，每來難塞請。", "後身習鑿齒，名儷乃公盛。", "新詩再出奇，後出尤雅正。", "高吟步芳園，靈籟想隨應。", "荆戶厭盧羅，陳勢無前勁。", "鍧隠度九軌，眇睨秋蛇徑。", "狐兔新竄伏，願前王公乘。", "我學但宋璞，多慙楚珩映。", "才與年貌衰，不擬拂晨鏡。", "妙句駢魁傑，曩見絕夸競。", "居然大小巫，詎容耻受命。", "目窺曹劉牆，日有韶濩聽。", "古今尚論間，未遽優劣訂。", "此意客未知，太簡效規警。", "平生孔文舉，敢替此心敬。"]'),
('bb6be3f0-45b3-4adb-8547-2798ca72628d','分韻得家字','陳造','宋','宋诗','song-poetry','','[]','東園郡勝處，不作里所遐。',144,'全唐诗/poet.song.150000.json','["東園郡勝處，不作里所遐。", "池臺掇天巧，草木專年華。", "一雨洗清曉，十頃圍紅霞。", "云何秉燭客，未駕載酒車。", "掾郎郡之望，士價詩名家。", "折簡挽名勝，行庖富柔嘉。", "清風應靈籟，高譚振衝牙。", "酬酢角鯨吸，賡和紛天葩。", "痛飲未渠醉，浩興渺無涯。", "孰知此老憊，坐受强敵加。", "空弮將一旅，堅陣凌五花。", "詩成字欹倒，病眼正麻嗏。"]'),
('bce11135-6a1c-4705-91aa-85a72ccb2202','遊乾明分韻得山字','陳造','宋','宋诗','song-poetry','','[]','竹風清如水，浣我塵埃顔。',96,'全唐诗/poet.song.150000.json','["竹風清如水，浣我塵埃顔。", "老禪貧無錐，小破蔬筍慳。", "短轅下鴟夷，共此半日閑。", "住筆訊鶑燕，把盃屬江山。", "老夫病止飲，苦語澀莫刪。", "揆予郊島寒，著君季孟間。", "江柳未遽折，園花且同攀。", "後夜短亭夢，漫寄東風還。"]'),
('44363e71-162f-4f22-a3dd-28e6f459b1df','小飲俯江樓分韻得俯字','陳造','宋','宋诗','song-poetry','','[]','流光肯貸人，春事遽如許。',156,'全唐诗/poet.song.150000.json','["流光肯貸人，春事遽如許。", "眼不到蜚鴻，身每念縛虎。", "他日載酒約，坐受陰寒阻。", "非君韻超俗，疇肯顧羈旅。", "今朝鶑花前，有興浩莫禦。", "茲樓可圖畫，山立瞰江滸。", "壯侔彭城蘇，氣吞潯陽庾。", "乘凌脫埃𡏖，盤躄上煙雨。", "向來狀雄觀，尚欠魁傑語。", "江山君周旋，得句忍不吐。", "詩成人未醉，鄰鷄喚亭午。", "新音略韶濩，至樂非簫鼓。", "却話庾與蘇，今古一仰俯。"]'),
('febd3fdc-ae69-483f-8909-b6ceefd3a062','招朱法曹趙宰趙予野飲  其一','陳造','宋','宋诗','song-poetry','','[]','秦郵望儀真，相與不三驛。',132,'全唐诗/poet.song.150000.json','["秦郵望儀真，相與不三驛。", "仕學四十年，此地幾旅食。", "寓公芹泮士，十九盡親識。", "茲遊最奇偉，詩壇許投迹。", "每當觴詠間，不蓋慙頰赤。", "赤手桃虓虎，空弮抗雄戟。", "四盼號猿手，未敢箭鋒直。", "排日有勝踐，尚恐坐岑寂。", "纔卷俯江帳，復蠟東園屐。", "小奚費收攟，巨橐珍的歷。", "摩挲歸裝富，足容傲侯伯。"]'),
('b17c323b-5053-412e-a7af-623dab837c6b','招朱法曹趙宰趙予野飲  其二','陳造','宋','宋诗','song-poetry','','[]','自公置簿領，來作一笑適。',120,'全唐诗/poet.song.150000.json','["自公置簿領，來作一笑適。", "表表三英粲，各各萬夫特。", "揆予自僑寓，人詫有此客。", "風煙入揮毫，江山皆動色。", "尚友古所貪，解后歸來得。", "今朝鄉思動，招邀話暌隔。", "非復向軒豁，但有新凄惻。", "吟詩尚爾工，把酒不能喫。", "縣知短長亭，小蓬雲月白。", "還應蘧蘧夢，蜚墮清江側。"]'),
('4fa48857-f293-4c4f-ba1a-65d5582dfc20','儀真諸公餞別','陳造','宋','宋诗','song-poetry','','[]','旅懷我岑寂，詩語君雋永。',120,'全唐诗/poet.song.150000.json','["旅懷我岑寂，詩語君雋永。", "新篇蜚墮前，坐閲仙府景。", "曉林媚紅酣，春池涵淥靜。", "叱吸風起籟，模寫燈取影。", "東園固成言，此境亦深靚。", "應世足變遷，爲謀難要領。", "酒車且新圖，客棹非舊整。", "明朝鷗鷺前，鴨綠渺千頃。", "飛觴擊鉢地，獨夜起重省。", "還應蓬背雨，閑滴魂夢冷。"]'),
('edee9024-9d66-4cab-a100-91abdabc8b7d','真州諸公語別','陳造','宋','宋诗','song-poetry','','[]','屈指舊新雨，何人顧蓬萊。',96,'全唐诗/poet.song.150000.json','["屈指舊新雨，何人顧蓬萊。", "駢車各鴟夷，良爲老夫來。", "古今漆投膠，不獨數陳雷。", "衮衮慰勞意，一盃復一盃。", "索句不解工，何以寫別懷。", "敢惜吟髭折，柰此雨意催。", "此會良姱嫮，此行重徘徊。", "得無葉舟重，滿載離愁回。"]'),
('2164e8f4-b9fb-4c29-8271-ffe5b676b9e1','送趙夷仲南歸','陳造','宋','宋诗','song-poetry','','[]','離索老不堪，應接意多遻。',144,'全唐诗/poet.song.150000.json','["離索老不堪，應接意多遻。", "愛者挽不留，惡者推不去。", "道人心如水，胡復生愛惡。", "方厭塵瞇眼，倏驚瓊爲樹。", "趙侯南州英，中抱經世具。", "碧巖紫電耀，翠竹青鸞翥。", "聯翩拜新作，一一彈丸句。", "傾蓋得此友，霽月破愁霧。", "交君良恨晚，別我用許遽。", "溽暑挾旱氣，河底車取路。", "在客身爲本，食眠要將護。", "燕子遡北風，端許問尺素。"]'),
('54563635-8859-4929-a5a4-b0fd74d92b85','立秋日','陳造','宋','宋诗','song-poetry','','[]','酷暑如酷吏，頃刻不可對。',96,'全唐诗/poet.song.150000.json','["酷暑如酷吏，頃刻不可對。", "萬口噤不息，束濕底多罪。", "况我七十翁，形劣氣已憊。", "懣若墮丹書，孰者我牘背。", "微風忽鳴秋，遽喜又無害。", "天豈芻狗我，生死置度外。", "會看三日雨，怛悼推所愛。", "甘澤洽嘉穀，生意亦蕭艾。"]'),
('d2855ae0-ffc8-4765-8aaa-a1ec81762ec0','寄嚴文炳  其一','陳造','宋','宋诗','song-poetry','','[]','故人千里遠，論心未遐棄。',48,'全唐诗/poet.song.150000.json','["故人千里遠，論心未遐棄。", "不謂江淮隔，尺書鴈能寄。", "春風生展掩，滿慰別後意。", "陳義凜冰霜，不獨相思字。"]'),
('d08e07c1-4bf0-40ab-874e-0f717b8e56f6','寄嚴文炳  其二','陳造','宋','宋诗','song-poetry','','[]','隻影秋鴻驚，獨夜秋葉零。',48,'全唐诗/poet.song.150000.json','["隻影秋鴻驚，獨夜秋葉零。", "離索欻五霜，搔首聽此聲。", "豈無金石友，相避參辰星。", "安得木作腸，與世無復情。"]'),
('d360d8c7-aa2f-40a8-963f-9912a7c7b17a','寄嚴文炳  其三','陳造','宋','宋诗','song-poetry','','[]','子雲草玄宅，門徑積莓苔。',48,'全唐诗/poet.song.150000.json','["子雲草玄宅，門徑積莓苔。", "昨夢憑詩說，新雨無客來。", "衮衮手可炙，自詫甘寒灰。", "蜀莊寂寞者，念我首獨回。"]'),
('65ed158e-893a-48e7-80da-0358153d028b','寄嚴文炳  其四','陳造','宋','宋诗','song-poetry','','[]','烏墅兩馮君，風霆藹休問。',48,'全唐诗/poet.song.150000.json','["烏墅兩馮君，風霆藹休問。", "自昔從之遊，詩力借餘潤。", "夫君凜一敵，鴻筆上羣俊。", "舊壇今尋盟，得句毋我靳。"]'),
('11fee861-9aff-40fb-b786-e820776f22db','寄嚴文炳  其五','陳造','宋','宋诗','song-poetry','','[]','嚴子老於菟，彪炳踞賢關。',48,'全唐诗/poet.song.150000.json','["嚴子老於菟，彪炳踞賢關。", "可憐五車學，僅博九品官。", "客程望至喜，江闊山叢攢。", "緬懷造物心，念子詎能安。"]'),
('a53b4943-78e7-4e47-aa92-50ba6f9e7259','寄嚴文炳  其六','陳造','宋','宋诗','song-poetry','','[]','善忘常憎醫，獨者自尊足。',48,'全唐诗/poet.song.150000.json','["善忘常憎醫，獨者自尊足。", "嚴子骯髒面，如我不諧俗。", "世情趣操間，憎愛岐珉玉。", "饒舌誇我賢，祗取白眼辱。"]'),
('6556a03e-2a7b-4d24-babb-2f958849988c','寄嚴文炳  其七','陳造','宋','宋诗','song-poetry','','[]','聯鑣行樂地，俛仰成古今。',48,'全唐诗/poet.song.150000.json','["聯鑣行樂地，俛仰成古今。", "可但捧觴人，貫珠無復音。", "繾綣棋酒伴，電泡半銷沈。", "何時兩衰翁，話舊同清斟。"]'),
('206b446b-23d2-4f18-86d6-03d2ef77718c','寄嚴文炳  其八','陳造','宋','宋诗','song-poetry','','[]','趙侯當賜環，倔强耻媚竈。',48,'全唐诗/poet.song.150000.json','["趙侯當賜環，倔强耻媚竈。", "張侯鳴琴手，戍期幾時到。", "何郎偕賢書，論價未足道。", "多煩問何如，好語君一報。"]'),
('af02b381-5a3d-4fe9-b2bc-4d4db0226de0','寄嚴文炳  其九','陳造','宋','宋诗','song-poetry','','[]','石湖良樂眼，收士冀北空。',48,'全唐诗/poet.song.150000.json','["石湖良樂眼，收士冀北空。", "嗟我孤所期，經世老無庸。", "一莊頼芥庵，報厚艾亦豐。", "賓實得美謚，表表無終窮。"]'),
('5b46ae13-177a-48e2-9df1-d48a37fc194e','寄嚴文炳  其一○','陳造','宋','宋诗','song-poetry','','[]','嚴子從我時，脩竦峙雙鵠。',48,'全唐诗/poet.song.150000.json','["嚴子從我時，脩竦峙雙鵠。", "章綬裹瘦軀，此相胡宜肉。", "當嗣溧陽尉，苦語叩哀玉。", "寧當蘇門翁，清嘯答幽谷。"]'),
('97909725-1790-4954-8e41-11d1f3206b7b','次韻楊宰檢旱野宿','陳造','宋','宋诗','song-poetry','','[]','旱後訪親知，悲風鏖愁霧。',84,'全唐诗/poet.song.150000.json','["旱後訪親知，悲風鏖愁霧。", "未辦飽翳桑，况能嫁阿騖。", "令君妙爲政，果藝今求路。", "道逢枵腹民，挾纊誦言句。", "保社知自愛，奪攘可無慮。", "飛騰要及時，封殖須此樹。", "來年步畏壘，繪象各村墅。"]'),
('9ae704f4-5ab4-4a54-b4d6-b7f88fb7cd7e','題劉行父凈香軒','陳造','宋','宋诗','song-poetry','','[]','劉郎何所有，寒碧二百本。',168,'全唐诗/poet.song.150000.json','["劉郎何所有，寒碧二百本。", "方渠懋進脩，藉爾伴蕭散。", "妙處鼻觀領，翛然市聲遠。", "朱墨五千卷，日力自繾綣。", "久聞伯仲間，珠璧各櫝韞。", "一笑挹此君，方外得嵇阮。", "饑鳳吟夜良，斑犀散春晚。", "慣嘗推枕聽，肯作芼羹挽。", "長翁紀幽致，一字粲褒衮。", "譜傳渭川孫，石屹益州笋。", "行當洊驚雷，龍躍闖天閫。", "功名有咄嗟，世道計舒卷。", "平昔對床約，里閈規息偃。", "大屋俯嬋娟，晝繡替前扁。"]'),
('7887a588-4ee5-47be-8145-387335bb6337','次姜堯章贈詩卷中韻  其一','陳造','宋','宋诗','song-poetry','','[]','徐郎巢已焚，庭竹亦無在。',60,'全唐诗/poet.song.150000.json','["徐郎巢已焚，庭竹亦無在。", "太倉五升米，舉室枵腹待。", "云何鮭菜供，日與長翁對。", "世有作金術，閭里頗猜怪。", "丘嫂剪髻餘，舊質疊新債。"]'),
('bfb2a480-8909-4815-b48d-44b1a2cffbbf','次姜堯章贈詩卷中韻  其二','陳造','宋','宋诗','song-poetry','','[]','詩傳侯王家，翰墨到省寺。',72,'全唐诗/poet.song.150000.json','["詩傳侯王家，翰墨到省寺。", "姜郎粲然文，羣蜚見孔翠。", "論交辱見予，盧馬果同異。", "念君聚百指，一飽仰臺饋。", "我亦多病過，忍口嚴酒戒。", "終勝柳柳州，吐水賦解祟。"]'),
('d0e69592-a5c7-4039-88e6-5dd2b73e3406','次姜堯章贈詩卷中韻  其三','陳造','宋','宋诗','song-poetry','','[]','壯年志在行，皇皇困無君。',72,'全唐诗/poet.song.150000.json','["壯年志在行，皇皇困無君。", "老矣此念灰，去住如閑雲。", "詩壇二三子，一見勝百聞。", "徐郎吳下蒙，絢麗工語言。", "滔天自濫觴，昔人求其源。", "隠几有妙領，未覺市聲喧。"]'),
('5ed95e50-bb8f-4e04-84ee-6a9346543dfd','次姜堯章贈詩卷中韻  其四','陳造','宋','宋诗','song-poetry','','[]','自甘謝祖風，屑屑掃一室。',48,'全唐诗/poet.song.150000.json','["自甘謝祖風，屑屑掃一室。", "準擬高史來，函丈置三席。", "聲名絕輩行，文字追古昔。", "黄白馬上郎，覿面不相挹。"]'),
('edb20123-7f87-4bf1-8d60-0b4e3472a333','次姜堯章贈詩卷中韻  其五','陳造','宋','宋诗','song-poetry','','[]','眼青節食事，日耐饑雷吼。',48,'全唐诗/poet.song.150000.json','["眼青節食事，日耐饑雷吼。", "茲幸陪衆後，酒巵甫到口。", "不離寂寞濱，徑造無何有。", "問津歸有期，尚許尋盟否。"]'),
('355466c1-1987-4a28-9af5-0529f0b75dc9','次韻林子長計使','陳造','宋','宋诗','song-poetry','','[]','林侯上州麾，便飫大官飯。',96,'全唐诗/poet.song.150000.json','["林侯上州麾，便飫大官飯。", "左淮魚稻供，顧肯回一眄。", "待人均待士，樂易屏崖岸。", "懸知訖民庸，功倍而事半。", "淮鄉舊樂土，兼有齊俗緩。", "頃來南北雜，頗復煩城旦。", "要須禁奪攘，立可息愁嘆。", "爲公泚銀筆，攘袂歌粲晏。"]'),
('cd838fe9-bd34-47d9-9e01-1f0f4fe38a35','次林子長韻','陳造','宋','宋诗','song-poetry','','[]','孤亭屹山椒，山靈信多助。',132,'全唐诗/poet.song.150000.json','["孤亭屹山椒，山靈信多助。", "比肯迂玉節，來作數刻住。", "江明山動色，取重以公故。", "未須坐譚客，子弟自翹楚。", "雲嵐遠明滅，阡陌隨指顧。", "何以驗人情，楚歈雜吳舞。", "我來空想像，夢去上煙雨。", "尚及拂雲飲，醉狂煩杜舉。", "新歡償昔遊，幸會乃如許。", "古人重一飯，志士賦盛遇。", "歸時混遊人，健倒各扶路。"]'),
('081b4cd0-5f26-49fb-9f1e-d96aa58e5a7e','再次韻酬林子長運使','陳造','宋','宋诗','song-poetry','','[]','繡衣如椽筆，可但江山助。',132,'全唐诗/poet.song.150000.json','["繡衣如椽筆，可但江山助。", "登樓得秀句，飛雲爲公住。", "使君傾意氣，接我便親故。", "自忖庸鄀陋，兩公富全楚。", "賦雪容末至，高軒先左顧。", "醉鄉信餘地，肯作長沙舞。", "和氣挽春回，冰柱下簷雨。", "代舍著狗盜，珠履賁豪舉。", "阿遷詫齊魏，瑣瑣吾未許。", "我從兩公遊，趣舍本神遇。", "更當問學閒，司南取夷路。"]'),
('63117874-1794-4197-bc9f-8bbadc8e520c','再次韻','陳造','宋','宋诗','song-poetry','','[]','雪神再出奇，剪水誰佽助。',132,'全唐诗/poet.song.150000.json','["雪神再出奇，剪水誰佽助。", "羣仙幻塵寰，落勢未肯住。", "政成氣乃和，此瑞豈無故。", "同雲方頌周，惡氛已銷楚。", "乾坤玉花中，客子眩回顧。", "人家占嘉平，酒處應起舞。", "了知及物功，當倍蘇旱雨。", "前雪淮海燕，把酒欲輕舉。", "今雪燕拂雲，勝槩驚似許。", "客途一笑適，樂事詫晚遇。", "回思何人家，鷄黍羞季路。"]'),
('05324d67-5942-4304-80a9-f97c0d8d9426','陳宣卿爲予作後彫圖','陳造','宋','宋诗','song-poetry','','[]','吾宗灑畫墨，似我詩得趣。',144,'全唐诗/poet.song.150000.json','["吾宗灑畫墨，似我詩得趣。", "未至心手忘，敢議江山助。", "東絹十幅圍，中有千尺樹。", "窮冬萬蟲蟄，拆地雙虬怒。", "彷彿風雨聲，想像棟梁具。", "人間汗反漿，對此毛髮豎。", "怪君物寫影，落筆神與遇。", "自言閲世孰，妙解等僧悟。", "每當槃薄餘，了知精靈聚。", "此圖尤傑出，持用博新句。", "墨君第一流，論世無殆庶。", "三熏且十襲，復靳爲子賦。"]'),
('475e71a2-4343-4a3e-a4ac-b73173bc3420','次趙判宗送李象山韻','陳造','宋','宋诗','song-poetry','','[]','邑政易墮，我方在行。',200,'全唐诗/poet.song.150000.json','["邑政易墮，我方在行。", "挽袖柅車，交遊至情。", "兩君玉峙，表表國士。", "下榻傾倒，有賢公子。", "我介三子，匪同而和。", "提衡掖挽，交口孰何。", "月堂之評，罙久未改。", "匿瑕振過，茲焉有待。", "卜夜之飲，輟驪駒章。", "顧雖情鍾，河魚未康。", "作吏則疎，羨人報政。", "彼益者友，工藥我病。", "低昂達窮，冥心所遭。", "獨喜故人，往偕仙曹。", "摇摇脩程，烱烱初度。", "眷言顧之，矯首雲路。", "胡不小留，共頹醉山。", "胡不更僕，共譚孔顔。", "西睇歸帆，徙倚悽切。", "去留之間，仙凡斯別。"]'),
('490a2b20-177a-49e2-8ab2-bd7af58aa7f3','再次韻','陳造','宋','宋诗','song-poetry','','[]','載羽其觴，客遄于行。',200,'全唐诗/poet.song.150000.json','["載羽其觴，客遄于行。", "歸從我私，茲焉用情。", "一奇搴秀，萬金論士。", "生世已後，識古君子。", "宮倡羽隨，至樂則和。", "俚音間之，人謂斯何。", "潔不容緇，薰不蕕改。", "言受此柄，劣副期待。", "斯道在公，九報其章。", "人徯時施，躋之阜康。", "曾是偉人，而未聞政。", "袖司命手，旁睨世病。", "海瀕埤污，蒼山周遭。", "觴詠翺翔，樂殊爾曹。", "盍攄胸奇，煥我王度。", "盍提公言，闢我賢路。", "赫日中天，麗彼南山。", "賡歌交修，不靦其顔。", "有鉛者刀，用或一切。", "雲龍從之，無重此別。"]'),
('366e5e09-6fcd-4b33-a2de-bc4e56acf609','次程帥勸農和陶詩韻','陳造','宋','宋诗','song-poetry','','[]','我官于房，庸諗房民。',240,'全唐诗/poet.song.150000.json','["我官于房，庸諗房民。", "是腹枵然，惟貯一真。", "服事告工，以成以因。", "雄也言之，參天以人。", "燥之潤之，是有黍稷。", "天不竟刈，物豈自植。", "繫人之力，溫飽稼穡。", "惟蠶而衣，如稼而食。", "盍槌于家，盍桑于陸。", "飼眠後先，如族昭穆。", "爰繰爰織，如寇之逐。", "悠悠玩日，迄莫歸宿。", "孰溉不車，曾不計久。", "孰視槁乾，徒用播耦。", "吳豐楚約，誰非朕畝。", "穗斯繭斯，均措厥手。", "彼多其儲，汝則易匱。", "傚勞計工，寧終不冀。", "蹀躞十駕，與驥一至。", "枵中赤立，吾代爾愧。", "吏職民憂，無庸汝鄙。", "農以濟學，繄吾素履。", "豈曰多言，率遵前軌。", "教詔順從，庶或兼美。"]'),
('97e56361-a8eb-4fe3-8966-4ca45d8c2dbd','程帥和陶二詩見憶次韻','陳造','宋','宋诗','song-poetry','','[]','我瞻西郊，雲停不雨。',160,'全唐诗/poet.song.150000.json','["我瞻西郊，雲停不雨。", "鷄栖亂山，十舍千阻。", "一書緘春，慰厲存撫。", "望之或違，搔首企佇。", "停雲釃之，蜚雨濛濛。", "啟筒有獲，如渴吸江。", "孤月河漢，輕颸牖窗。", "憶侍誨色，杖屨後從。", "盱衡推予，褒衮儷榮。", "靡懷不傾，靡言不情。", "會晤良難，欻然西征。", "孰謂愁斛，無自而生。", "竹萌觸雪，粟花綴柯。", "風日山城，未春已和。", "命駕取塗，計日不多。", "官曹簡書，公其謂何。"]'),
('4d5e732f-0e51-4145-8e95-a9228d50a8a9','明妃曲','陳造','宋','宋诗','song-poetry','','[]','漢宮第一人，只合侍天子。',168,'全唐诗/poet.song.150000.json','["漢宮第一人，只合侍天子。", "四絃春風手，可用入胡耳。", "天生國艷或爲累，金賂畫工寧不耻。", "玉顔初作萬里行，朔風黧面邊塵昏。", "路人私語淚棲睫，况妾去國懷君恩。", "穹廬漸耐胡天冷，政復難忘心耿耿。", "夜深拜月望長安，顧嘆當時未央影。", "胡雛酌酒單于舞，銘肺千年朝漢主。", "傳聞上谷與蕭關，自頃耕桑皆樂土。", "向來屯餉仍繒絮，廟算年年關聖慮。", "但令黄屋不宵衣，埋骨龍荒妾其所。"]'),
('a805687c-b777-4bc3-a9e3-f3898134b407','柘臯短吟','陳造','宋','宋诗','song-poetry','','[]','鐵山橫飛截平野，寧復江流飲胡馬。',128,'全唐诗/poet.song.150000.json','["鐵山橫飛截平野，寧復江流飲胡馬。", "大酋膽落狐鼠逃，虎頭將軍自天下。", "拂廬連絡屯長雲，提戈敢謂秦無人。", "驚霆白晝振解葉，淮地一掃留無塵。", "歌謠千載淮民口，將軍歸飲策勳酒。", "烏袍使者來如煙，騰書乞和胡稽首。", "蠅鳴鴟噪初不聞，賈怒一舉雌雄分。", "辛勤結髮七十戰，數奇堪笑李將軍。"]'),
('616ad358-7ff1-48c1-b2ac-a8a4cf5a0413','題趙伯政醫俗軒','陳造','宋','宋诗','song-poetry','','[]','風淫氣格初不意，往往腠脈流腸胃。',96,'全唐诗/poet.song.150000.json','["風淫氣格初不意，往往腠脈流腸胃。", "金匱一編亙古今，幾人用之能起廢。", "痛恙切身知謁醫，俗氣痼人渠不知。", "持籌側肩蠹日力，錦鞲金彈隨癡兒。", "斯人斯疾可攻否，更恐良醫望之走。", "南窗解榻竹風清，請訪軒中十全手。"]'),
('eaf39459-bac6-469a-9af9-d3edf034bdd7','急筆贈歐處士','陳造','宋','宋诗','song-poetry','','[]','南州江山昔所歷，雨峰黯靉晴江碧。',98,'全唐诗/poet.song.150000.json','["南州江山昔所歷，雨峰黯靉晴江碧。", "幾年思之忽墮前，政得歐生醉時筆。", "斯人歷覽山川奇，得興落筆天露機。", "不須十日五日一水石，已可王宰相攀追。", "相逢便整南歸柂，短章許君慵未果。", "酒邊搜句敢言工，不解似君般礴臝。"]'),
('a200923f-5942-4b1f-8116-fb56906ba568','記夢示師是','陳造','宋','宋诗','song-poetry','','[]','青燈寒夜思吾鄉，合眼便坐吾家堂。',112,'全唐诗/poet.song.150000.json','["青燈寒夜思吾鄉，合眼便坐吾家堂。", "阿丁烱然目如水，綵服蹁躚趨我傍。", "中心喜之謬督過，還爲遨嬉廢書課。", "指似斜日西窗紅，小賦未破書未供。", "向渠不敢恩勝義，亦憐忸縮不自容。", "蝶蜚鹿失忽驚寤，摵摵霜風在庭樹。", "幾時筆力跨乃父，與汝相忘不關慮。"]'),
('e1ab0e37-569c-41ae-98de-edb84d54d120','題胡處士猿麞圖','陳造','宋','宋诗','song-poetry','','[]','畫工神品今代無，祁岳一脈傳醉胡。',160,'全唐诗/poet.song.150000.json','["畫工神品今代無，祁岳一脈傳醉胡。", "幾年傲睨不落筆，乘興掃出赤縣圖。", "今君所寶亦第一，我疑神遇非有筆。", "青林紅葉晚未暝，遥山遠水秋一色。", "五猿踞石相因依，兩猿挂樹松枝低。", "仰睇側顧麞善疑，其二行齧如不知。", "昔人畫馬師廐馬，畫山直付居山者。", "野猿不馴麞易驚，邈影渠能寫閒暇。", "草露空荒遠刀几，即今放麑誰氏子。", "山蜂負毒不足憐，盍貸蠨蛸留報喜。"]'),
('e8c7458a-de37-499a-bbe8-957c8e3019d1','百花樓','陳造','宋','宋诗','song-poetry','','[]','樓中香漂百和濃，樓下錦纈翻東風。',64,'全唐诗/poet.song.150000.json','["樓中香漂百和濃，樓下錦纈翻東風。", "玉樽美酒清若空，吳姬粧面相映紅。", "人生一笑不易得，是間一醉千金直。", "元龍百尺君勿論，芳時且可金杯側。"]'),
('ad992dfd-d39e-45c7-a674-f854262f7849','題劉明府所藏秋江欲雨圖','陳造','宋','宋诗','song-poetry','','[]','墨雲含雨江空濛，島嶼細瑣連煙空。',176,'全唐诗/poet.song.150000.json','["墨雲含雨江空濛，島嶼細瑣連煙空。", "我家茆屋菰葦叢，卷蓑背笠隨漁翁。", "展掩倍覺心神融，緬想慘澹經營中。", "王孫玉面食肉相，萬里山川入遐想。", "當時宮禁斷過逢，可得如儂逞江望。", "江天漠漠那容畫，渺莽風烟生筆下。", "鳬鴻滅沒波不摇，霧墅霜林共蕭灑。", "乃知絕藝神與通，般薄傲睨窺化工。", "市師日日江湖上，幾人擅價能無窮。", "君家雙蓮冰玉質，此畫與人俱第一。", "固應緘鐍付牢收，俗眼紛紛莫輕出。"]'),
('26e4c871-dfda-4ee9-8633-08ec0d06d0f8','送項平甫教授之成都','陳造','宋','宋诗','song-poetry','','[]','昔人石穴命西蜀，豈知桃源華胥隠石腹。',228,'全唐诗/poet.song.150000.json','["昔人石穴命西蜀，豈知桃源華胥隠石腹。", "詩人昔吟蜀道難，何曾錦城風物平時看。", "平時風物今猶故，井絡坤維神所護。", "漢官威儀二百年，斬新不受胡塵污。", "蜀民日爲藥市遊，家說追歡不說愁。", "蜀人之文落中州，中州傖父縮頸羞。", "吾徒向來夢遊處，今日登僊送君去。", "遨頭上客人所敬，翰林先生士知慕。", "似聞儒冠不容假，挽致鄒魯無難者。", "况君筆力西漢前，亟遣人才有揚馬。", "錦城之樂樂未涯，綠鬢朱顔君更佳。", "要奉板輿追勝日，暮萬里橋朝浣花。", "古今勝槩爭入眼，歸軒日日詩囊滿。", "黄鵠東飛定有書，莫靳珠璣祇推懶。"]'),
('26c5c991-ea27-48f0-a77c-8ac6527928eb','題欽廟主器時所作登瀛圖','陳造','宋','宋诗','song-poetry','','[]','唐家大府開天策，祖廟工歌登七德。',226,'全唐诗/poet.song.150000.json','["唐家大府開天策，祖廟工歌登七德。", "僞王連組𥿊頸歸，山東羞死虬鬚客。", "文儒濟濟陪英遊，海內共指登瀛洲。", "未妨濫吹一延族，中有謀斷皋伊流。", "崇寧聖人撫洪業，黄頭遺種初芽蘗。", "青宮進講多暇日，睿情遠覽思才傑。", "水墨落紙分毫釐，心融筆忘天運機。", "鸞翔鵠峙儼在目，更用褚亮摛辭爲。", "天翻地覆人得知，神京北風吹皁旗。", "空令便橋乞盟未央酒，盛事拂膺正觀時。", "天家所寶君家得，拜手披圖悼今昔。", "鼎湖龍去餘弓劍，上林鴈來斷消息。", "莫年筆力猶枝梧，慣題七騎陰山圖。", "爲君斲句偕畫往，貸我老淚淋衣裾。"]'),
('bf23e175-8299-4dc0-9cf4-640c8649be6f','布穀吟','陳造','宋','宋诗','song-poetry','','[]','潑袴不容脫，鳥語徒殷勤。',232,'全唐诗/poet.song.150000.json','["潑袴不容脫，鳥語徒殷勤。", "輸租質農器，有袴那解新。", "官中催科吏如虎，告時趣耕爾能許。", "即今春種未入田，安得縣胥知愧汝。", "卑棲俛喙良易謀，聒聒彊任田家憂。", "啼時未旦夜不休，班班血痕銜口頭。", "人將近似測禽語，汝意真解憂農不。", "或傳悍妻天所怒，姑不可撾渠不顧。", "罰爲此鳥聲曩愆，警世毋爲郭家婦。", "南方諛佛古到今，人持數珠家梵音。", "區區說似一百八，譏訶勸相知何心。", "浙風淮俗隔江水，意解禽言乃如此。", "蘇黄妙句誰嗣之，兩地流傳併須紀。", "世間儒墨紛相攻，巨細彼此臧穀同。", "爭如痛飲卧長晝，付渠馬耳射東風。"]'),
('0abc9414-a5a0-4bae-9bf5-5734f0707e4e','薄薄酒','陳造','宋','宋诗','song-poetry','','[]','薄薄酒，顔可丹。',319,'全唐诗/poet.song.150000.json','["薄薄酒，顔可丹。", "麤麤布，身不寒。", "醜醜婦，貧相歡。", "人生浪悲行路難，欲不外騖心內安。", "富貴底用極力奸，政自沐猴求棘端。", "君不見寒儒骯髒默自守，橫前書笈，燕坐甕牖。", "麻畦可衣，秫田可酒。", "抽針紉綻，侑罇鼓缶。", "齊眉結髮，頼有此婦。", "人不裂眥，事無掣肘。", "陶陶此興殊未窮，一身易足天地中。", "巷東畢公子，爲樂渠能同。", "宅舍頗軒亭，園池亦花草。", "相過便開樽，掀髯寫懷抱。", "蘭芳菊秀梅含春，拂翠勻紅隨分好。", "乏愛不無苧衣贈，取醉何妨接䍦倒。", "畢公子，吾之樂兮樂自如。", "一盃對婦兮，布衣蔽其軀。", "君之樂兮樂有餘，妓女能楚楚。", "罇罍應指呼，醉鄉寬閑兮吾得俱。", "設侍以金谷傾城之艷姝，酌以宜城九醖之醪敷。", "被狐白兮擁羅襦，朝歌暮燕，窮歡極娛。", "婪酣佁儗驕妻孥，外若豐澤中槁枯。", "吾不彼願猶彼不吾羨。"]'),
('c8cd111a-e9f1-4b79-9cd7-cd71b37f6088','讀師文和郡侯喜雨詩次其韻','陳造','宋','宋诗','song-poetry','','[]','濤波襄陵尚霖雨，龍伯不省田家苦。',320,'全唐诗/poet.song.150000.json','["濤波襄陵尚霖雨，龍伯不省田家苦。", "官中出鏹瘞流尸，內地之民無宅土。", "京邑本根枝外邦，渠儂枵虛闖官倉。", "流亡可飽骨可肉，縣官仁愛吏慈祥。", "古來畏天災無小，迄令百顰餘一笑。", "陽愆陰伏誰致此，共說羣憸投有昊。", "一昨雩禱飯不葷，神祠佛屋香炷氳。", "霓望朝昏耐跼蹐，風傳真贋長紛紜。", "我歸得同郡人樂，愍農喜雨收奇作。", "想摩鯨牙凌浩蕩，更穿月脅翔遼邈。", "吾邦不熟農告功，溜匙雲子行沾儂。", "小兒解謝倩人誚，搜鎸徑欲分吾窮。", "乃公拙無尺一召，他日當歸有先兆。", "耕先耘後計未失，誰謂山林迹如掃。", "世人二五不知十，赴爭奪場不遺力。", "分表營營竟何補，截趾適屨山藏澤。", "黄堂詩老民所天，秋來衢路有醉眠。", "樂職未賦吾歉然，人言此筆須臞仙。", "小草可錄寸有長，會從之遊據胡床。", "蜂腰鶴膝容探湯，借兒茹胾升公堂。"]'),
('df9ddf38-c58f-4f63-95b8-4e224d0058fe','娟峰','陳造','宋','宋诗','song-poetry','','[]','當年金華小家兒，神遊九天狹八維。',232,'全唐诗/poet.song.150000.json','["當年金華小家兒，神遊九天狹八維。", "房陵之山秀而奇，蔚藍一山羣山推。", "兒肯下顧停軿輜，珠貝作宮瓊門楣。", "門前亂石無津涯，一叱轉眼羊萬蹄。", "羒羝𦍩羯紛躨尼，蹲鳴踞齧供兒嬉。", "有褐之叟鬢已絲，似黠非黠癡非癡。", "傲睨竊覘兒所爲，掉臂席卷靡孑遺。", "一盃見罰兒釂巵，亟鞭風馭還瑶池。", "幻變起滅荒是非，彼此失得誰成虧。", "即有而無道乃幾，仙者狡獪人得知。", "以偷而名真見疵，我來訪古求端倪。", "山吾良友兒吾師，嘉木異石相因依。", "如刻如椓如鬢眉，名峰以娟吾始之。", "爲丐片石儻可碑，更遣子虛摛厥辭。", "此兒此叟當解頤。"]'),
('34ef3579-dc8b-4e02-82b6-a6ca099efc24','墾山叟','陳造','宋','宋诗','song-poetry','','[]','雜木漫山誰所種，居不臨流多不用。',136,'全唐诗/poet.song.150000.json','["雜木漫山誰所種，居不臨流多不用。", "九月霜風捲黄落，羣山一昔皆班駮。", "遥看拖帔橫椽衣，農家刈粟山有畦。", "家家墾田日嫌窄，荒林翳薈惜虛擲。", "斸荒作熟不挂籍，輸官之餘給衣食。", "州中之政常近厚，不欲屑屑校升斗。", "寧其棄之聽民取，實亦藉是作康阜。", "繼承不皆惠慈守，汝須彌縫吏胥口，防有後來規稅畝。"]'),
('acc42702-d68f-4fdd-8e82-72705460656e','竹米行','陳造','宋','宋诗','song-poetry','','[]','竹君亢宗擅楚墟，一一脩聳山澤臞。',216,'全唐诗/poet.song.150000.json','["竹君亢宗擅楚墟，一一脩聳山澤臞。", "風流秀整與世殊，楚俗食息皆爾須。", "薪之籬之且籧篨，笲筥箱篚䉉籃笯。", "溝瓦厥祖羹其雛，隨索斯獲掇諸塗。", "今歲麥秋旱歲餘，得麥僅足償官租。", "竹君憫農如士夫，著花結實千林俱。", "密砌玉粒綴旒珠，株株擷取雖錙銖。", "彌頃亙畝無閑株，磑磨蒸炊勝雕胡。", "鄰里乞索水火如，坐令顰蹙興歌呼。", "野叟好事能分吾，香清而洌甘而腴。", "此君行能不一書，此惠及物旋就枯。", "摩頂放踵忘其軀，所學無乃墨者徒。", "老子苟祿天之隅，袖手無策蘇𡞦孤，投匕三嘆吾慙渠。"]'),
('2fe3e8f1-08a5-45cf-85c5-1694c832fac9','聞舒州書生聚衆爲盜','陳造','宋','宋诗','song-poetry','','[]','邊頭僅絕胡塵警，頻年麥秕禾不穎。',224,'全唐诗/poet.song.150000.json','["邊頭僅絕胡塵警，頻年麥秕禾不穎。", "淮民久矣困憔悴，淮俗豈常藏不逞。", "槌鑪血馬中夜呼，劫吏驅民刃加頸。", "吾民苦旱無生意，更復跳梁汝爲梗。", "堂堂王度無玷缺，赫赫軍容仍暇整。", "前年蜑戶煽凶威，長蛇封狶摇湖嶺。", "元戎白羽纔一揮，欲丐微生一無幸。", "爾曹么麽真癬疥，天網莫倚容蛙黽。", "昧逐青蟲干斧鑕，盍辭綠林救要領。", "鯨鯢虀粉有前戒，儻被皇恩各鄉井。", "旱魃逞妖民倒垂，廟堂聖賢自司命。", "徑須委節發陳廩，少息流離服頑橫。", "勸分己責可次第，庶援沉焚痊國病。", "正資方岳佐堯禹，側佇剡章伸此請。"]'),
('2d7c890e-ad2c-471f-af3a-ef1ebe7e2621','田家嘆','陳造','宋','宋诗','song-poetry','','[]','五月之初四月尾，菖蒲葉長楝花紫。',144,'全唐诗/poet.song.150000.json','["五月之初四月尾，菖蒲葉長楝花紫。", "淮鄉農事不勝忙，日落在田見星起。", "前之不雨甫再旬，秧疇已復生龜紋。", "近者連朝雨如注，麥隴橫雲欲殷腐。", "如今麥枯秧失時，舉手仰天禱其私。", "秧惡久晴雨害麥，兼收并得寧庶幾。", "餠托登盤米藏庾，儂家歲寒無重糈。", "豈知送日戴朝星，凡幾憂晴幾憂雨。", "吾儕一飽信關天，下筯敢忘田家苦。"]'),
('39f92781-b80a-441c-a862-5deb475c373c','寄馮尉','陳造','宋','宋诗','song-poetry','','[]','我遵兔徑西山麓，荆棘鈎衣塵瞇目。',176,'全唐诗/poet.song.150000.json','["我遵兔徑西山麓，荆棘鈎衣塵瞇目。", "憐渠此地費流光，君亦風餐并露宿。", "遺蝗蹢躅無地皮，田禾蠶食猶孑遺。", "洊饑可念勞可忍，君自坦坦人憐之。", "繁昌亂山僅容鏬，一一到我馬蹄下。", "南村喫飯宿北村，罷極憑詩寫悲唶。", "即今不作勞者歌，器識視我幾倍過。", "脫身箠楚吾已多，簡書趨走子如何。", "皇家獵雋張雲羅，長安知己肩相摩。", "五雲深深護臺閣，縹緲羣僊依碧落。", "即看郭振起通泉，應笑卑陬郡文學。"]'),
('cf10a16b-3eef-489f-aa9a-e6f4f3b5ea87','鸛带箭行','陳造','宋','宋诗','song-poetry','','[]','城邊鸛城棲，水食衣楚楚。',132,'全唐诗/poet.song.150000.json','["城邊鸛城棲，水食衣楚楚。", "欲鳴不鳴候天雨，此肉胡宜登鼎俎。", "柳營子弟弓石八，南山之石猶飲羽，如汝正可虛弦取。", "血毛分披誰汝憐，低摧直訴使君前。", "使君德意孚魚鳥，全汝之生令汝飽。", "徐行側睨若無旁，飲潔啄腥近臺沼。", "使君暫擁山城麾，詔音不日遄其歸。", "矢來無鄉汝誰依，江湖粗飽莫卑飛。"]'),
('8fb94340-55d2-4a06-8c98-ff4ff730e489','送瑞蓮新米白酒與韓監倉','陳造','宋','宋诗','song-poetry','','[]','珍珠滴紅敵紫腴，君家寶此如珍珠。',64,'全唐诗/poet.song.150000.json','["珍珠滴紅敵紫腴，君家寶此如珍珠。", "我家玉友亦勝友，論交遣到君座隅。", "秋蓮結實甘勝蜜，香粳薦新玉爲粒。", "遥知毫末不及賓，一笑聊同孟光喫。"]'),
('e9e645c7-5bf6-4e6f-8b47-96b6d4e53fcc','招鄭良佐','陳造','宋','宋诗','song-poetry','','[]','向來聞名思見面，常恨東西異鄉縣。',64,'全唐诗/poet.song.150000.json','["向來聞名思見面，常恨東西異鄉縣。", "即今去我一葦航，亦復經年不相見。", "重陽佳辰可虛辱，橙香蟹肥家釀熟。", "相過一醉猶待速，爲君已約東籬菊。"]'),
('e96d1a6f-1291-435c-8e8f-73ee646a3016','臘茶并三詩送李元誠  其一','陳造','宋','宋诗','song-poetry','','[]','池魚千里磨蟻旋，人生出處俱可憐。',64,'全唐诗/poet.song.150000.json','["池魚千里磨蟻旋，人生出處俱可憐。", "束書結鄰晏溪側，淮安一寤三十年。", "積今成古閲飛電，我與昔人同此嘆。", "悲歡離合置勿論，且喜重逢各彊健。"]'),
('a6bac490-95b8-446d-bc91-ba3ac190d870','臘茶并三詩送李元誠  其二','陳造','宋','宋诗','song-poetry','','[]','向來衮衮論風期，百年心事多好違。',64,'全唐诗/poet.song.150000.json','["向來衮衮論風期，百年心事多好違。", "君如荆石尚衷璞，我似野馬初受羈。", "射陽廣陽水雲屋，襄城郵城塵土衣。", "俛眉作吏一不遂，丘壑付君未覺非。"]'),
('00173b77-9c07-445f-99ca-3b02918f4703','臘茶并三詩送李元誠  其三','陳造','宋','宋诗','song-poetry','','[]','北風吹霜戰林樾，菊花彫零梅未發。',64,'全唐诗/poet.song.150000.json','["北風吹霜戰林樾，菊花彫零梅未發。", "留君無物供吟筆，一炷沉煙伴清絕。", "騷人悲悽爲摇落，舟挽不回仍此別。", "還家試碾壑源春，何似盧郎三百月。"]'),
('80e03fb2-4fc0-4d30-bb54-b050d3f81ac5','喜雪六首  其一','陳造','宋','宋诗','song-poetry','','[]','寒空黯慘塞不開，簁瓊屑玉卷地來。',64,'全唐诗/poet.song.150000.json','["寒空黯慘塞不開，簁瓊屑玉卷地來。", "乾坤變滅定何意，風爲披拂雲剪裁。", "和聲載路天亦喜，簸弄花絮爲春臺。", "了知麥秋更好在，老農指此豐年媒。"]'),
('8af9c138-f167-4601-82c7-f82a3ffd4b47','喜雪六首  其二','陳造','宋','宋诗','song-poetry','','[]','平明僮奴更笑呼，羣飛掇取如拾塗。',64,'全唐诗/poet.song.150000.json','["平明僮奴更笑呼，羣飛掇取如拾塗。", "僵鳶窘兔真鮮腴，勸汝貸此驚啼烏。", "巢營卯伏知念母，一一向來反哺雛。", "梟獍縱橫鳳高引，殄滅此族寧良圖。"]'),
('a1af468a-0854-4235-8e09-fbb63ae92095','喜雪六首  其三','陳造','宋','宋诗','song-poetry','','[]','玉龍睡起長風激，盡蛻玉鱗漂八極。',64,'全唐诗/poet.song.150000.json','["玉龍睡起長風激，盡蛻玉鱗漂八極。", "蓬仙帝女聚瑶臺，剪水效祥誰所役。", "或疑天公陋塵域，幻作冰壺供一劇。", "是耶非耶竟莫知，杯酒聊容曲身直。"]'),
('a8b3521f-3f0a-40c4-9b6b-5eba4e1a2940','喜雪六首  其四','陳造','宋','宋诗','song-poetry','','[]','淮春之樓高突兀，憑欄小耐寒如割。',64,'全唐诗/poet.song.150000.json','["淮春之樓高突兀，憑欄小耐寒如割。", "平湖穹山兩西子，愛此鮮粧巧塗抹。", "回首斜陽照屋梁，玉際坤輿尚摧壓。", "今宵更呼甓社龍，高挂明珠照空闊。"]'),
('d8d1a0fa-9b60-409d-bb14-e0be6a38fd0a','喜雪六首  其五','陳造','宋','宋诗','song-poetry','','[]','去年孰不蘇捐瘠，今年已餘四鬴食。',64,'全唐诗/poet.song.150000.json','["去年孰不蘇捐瘠，今年已餘四鬴食。", "自公之來適吾願，挽回太和壽此域。", "一旬再雪近歲無，日日歡謠沸阡陌。", "瓦溝待泮亦不惡，要趁春前作三白。"]'),
('3e273b19-4c2c-4a6a-aec2-7474a6423a51','喜雪六首  其六','陳造','宋','宋诗','song-poetry','','[]','南鄰賞雪珠箔褰，紅爐綠酒圍嬋娟。',67,'全唐诗/poet.song.150000.json','["南鄰賞雪珠箔褰，紅爐綠酒圍嬋娟。", "北鄰飛雪灑枕席，擁戶亭午無炊煙。", "袁安吻燥屋不補，東郭足皸履已穿。", "嗚呼悲歌兮歌且止，安得薪炭如蓬酒如水。"]'),
('6c216c30-6518-4bb1-85dc-21870bb61ebb','東園詩寄興化吳從道','陳造','宋','宋诗','song-poetry','','[]','溪流抱玦園亭裏，三面欄干壓清泚。',160,'全唐诗/poet.song.150000.json','["溪流抱玦園亭裏，三面欄干壓清泚。", "養花種竹今幾年，紅紅綠綠皆風煙。", "黑頭主人富文墨，隙地營園喜留客。", "去年香霧摇東風，藉花一醉君見容。", "翡翠拂衣蝶窺酒，歸時簷牙挂星斗。", "有物繫足寒前盟，徙倚東風空復情。", "歌前酒所何限意，黄鸝應說鷗應記。", "一春不風即蜚雨，曾奉親輿賞花否。", "向來券游付夢雲，向來券負今償君。", "濡毫却嘆無好語，說似能詩葉明府。"]'),
('88bf31fc-2edd-4366-b609-8b81a117a6c8','葉進卿寄和章次韻復之','陳造','宋','宋诗','song-poetry','','[]','君文如泛濤淵裏，方快驚瀾忽清泚。',160,'全唐诗/poet.song.150000.json','["君文如泛濤淵裏，方快驚瀾忽清泚。", "手抄口誦欲忘年，小窗長日銅爐烟。", "端宜飲我三斗墨，有底向人矜此客。", "平生歌頌仍歌風，寬柔靜直能形容。", "心知公瑾勝醇酒，人仰韓公真北斗。", "詞壇正倚君主盟，筆驅化工鉤物情。", "詩來得我玩世意，刻石便當幽居記。", "兒曹轉手作雲雨，陳雷輸心可人否。", "中牟報政徑青雲，此老洗眼久徯君。", "重逢首理車笠語，定指渠儂笑城府。"]'),
('4608ef46-d38b-400b-b514-c5432bb65098','再次韻酬葉進卿','陳造','宋','宋诗','song-poetry','','[]','病翁耐病杯杓裏，鼠矢壓書毫不泚。',160,'全唐诗/poet.song.150000.json','["病翁耐病杯杓裏，鼠矢壓書毫不泚。", "眼中凜凜黄初年，讀詩意欲凌紫煙。", "君才王佐綬猶墨，公外從容作詩客。", "心期與俗馬牛風，化頑惠弱清而容。", "不學玄明剛制酒，不學陶公辭五斗。", "斯民信君如詛盟，飲羊攫金皆用情。", "聖皇旰食求賢意，姓字今應御屏記。", "太微清都上雲雨，鹽梅調鼎極可否。", "一艇付我眠溪雲，詠歌太平橫紫君。", "十行看君拜天語，去酌天漿列仙府。"]'),
('0b2d4dcd-04e3-4b4d-b59b-348fbfc0a4cc','次韻寄葉進卿','陳造','宋','宋诗','song-poetry','','[]','回車記我君能賢，席門忽下鳬背僊。',128,'全唐诗/poet.song.150000.json','["回車記我君能賢，席門忽下鳬背僊。", "參辰相避徒自惜，但有妙語邦人傳。", "阿戎齒錄雖牽聯，陸沈父書如縛禪。", "題鳳不寘嵇喜下，殺鷄容羞季路前。", "才名放君一頭出，高山可仰井用汲。", "小兒弄筆不及嗔，顧捐鄭璞收和璧。", "作十日飲當有時，岸花水芝皆可詩。", "祗憂老氣不復振，挑大國楚提偏師。"]'),
('6147df2c-b291-4cb0-96f4-be881751743e','再次韻酬進卿','陳造','宋','宋诗','song-poetry','','[]','平生友仁今事賢，長裾每侍黄堂仙。',128,'全唐诗/poet.song.150000.json','["平生友仁今事賢，長裾每侍黄堂仙。", "東方一士復石友，平安幾見郵音傳。", "斬新好語來翩聯，當念醉叟方逃禪。", "亦知平處古人上，更卜氣蘇君子前。", "敢辭敝帚爲君出，眢井塵生不受汲。", "但思共坐蓮蕩風，雲錦明船月升璧。", "把酒一歡當及時，定拚費日仍費詩。", "轉頭相望便淮浙，已辦僱直呼篙師。"]'),
('54f79afa-73e3-4f0c-ad15-9f2bafb303b1','喜雪篇','陳造','宋','宋诗','song-poetry','','["\u592a\u6e56"]','玄冥職寒事，庀職今幾時。',338,'全唐诗/poet.song.150000.json','["玄冥職寒事，庀職今幾時。", "窮秋試雪似早計，冬令欲盡噤莫施。", "風聲不怒日車近，客裘未綿河未澌。", "吳門十萬家，心口同一疑。", "天公行四序，暑寒各有宜。", "歲云暮矣未見雪，嗣歲何以銷疹疵。", "或云太湖龍，避靜扃神扉。", "把弄明月坐貝闕，世間休戚吾何知。", "瑶臺十二層，列坐萬玉妃。", "屑瓊翦水亦戲事，仙界運指想不龜。", "徒勞望切切，終竟來遲遲。", "芹宮冰氏翁，見與俗異岐。", "亦知仙人不作省事過，龍公肯如游惰兒。", "顧此千里間，司命付吏師。", "拊摩窮日力，日究仍夜思。", "向來裸露各溫燠，一衾一絮公手之。", "趙衰之日周比屋，更以晴日相融怡。", "黄童白叟歌且舞，和聲協氣塤應箎。", "羣仙飄然下，龍亦赴指麾。", "先之汛灑五日雨，一雪不待公有祈。", "花作坻壠絮作陣，雪爲翦刻風爲篩。", "豈直冬溫要彈壓，抑令宿麥蒙沾滋。", "去年豈無雪，雪神春不歸。", "賑施不預計，熟視民饑羸。"]'),
('71aec63f-89f1-4aaf-af60-cb400ec00eef','次郭祕正韻','陳造','宋','宋诗','song-poetry','','[]','伊昔乃祖使朔幽，艱難以來無此流。',208,'全唐诗/poet.song.150000.json','["伊昔乃祖使朔幽，艱難以來無此流。", "節旄欲盡氣彌厲，始元屬國真其疇。", "清篇神護到江表，河梁訴別豈所侔。", "嗣孫學力有家法，洪毅不割清不浮。", "驥子受轡抹燕越，粉袍長鋏猶小留。", "人稱張籍好古淡，我愛趙壹辭伊優。", "往之論交恐避俗，是人摇颺如綴旒。", "長年閔默墮俗學，夙志顧省傷羈囚。", "頎然扣門出新作，山奇海祕困窮搜。", "頃從同盟漫著脚，欻遇强對須抽頭。", "吾鄉巨擘子龔子，磊塊貯腹皆陽秋。", "麗唱妍和日九返，君腕脫矣盍少休。", "惡語送似定一笑，共笑燕石酬精璆。"]'),
('d0c0631a-a61b-45f5-9c9e-5b9738a5c4ad','試俞珣筆呈羅大著','陳造','宋','宋诗','song-poetry','','[]','市工營營有工拙，珣也旁睨裁一吷。',80,'全唐诗/poet.song.150000.json','["市工營營有工拙，珣也旁睨裁一吷。", "扣門屬我祗厚顔，結字著書無一愜。", "繡衣仙人歸告猷，盍收此長助毫髮。", "青霄政須立螭珥，黑頭當看獲麟絕。", "豐功被世名不滅，珣亦歸裝倒明月。"]'),
('04cd9251-44ef-4973-b365-01085b2ca5bd','春雨寒甚作長句','陳造','宋','宋诗','song-poetry','','[]','白龍天飛宜莫測，吳儂解數歸消息。',160,'全唐诗/poet.song.150000.json','["白龍天飛宜莫測，吳儂解數歸消息。", "年年青帝發生時，似妬園林春動色。", "西山龍母誕彌月，歸覲親顔供子職。", "壽觴瓊醴俗共傳，玉鱗素鬐誰所覿。", "酸風鼓寒苦霧塞，行人縮頭欲僵立。", "蛟鼉凍蟄大水拔，更問嬌紅并眉白。", "閉門三夜淙簷雨，起視溪流高數尺。", "去年夏秋走祈禜，雲電收藏日血赤。", "農家倚鋤望眼穿，白汗呀流地龜拆。", "天可問，曷不遣，兩龍此時會生日。"]'),
('0e28f5cb-5869-4b4e-b338-803eb02462ed','王秀才亦愛軒','陳造','宋','宋诗','song-poetry','','[]','王郎一室天地中，客來有榻樽不空。',64,'全唐诗/poet.song.150000.json','["王郎一室天地中，客來有榻樽不空。", "奉親一笑辦能事，插架萬軸收新功。", "男兒磊落四方志，况子郎罷方詩窮。", "亟書周庸賜漢第，可用容膝師陶翁。"]'),
('ac4d54d2-ffcc-4736-8294-c58dc1aea68e','寄鄭良佐','陳造','宋','宋诗','song-poetry','','[]','書生著書貪日課，文士賣文救窮餓。',195,'全唐诗/poet.song.150000.json','["書生著書貪日課，文士賣文救窮餓。", "青樓歌酒屬富兒，不意此名君乃荷。", "風波平地自誰始，一倡從知百人和。", "東魯男子舊蹤謹，南郡諸生底逋播。", "平安敢煩街吏報，潔白長賡楚人些。", "流言不計兩曾參，機上慈親枉驚墮。", "阮舍尤須辨南北，杜冠可無分小大。", "寧知宋玉笑登徒，或指宣尼作陽貨。", "璧亡誤使張儀去，兵利徒爲少卿禍。", "違從兄食祇厚誣，償同舍金聊引過。", "無黥可息劓可補，未信白璧青蠅涴。", "君不見吾宗孟公士所傾，亦有俗子驚人坐。"]'),
('1ab91709-7604-4470-9726-a8560a07635d','贈龔養正二首  其一','陳造','宋','宋诗','song-poetry','','[]','思君不辦一再過，束書謝客方卧痾。',64,'全唐诗/poet.song.150000.json','["思君不辦一再過，束書謝客方卧痾。", "不爲儒林丈人地，可耐造物小兒何。", "我亦病氣剛制酒，自春迄秋在告多。", "幾時蹁躚數訪我，爲君快作鯨飲河。"]'),
('b0371205-b97d-416b-9067-b887c45827d5','贈龔養正二首  其二','陳造','宋','宋诗','song-poetry','','[]','百骸綴聯等非實，調虞小愆諸病入。',64,'全唐诗/poet.song.150000.json','["百骸綴聯等非實，調虞小愆諸病入。", "忘三彭仇念昔聞，作五禽戲瞢此術。", "吾身甚羸心甚安，妻孥已捐今昔觀。", "平生學力外生死，砭劑求工聊復爾。"]'),
('1302ffc6-5bbd-468b-a891-ea3686168f32','次韻嚴上舍讀書目昏','陳造','宋','宋诗','song-poetry','','[]','聲利營營閲蜚電，人生悲歡更幾遍。',112,'全唐诗/poet.song.150000.json','["聲利營營閲蜚電，人生悲歡更幾遍。", "羣兒沈迷如病酲，尚念醇醪夢酣醼。", "吾儕較之唯阿爾，書淫僅逃紅綠眩。", "短檠半世課蠅頭，老閲舊藏紛莫辨。", "近從損讀得奇方，穩坐幽窗憩吾倦。", "嚴侯著書定千載，尚向枯策求聞見。", "可無一洗竇郎癡，捉筆因君拂塵硯。"]'),
('6f33d502-8c8d-4822-b64f-08c7f618e63d','謝韓幹送絲糕','陳造','宋','宋诗','song-poetry','','[]','玉顆瑩澈珠就磋，吳鄉早秔莫計過。',288,'全唐诗/poet.song.150000.json','["玉顆瑩澈珠就磋，吳鄉早秔莫計過。", "無乃風露秀結異，移種崑崙之水禾。", "君家厨婦窮百技，三舂九淅付重羅。", "銀絲萬尋忽縈積，中疎外潔生搓挼。", "扶桑仙蠶大如盎，繰之本供織女梭。", "怳驚萬喙鬭新巧，罥作米茸雪網窠。", "即今擬形供食事，纖手幻出千絇多。", "倒甑入筯第三絕，色香兼味皆可歌。", "周官賓祭珍飺餌，有此復具理則那。", "詩翁物色及粔𥹡，得此來前當見訶。", "鱠盤漫詫金縷飣，湯餠徒夸銀線窩。", "瓊酥玉膩信非匹，胡麻崖蜜仍相和。", "感君泛愛記衰朽，回首一笑分餘波。", "腐儒口實長作累，饞噇之名定不磨。", "金山別去每挂夢，老眼復見還雙摩。", "婪酣得飽問便腹，如汝平生相負何。", "更從公子乞方法，日當飫之老澗薖。", "買田二頃不種秫，未怕酒客來操戈。"]'),
('c39bc501-dfcf-447a-aa43-740f5705d173','韓守松卿索近詩','陳造','宋','宋诗','song-poetry','','[]','昔人技成嘆屠龍，似我五字躭雕蟲。',128,'全唐诗/poet.song.150000.json','["昔人技成嘆屠龍，似我五字躭雕蟲。", "鎸肝搯腎探戃恍，半世不辭詩得窮。", "詩成頗訝神與力，疇昔夢中分五色。", "援毫動作萬鈞斡，應俗何曾一錢直。", "豪韓有句當千年，取世所遺政自賢。", "數篇蜚向青眼邊，可復把玩盤中圓。", "君家十頃圍翠密，近榭遠亭如畫出。", "時須喚我一罇同，笑對風煙揮此筆。"]'),
('891da08d-6f0f-427d-bb4e-32397909aad8','食晚菘新筍','陳造','宋','宋诗','song-poetry','','[]','化兒出奇安此腹，不稱智囊不盛肉。',128,'全唐诗/poet.song.150000.json','["化兒出奇安此腹，不稱智囊不盛肉。", "饑雷收聲纔脫粟，薦以藻芹仍杞菊。", "園丁可是監河侯，供我朝昏三畝綠。", "即今春菘晚不衰，况復桂筍森可束。", "含烟带露不相下，拄腹撐腸未云足。", "食單一日得一雋，回首常嗜真輿僕。", "殿春日月官上速，日擷芝莖剝纖玉。", "風排雨浥猶須卜，卧作枯荄起成竹。"]'),
('d374257c-91c7-40fc-806c-2dc73b15e4e7','題姑蘇南道者庵','陳造','宋','宋诗','song-poetry','','[]','城南路長勤往返，迎送何由貸吾嬾。',64,'全唐诗/poet.song.150000.json','["城南路長勤往返，迎送何由貸吾嬾。", "向來紅葉撲吟袍，重到綠秧圍望眼。", "有人閲世風前蓬，年年客我此庵中。", "問津莫問庵中翁，貝葉結伴渠陽聾。"]'),
('edc8226c-3edc-44a6-9b6b-09ff79924d37','贈鹽城諸友','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','泉脈不通海濱土，人家轆轤上鹹鹵。',163,'全唐诗/poet.song.150000.json','["泉脈不通海濱土，人家轆轤上鹹鹵。", "新秔本自玉爲粒，薦熟便如猩血煮。", "初嘗已嘆失香味，久食更憂戕肺腑。", "城西禆海百頃寬，紺碧瀰瀰含霧雨。", "我者艤柂酌清泠，潔比盤冰味牛乳。", "得非天意補此乏，跬步可𣂏殊不苦。", "但令十舟玄津致，坐遣千室皆甘茹。", "迄今俗習不自拔，如食置傍饑不取。", "銅章師帥盡時賢，盍有教條祛惰窳。", "君不見樂天六筦挽西湖，惠利可容今愧古。"]'),
('19b96f85-bd2e-4273-9a34-1d4b1ce248b6','歸自淮南雪行呈張鹽袁憲','陳造','宋','宋诗','song-poetry','','[]','歲星逼歲回躔吳，吳兒不用憂旱枯。',224,'全唐诗/poet.song.150000.json','["歲星逼歲回躔吳，吳兒不用憂旱枯。", "社鬼雨師當率職，雪龍已復隨指呼。", "百年眷屬無寧居，崩騰膠葛周太虛。", "翻雲挾雨動十日，灑潤及物無遺餘。", "帝意嘿與皇心符，屢豐政欲𡞦鰥蘇。", "鳳麟告瑞底用此，粟麥充腹可使無。", "節物破臘催謝徂，挽回和氣浮洪爐。", "熏煙已告佛供罷，壽斝想見皇情娛。", "漂然一舸將腐儒，風前壞席爭長塗。", "乘凌繽紛入縹緲，俛仰色界行畫圖。", "平生壯觀老不孤，今段造物真娛予。", "擬從玉妃助剪水，徐與帝子看積蘇。", "天僊著我白玉壺，應笑袖手毫不濡。", "歸從繡衣兩詩伯，照夜更掇驪龍珠。"]'),
('69adf15e-56ed-4e95-8ff8-ce9d659d7568','龍泉','陳造','宋','宋诗','song-poetry','','[]','神龍媚此清淺居，欻然騰陵行太虛。',64,'全唐诗/poet.song.150000.json','["神龍媚此清淺居，欻然騰陵行太虛。", "越民倚頼龍沾濡，頻年歲事勝三吳。", "至仁一視無戚疎，置彼此及心缺如。", "嗟龍自伐端欺予，淮南之民如渴烏。"]'),
('ce23b4ea-bfdd-49c5-af9c-d8b7c00a12b1','登龍泉山','陳造','宋','宋诗','song-poetry','','[]','越山東來萬煙鬟，餘姚爲邑山四環。',64,'全唐诗/poet.song.150000.json','["越山東來萬煙鬟，餘姚爲邑山四環。", "客車細穿市井間，邑屋更繞龍泉山。", "佛閣翬飛最高處，遠近嵐霏隨指顧。", "小留開船有新句，君知可是囚山賦。"]'),
('5c3a9568-ce93-4dbc-94b3-ad48607d811a','丈亭','陳造','宋','宋诗','song-poetry','','[]','小江隨山巧回互，轉首碧流分兩股。',64,'全唐诗/poet.song.150000.json','["小江隨山巧回互，轉首碧流分兩股。", "丈亭繫纜待潮生，徙倚纔容一炊許。", "潮信曾何差頃刻，固應作意憐行客。", "爲誰東去爲誰西，酌酒殷勤酬河伯。"]'),
('9a2af3b1-3c42-444d-912a-5491b3d8f2d7','癸丑勸耕凈居','陳造','宋','宋诗','song-poetry','','[]','十五里近車不驅，凈居之役良舒徐。',192,'全唐诗/poet.song.150000.json','["十五里近車不驅，凈居之役良舒徐。", "愁霖鼓寒妬春事，倏喜淡日行雲衢。", "涉患知樂聞自古，積忙得閑聊慰予。", "崇堂修廡般礴久，龐眉鮐背紛前趨。", "爲催酒炙勞苦罷，細問里閭愁嘆無。", "怡然離席手加額，共說溫飽沾妻孥。", "頻年豐登豈偶爾，聖恩及物天地俱。", "卑官政拙民未厭，輦輸肩負憐朱愚。", "餠果在袖笑在頰，闖門稚子爭携扶。", "我亦僧飯對兩雛，未妨清坐留斯須。", "爐香翻頻茗事竟，殿影已曀東廊隅。", "復撚吟髭度盤紆，人聲鳥語樂有餘。"]'),
('a4cc0af8-5a99-4d80-acdb-23369849d276','贈妙勝主人','陳造','宋','宋诗','song-poetry','','[]','輿臺却略車不前，寒風皴肌冰在袖。',256,'全唐诗/poet.song.150000.json','["輿臺却略車不前，寒風皴肌冰在袖。", "還家大勝去家時，景物頓回春氣候。", "宿雲壞裂無幾留，滿放羲輪碾晴晝。", "卧石犖确猶潤濕，短籬檀欒挺疎瘦。", "是處麥畦間青壤，誰家柳陰圍碧溜。", "前山競獻曉髻濃，後海全收紋縠皺。", "妖桃艷杏各趺萼，近樹遥林錯文繡。", "池魚酣煖泳清淺，山鳥何知語幽茂。", "搜詩忽忘路遠邇，啅鵲不離車前後。", "閑身勝踐多齟齬，緩駕幽尋容宿留。", "轉從凈宇寄倦憩，得訪老禪閑話舊。", "拂除塵壁詩刻在，俛仰歲華春事又。", "開單一飯吾易飽，袖手千倡渠無陋。", "戴星摩撫防務廢，挽袂留連慚意厚。", "出處殊科要酬應，氣味相投真邂逅。", "吾歸自竟武城歌，放師道價諸山右。"]'),
('cb31f91e-8f8a-4980-a4f1-a3c97ad5df5b','贈趙排岸兼簡汪尉','陳造','宋','宋诗','song-poetry','','[]','二年俛眉簿書俗，分無足音到空谷。',320,'全唐诗/poet.song.150000.json','["二年俛眉簿書俗，分無足音到空谷。", "趙侯縹緲塵外人，肯艤歸舟問幽獨。", "冰壺炯炯當九秋，巖電熠熠懸雙目。", "小家樽俎解咄嗟，卷褥或能營酒肉。", "從容不待投轄留，坐來屢跋銅盤燭。", "酒酣辭鋒不受觸，脫手詩成驚破竹。", "雄才偉論兩超絕，磊嵬大稱此腰腹。", "定多欬唾到銀筆，自可風標藏畫軸。", "別去日月詎幾餘，豐悴真成手翻覆。", "慈烏絕哺心糜碎，脊令斷行淚陸續。", "化兒與人底異情，念君胡寧耐荼毒。", "詩腸祇作饑雷吼，譚舌未免窮塗哭。", "肉割鷺股竟何補，書憑雁翼慚虛辱。", "退之方急一簞食，少陵徒思萬間屋。", "語追競病代舍寬，王將軍家祿千斛。", "奮蜚行矣君有待，否泰更之吾已熟。", "豈容步仞局赤驥，會見青冥上黄鵠。", "奉川之汪乖崖上，有粟如阜金如粟。", "載寬縣籍償丁算，長與饑民共年穀。", "一牛鳴地監河侯，盍令顔闔能饘粥。"]'),
('52eda191-ec34-45c0-a6a0-428841cbd5a9','雲巖曉  其一','陳造','宋','宋诗','song-poetry','','[]','淮山歸夢清莫續，僧窗睡足雨亦足。',64,'全唐诗/poet.song.150000.json','["淮山歸夢清莫續，僧窗睡足雨亦足。", "鐘鳴鼓動萁爐紅，深炷沈檀共僧粥。", "我生身口良易供，志願略與山僧同。", "明年聽雨淮之東，還許幽人林下逢。"]'),
('d0ec7fff-2804-440a-a9c2-7478c3457b50','雲巖曉  其二','陳造','宋','宋诗','song-poetry','','[]','深堂清話紅燈續，不減前人參白足。',64,'全唐诗/poet.song.150000.json','["深堂清話紅燈續，不減前人參白足。", "譚禪論詩僕爲僵，更啖芋魁分茗粥。", "賦租正爾憂闕供，安得繼日笑語同。", "他年渭北仍江東，鴈書定復嗟乖逢。"]'),
('b8d46e0c-2488-4460-ab9f-00757650f9f1','凈居主人索詩急筆賦','陳造','宋','宋诗','song-poetry','','[]','凈居棟宇犀辟塵，山居不乏塵外人。',96,'全唐诗/poet.song.150000.json','["凈居棟宇犀辟塵，山居不乏塵外人。", "我來肯作厭客想，老語一一刊翠珉。", "頻年愧煩香積供，醉後狂言亦安用。", "詩成每博覆瓿譏，更向叢林繫輕重。", "皎公啟公後進師，好事繼今誰似之。", "他年落筆須妙質，政自兩公勞夢思。"]'),
('71079702-b6ae-4004-ac30-1f1b56fcb080','送雲巖老住天寧寺','陳造','宋','宋诗','song-poetry','','[]','道人兀坐雲巖山，雲巖之雲是知己。',160,'全唐诗/poet.song.150000.json','["道人兀坐雲巖山，雲巖之雲是知己。", "風噓岫吸漫不知，道人之心亦如此。", "從地湧出煥金碧，信手拈來自奇偉。", "門施鐵限十五年，一旦刺頭閙籃裏。", "天寧古剎中闤闠，學子遊人萬其趾。", "世將喧靜計今昔，不信道人心似水。", "方圓隨器我何與，乘流即行坎當止。", "十字街頭鐘鼓鳴，八千偈成一彈指。", "今秋客公我得閑，井甘不竭囊無底。", "清譚要洗三載塵，肯學玉川勞送米。"]'),
('e3ba6373-f48c-4699-ba88-739aedc7bcf0','識村翁語','陳造','宋','宋诗','song-poetry','','[]','山僧一生饜山蔌，溪叟所仰纔魚菽。',136,'全唐诗/poet.song.150000.json','["山僧一生饜山蔌，溪叟所仰纔魚菽。", "闖首侯家與相家，珍膳不應填汝腹。", "百二歲翁清且羸，茵坐鼎食寧其宜。", "焉知暫飽博長往，穀神震怒脾媼悲。", "官家顆粒皆民力，此祿食之須此骨。", "兩翁妄食壽弗延，當念無功暴天物。", "我雖不偶猶餐錢，車行肉飽隸後先。", "食功揣己懼不稱，因翁有言呼使前，盤几畢識翁所言。"]'),
('17693c18-0652-4551-a552-b0f929b4f7b2','魏知元有贈仍索詩作此言別二首  其一','陳造','宋','宋诗','song-poetry','','[]','朋從應酬岐薄厚，魏郎凜凜金石友。',64,'全唐诗/poet.song.150000.json','["朋從應酬岐薄厚，魏郎凜凜金石友。", "四年再面情轉親，日有溫言到衰朽。", "涇渭不混清濁流，雲雨肯隨翻覆手。", "自今淮徼望吳天，安得山林長聚首。"]'),
('d8af9a71-ba7d-45cf-8a22-61e6b8bfc0a2','魏知元有贈仍索詩作此言別二首  其二','陳造','宋','宋诗','song-poetry','','[]','作詩求工今則然，古人培本深其源。',64,'全唐诗/poet.song.150000.json','["作詩求工今則然，古人培本深其源。", "周雅莊騷略未究，浪摹月露綴語言。", "知君胸中藏武庫，平生遊戲皆好句。", "老夫血指妙斲前，亟當還家事溫故。"]'),
('f2863de9-0e00-44b6-ba3e-ff81a44cd9a2','贈送行六子  其一','陳造','宋','宋诗','song-poetry','','[]','北風獵獵吹行舟，客子坎止今乘流。',160,'全唐诗/poet.song.150000.json','["北風獵獵吹行舟，客子坎止今乘流。", "汀洲立鷺仍飛鷗，定應笑我當退休。", "一貧所驅不自由，表表六子古與儔。", "知我此意不見羞，送行兩舍未轉頭。", "我生甚愧羊荆州，郭吉校君誰劣優。", "天氣冰井風力遒，召棠蕪城甘滯留。", "推挽共作平山遊，倚欄逸興浩莫收。", "劇譚落屑酒溜油，不許旅寓生羈愁。", "飽閲世態諳枵浮，高情如君未易求。", "嗟予老矣胡爲酬，相與金玉論軻丘。"]'),
('05897882-c219-4b2d-8541-62d2f23489c2','贈送行六子  其二','陳造','宋','宋诗','song-poetry','','[]','此身漂然不繫舟，呂梁灧澦皆安流。',160,'全唐诗/poet.song.150000.json','["此身漂然不繫舟，呂梁灧澦皆安流。", "江湖萬頃浮一鷗，此心玩世常休休。", "吳山楚水紀所由，湘纍老枚寧匹儔。", "琢句亦復忘晨羞，搯抉肝腎掉白頭。", "歲六十四方佐州，計原夫日無乃優。", "客路日月迅且遒，朱顔壯志逝莫留。", "吾聊爾爾賦遠遊，山川自可卷軸收。", "老懷槁暴今膏油，訪峴山石弔莫愁。", "庸隨大楚皆萍浮，顧我不樂夫何求。", "緬思六客同獻酬，如挹韓衆追浮丘。"]'),
('0d9b4da9-4fa7-468a-af66-058cbb88d4de','謝儀真諸公','陳造','宋','宋诗','song-poetry','','[]','十幅擬掛東風蒲，衆賢好事爭挽裾。',208,'全唐诗/poet.song.150000.json','["十幅擬掛東風蒲，衆賢好事爭挽裾。", "盍不一笑留斯須，咄嗟而具成燕胥。", "僊醴湛湛白玉壺，篆烟褭褭黄金爐。", "駢集水豢羅山膚，彼姝者子不待呼。", "韈塵相携來坐隅，炯然皓齒明眸俱。", "含宮吮羽纍貫珠，移柱品索鳳將雛。", "詼笑盡略世謭拘，諸賢堂堂吏而儒。", "才猷聲稱雄萬夫，慰藉傾倒向老迂。", "風義已與古并驅，况把樂事分窮塗。", "衰顔得酒失槁枯，暫容二子相映朱。", "尚憶扶醉下筍輿，江灘人聲雜鴈鳧。", "一歡轉頭墮空虛，此歡欲繼良難圖。", "周旋四賢偕兩姝，此人此日吾知無。"]'),
('751396d1-a464-407c-b650-f0b209f34c11','繁昌縣感舊','陳造','宋','宋诗','song-poetry','','[]','繁昌古縣依山麓，縣外峯巒更重複。',160,'全唐诗/poet.song.150000.json','["繁昌古縣依山麓，縣外峯巒更重複。", "連山斷處圍平陸，有地可耕無十六。", "昔我作尉三年留，局促似爲山所囚。", "野行村宿飯古寺，山路孰悉如吾州。", "車如鷄栖馬如狗，風袂塵襟博升斗。", "是時身健髮財斑，頗復興懷爲奔走。", "遠近人家山影濃，與我周旋圖畫中。", "山鳥翔集相和應，野花開謝能白紅。", "薄宦而今更長道，回頭祇覺當時好。", "筋骸罷憊鬢摧頹，不嘆漂零嘆吾老。"]'),
('bd5b1b00-735d-4965-a956-5d1c5a799c86','琵琶亭','陳造','宋','宋诗','song-poetry','','[]','抱愁莫遣朱絃鳴，此聲更與愁人聽。',160,'全唐诗/poet.song.150000.json','["抱愁莫遣朱絃鳴，此聲更與愁人聽。", "江邊一聞琵琶語，月慘風悽如動情。", "何况思婦傷幽獨，少年多藝顔如玉。", "江州司馬廊廟人，暮上諫書朝放逐。", "輕攏細撚忍淚彈，開樽側耳思惘然。", "一詩說盡兩心事，遺音翻入歌舞筵。", "此翁詩名自千古，誦詩亦嘆琵琶女。", "誰惜亭前泊舟客，頗爲漂零動悽楚。", "鄰家故妓春風手，此曲每侑澆愁酒。", "今宵月影祇三人，倚欄長嘯空搔首。"]'),
('a9fc076e-35d3-4106-a9f3-41abefb8d0f7','題陳主管東牆三峴圖','陳造','宋','宋诗','song-poetry','','[]','堂上不合青楓起煙霧，牆間江山更疑誤。',146,'全唐诗/poet.song.150000.json','["堂上不合青楓起煙霧，牆間江山更疑誤。", "千巖萬壑眩明滅，暖翠浮嵐滿窗戶。", "峴山鼎列屹相望，發地撐空鶱欲翔。", "一峯拔起羣山上，嶪若紫蓋相雄長。", "仙山佛國住杳靄，晨煙暮雲追戃恍。", "良工妙與山寫真，詩中有畫須詩人。", "誦君清詩對畫壁，承蜩斲鼻俱疑神。", "知君懷古有高趣，我擥襄山識佳處。", "願抄此詩謄此圖，開卷時時揖羊杜。"]'),
('12d5f32e-25a3-40b3-930b-e0f8a7359665','次韻許節推喜雨  其一','陳造','宋','宋诗','song-poetry','','[]','昨夕聽雨喜不寐，清曉欲作喜雨詩。',160,'全唐诗/poet.song.150000.json','["昨夕聽雨喜不寐，清曉欲作喜雨詩。", "撚髭臨紙筆未落，墮前乃獲瓊瑰辭。", "白鵝免烹巫不鼓，麥田欲乾沛甘雨。", "玄璧揚輝珠剖蚌，詩思方慳得奇語。", "似聞比屋歌謠中，如我與君歡喜同。", "偕渠一飽已入手，錫羨陰隲繄誰功。", "民是天民天自恤，佻天之功天所疾。", "君言寵矣吾敢荷，更喜因詩識詩律。", "吾儕豐悴懸諸天，此雨無亦天興憐。", "轉頭匕筯薦餠托，鼓腹可但田家樂。"]'),
('ca1dd845-d8ee-4c38-bc28-77c2681bef49','次韻許節推喜雨  其二','陳造','宋','宋诗','song-poetry','','[]','舊雨新雨不後期，豐年當復歌周詩。',160,'全唐诗/poet.song.150000.json','["舊雨新雨不後期，豐年當復歌周詩。", "手調玉燭屬廊廟，歸功假手敢固辭。", "婦子赴工聽曉鼓，山歌和應揮汗雨。", "麥黄蠶老十分熟，坐衙日日聞此語。", "偕君薄宦羣山中，與我憂喜大抵同。", "畏壘謬詫庚桑楚，醉鄉盍訪王無功。", "向來小旱煩憂恤，喜雨新來慰衰疾。", "焉得妙思作彊對，如塤如箎呂應律。", "行藏老矣不問天，一飽肯受兒輩憐。", "爐熏頻炷窗頻托，公餘還我文字樂。"]'),
('b8fb1919-d5c9-45e5-ac6b-0ca50af3dc96','再次韻答余司理','陳造','宋','宋诗','song-poetry','','[]','雨來不後晴不遲，今晴昔雨皆可詩。',160,'全唐诗/poet.song.150000.json','["雨來不後晴不遲，今晴昔雨皆可詩。", "自憐老去才易盡，平日尚有黄絹辭。", "挑燈初聽鼕鼕鼓，南風收盡簷間雨。", "麥根既潤燥乃宜，此事時傳老農語。", "人家屋脊黄雲中，南村北村歡笑同。", "定知老子喜欲舞，鼎來騷客爭奏功。", "詩人例窮天肯恤，浩然不逢李賀疾。", "宿習纏結我未脫，前身永思今次律。", "君亦妙巧戕其天，低摧與我皆可憐。", "此篇嚴密更開托，却須編入襄陽樂。"]'),
('2a347ac2-01f2-463c-8801-6d7b1614eb70','次韻答路監嶽','陳造','宋','宋诗','song-poetry','','[]','房陵水秀山崛奇，政與路子昌其詩。',160,'全唐诗/poet.song.150000.json','["房陵水秀山崛奇，政與路子昌其詩。", "臨風啟緘誦傑句，狂酲病卧聞楚辭。", "陰陽閉縱坎其鼓，年年凟神爲暘雨。", "所嗟坐衙未暖席，已有疲民相告語。", "買牲釃酒方熱中，霈然一雨千里同。", "雨足便晴夏田好，麥秋决可收全功。", "與民父天免銜恤，更因歡喜忘肺疾。", "雄篇良佩君記存，聯翩古調仍唐律。", "人才高下淵視天，貂不易續私自憐。", "側理漫草腮漫托，纏聲鹿鳴媲林樂。"]'),
('c1340a07-4ca0-4808-9306-340c479b1de2','再次韻答節推司理','陳造','宋','宋诗','song-poetry','','[]','人生行樂當及時，底用躭古仍癖詩。',160,'全唐诗/poet.song.150000.json','["人生行樂當及時，底用躭古仍癖詩。", "老子平日汗牛載，五窮追逐不得辭。", "羅幃圍香擊鼉鼓，食填巨壑酒如雨。", "君看白面紈袴郎，不知經史何等語。", "笑我蠹魚塵簡中，口角儒墨紛異同。", "腹雷晝隠吟仰屋，詫向子墨收新功。", "雪毛眵眼不自恤，譏訶抵觸取憎疾。", "幾人插羽上金鑾，漫云九事八爲律。", "不如醇朴還吾天，抉腸剔腎誰汝憐。", "且從酒徒趁落托，向來失計今差樂。"]'),
('eff0d6b9-8051-427d-993f-fdd85e511b4b','再次韻答梁教授','陳造','宋','宋诗','song-poetry','','[]','陰晴如期喜可知，况復攟束收新詩。',160,'全唐诗/poet.song.150000.json','["陰晴如期喜可知，况復攟束收新詩。", "相如未至客之右，開編自愧多蕪辭。", "倅貳付我千家聚，佩襟戴君霑化雨。", "相從可獨臭味同，接耳僅聽淮鄉語。", "詩來驚倒囁嚅翁，結字著語古與同。", "少須官廨住家穩，往問句法幾即功。", "似聞知津問沮溺，山間晴乾度山疾。", "一笑行舉通家杯，計日尚前蕤賓律。", "過君定發醯甕天，傾囷倒廩當吾憐。", "家居除領齊眉托，意與諸雛誦思樂。"]'),
('c9e39cae-5755-46df-8af6-01fceb303027','記揚州舊事','陳造','宋','宋诗','song-poetry','','[]','合宮嚼蕊今柳枝，燕臺酷賞騷人詩。',160,'全唐诗/poet.song.150000.json','["合宮嚼蕊今柳枝，燕臺酷賞騷人詩。", "國色天香豈凡品，瓊枝璧月信好辭。", "向來弄影對簫鼓，楚山高深自雲雨。", "若爲白晝去臨邛，鸚鵡難防漏私語。", "翡翠久矣雕籠中，轉頭縹緲雲鴻同。", "遥知懷璧駭衆目，負山雖力難爲功。", "敢意歸來辱收恤，瑾瑜匿瑕山藏疾。", "客子一誦打鴨章，東君盧胡置嚴律。", "風生翠扇閶闔天，酒邊重聽想夫憐。", "樓中之燕當掌托，老子久謝裙裾樂。"]'),
('b69f3643-69a0-4b1c-8cf4-31d19c6fe3ca','再次韻答節推司理路監嶽','陳造','宋','宋诗','song-poetry','','[]','世傳秀句我既不能如唐王維，民依慈母亦復不能如漢杜詩。',170,'全唐诗/poet.song.150000.json','["世傳秀句我既不能如唐王維，民依慈母亦復不能如漢杜詩。", "一官彊顔竊溫飽，粗免庚癸形廋辭。", "分從村歌趁社鼓，厭見翻雲覆手雨。", "橐中僅辦買山錢，徑當拂衣踐此語。", "三子表表吾眼中，趣操肯復衰朽同。", "辭壇嶄然推大手，官業行矣收雋功。", "老夫老矣暇他恤，灌園之隙要治疾。", "折腰曳裾今痛定，端知縮鼈取卒律。", "誰能違性譽所天，俛眉屏息前乞憐。", "回思一挽間千托，带索彈琴有餘樂。"]'),
('5c6cb5ad-6e74-4feb-a16d-fd646542e1ce','贈梁教授','陳造','宋','宋诗','song-poetry','','[]','梁侯藿菽芼山雌，冷坐欲試菁莪詩。',160,'全唐诗/poet.song.150000.json','["梁侯藿菽芼山雌，冷坐欲試菁莪詩。", "嗣聖急賢饑渴似，項背趣召君得辭。", "九門方懸帝堯鼓，久旱可無傅巖雨。", "幾聽言議得韜韞，了知它日酬所語。", "人言才俊當居中，可使流落吾輩同。", "鄧禹舊補文學掾，蕭何不書野戰功。", "民庸國計當惠恤，和扁之側無廢疾。", "會看同沐一臺春，底用更試三尺律。", "生齒所戴共此天，杞國過憂吾絕憐。", "八柱如虧遲君托，未應詩酒私所樂。"]'),
('d2fa2245-50dd-434b-9d79-edec6b1e7cb7','次韵梁教授','陳造','宋','宋诗','song-poetry','','[]','房陵爲州亂山鎖，雅宜著此衰病身。',224,'全唐诗/poet.song.150000.json','["房陵爲州亂山鎖，雅宜著此衰病身。", "勿云蕞爾曹鄶下，舞袖莫回脚不伸。", "土風疎鬯北通魏，語音勁正西带秦。", "入筯卧沙慣割鮮，溜匙雲子免薦陳。", "發軔淮鄉此般礴，兩地頗復同真純。", "出處徑付無何有，泊乎無營道自親。", "損欲驟覺靜勝熱，休心寧作艮列夤。", "聲名藉甚梁夫子，相與一笑寂寞濱。", "胸次但有雲夢澤，衣上不留京洛塵。", "賓友固應消鄙吝，妻孥亦解忘賤貧。", "衮衮新篇警衰朽，清淵曉吹轉漪淪。", "顧慚陸沈俗吏行，長須叩戶何妨頻。", "世儒難得詩造妙，汝曹但詫錢通神。", "甓社它年訪遺老，爲君蠅頭編舊草。"]'),
('59762d1a-3ec8-4c83-b1fc-6661efaa448e','次韻梁教授','陳造','宋','宋诗','song-poetry','','[]','一代司馬公，山立皋稷後。',184,'全唐诗/poet.song.150000.json','["一代司馬公，山立皋稷後。", "聲名竦華夷，所樂在五畝。", "著書不止陵左班，措世治平嘉祐間。", "不欺之學誰與嗣，元城逸駕君獨攀。", "秀野之堂新斷手，儼如拱侍公左右。", "扁榜結字吾何取，顧使與堂傳永久。", "斯邕古篆學未成，鍾王石經空典刑。", "向來玩碑一再宿，怒猊渴驥慚舊評。", "柴車爭道乏妙領，畫沙之錐猶露穎。", "閉門柿葉徒滿屋，竟使吳霜颯垂頸。", "潮乎相逢奈老何，妙語愛君金叵羅。", "及君未中元祐科，深衣容我時相過。"]'),
('b88e3ce4-ac0d-4dae-a1e3-69056987025d','次韻梁廣文重午弔古  其一','陳造','宋','宋诗','song-poetry','','[]','去年重午飲酒歸，賡歌酬酢無俗子。',176,'全唐诗/poet.song.150000.json','["去年重午飲酒歸，賡歌酬酢無俗子。", "今年重午約同飲，更向詩人閲詩史。", "平生玩物遊戲爾，把酒孰知情所寄。", "交朋徑略形體中，嗜好本非杯勺裏。", "自昔騷人吟九辯，亦知令尹安三已。", "宗英分嚴君恩重，一身摧折財稊米。", "空遺楚俗千古哀，沈菰鼓鷁喧江涘。", "屬世休明偕五細，尚論取友吾謝此。", "但製荷裳扈明月，無復凄風起蘋芷。", "明日菖盤薦急觴，容我客間先坐寐。", "君來何止四者并，九室之春賤如水。"]'),
('ecf246c6-0bed-46c0-b055-b90e03e7c5fa','次韻梁廣文重午弔古  其二','陳造','宋','宋诗','song-poetry','','[]','菰粽蘸蜜綵作絲，竹萌尚籜榴未子。',176,'全唐诗/poet.song.150000.json','["菰粽蘸蜜綵作絲，竹萌尚籜榴未子。", "官居端午不可孤，小却文移謝胥史。", "酒社切戒屐聲疎，詩郵莫漫奚奴寄。", "與君相望淮南北，宦遊適偕亂山裏。", "老紆章紱我不稱，路指雲霄君未已。", "相期玳席醉九室，先向花牋驚八米。", "自昔詞源浩千頃，粗許老子窺涯涘。", "明朝酒罷詫里閭，頗嘗見客今有此。", "古人獨醒怨不逢，時搴葹薋棄蘅芷。", "吏隠顧竊詩酒樂，自公委蛇容食寐。", "一歡况復酬佳節，豪飲當觀建瓴水。"]'),
('a6f62ced-2619-40d7-a6c0-5a0f5c696d5a','急筆次梁教授韻','陳造','宋','宋诗','song-poetry','','[]','旱氣如燬民其咨，漂然一雨喜可知。',256,'全唐诗/poet.song.150000.json','["旱氣如燬民其咨，漂然一雨喜可知。", "醮席龍壇揭精意，青章祝號免愧辭。", "馨香了知罔時怨，耕耦亟用發爾私。", "四鬴足食可倚俟，三年餘蓄夫何疑。", "小麥囷藏繭已擇，及此得雨未後時。", "陰晴向人信大巧，此柄似付吾輩持。", "豈特貧窶免逋捕，抑令催歛減箠笞。", "旱魃蝗蝻方躑躅，不待炎火俄殲夷。", "吾皇聖德帝所佑，上瑞何必占蓍龜。", "職民之憂假守事，遇災詎可缺禱祠。", "貪功謂盜古不予，讀詩愧色浮清涯。", "揣己未敢拜此賜，亦念佳句堪療饑。", "擊鉢千紙久不講，聚頭一醉屬有期。", "自公退食况病減，今我不樂將誰欺。", "青樓歌舞有新按，中年絲竹聊自怡。", "已戒隸人謹約束，酒闌一屏驪駒詩。"]'),
('8b142685-495a-4ac3-88f7-f0911d179191','高頭市','陳造','宋','宋诗','song-poetry','','[]','陂行欲盡山崛起，十數人家住山觜。',144,'全唐诗/poet.song.150000.json','["陂行欲盡山崛起，十數人家住山觜。", "行人不炊市無米，買餠充腸聽頤旨。", "日未薄山收市里，閉戶人家呼不起。", "今春倦憩車曾抳，風物人情不如此。", "主人睨屋爲翁指，方秋此屋猶在水。", "閭里襁負皆轉徙，老夫危不魚腹死。", "更向秋田問餘幾，使之饑寒責廉耻。", "不忘資人約諸己，焉得人人顔氏子。", "向純厚俗今不美，曾是登山號庚癸。"]'),
('39b5d20a-95e0-4866-a0cb-63776c28f078','謝高機宜惠紙','陳造','宋','宋诗','song-poetry','','[]','詩人百用皆草草，文房所儲備精好。',160,'全唐诗/poet.song.150000.json','["詩人百用皆草草，文房所儲備精好。", "君家此紙世上珍，肯分嘉惠及此老。", "女膚膩滑葭膜勻，溪叟搗冰舊疑神。", "何人袖有善幻手，解藍田玉山爲貧。", "銀光魚卵人皆重，薛濤小牋纔近用。", "盍自留供鳳尾諾，十吏卷舒看飛動。", "杜郎百幅顧見貽，敢用實腹療朝饑。", "囊詩方逐大堤客，快意揮掃播掿辭。", "策翰墨勳闖宏大，功名逼君方未沬。", "何當太史牛馬走，秉筆特書端有待。"]'),
('741ca2be-e035-4b41-988b-7b31a19e83e7','寄安撫程丈','陳造','宋','宋诗','song-poetry','','[]','書生次舍先菜把，迺有甘肥來筯下。',160,'全唐诗/poet.song.150000.json','["書生次舍先菜把，迺有甘肥來筯下。", "今日之羊我爲政，屬饜敢忘分甘者。", "府公寬容蓋代豪，憐我詩窮仍老饕。", "卧沙九肋匕不筯，出甑嫩顫如花糕。", "即今野飯山棲地，食指屢動饑涎墜。", "穀城明府府公似，割鮮庸繼臺無饋。", "食神黄媼喜欲顛，一夜搜詩不得眠。", "將軍問腹汝見負，世用官業俱茫然。", "論情少須分袂處，未敢徑指房山路。", "餓鷹得飽遽颺去，政恐陳登輕呂布。"]'),
('69f128af-d5aa-4aaf-96b2-3787281e94bd','次韻程安撫蟹二首  其一','陳造','宋','宋诗','song-poetry','','[]','橫前兩鋒踞草泥，恃勇寧復防吳兒。',112,'全唐诗/poet.song.150000.json','["橫前兩鋒踞草泥，恃勇寧復防吳兒。", "倏隨主父死五鼎，豈止郭最遭寢皮。", "凡物有用皆賈禍，汝禍已酷孰使之。", "平生一窟不自辦，敢羨鯨鱷遊天池。", "含飴茹酒瞢懷璧，僅得士女稱珍奇。", "不摇喉牙詫雋永，遠封甖缶爭矜持。", "爬沙躁擾良可念，請續杜老觀漁詩。"]'),
('3f2f9e84-2476-41b8-a2ec-ccdd9a5ae148','次韻程安撫蟹二首  其二','陳造','宋','宋诗','song-poetry','','[]','物生不學螭蟠泥，禍及乃諉造化兒。',112,'全唐诗/poet.song.150000.json','["物生不學螭蟠泥，禍及乃諉造化兒。", "良材厚味庸自保，熊斃以掌豹以皮。", "雄戟介甲亦壯矣，乘流未可聽所之。", "託身要是鯤鵬宅，不然借穴習家池。", "主人仁心及蟲蟻，一肉三韭不好奇。", "每譏騷客寒蒲縛，更笑狂士左手持。", "忍饞愛物良未失，可愧於牣形聲詩。"]'),
('3c2b26dc-2589-4184-931d-3ed223fb9ae5','次前韻言懷','陳造','宋','宋诗','song-poetry','','[]','莊叟所願龜曳泥，正平止從屠沽兒。',112,'全唐诗/poet.song.150000.json','["莊叟所願龜曳泥，正平止從屠沽兒。", "了知聲利昏酣者，一一癡骨包妍皮。", "江湖我雖吏隠去，仰視二子終愧之。", "逝將歸種二頃秫，又欲深鑿六畝池。", "目寄飛鴻百念息，付渠夸世與釣奇。", "山翁溪友結三益，長年直鈎時一持。", "灌園之隙課阿買，分題細和陶翁詩。"]'),
('c648e6fc-a18f-4471-97f9-3cd6ac20858f','次韻程帥','陳造','宋','宋诗','song-poetry','','[]','嗜慾割去土與泥，調虞氣血等稚兒。',112,'全唐诗/poet.song.150000.json','["嗜慾割去土與泥，調虞氣血等稚兒。", "拘拘謭謭世所怪，未免鶴髮仍鷄皮。", "甘脆爲目不爲腹，蠶繭自縛良苦之。", "兩螯公子大於扇，九室春色堪爲池。", "開緘况讀萬選句，快意領此一段奇。", "自憐忍欲忍艾似，涎流津饐不自持。", "明知喘疾有時愈，更寄斫雪加餐詩。"]'),
('87f4633d-1706-4350-850c-ae6f3a21b812','分糟蟹送沈守再次韻','陳造','宋','宋诗','song-poetry','','[]','笑呼赤脚拆印泥，婦姑歡喜舞兩兒。',112,'全唐诗/poet.song.150000.json','["笑呼赤脚拆印泥，婦姑歡喜舞兩兒。", "沅江似識九肋鼈，伏雌祇慣五羖皮。", "海螯不落江𧎼下，郭索公子是似之。", "但聞淮浙詫此味，豈意分派來江池。", "閉戶獨享良多愧，古以饕餮聯窮奇。", "使君據案带減圍，一杯解顔情分持。", "未用秉燭喚窈窕，促軫且絃詩老詩。"]'),
('2a23c3ef-7aaf-4ddd-9934-152df60cc157','再次韻','陳造','宋','宋诗','song-poetry','','[]','腷趵履險不踏泥，我亦策蹇驅馿兒。',112,'全唐诗/poet.song.150000.json','["腷趵履險不踏泥，我亦策蹇驅馿兒。", "玄雲吹寒作飛雪，瑣碎渺漭無地皮。", "幻蒼變白頃刻爾，翕張披拂誰爲之。", "定自帝所千玉妃，羽衣鶴帔集瑶池。", "俯視下方粲一噱，剪水刻花爭出奇。", "忍寒索句徒自苦，萬象偕我遭控持。", "明朝雪收鵲亦喜，郵筒到眼還新詩。"]'),
('ff1dbcfd-b4fb-403b-8e3a-956b95f6e60a','帥寄詩再次韻','陳造','宋','宋诗','song-poetry','','[]','才力高下岐雲泥，龜鏡國老乳臭兒。',112,'全唐诗/poet.song.150000.json','["才力高下岐雲泥，龜鏡國老乳臭兒。", "紛紛過眼敗人意，棘端覓猴毛不皮。", "江西久無金華伯，平水未識元微之。", "府公牙頰著天籟，吮潄濩武鳴咸池。", "江城屢雪傳新作，梁園賦客讓瓌奇。", "振兩文忠舊號令，赤手破敵無所持。", "小人拜賜但袖手，匪報未辦瑶華詩。"]'),
('fc27779a-c0cb-4543-88f5-46711b5a7e06','携襄陽詩卷示子孫再次韻','陳造','宋','宋诗','song-poetry','','[]','還家未澣衣袂泥，聚首笑語環孫兒。',112,'全唐诗/poet.song.150000.json','["還家未澣衣袂泥，聚首笑語環孫兒。", "挽鬚倒褚問所得，酬倡定續陸與皮。", "小子情話吾所師，指瑜擿瑕切中之。", "謂公傑作含古意，白月在天影在池。", "阿翁贔屭十駕足，故步雖在欠新奇。", "向者護前今不爾，自呼罰爵爲汝持。", "與問潮乎奈吾老，亦喜商也能言詩。"]'),
('1dfc5f20-9370-43a2-9571-f557ea0a9920','再次韻','陳造','宋','宋诗','song-poetry','','[]','歸擔乍弛誰洗泥，使君載酒携歌兒。',112,'全唐诗/poet.song.150000.json','["歸擔乍弛誰洗泥，使君載酒携歌兒。", "小家捲褥當酒負，醉倒一笑眠虎皮。", "平生自審枯槁甚，高情顧肯振拂之。", "均州從事六輩來，歡喜如官浴鳳池。", "詩筒偕拜府公賜，格律高古語崛奇。", "頭風失去肺渴減，病夫雖病容枝持。", "南山側望潔齋久，知我日誦無生詩。"]'),
('c741df14-0b1a-4a9c-a88c-5b818cda7e92','寄程安撫','陳造','宋','宋诗','song-poetry','','[]','歸袖翩翩去誰禦，篝燈熒熒翳復吐。',384,'全唐诗/poet.song.150000.json','["歸袖翩翩去誰禦，篝燈熒熒翳復吐。", "取道言從草市西，問津更訪脩竹塢。", "殘夢欻過均州山，殺更尚數襄陽鼓。", "盎盎屯雲連遠岫，剪剪北風斜細雨。", "袖手縮頸寒可勝，羨殺昨宵宿僧宇。", "伏龍一炊隨分飽，小市居民無醢脯。", "孔明棲遯此其地，有廟纔餘十里所。", "側望縛足欠一往，不得持盃弔忠甫。", "鹿門三峴率如此，何者不爲積陰阻。", "行行野香間幽艷，晤對未用嗟無侶。", "櫟林森疎陂淥凈，江梅水仙爭媚嫵。", "殿秋迎臘太早計，花神今歲良誇詡。", "黄堂交筆爲爾吟，題品再三猶記不。", "天涯驟作懸麻勢，但聽人家擁爐語。", "寂寂關門喚不譍，青錢可能沽重糈。", "奪煬爭席吾敢校，定知楚俗輕羈旅。", "土風人情管頭好，不比陽阿輒相遻。", "饋漿亦有白首翁，束縕乃得青裙女。", "推枕每被荒鷄催，捉鞭動與寒鴈伍。", "東村西里無乾地，上山下山泥濺股。", "隸廝任輦起復僵，登頓連朝吾愧汝。", "空荒頗怪人迹絕，撩亂俄驚雪花舞。", "攪絮鋪鹽疑變幻，寒壑漫山太熒侮。", "瀰漫六幕眩明滅，夢汞兩間迷仰俯。"]'),
('d0066048-505e-4380-90fb-a3cd682c1f58','贈安道士','陳造','宋','宋诗','song-poetry','','[]','吳罝傳世皆妙語，善昇乃近崔遵度。',112,'全唐诗/poet.song.150000.json','["吳罝傳世皆妙語，善昇乃近崔遵度。", "絲桐造妙詩疑神，古來多屬方外人。", "羨君矯矯雲山客，子墨桐君生莫逆。", "此人此藝吾了然，錦囊傑句多時賢。", "月斧雲斤且遊戲，纏聲鹿鳴莫經意。", "古人進藝道與俱，如君不應古與殊。", "謁帝行如稷丘子，莫謾瓜芋嗤侯喜。"]'),
('a3e4424c-57af-4ef1-88e9-646c6fb44539','程帥以古人名作詩見寄擬作謝之','陳造','宋','宋诗','song-poetry','','[]','胸次不平當近酒，熱官奮揚肯回首。',160,'全唐诗/poet.song.150000.json','["胸次不平當近酒，熱官奮揚肯回首。", "即今羊杜詩中仙，襄陽城中獅子吼。", "我將仲子趨黄堂，孰看畢戰搴旌幢。", "抗顔路塵旋行役，但有魂夢公之傍。", "瀕海作宰我漫仕，留贊郡符真左計。", "老夫已老子白丁，解頤與言游戲事。", "駢羅隠服芙蓉裳，設張翰墨當絲簧。", "敢向青山簡奇勝，有田肯賣吾倒囊。", "如公端合穆王度，不靳尚作歸田語。", "蓬萊朱金久已齊，還許遠來結鄰否。"]'),
('14ea4512-bd6b-468e-ad5b-3ef4b332a9bf','暗用古人名詩寄程帥','陳造','宋','宋诗','song-poetry','','[]','羨公椽筆銜陽秋，黄鍾大呂豪端收。',96,'全唐诗/poet.song.150000.json','["羨公椽筆銜陽秋，黄鍾大呂豪端收。", "省闈高掇未足道，文章老手第一流。", "轇轕玄譚已驚衆，倒河翻瀾駭飛動。", "遞中筒詩陸續來，舊債未償新債重。", "即今搦管重犯嚴，强顔回顧口如箝。", "更驅行李伸此情，句法政用公鎸劖。"]'),
('3ff21173-edcb-4d7d-b30d-066d1dffb504','次韻張秀才題汪叔量挹秀亭  其一','陳造','宋','宋诗','song-poetry','','[]','清江如玦山如環，主人胸次自江山。',128,'全唐诗/poet.song.150000.json','["清江如玦山如環，主人胸次自江山。", "寰中秀氣困豪取，著亭杳靄空濛間。", "碧浪明邊帆影遠，暖風香裏林花晚。", "市聲隠地了不聞，貪看霏煙抹層巘。", "青山隠吏鬚已霜，带寬未用憐東陽。", "每來亭上小箕踞，傲睨山色挹江光。", "一樽從君多暇日，更誦清詩綠人髮。", "絕勝九衢塵霧中，金印纍纍客牢石。"]'),
('ea63075f-f342-4818-9dcd-f2d60ed8bf4f','次韻張秀才題汪叔量挹秀亭  其二','陳造','宋','宋诗','song-poetry','','[]','清遊如省隔世環，身繫組綬心溪山。',128,'全唐诗/poet.song.150000.json','["清遊如省隔世環，身繫組綬心溪山。", "此亭攫踞山水上，羨君脫屣塵埃間。", "不應室邇嗟人遠，時上風煙慰衰晚。", "怳如坐我天姥傍，長嘯持杯揖雲巘。", "張侯清吟句挾霜，肯因聞笛賦山陽。", "空青染袂醉頹玉，笑人簿領閲流光。", "誅茅結鄰約他日，會映軒窗晞禿髮。", "徑從兩君賦歸來，何須官滿六百石。"]'),
('0f7da0f5-43a5-4f06-b44c-453a9045d4fd','次韻鍾汝楫','陳造','宋','宋诗','song-poetry','','[]','鍾郎耐暑如被酒，亦復不閑讀書口。',92,'全唐诗/poet.song.150000.json','["鍾郎耐暑如被酒，亦復不閑讀書口。", "胸中莫可渚涯窺，筆下時作蛟龍吼。", "老夫瞠若終後塵，兒子徒勞汗流走。", "中年眼見花，養痾肘生柳。", "漂然振我衰懦氣，此士此詩今僅有。", "亦思琢句與周旋，强敵當前難措手。"]'),
('825ce66a-0982-4e5c-a264-230a7dce7876','再次韻示師文','陳造','宋','宋诗','song-poetry','','[]','中年多病剛制酒，文字譏評慵挂口。',92,'全唐诗/poet.song.150000.json','["中年多病剛制酒，文字譏評慵挂口。", "克家尚須獅子子，時踞風林一哮吼。", "藏山有書當衣鉢，端能太史牛馬走。", "之齊莫操竽，名楚要穿柳。", "未聞狗監薦子虛，聊遣吳王質非有。", "獨無鼓吹娛乃公，勝日不應長袖手。"]'),
('17fee3b3-eac4-4565-b18e-27ac5d872765','長句簡諸公','陳造','宋','宋诗','song-poetry','','[]','君家開宴爲酴醾，竹聲裂石絃輥雷。',288,'全唐诗/poet.song.150000.json','["君家開宴爲酴醾，竹聲裂石絃輥雷。", "我家芍藥繼如許，如解商量先後開。", "深紅妍白各媚嫵，瓊肌玉骨無纖埃。", "日高未覺睡態足，風定亦送龍香來。", "素艷壓架頩欲雨，粧面卧叢羞未擡。", "邢娥微服屏粉黛，衆女望影慙莫陪。", "真妃嬌泥午酒困，紅潮作暈回香腮。", "春到陋邑好花少，鬰鬰高柳間古槐。", "濃李淺桃不入眼，菖條杏葉何有哉。", "喜如足音賞魏紫，愁寄驛使邀江梅。", "殘春索寞風絮亂，有此二物生庭隈。", "維揚金腰可伯仲，閩南素馨但輿臺。", "倚煙娉盈復妖嫮，等閑力挽春光回。", "東皇有情花有意，似欲我輩倒玉罍。", "君家賞花我方病，憶花有恨空成堆。", "我家花開病適愈，對花發興知難裁。", "簿領困人日作惡，玉山猛判花前頹。", "及今樂事須秉燭，風狂雨橫誰能猜。"]'),
('a09f28db-ddfa-4990-86e7-a92726aa224b','愛笋','陳造','宋','宋诗','song-poetry','','[]','犀非犀，玉非玉，拂拂輕霜浮脆綠。',112,'全唐诗/poet.song.150000.json','["犀非犀，玉非玉，拂拂輕霜浮脆綠。", "披籜含梢欲成竹，娟娟褭褭森可束。", "稀間只稱佳月照，勁處差耐清風觸。", "少忍充庖得補林，主人爲目不爲腹。", "論材似也子勝人，終竟鼻祖與膏馥。", "官閑盡日據胡床，樂與此君同避俗。", "冷笑京華癡少年，枉費千金買花木。"]'),
('f377afc7-1dbc-4c59-8e0b-d4730ad63869','次趙判院韻','陳造','宋','宋诗','song-poetry','','[]','公詩見壓楚服隨，孤軍懾怯逢荆尸。',128,'全唐诗/poet.song.150000.json','["公詩見壓楚服隨，孤軍懾怯逢荆尸。", "將壇已辦降旗送，顧乃借重如等夷。", "文工武習知餘事，腰箭臂弓聊寓意。", "僕姑不作餓鴟鳴，策策鮫人珠迸淚。", "巧匠血指非意及，微恙未須湯熨治。", "蟹螯置把蛇卧影，生世多才古爲累。", "誰家酒好花打圍，今日人閑柳生臂。", "不妨惡客著坐隅，身則獨醒心解醉。"]'),
('cdb59d05-303f-499e-b4fa-56854337482c','出郭  其一','陳造','宋','宋诗','song-poetry','','[]','江縣居人寒食下，少在縣中多在野。',256,'全唐诗/poet.song.150000.json','["江縣居人寒食下，少在縣中多在野。", "哭聲不似笑聲長，麗服新粧盡遊者。", "長郊芳草接天綠，我亦行行策罷馬。", "盍簪命醉豈不懷，卑官出入元無假。", "偶來却勝特來好，觸處春光可圖畫。", "幾日陰寒風用壯，今朝霽景天所借。", "趁人胡蝶作團蜚，逐婦鳴鳩數聲罷。", "夭桃艷杏雖已過，郁李金沙猶未謝。", "其餘紅白爭姱嫮，醉態啼粧各瀟灑。", "顰風笑露頩欲語，半吐梨花最閑雅。", "游人幾許健倒去，紅粉誰家短牆亞。", "良辰獨醒還自惜，捐佩一樽猶可貰。", "餠盤餳筯已寒盟，故人應問花應訝。", "對春長作了事癡，不念清歡本無價。", "會當從公謝不敏，百罰深杯不辭把。", "魏花有約待人歸，秉燭酬春期後夜。"]'),
('bdcb649e-6696-40ac-a9b3-7c49e04f278d','出郭  其二','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','對花不領幾柳下，以詩自苦如東野。',256,'全唐诗/poet.song.150000.json','["對花不領幾柳下，以詩自苦如東野。", "今年陡覺負芳時，狎興蕭條殊曩者。", "西湖南園怳入夢，漫道尻輪神作馬。", "可堪山鳥勸歸去，擬爲蒓羹乞長假。", "十分銷瘦空自憐，一段閑愁倩誰畫。", "春光只比東逝波，堂堂去意那能借。", "青梅崖蜜倏登俎，禊祓鞦韆仍復罷。", "感君妙句慰岑寂，欲挽清歡付衰謝。", "光風摇摇壓輕暑，亭榭况經微雨灑。", "徑煩麴糵寬懷抱，未用文章繼風雅。", "飜階芍藥醉面欹，壓架酴醾香蓓亞。", "江城日有問字人，酒不論錢更須貰。", "君今頼以主人賢，我亦不憂官長訝。", "鶑花好處醉爲鄉，與君平日俱聲價。", "旗亭市樓故鄉約，歲晚會須茅一把。", "客中一笑且追陪，飲勿言歸當卜夜。"]'),
('34cbcbea-f44e-4bc0-a2a0-2eaaf5e209ca','次韻張秀才','陳造','宋','宋诗','song-poetry','','[]','風前病眼如挾沙，蕭蕭兩鬢吹蒼華。',64,'全唐诗/poet.song.150000.json','["風前病眼如挾沙，蕭蕭兩鬢吹蒼華。", "翩然一馬度平楚，時見碧溜浮梅花。", "胡蝶蘧蘧恐非夢，乾鵲角角營其家。", "哦君新詩念鄉國，鴈字一行天際斜。"]'),
('5b5837ba-62ba-44cd-9415-dd00903aa23f','望夫山','陳造','宋','宋诗','song-poetry','','[]','亭亭碧山椒，依約凝黛立。',104,'全唐诗/poet.song.150000.json','["亭亭碧山椒，依約凝黛立。", "何年蕩子婦，登此望行役。", "君行斷音信，妾恨無終極。", "堅誠不磨滅，化作山上石。", "煙悲復雲慘，髣髴見精魄。", "野花徒自好，江月爲誰白。", "亦知江南與江北，紅樓無處無傾國。", "妾身爲石良不惜，君心爲石那可得。"]'),
('179d78c2-1861-435a-ba84-d8fe03a915f3','檢旱宿香雲','陳造','宋','宋诗','song-poetry','','[]','香雲之山瞰平楚，松篁路窮得僧宇。',176,'全唐诗/poet.song.151000.json','["香雲之山瞰平楚，松篁路窮得僧宇。", "明窗深室皆嚴靚，白菊紅蕖相媚嫵。", "它日欲來坐忙迫，此行忽忽寧得所。", "蒲團憩定飯秋蔬，衣袂黄塵尚如許。", "山僧共話豈須禪，但愛茶甌如潑乳。", "投床有夢不能記，忽聽風林如過雨。", "鷄聲不貸擁被溫，又控罷驂陵險阻。", "出門便覺仙凡隔，猶聞窣堵風鈴語。", "今年旱暵遂無年，枵腹籲天連保伍。", "頗能念我困馳驅，兩兩致詞相勞苦。", "但使秋租毋病汝，吾自卑官慣塵土。"]'),
('01ec6e56-6b25-4679-accd-f95737172bda','田家歎','陳造','宋','宋诗','song-poetry','','[]','秧欲雨，麥欲晴。',48,'全唐诗/poet.song.151000.json','["秧欲雨，麥欲晴。", "補創割肉望兩熟，家家昂首心征營。", "一月晴，半月陰。", "宜晴宜雨不俱得，望歲未免勞此心。"]'),
('e5de8cc9-609e-4e9a-bbab-01d7e2fb2386','謝翟元卿詩卷見投','陳造','宋','宋诗','song-poetry','','[]','從君只比羊胛熟，得詩已可牛腰束。',224,'全唐诗/poet.song.151000.json','["從君只比羊胛熟，得詩已可牛腰束。", "誰言此老四壁立，襞積錦繡羅羣玉。", "晨興諷誦暮編綴，未覺饑雷隠枵腹。", "我生嗜學類貪夫，婪酣欲訴南山竹。", "詩人到眼輒自慰，句法得君今意足。", "向來玄鑰笑談啟，大勝幾年膏火讀。", "駸駸警我欲川增，前之汗漫今邊幅。", "頗嗟詩客千鈞筆，不博長安一囊粟。", "人不求君君不即，高卧窮鄉數椽屋。", "苦無好事問奇字，寂寞寒庖供苜蓿。", "長篇短韻寫不平，日使貧交得驪目。", "握瑜不價自應爾，有底汲汲須圓曲。", "我有鴟夷繫短轅，持澆胸中三萬軸。", "尚恨不作多田翁，秔糯分君歲千斛。"]'),
('247cfb85-db7e-4610-a40f-8c2dff928fcb','題蕪湖雄觀亭','陳造','宋','宋诗','song-poetry','','[]','大江來東南，旁受衆壑輸。',264,'全唐诗/poet.song.151000.json','["大江來東南，旁受衆壑輸。", "下驛峽門窄，積水陡下百尺餘。", "勢如千鼓駴萬馬，闛𨵝嚙蹙崩騰排軋爭危塗。", "蟂磯頼是作齟齬，不然頹沙裂岸寧復通舳艫。", "霜晴似揭天兩鏡，瞥眼浪濤相吞屠。", "不知河伯窟宅託何所，只應蛟鱷跋疐無寧居。", "陰晴明晦何限景，付與沙鷗浦鷺綸竿夫。", "令君作亭攬其要，豁然眼界了江湖。", "我昔暫登覽，詩瓢仍酒壺。", "寒聲隠隠撼窗戶，綠霧噴噀擅曉晡。", "吳檣楚柁亂秋葉，蜚山湧雪畧座隅。", "淮山千髻更在洪濤外，昏煙淡日時有無。", "昆陽勝負等蠻觸，魏中之梁直錙銖。", "人生紅塵中，局縮轅下駒。", "安得李成王宰不死俱在眼，水墨揮灑丹青摹。", "江山千里入卷軸，從此不數玄圃崑崙圖。"]'),
('b70e3e8d-d069-498b-b577-266f83425868','張秀才枕屏','陳造','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','寒風慘澹森木古，羣鴉無人自翔舞。',64,'全唐诗/poet.song.151000.json','["寒風慘澹森木古，羣鴉無人自翔舞。", "重山積水幾里所，稍見孤舟渺煙雨。", "意吞洞庭卓天姥，短屏數幅渠能許。", "何時去作湖山主，還喚詩翁來著語。"]'),
('b9109871-0042-4d45-be0a-f4182a8b2054','謝朱宰借船','陳造','宋','宋诗','song-poetry','','[]','書生祿𨔤空自憐，三年官滿囊無錢。',128,'全唐诗/poet.song.151000.json','["書生祿𨔤空自憐，三年官滿囊無錢。", "身如絆驥心千里，安得一舸西風前。", "令君磊落濟川手，留滯亦憐窮獨叟。", "大舟百尺影白虹，借我搬家我何有。", "函牛之鼎著鷄肋，涓滴渠須瓠五石。", "劣留兩席寘圖書，輦石囊沙壓摇兀。", "典衣買酒餉三老，槌鼓鳴鑼人看好。", "相過重讀借船帖，我自盧胡君絕倒。"]'),
('5a9c16e2-4be2-4eb8-9a3a-89fb74b7bd43','墨梅魚扇寄孫成甫','陳造','宋','宋诗','song-poetry','','[]','都城六月難爲客，暑焮火山不餘息。',128,'全唐诗/poet.song.151000.json','["都城六月難爲客，暑焮火山不餘息。", "從人輒博褦襶嗔，假館翁家得休適。", "髯翁囷積胸中奇，對客清談霰雪飛。", "扇材寄似亦安用，聊代玉麈談間揮。", "須知寒夜冰花影，著子駢枝可調鼎。", "濠梁之樂物我融，翁自欣然渠不領。", "向來般礴非畫工，象外析理翁則同。", "少酬他日清凉惠，知我夢依君子風。"]'),
('20604021-d325-47d0-bf23-d6af7de41f07','從王守獵','陳造','宋','宋诗','song-poetry','','[]','生世能忘塵外趣，官居定作車中婦。',160,'全唐诗/poet.song.151000.json','["生世能忘塵外趣，官居定作車中婦。", "男兒胸次萬斛寬，不著塵埃著詩酒。", "虎頭起秀屹雙高，層城更是干青霄。", "使君領客凌縹緲，天風颯颯摇旌旄。", "吳嶠魯山青未了，眇視平淮衣带繞。", "艷歌濃笑碧雲深，聲下人間却驚鳥。", "不妨卷障下煙霏，翠袖紅粧旋打圍。", "杯行飛瀑亂歌吹，蜚霧暗香俱在衣。", "詩翁得興飛綵筆，銅丸脫手初無迹。", "酒酣登車接離倒，馬上梁州霜月白。"]'),
('e8f7f0af-5acf-4f4f-b0b6-bf704780c3da','散解廟行','陳造','宋','宋诗','song-poetry','','[]','巨靈揮斧山爲拆，谽谺飛出寒溪碧。',192,'全唐诗/poet.song.151000.json','["巨靈揮斧山爲拆，谽谺飛出寒溪碧。", "南酉北枧皆戶家，種秧插稻供衣食。", "此水不枯歲不饑，此溪不涸龍是司。", "森木古屋龍所宅，人家望歲如取携。", "笳簫嗚嗚坎坎鼓，秋報春祈從父祖。", "鷄豚肥腯社酒香，擎跪曲拳誰敢侮。", "年時雩禱嗟徒勤，適龍睡熟喚不聞。", "溪心蒿艾化埃壒，可怪嘉穀遭惔焚。", "千溝萬澮分飛瀑，面露摇風際天綠。", "懷寶睡足龍亦驚，雁門之踦此焉復。", "安得溪水長滂浪，龍不忸怩民樂康。", "向來野草填饑腸，怨氣括作頤下囊。"]'),
('17a0199b-394a-42a6-9303-288a4c0ea554','粉水行','陳造','宋','宋诗','song-poetry','','[]','散解溪紆福溪直，兩山空中瀉清激。',160,'全唐诗/poet.song.151000.json','["散解溪紆福溪直，兩山空中瀉清激。", "潴渟壅建幾千家，邀入中田作膏液。", "餘流復合古城東，末世尚奏鉛華功。", "定名粉水自誰始，水神有靈當熱中。", "去年龜紋布溪底，房民倒垂憂死徙。", "今年活活夜繼晨，淥漲稻禾三百里。", "此溪今昨殊虧盈，郡民即溪岐死生。", "天設地施禹疏鑿，世人盍亦求其情。", "古來名實爲賓主，兩溪厚農非小補。", "但令旄孺無饑羸，安用女子相夸詡。"]'),
('3cb7c665-d85a-4b43-abc7-c03724bef229','田家謠','陳造','宋','宋诗','song-poetry','','[]','麥上場，蠶出筐，此時祇有田家忙。',144,'全唐诗/poet.song.151000.json','["麥上場，蠶出筐，此時祇有田家忙。", "半月天晴一夜雨，前日麥地皆青秧。", "陰晴隨意古難得，婦後夫先各努力。", "倏凉驟暖繭易蛾，大婦絡絲中婦織。", "中婦輟閑事鉛華，不比大婦能憂家。", "飯熟何曾趁時喫，辛苦僅得蠶事畢。", "小婦初嫁當少寬，令伴阿姑頑過日。", "明年願得如今年，剩貯二麥饒絲綿。", "小婦莫辭擔上肩，却放大婦常姑前。"]'),
('ad59406b-ff45-4e1c-8182-15184eab22ac','鹿鳴燕','陳造','宋','宋诗','song-poetry','','[]','亂山森立圍古房，重碧疊青天與長。',200,'全唐诗/poet.song.151000.json','["亂山森立圍古房，重碧疊青天與長。", "鍾奇孕秀爲雋良，有如六子爭軒昂。", "胸次襞積雲錦章，漢之晁董唐常楊。", "當日折衝陣堂堂，尺箠不折築受降。", "皇上籲俊奄帝王，士孟其晉如康莊。", "即今勸駕觀國光，接翼便合鴛鷺行。", "後先差池似未妨，一夔自足開天荒。", "五大次第趨巖廊，懷寶判閲三星霜。", "一盃首餞江夏黄，一詩竊比振履商。", "功名逼人未易量，坐來相映眉間黄。", "誰遣大宅浮春陽，他年朝路偕翺翔。", "惟南有斗耿昊蒼，一字定寄漁樵鄉，老子善誦君叵忘。"]'),
('b537ddb0-2446-4ca8-bc96-4a3868f139ef','次前韻送胡省元','陳造','宋','宋诗','song-poetry','','[]','南宮嚴嚴各分房，過眼千牘春晝長。',200,'全唐诗/poet.song.151000.json','["南宮嚴嚴各分房，過眼千牘春晝長。", "戛戛百楛收一良，主司黍累作低昂。", "黄道湛碧誰爲章，胡郎筆勢傲長楊。", "掉臂舊升賈馬堂，自讀君文此心降。", "看寫帝伯仍皇王，諸公盥誦顔爲莊。", "射策便近天子光，一鳴坐瘖千駟行。", "騰陵絕澗略不妨，我昔塗抹策寒荒。", "囊筆亦解趨東廊，一官蹭蹬鬢頷霜。", "桑榆聊樂師陳黄，逐逐一飽隨工商。", "才無它奇堪斗量，放君綠鬢便銀黄。", "功名若木昇朝陽，鵰鵬舉翮雲路翔，腰印纍金玉佩蒼。", "功成晝繡歸鄭鄉，車笠舊誓無相忘。"]'),
('283b31a8-ed9e-4e1b-b957-fb04d078812d','次韻許節推喜雪','陳造','宋','宋诗','song-poetry','','[]','雪後緘詩送春燠，何異祠壇起祇肅。',384,'全唐诗/poet.song.151000.json','["雪後緘詩送春燠，何異祠壇起祇肅。", "吟哦三嘆思答報，幾欲揮毫紙隨縮。", "多聞實藉益者三，敬客不啻需之六。", "別君方看月弦下，及門僅比羊胛熟。", "前時爲雪謁仙佛，俯傴叩神如問卜。", "陰陽妙由帝把握，寅亮傍頼公迪篤。", "死生休戚繫雨晹，此柄不輕果誰屬。", "天公欠雪如負券，得之無庸計遲速。", "盈尺告功遽放晴，孰謂十寒財一暴。", "念子詩愁替酒狂，幾日風餐仍露宿。", "想見晨窗誤月明，催汲溪泉煮山蔌。", "雲際羣峯駮粉繪，日下衆壑淙哀玉。", "我雖越俎政無補，猶飽官饔住官屋。", "不嗟破履印遺趾，更免長鑱斸黄獨。", "剝啄或肯送尺書，傾箱中有麖鹿肉。", "遥知合圍罥蹄角，驚奔窘怖徹毛骨。", "放麑歠羹未恝然，老子平生蔬茹足。", "瓶中療饑餘白粲，甕裏度寒仍旨蓄。", "隠几日日面南山，捉筆時時瀉懸瀑。", "但有赤脚侍玉川，分無散花問金粟。", "春前三白盛世瑞，幸此迂愚寬譴逐。", "朝來徙倚觀稼上，宿麥泛煙青極目。", "佻天之功敢僥罪，含生有自如其欲。", "寒梅嫵媚粧更新，弱柳瓏璁眉上蹙。"]'),
('f51b2199-eb54-4c74-9651-ade4b1661589','謝襄陽陶宰惠靖節先生編年大本','陳造','宋','宋诗','song-poetry','','[]','陶翁清節人可追，陶詩妙處吾所師。',224,'全唐诗/poet.song.151000.json','["陶翁清節人可追，陶詩妙處吾所師。", "百篇昭昭揭日月，行雲流水無定姿。", "顛倒後前昧甲子，可忍白璧猶小疵。", "三家紀述互踳駮，千載傳授仍參差。", "遠孫挺立翁不死，吏隠平挹鄉里兒。", "空洞胸襟著今古，遺編訂正當屬誰。", "扶微擿隠究茫昧，別白蒼黑分毫釐。", "翁拔俗心詩其寓，彼未易識此則遺。", "幽意隠義眼中了，筆端有口今見之。", "細書大字肯及我，故人嘉惠良不貲。", "摩挱老眼屏湯熨，欻訝毛孔生凉颸。", "歸裝不憂更空匱，招隠正用寬衰遲。", "世間報施有厚薄，自顧壁立謀晨炊。", "心期烱烱共一月，未妨相望天之涯。"]'),
('23214ccb-924b-468d-b443-891bcbd53f41','題識山堂','陳造','宋','宋诗','song-poetry','','[]','物之或暌九牛毛，理有適契鶴鳴皋。',240,'全唐诗/poet.song.151000.json','["物之或暌九牛毛，理有適契鶴鳴皋。", "對山眩旋目無主，山靈定笑山不遭。", "廬阜姿態杳莫狀，煙容嵐影翻海濤。", "德人眼力了天巧，離朱眸睨難形逃。", "高堂面勢踞縹緲，曠度灑落遺塵勞。", "萬巧千奇領定體，如闖闤闠挹同袍。", "要須般礴煩畫史，正自指顧分秋毫。", "聞道樽罍富賓從，至今卷軸餘風騷。", "我登斯堂唶遲暮，仙翁已躡海上鰲。", "橫前三萬八千丈，天台信美非其曹。", "崩騰恍駭失要領，窺覘歷覽首屢搔。", "先生翳鸞驂紫鳳，想後韓衆前盧敖。", "白玉之童手碧桃，雙成智瓊各雲璈。", "神遊未置茲山遨，徙倚悵望吾鬰陶。", "塵中局束真狴牢，但覺德人山與高。"]'),
('4d73aa1e-697d-4b5f-9eab-b89f83bc296d','次韻高殿撰題東山','陳造','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山佳處雲英英，鶴歸誰識丁佐卿。',160,'全唐诗/poet.song.151000.json','["廬山佳處雲英英，鶴歸誰識丁佐卿。", "東林遺址倏興廢，未害諸老傳清名。", "向來杖屨孰遊歷，猿鳥近人鷗不驚。", "樂天本願祇兜率，思邈不忘聽化城。", "一從棘位復帥閫，晉酌白獸懸旄旌。", "先生本自遠公輩，夢繫蓮社松竹行。", "即今上品已補處，妙句留并山崢嶸。", "未下飲光領一笑，曾是圓澤論三生。", "何人著語嗣絕響，浪許伯起新有聲。", "尚憶詩翁運椽筆，坐排九派咸東傾。"]'),
('b7920813-15c8-47ca-ac25-605a170c003f','次韻徐監嶽四首  其一','陳造','宋','宋诗','song-poetry','','[]','文字挽回正始音，如君豈合安家林。',64,'全唐诗/poet.song.151000.json','["文字挽回正始音，如君豈合安家林。", "干祿不作次且嘆，讀書方競分寸陰。", "斯人與室幸孔邇，有底尋丈能汲深。", "兩詩竟得摩老眼，慰我饑渴他年心。"]'),
('d5b26955-a588-4ab4-80e5-238f0ae9b626','次韻徐監嶽四首  其二','陳造','宋','宋诗','song-poetry','','[]','落落過眼誰知音，故山檜枝森碧林。',64,'全唐诗/poet.song.151000.json','["落落過眼誰知音，故山檜枝森碧林。", "白鷗盟堅不待歃，豈應辟影忘息陰。", "末路功名夢已斷，生平丘壑情自深。", "素琴濁酒般礴地，頗領淵明千載心。"]'),
('201ad73b-474c-441b-8c61-b8904dc18de0','次韻徐監嶽四首  其三','陳造','宋','宋诗','song-poetry','','[]','湖間波聲環珮音，湖上遊子紛如林。',64,'全唐诗/poet.song.151000.json','["湖間波聲環珮音，湖上遊子紛如林。", "坐窗日夢舊遊處，屯雲重霧專積陰。", "凄風剝香梅塢滑，輕煙暝翠松行深。", "畫船載酒年少事，老不耐閑猶此心。"]'),
('dd79c247-7f81-4f4c-a0d9-b586494c9828','次韻徐監嶽四首  其四','陳造','宋','宋诗','song-poetry','','[]','抱枝山鳥雖好音，未放紅糝黏青林。',64,'全唐诗/poet.song.151000.json','["抱枝山鳥雖好音，未放紅糝黏青林。", "東風一掃寒雨盡，羲馭明晦雲移陰。", "嶝嶺熹晴亂屏合，漣漪湛淥半篙深。", "翩躚舟子得我羨，笑傲山影眠波心。"]'),
('893413b6-a277-44fc-8c5a-58d28e8e1724','再次韻呈林子長郎中二首  其一','陳造','宋','宋诗','song-poetry','','[]','諸生吾伊鶑燕音，憶嘗客我詩書林。',64,'全唐诗/poet.song.151000.json','["諸生吾伊鶑燕音，憶嘗客我詩書林。", "交期離合悼今昔，宦路漂泊費光陰。", "故人恩意歌酒款，省郎香霧簾櫳深。", "二十四年一笑適，可待車笠論初心。"]'),
('499a96db-947a-4266-a28f-bc0a4c48cfec','再次韻呈林子長郎中二首  其二','陳造','宋','宋诗','song-poetry','','[]','三嘆熟君朱絃音，可但文價高儒林。',64,'全唐诗/poet.song.151000.json','["三嘆熟君朱絃音，可但文價高儒林。", "課聞安仁最花縣，車想召伯駐棠陰。", "詩壇自昔隠一敵，意匠超忽陵高深。", "補衮活國要次第，向來子牟魏闕心。"]'),
('c5bec851-3d01-472e-8703-5fe978680712','正月晦步西湖小憩市樓','陳造','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鼓腹不詫金石音，吟步竹塢俄梅林。',64,'全唐诗/poet.song.151000.json','["鼓腹不詫金石音，吟步竹塢俄梅林。", "方愛羣鶩漾清泚，忽聽一鴻啼晏陰。", "野飯不妨隨分飽，盃酒却憶向來深。", "明朝晴雨恐未卜，鷗鷺盟寒空復心。"]'),
('6b64933e-afa9-41d8-b065-34c9b12f6fb1','再次前韻呈林郎中五首  其一','陳造','宋','宋诗','song-poetry','','[]','清詩似奏韶樂音，林侯宿世孤山林。',64,'全唐诗/poet.song.151000.json','["清詩似奏韶樂音，林侯宿世孤山林。", "疎雲時漏凉月影，雛鳳獨嘯修竹陰。", "金華后山儼在目，非子誰復鈎其深。", "掩卷炷香三嘆息，向來望若空潛心。"]'),
('2d41d2de-0ae4-4504-b4c7-6a4c707d6264','再次前韻呈林郎中五首  其二','陳造','宋','宋诗','song-poetry','','[]','坎流行止忌株守，敢薄紳笏高山林。',64,'全唐诗/poet.song.151000.json','["坎流行止忌株守，敢薄紳笏高山林。", "平時交期車合轍，回首夷路鶴鳴陰。", "窮鳥低摧客吟苦，九虎眈視天門深。", "南道主人推轂手，頼君未遣灰吾心。"]'),
('95603c4f-532f-4840-babb-2708987cf616','再次前韻呈林郎中五首  其三','陳造','宋','宋诗','song-poetry','','[]','儀圖登俊煩玉音，何人望傾英俊林。',64,'全唐诗/poet.song.151000.json','["儀圖登俊煩玉音，何人望傾英俊林。", "比喜諸公挽此傑，正復寶鼎薦汾陰。", "楚珩趙璧希代寶，丹地紫閣五雲深。", "論思調虞要無迹，安用夫人知格心。"]'),
('9ce0ddf8-2b9e-4404-a1e8-d5a636c4188c','再次前韻呈林郎中五首  其四','陳造','宋','宋诗','song-poetry','','[]','一書僅達缺嗣音，蔀屋有夢定山林。',64,'全唐诗/poet.song.151000.json','["一書僅達缺嗣音，蔀屋有夢定山林。", "賢者即今在王所，陳人不憂老牆陰。", "或容連茹鴛鷺後，聞道結知君相深。", "時遣吳姝近酒盞，更防蜀鳥摇歸心。"]'),
('5f88b1c7-dc1b-40cf-b306-d6666565c8e1','再次前韻呈林郎中五首  其五','陳造','宋','宋诗','song-poetry','','[]','春皇報人如寄音，紫燕窺簾鶑遶林。',64,'全唐诗/poet.song.151000.json','["春皇報人如寄音，紫燕窺簾鶑遶林。", "于時不無客欣戚，此意正繫天晴陰。", "傍湖樓影酒旗直，到眼人家花霧深。", "老子獨醒尚此興，歸時參昴橫天心。"]'),
('55a13596-5257-4d45-8226-e2d7c45cf5e4','徐南卿招飯  其一','陳造','宋','宋诗','song-poetry','','[]','徐郎陋巷四立壁，乘間亦戒賓友食。',133,'全唐诗/poet.song.151000.json','["徐郎陋巷四立壁，乘間亦戒賓友食。", "慈親衰鬢不供剪，定賣春衣典書冊。", "念君治具良騷騷，與渠侵早來得得。", "小樓十客不餘地，猶勝陶翁劣容膝。", "江西米{擥手=米}絲作窩，吳國香秔玉爲粒。", "嗣宗阿戎各好士，笑頡羹鄙仍婦德。", "老子旅寓得此飽，勃鬰詩情喙三尺。", "出門未妨雨墊巾，萬屐聲中緩歸策。"]'),
('cc51c94d-7960-4ed6-acb2-009fbeaca453','徐南卿招飯  其二','陳造','宋','宋诗','song-poetry','','[]','東隣客來每堅壁，西鄰客來常蓐食。',128,'全唐诗/poet.song.151000.json','["東隣客來每堅壁，西鄰客來常蓐食。", "旅中一飽豈細故，偕舉大事書之冊。", "末路孜孜食眠計，外此敢忘戒在得。", "蘇端向我顔色好，衝雨不辭泥沒膝。", "居貧頗禁惡客惱，念子秤薪仍數粒。", "肺可用禴米可餠，併付饞僮飽君德。", "人謂裁詩等裁錦，拙婦渠能把刀尺。", "陶翁宜報苦未賡，搜攪肝腸閑倚策。"]'),
('e10eeffa-bf1d-4aa7-b3e3-fe6876ab4da4','徐南卿招飯  其三','陳造','宋','宋诗','song-poetry','','[]','白晝曲肱睨東壁，鸒斯空復賊糧食。',128,'全唐诗/poet.song.151000.json','["白晝曲肱睨東壁，鸒斯空復賊糧食。", "晚途自笑硯生埃，少日頗嘗韋串冊。", "生世恐隨草木腐，忍使功言兩無得。", "長安寧無翕赩者，自疑有鐵關腰膝。", "樂天任運時近酒，子房逃榮猶却粒。", "求窮我者迄未知，夫此誰怨夫誰德。", "擬訪鶑花豁襟抱，門外雨餘泥一尺。", "山陰不待興盡回，掠面東風寒策策。"]'),
('3ab57050-4047-40ba-bec5-350e875a1ff9','再次韻謝徐監嶽惠和章','陳造','宋','宋诗','song-poetry','','[]','若人胸中著奎壁，落筆似不煙火食。',128,'全唐诗/poet.song.151000.json','["若人胸中著奎壁，落筆似不煙火食。", "平生著述奏奇勳，玉綴珠編今幾冊。", "定知前輩與爭驅，抑使衰翁飽新得。", "涎顙十駕終後塵，坐看康莊驂齧膝。", "陶猗廩庾詫陳腐，小家瓶罍不餘粒。", "清詩屬我猥見予，祇遣心顔賸慙德。", "條枚拱把竟何取，挺拔蒼松二千尺。", "政恐血指匠石前，袖手觀傍猶上策。"]'),
('652f4707-e400-4048-a83b-e13ac9ccd67a','再次林郎中韻','陳造','宋','宋诗','song-poetry','','[]','幾年塊處斷足音，日詠楚些歌常林。',64,'全唐诗/poet.song.151000.json','["幾年塊處斷足音，日詠楚些歌常林。", "朋知久矣張邴我，矻矻抱甕如漢陰。", "末路面顔殊自笑，故人情義無與深。", "桑榆可收倚君重，表表玉立行班心。"]'),
('02c4bba0-4f89-4b95-b895-2617ef4467df','贈王仲和架閣','陳造','宋','宋诗','song-poetry','','[]','朱樓窗霏楊柳烟，樓中香霧浮龍涎。',208,'全唐诗/poet.song.151000.json','["朱樓窗霏楊柳烟，樓中香霧浮龍涎。", "眩旋客眼錦繡筵，閙花打圍妖且妍。", "小蓓稚萼紅玉鮮，酒行急管雜繁絃。", "羯鼓催開褭風蓮，橫笛未放蛟鼉眠。", "老子判醉忘華顛，歸去就枕疑針氈。", "但有夢語追遊仙，芳訊忽聽青翼傳。", "翠鸞彩雲欻漂翩，縹緲三十六洞天。", "水佩風裳若箇邊，重來朱樓柳吹綿。", "樓中主人卓詩肩，瀹處士茗安僧禪。", "兀坐向我俱可憐，君才時彥孰後先。", "宦路已著祖生鞭，富貴取携固有然。", "列屋指見羅嬋娟，老子賢否真天淵。", "蕙蘭香中錦瑟前，觴詠或可君周旋。"]'),
('df714039-8e5b-4626-ba39-9911a54d4cf5','次韻林郎中龔宗簿','陳造','宋','宋诗','song-poetry','','[]','散人擁書茅屋底，祇合下澤居鄉里。',128,'全唐诗/poet.song.151000.json','["散人擁書茅屋底，祇合下澤居鄉里。", "浪指青冥期策足，端復滄浪規洗耳。", "林侯坐分韓席半，龔侯天才寧習慣。", "瓢酌天漿泰紫傍，峩峩貝闕連蜚觀。", "名位顧肯卑微休，兩傑未易今世求。", "老子志願一丘壑，鷦鵬彼此消遥遊。", "清篇駢來真好在，誰云物理莫兩大。", "捧心血指不得辭，門外長須翹足待。"]'),
('8789671c-022c-4a7e-8258-ed38deaaec14','再次韻寄林郎中','陳造','宋','宋诗','song-poetry','','[]','林侯理窟元無底，如拜宣尼親闕里。',128,'全唐诗/poet.song.151000.json','["林侯理窟元無底，如拜宣尼親闕里。", "經笥沈醇文筆古，俯視時流皆口耳。", "我生憂虞占多半，鼈跛蠖屈今已慣。", "林侯尚抗倉庾塵，盍胡嘗作不二觀。", "相魯君小公儀休，從政顧自愧由求。", "崧高蒸民有吉甫，飄風浪欲歌來游。", "索米惜不留行在，坐論看君偕五大。", "樵謳或配鼎彝書，衰翁縱衰猶可待。"]'),
('753e6286-76dd-4236-b078-974a49bf3bf5','再次韻呈林子長郎中龔養正寺簿','陳造','宋','宋诗','song-poetry','','[]','荒學蹄涔易窺底，祿𨔤不應夾帝里。',128,'全唐诗/poet.song.151000.json','["荒學蹄涔易窺底，祿𨔤不應夾帝里。", "昧爲此役君定笑，當念平生意行耳。", "過耳毀譽紛相半，曳裾袖刺何嘗慣。", "餬口未忘丐斗升，投閑正須問祠觀。", "歸雲倦鳥且罷休，鏡中頭顱盍反求。", "小兒能耕婦能餉，老子卒歲良優游。", "石友青雲兩君在，肺肝傾倒不自大。", "還家猶可詫里閭，渠儂祇博白眼待。"]'),
('61ec05d5-84b1-4d4d-b569-89ecef821a09','再次韻林郎中','陳造','宋','宋诗','song-poetry','','[]','醉鄉陶然真我底，落世瞢作魚千里。',128,'全唐诗/poet.song.151000.json','["醉鄉陶然真我底，落世瞢作魚千里。", "頗思溪風鳴檜枝，一洗半生市聲耳。", "帝城春月雨强半，躡屐衝泥今已慣。", "湖瑩冰奩濤湧山，回思向來領奇觀。", "角角倦鵲語未休，晚鳩饒舌如有求。", "明朝定可載酒去，携兒一爲湖上游。", "湖西羣艷雖無在，宿雲掃空天宇大。", "蹇吾健倒趁早歸，醉尉未須嗔目待。"]'),
('1d9194b3-9ea9-48fc-adce-1e745113538f','次兒輩喜雨韻呈太守','陳造','宋','宋诗','song-poetry','','[]','老子簞食師顔淵，憂世不合居民先。',128,'全唐诗/poet.song.151000.json','["老子簞食師顔淵，憂世不合居民先。", "今年不雨春破夏，惴惕亦復針氈然。", "嗟嗟五月河無水，溫飽之望疑已已。", "一雨滂浪彌夜旦，龍伯至仁端起死。", "國史未用書旱雩，人神幽顯修交孚。", "老子一飽危不給，恩私仰戴君大夫。", "君恩如天不遺物，龍伯豈應甘蠖屈。", "使君况是龍之友，偕兒同依趙卿日。"]'),
('a1c6a969-69c6-456b-aced-9536c6918e96','再次韻寄楊宰','陳造','宋','宋诗','song-poetry','','[]','小家作活魚脫淵，凶歉之備渠能先。',128,'全唐诗/poet.song.151000.json','["小家作活魚脫淵，凶歉之備渠能先。", "勞勤頗似抱甕叟，安得心數如計然。", "人方渴羌欲沽水，龍公睡足那容巳。", "怒捲淮江作飛雨，旱魃潜藏蝗蝻死。", "令君丘禱亦魯雩，天心默隨人意孚。", "百里旄倪歌載塗，我亦飽飯竟潜夫。", "今君豈復池中物，中年墨綬人稱屈。", "高郎小邑徑刺史，老子賀書當不日。"]'),
('3c1bc28a-e09e-4953-a44d-33b0a88f8d9b','使君有詩復次韻','陳造','宋','宋诗','song-poetry','','[]','詩播樂職聞子淵，貴耳底用泥古先。',128,'全唐诗/poet.song.151000.json','["詩播樂職聞子淵，貴耳底用泥古先。", "吾宗使君當世賢，援今輩古敢間然。", "祖武孫謀有源水，功名濟美方未已。", "即今朝野屬望深，簡齋仙人真不死。", "詩律欲並元劉驅，郡政坐使豚魚孚。", "編輯妙製紀殊績，瘖不措手吾非夫。", "壯歲毫端有神物，才與年衰此心屈。", "伸紙索句頗强顔，漫把清明譽天日。"]'),
('789651e9-e314-4680-9fc1-0a06d1f94e6c','贈臧汝舟次韻','陳造','宋','宋诗','song-poetry','','[]','昔人得珠沒濤淵，悟後悚惕悔厥先。',128,'全唐诗/poet.song.151000.json','["昔人得珠沒濤淵，悟後悚惕悔厥先。", "世間萬事無真是，辯口莫究然不然。", "此心疑然古井水，與俗方圓寧得已。", "紋楸亦有進道機，介視勝負齊生死。", "臧子多智守己愚，能事不蓋已日孚。", "南風覆舟後詐狙，義戰得雋逾老夫。", "閑中敗意防俗物，喜君相過不待屈。", "此樂政令兒輩知，閲日無庸譏愒日。"]'),
('fb15bcb3-f3db-401f-beab-dcb00722a34b','次韻楊宰花石綱遺石','陳造','宋','宋诗','song-poetry','','[]','令君藻翰輩古先，脫口一可樂石刊。',160,'全唐诗/poet.song.151000.json','["令君藻翰輩古先，脫口一可樂石刊。", "盍令珥筆草大冊，底用韻語談槐安。", "一詩爲弔湖邊石，深感崇寧全盛日。", "玉燭叶和黄道明，天扶休運非人力。", "豐碑端合頌虞周，遠來近悅絕嘆愁。", "有君無臣古所恨，殲佞嬉笑乘膠舟。", "鴆心飴口諛聖主，漕石移花閙南土。", "玲瓏蒼石中路棄，不見姦憸歐刀死。", "此心安得此石頑，感物抱恨甘終天。", "平日志願裹馬革，杖扶鬻茹吾衰年。"]'),
('8d0e560f-a94f-469b-895b-77de2f01e2cc','再次韻楊宰','陳造','宋','宋诗','song-poetry','','[]','君不見奇章平生石解顔，有得甲乙勞鎸刊。',166,'全唐诗/poet.song.151000.json','["君不見奇章平生石解顔，有得甲乙勞鎸刊。", "又不見衛公平泉嚴作戒，要與山岳爭完安。", "衽席杯盤易沈溺，可無雅好嬉過日。", "生須玩物不流物，負山暇問誰有力。", "此石擯棄歲幾周，幾人摩挱動詩愁。", "不妨野鳥印爪跡，曾是畫鷁明方舟。", "奇嗜豈必真無取，尤物未可輕糞土。", "二公真情不激詭，靜對孱顔堪樂死。", "揆予骯髒如石頑，一跌叵復能朝天。", "石默不言詩爲宣，正用吟玩忘吾年。"]'),
('2cd04d80-de5d-4b53-866d-54780219a7b9','次韻解禹玉','陳造','宋','宋诗','song-poetry','','[]','夫君官職雖西班，夫君不獨師孔顔。',368,'全唐诗/poet.song.151000.json','["夫君官職雖西班，夫君不獨師孔顔。", "畫手人言逼曹覇，詩力自詭追子山。", "對客每遊庖丁刃，得興笑解齊女環。", "般礴臝前筆未落，競病韻險思不慳。", "掀髯掃出山河影，就醉或放風月閑。", "我亦平生弄翰墨，諸公頗置齒頰間。", "側身南望常仰高，肯交下風俄二毛。", "京口市樓聽度曲，廣陵帥席陪揮毫。", "悲吟自作夜蟲響，絕唱傍羨秋鷹豪。", "虛孰高名擅顧陸，僅識妙思陵莊騷。", "金阜老仙憲文武，醴筵繼日喚我曹。", "銀臺吐燄眩金翠，繡帷護煖聞蘭膏。", "挈挈去尋樵牧盟，貸我抗俗慙山靈。", "風流雲散有悲唶，目前赤脚仍樵青。", "府公忽駕西蜚鵠，言訪劍閣摹舊銘。", "女媧青泥萬山外，爭突雲日寒崢嶸。", "前歡弦斷更容續，一紙寄意良未能。", "向者望望君不來，談舌攢棘胸填埃。", "叩門剝啄粲一笑，灑然一洗衰病懷。", "新詩絕妙不我靳，笑口忽復緣君開。", "驥足爭先真老矣，屠門大嚼亦快哉。", "但令石交不遐棄，此外擾擾付一咍。", "幾時携將好東絹，倩卷吳中山水回。"]'),
('074c5d5e-755e-42b1-ad65-2b28a70173a9','贈解禹玉','陳造','宋','宋诗','song-poetry','','[]','讀書祇博雙鬢斑，詩好豈解留朱顔。',371,'全唐诗/poet.song.151000.json','["讀書祇博雙鬢斑，詩好豈解留朱顔。", "平時無客憐轍鮒，觸處有人嘲飯山。", "相府略嘗喚宜祿，木門不夢窺銅環。", "多病但結藥裹伴，得酒間發詩囊慳。", "頻頻終慊鸒斯飽，浩蕩擬逐江鷗閑。", "未死更費屐幾兩，此生祇欠茅三間。", "丁年悔不全吾高，正坐枵腹守不毛。", "卑官餬口竟何補，捐棄什百收一毫。", "執版仰看上官面，可復直氣陵羣豪。", "夜剔殘燈賦招隠，愁追交情廣楚騷。", "豐約僅足優龍具，汙隆真可付馬曹。", "共嗟孔奮不自澤，政復所至無脂膏。", "向來枯策苦傷生，塗窮却用陶性靈。", "故人肯來問牢落，河畔罷吟草青青。", "夫誰急草修期檄，夫誰大刻班超銘。", "孽虜遊魂須晷刻，燕然蒼石高崢嶸。", "橫槊千篇月三捷，是責捨子誰當能。", "可遽學我賦歸來，臨流欲濯襟袂埃。", "老子期君舊不淺，看上要津舒壯懷。", "烏驚兔急易寒暑，堯蓂不辦供合開。", "文字玩世請少息，盛時難得君念哉。", "昔人聽謀取一得，勿以老耄資笑咍。", "君不見壯歲一跌子陳子，江湖畢世甘低回。"]'),
('4e816a78-5556-4c1c-91ae-14fb5e0770cd','次韻楊宰食蟹','陳造','宋','宋诗','song-poetry','','[]','長翁服食僧樣清，灌園得閑收落英。',224,'全唐诗/poet.song.151000.json','["長翁服食僧樣清，灌園得閑收落英。", "壯歲頗營口腹事，岡有罝罟梁有罾。", "大胾每快屠門嚼，美酒慣陪豪士傾。", "酒邊最愛無長叟，坐隅未揖先風生。", "揮斥肴品進此叟，似去傖荒遊上京。", "王謝家兒負販子，氣味不待口舌爭。", "年年屬饜不汝厭，勇向上黨人夸矜。", "一從多病戒奇嗜，屏絕鱗介疎薑棖。", "水中之怒寧阿系，丈室高卧幾凈名。", "二年閑殺把螯手，久要藥裹熏爐并。", "旱後籃筐薦蜞越，君乃下筯收所憎。", "銘盤久斷舊嗜好，垂涎忽誦新歌行。", "射陽浦口霜耿耿，繁梁埭頭霧冥冥。", "及今尖團日供百，莫孤君家竹葉清。"]'),
('fd838253-44c0-4309-9feb-8ed3b521f5d1','送羊侯因簡崔帥','陳造','宋','宋诗','song-poetry','','[]','殿廬護嚴外蕃宣，崔侯文武能兼全。',192,'全唐诗/poet.song.151000.json','["殿廬護嚴外蕃宣，崔侯文武能兼全。", "石城之政列城先，迄今遺愛春與妍。", "爾來淮上提帥權，淮民歌舞且晏眠。", "術業可但朝路傳，異域南首爭駢肩。", "舊故顧念無愚賢，如我衰病霜滿顛。", "眷眷未肯即棄捐，一紙緘春飛墮前。", "嬾拙雙足如繞纏，欲往謝之尋回船。", "每獨念之幾針氈，叔子北歸氣翩翩。", "棋酒辦與君周旋，未醉定復譚臞仙。", "知我抱犢方中田，黄堂名酒壓香泉。", "淮白不下槎頭鯿，叔子小駐當還轅。", "有人北望心拳拳，無使渴德垂饞涎。"]'),
('0caaaa9c-d300-4578-8162-b82ee737812a','次韻張守垂虹小駐','陳造','宋','宋诗','song-poetry','','[]','聞道垂虹舒遠目，江波浩蕩江天晴。',64,'全唐诗/poet.song.151000.json','["聞道垂虹舒遠目，江波浩蕩江天晴。", "江城竹馬待已久，未妨小寒鷗鷺盟。", "郡民憔嗟歲不熟，丈夫慨慷志在行。", "盛時陳力要接淅，遮莫常譚嗤老生。"]'),
('736c0053-8f6f-44a3-865d-75c5d27cd118','再分韻得花字','陳造','宋','宋诗','song-poetry','','[]','春工幾時來天涯，人間指顧成豪華。',144,'全唐诗/poet.song.151000.json','["春工幾時來天涯，人間指顧成豪華。", "未嘆丹杏無餘葩，能事已到桃李花。", "東園地勝賓盡嘉，塵邊霏屑杯中霞。", "將壇令下手一叉，陣勢欻變常山蛇。", "眉顰肩聳靜不譁，詩成笑語還紛拏。", "吾儕此樂世莫加，聚蚊金谷何足夸。", "但恐兒輩摇齒牙，法士亦復工疵瑕。", "君且休矣吾還家，况復高柳翻倦鴉。", "徑催紫衣巾小車，我亦款段隨揮檛。"]'),
('e79357a0-8889-4711-9981-dbfc561b45ce','贈趙子野','陳造','宋','宋诗','song-poetry','','[]','長翁飲德腹爲實，趙侯論交膠在漆。',128,'全唐诗/poet.song.151000.json','["長翁飲德腹爲實，趙侯論交膠在漆。", "官曹未肯孤吟賞，車載鴟夷挽衰疾。", "樓前紅樹媚晴霽，樓間清風細披拂。", "崢嶸帝皞專花事，彷彿江妃奏瑶瑟。", "巾欹幘墮人傲兀，堂堂飲興方未畢。", "眼看韶華吾囁嚅，氣摩蒼昊君豪逸。", "人間樂事易陳迹，便恐清歡轉頭失。", "孰知椽筆今詩史，煩君揮毫記今日。"]'),
('7b7b96cb-9f71-443f-bd56-425baf67ea87','贈劉行甫','陳造','宋','宋诗','song-poetry','','[]','劉郎雍容古君子，平時人指原夫耳。',64,'全唐诗/poet.song.151000.json','["劉郎雍容古君子，平時人指原夫耳。", "忽然闖我風雅壇，疾雷破柱蛟龍起。", "豫章可棟今七年，魏舒驚人纔一矢。", "後來獨步君仲宣，撫斲輪具吾衰矣。"]'),
('35ce2de2-eaa2-432b-aba6-c2c711abb1e5','次韻趙子野贈別','陳造','宋','宋诗','song-poetry','','[]','白地倒海翻重湖，趙侯塗改插架書。',176,'全唐诗/poet.song.151000.json','["白地倒海翻重湖，趙侯塗改插架書。", "石麟角犀清而腴，了知不是山澤臞。", "舌宮齒商鳳將雛，一笑著我東郭竽。", "曹後鮑前君指呼，郊寒島瘦君童奴。", "翠鳳未炙口不餬，吮漱沆瀣騎兔烏。", "擘水挹取驪頷珠，挂作白月照海隅。", "丹山阿閣久榛蕪，跳梁餓鴟啼鵓鴣。", "兩鳥囚作轅下駒，巨靈蹶起張怒鬚。", "一鳥伸喙羣翼趨，向來偃仆須君扶。", "大篇落手吾戒塗，春風得意揄翠裾。", "東西州爾非秦吳，猶金玉音寧所圖。"]'),
('b59cf95f-bebf-47f5-bbbd-3938e2a89f63','送曹器遠從使虜','陳造','宋','宋诗','song-poetry','','[]','暑風焮面黄塵底，曹侯據鞍輕萬里。',160,'全唐诗/poet.song.151000.json','["暑風焮面黄塵底，曹侯據鞍輕萬里。", "曉趁官程夜未休，不爲功名爲知己。", "男兒生有四方志，誰能俛眉婦車裏。", "周原咨度使塵飛，漢官威儀渠顙泚。", "異時橫草恐不免，此去灌瓜聊復爾。", "赤縣神州吾舊物，文謨武略君奇士。", "列聖恩波迄未涯，百年胡運今如此。", "山川險隘須默究，他日上前煩聚米。", "殺胡之林定何許，持酒遐望一啟齒。", "歸來有句敵車攻，老子滯懣資一洗。"]'),
('357f6921-dbe5-430e-b1ba-5a716f1b213d','送二趙金陵秋闈之行','陳造','宋','宋诗','song-poetry','','[]','君家種德麻葦似，兩郎今日東南美。',160,'全唐诗/poet.song.151000.json','["君家種德麻葦似，兩郎今日東南美。", "石麟角犀互輝映，拄腹撐腸皆錦綺。", "賢書聯翩取如掇，文字欲貴江淮紙。", "步光久匣自光芒，僕姑所指當披靡。", "去去秋風鼓鵬翼，翺翔烟霄此其始。", "建鄴山川古雄麗，平分勝槩供筆底。", "氣陵鍾阜峰頭雲，辭傾白鷺洲前水。", "聯璧不難先衆俊，歷塊仍能輕萬里。", "平日雙眼不屢青，奇窮一生端坐此。", "即今意氣爲君傾，老子閲人蓋多矣。"]'),
('fef7c44c-c490-4243-842a-1a632c1442b1','送劉常父秋試兼簡行父','陳造','宋','宋诗','song-poetry','','[]','良樂佇目思驥子，工師擇材須杞梓。',128,'全唐诗/poet.song.151000.json','["良樂佇目思驥子，工師擇材須杞梓。", "劉家昆季寧近用，直幹百圍日千里。", "戲綵之暇同鷄窗，平挹千古如探囊。", "尺箠政自無堅彊，况腰烏號手魚腸。", "鄉邦驚嘆有此客，一筆與翁箭鋒直。", "秋賦春闈溷子爾，老子賀書已濡筆。", "香名聯翩傳里閭，珠宮貝闕方權輿。", "他年日奉平反笑，更勝而今讀賀書。"]'),
('7bb8bb66-4f75-44af-9cb4-2fef9107f4b0','題六么後','陳造','宋','宋诗','song-poetry','','[]','愛愛少日淫奔女，愛愛死作貞烈婦。',199,'全唐诗/poet.song.151000.json','["愛愛少日淫奔女，愛愛死作貞烈婦。", "東隅一跌收桑榆，竟得佳名傳樂府。", "男子處死正自難，此女勵志雪柏寒。", "至今挺挺在人目，詩翁作詩垂不刊。", "誰翻此詩入宮羽，檀唇緩歌細腰舞。", "直掩霓裳羽衣曲，更問離魂饋漿女。", "且玩此舞空金巵，莫奏此曲增悲悽。", "蘭摧蕙枯崑玉碎，不如人家嫁狗隨狗鷄隨鷄。", "百年佳麗終枯骴，汝名芬芳無已時。", "捨生狥義渠安之，而我更用興悲爲。", "我悲所悲人不識，撫事懷人悼今昔。", "翻雲覆雨行路難，君不見買臣之妻彥升客。"]'),
('b6d30e97-0b7f-4335-bcc9-2784e85a0a2b','陳伯固使君禱雨得雪爲作','陳造','宋','宋诗','song-poetry','','[]','妖魃肆虐挻餘災，麥田未麥空黄埃。',160,'全唐诗/poet.song.151000.json','["妖魃肆虐挻餘災，麥田未麥空黄埃。", "饑民忍饑守鄉土，倚公力挽和氣回。", "梵筵告旱初拜手，補陀仙人已回首。", "楊枝一麾神受職，雪龍占先效奔走。", "飛翔作意擅曉昏，膏潤趁時救枯朽。", "人名此雪宗丞雪，祈禳取携屈伸肘。", "德政可但人間最，大士與徒龍與友。", "閔雨競喜雪應祈，今段尤拜天賜厚。", "歸前帝席指日冀，更遣奇祥福諸後。", "太歲在戌如在酉，看取乞漿還得酒。"]'),
('eb2b93c8-7d2e-45fe-8e02-cb69afd3d850','次韻楊宰','陳造','宋','宋诗','song-poetry','','[]','頭顱敢意封戶牖，飲處往往推祭酒。',112,'全唐诗/poet.song.151000.json','["頭顱敢意封戶牖，飲處往往推祭酒。", "宜人珍果亦鼎來，把杯未省嗟不偶。", "拳栗御棗玉山奇，南北氣殊仍地醜。", "少日詩人鱠鯨興，莫年醉客持螯手。", "令君未負將軍腹，襞積琅玕向誰剖。", "三珍薦槃侑從事，翛然徑訪無何有。", "詩來可但落饞涎，萬卷更慙王季友。"]'),
('9f48814f-7b87-4749-9132-0cb1e5d515ee','送赴省七子','陳造','宋','宋诗','song-poetry','','[]','憶昔塗抹鬢未秋，著書初不緣窮愁。',288,'全唐诗/poet.song.151000.json','["憶昔塗抹鬢未秋，著書初不緣窮愁。", "交契往往第一流，愛且助之恩意周。", "翳桑槃飯驚浪舟，如輠轉轂需膏油。", "疾需妙劑寒需裘，李郝硯席初綢繆。", "陳趙進脩警墮偷，出語鑿鑿珊瑚鈎。", "三臧筆底風雨遒，丁年出我便一頭。", "儒林丈人拔其尤，賢書政用譚笑收。", "七子寂寂從我遊，窮人累人君信不。", "迄今里閈聞沈浮，玉音下天正旁搜。", "南宮之行勿夷猶，巨魚縱壑鷹辭韝。", "鴈塔岐路鄰崑丘，捷音聯翩走吾州。", "壯志此去不啻酬，士抱奧學追前修。", "噤不施世吾儕羞，肯卧少室甘沈幽。", "肯闖侯門提蒯緱，賢科夷塗古共由。", "論才君等誰與儔，可學老子拙自謀。", "所向數奇老不侯，一樽上盡猶未休。", "索句軋軋繭緒抽，不作兒女聲悲啾。", "倚須接武拱帝旒，付我一竿釣滄洲。"]'),
('81309e6c-566a-409f-ac05-48a27fa8a434','石湖兩帖還李推官','陳造','宋','宋诗','song-poetry','','[]','石湖老子家蓬丘，一笑俯作人間遊。',144,'全唐诗/poet.song.151000.json','["石湖老子家蓬丘，一笑俯作人間遊。", "風度人品第一流，結字亦復無朋儔。", "還軫蓬丘俄十秋，恍開此帖揩病眸。", "便若執鞭侍瓊舟，狂奔渴驥騰驚虬。", "斷圭折劍紛然投，蜚虹曳霞爛相繆。", "人間至寶人貪求，無閭珣琪雍琳璆。", "彼此輕重寧其侔，借我肯作一月留。", "我癡不減顧虎頭，還君孰視仍牢收。", "愛護幸免惡客偷，亦幸不污寒具油。"]'),
('5ce762ed-ad7f-4729-99d7-1f5288d8d323','陳學正惠詩酬以長句','陳造','宋','宋诗','song-poetry','','[]','寒風折人粟生膚，局坐掩戶孰與娛。',128,'全唐诗/poet.song.151000.json','["寒風折人粟生膚，局坐掩戶孰與娛。", "吾宗高義駕爲迂，新詩爛粲慰槁枯。", "一百十二驪龍珠，春意誰遣生座隅。", "吾宗學力源委俱，决爲巨川潴陂湖。", "粉袍未脫口未餬，氣凌雲霄色敷腴。", "肝肺向我每傾輸，我老舊學慙榛蕪。", "妙語正頼君起予，不辦瓜李酬瑶琚。", "病鶴曳翮寒松臞，可復飛動索故吾。"]'),
('79eeddfd-20c0-467a-b6c6-b05be4a4102f','陳學正孫學錄有詩復次韻','陳造','宋','宋诗','song-poetry','','[]','俗子敗興蚊咂膚，獨頼勝士相嬉娛。',128,'全唐诗/poet.song.151000.json','["俗子敗興蚊咂膚，獨頼勝士相嬉娛。", "彼異趣者嗤我迂，豈知木茂水不枯。", "繄山韞玉淵懷珠，二子豪爽仍廉隅。", "才名角立風義俱，詩筆爲我翻重湖。", "雨膏霧沐春模糊，佳節尚忍孤雲腴。", "古來左角計贏輸，但有丘隴埋煙蕪。", "願言公等常娛予，不辱裋褐榮瓊琚。", "山雌卑飛未妨臞，更用鳥烏歌吾吾。"]'),
('b4624ae8-0702-4030-b68a-8636c3519232','戲作','陳造','宋','宋诗','song-poetry','','[]','書生稟賦紙樣薄，平日扶衰惟粥藥。',218,'全唐诗/poet.song.151000.json','["書生稟賦紙樣薄，平日扶衰惟粥藥。", "一日飲濕小嚙肥，河魚數日煩醫治。", "佳辰府公約把酒，嚴斥厨丁預節口。", "借問主賓酬酢餘，還許公榮袖手無。", "厚味腊毒古不予，如作病何仍古詰。", "生世例非金石堅，支離如我更可憐。", "饞噇動使諸病入，冷坐亦復百憂集。", "彭殤瘠肥本自齊，此理祇許蒙莊知。", "筯下萬錢無足取，厨薦三韭徒自苦。", "法士語飲應且憎，何如卧客懷中醉不譍。", "婪酣任人嗤穀伯，何如辟穀高人師黄石。", "陳遵張竦枘鑿夫何爲，彼此未可相是非。", "七十老翁誰能促戚縛此戒，醉死病殂吾命在。"]'),
('f91f5422-0330-4542-a514-ed8a00785b5b','次陳倅同年瓊露酒詩韻','陳造','宋','宋诗','song-poetry','','[]','君家家釀人家無，市酤漓澀真剝膚。',128,'全唐诗/poet.song.151000.json','["君家家釀人家無，市酤漓澀真剝膚。", "朝來洗盞釂先酒，凝若金莖秋露珠。", "色香第一味稱此，輿臺桑落卿玉腴。", "客間公榮不共飲，主人恩意無乃孤。", "歡伯三益能娛予，愁城九守付摧枯。", "淮鄉香泉豈其徒，魂夢枉用馳枌榆。", "君家家釀人家無，渴羌惱君君恕乎。", "爲君劇飲首就濡，可待謀樂間憂虞。"]'),
('70d984f2-2c01-492c-90d2-337d6a1892b7','題高夢錫指牛圖','陳造','宋','宋诗','song-poetry','','[]','將軍向來馬量谷，封君劣比羊千足。',168,'全唐诗/poet.song.151000.json','["將軍向來馬量谷，封君劣比羊千足。", "浮雲富貴漫夸毗，不博范叟回青目。", "此叟落魄水墨仙，松煤染指皆其天。", "奏刀浪詫牛無全，寢訛降飲二百角。", "身不服箱鼻不穿，觳觫肯受衆目憐。", "高郎畫徧米家船，此軸寶重一當千。", "老子老欲耕淮壖，薋菉葹滿高下田。", "政用百尾收烏犍，刀劍縱售能幾錢。", "展掩此畫空惘然，平日幽趣終拳拳。", "此叟儻可作九原，畫我草履麻爲鞭，經挂牛角羣牛前。"]'),
('9f90082e-6a3e-44bf-9ddf-98a6e3d74a1c','次朱必先與師是唱酬韻  其一','陳造','宋','宋诗','song-poetry','','[]','朱郎滿腹抱賢業，壯歲彈鋏仍哀歌。',128,'全唐诗/poet.song.151000.json','["朱郎滿腹抱賢業，壯歲彈鋏仍哀歌。", "飛將未侯方朔餓，天無老眼如子何。", "紛紛過眼日百十，超拔如君信難及。", "平陵筆陣吾敢支，穩掇世科人所必。", "小兒鹿鹿空肩隨，血指汗顔驚崛奇。", "於菟一嘯百獸懾，誰顧露草寒蛩悲。", "詩書鼓吹且强飯，舜咨皋謨適華旦。", "功名迫逐可得辭，等閑莫詠南山粲。"]'),
('a57238ae-f103-4de5-af8f-15de3e521ba0','次朱必先與師是唱酬韻  其二','陳造','宋','宋诗','song-poetry','','[]','男子負抱成蹉跎，唾壺自擊商聲歌。',128,'全唐诗/poet.song.151000.json','["男子負抱成蹉跎，唾壺自擊商聲歌。", "此聲此意誰解領，政用折柬招羊何。", "人言百里半九十，它日聰明嗟不及。", "雲衢掎袂夢空勞，神武挂冠吾已必。", "久要但有窮鬼隨，此鬼亦使文怪奇。", "推敲慣嘗京尹怒，登臨肯興賦客悲。", "蠶蟻可浴牛可飯，農家星候知昏旦。", "不妨婢子辦黄紬，更貸鄰僧供白粲。"]'),
('bab16350-f2fc-40f9-b794-43180755ea93','客以詩爲東園飲不果次其韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','東園千樹簉白紅，携壺滿意一醉同。',64,'全唐诗/poet.song.151000.json','["東園千樹簉白紅，携壺滿意一醉同。", "向來可是君宿諾，政復急雨斜驚風。", "縣知此興未渠盡，暖日晴雲豈終吝。", "叩門日聽長須來，老夫於子驂之靳。"]'),
('4d878396-6d81-49ea-a127-7723f8b192c4','客以詩爲東園飲不果次其韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','春池照影紅錦衣，鴛鴦與鴨同低摧。',64,'全唐诗/poet.song.151000.json','["春池照影紅錦衣，鴛鴦與鴨同低摧。", "金籠鸚鵡頗誶語，解道春色今寒灰。", "客來命笑還錯莫，此情不似君情薄。", "會須把酒杏花前，祇喚茶甌充罰爵。"]'),
('27150fde-c194-4b8b-8b1d-de3390db2df8','雨未止再次前韻二首  其一','陳造','宋','宋诗','song-poetry','','[]','蒼顔無酒不能紅，坐窗袖手禪衲同。',64,'全唐诗/poet.song.151000.json','["蒼顔無酒不能紅，坐窗袖手禪衲同。", "幾時羲馭肯憐客，滿意花卉摇光風。", "樽酒向君懷抱盡，賡歌劇譚忘悔吝。", "更看珠玉聯翩來，孰云猛乞猶小靳。"]'),
('275cbdd3-71f5-41d9-809a-47ee9d603528','雨未止再次前韻二首  其二','陳造','宋','宋诗','song-poetry','','[]','樽前罷唱金縷衣，花爲蔫萎玉爲摧。',64,'全唐诗/poet.song.151000.json','["樽前罷唱金縷衣，花爲蔫萎玉爲摧。", "欠伸舊識名駒子，蘭艾一燎同飛灰。", "匆遽不及呼莫莫，春愁禁人酒力薄。", "擬令大白徑浮君，畢獻繼今仍此爵。"]'),
('e231ef6c-7f44-4737-ae33-909c6ac5ff97','次韻魏知元  其一','陳造','宋','宋诗','song-poetry','','[]','詩人索詩無乃俗，我乎索之更虛辱。',64,'全唐诗/poet.song.151000.json','["詩人索詩無乃俗，我乎索之更虛辱。", "從來東郭濫吹竽，繆使尾續陽春曲。", "此腹涸矣勞誅求，我老知耻吾罷休。", "使君拂雲敞新樓，且可一醉同樓頭。"]'),
('cbae4068-a8f2-431e-8071-bb64de4297e9','次韻魏知元  其二','陳造','宋','宋诗','song-poetry','','[]','青樓琴客信超俗，俗外客子幸臨辱。',64,'全唐诗/poet.song.151000.json','["青樓琴客信超俗，俗外客子幸臨辱。", "定知略眼歲寒枝，肯負平生白頭曲。", "雌凰雄鳳副所求，和鳴之樂方未休。", "暗香疎影春借力，更看青子駢枝頭。"]'),
('b4b68e6d-558a-4035-a332-9aa3d200b80e','次高賓王餞徐南卿韻','陳造','宋','宋诗','song-poetry','','[]','徐郎坐窮無幾請，千里過我身將影。',64,'全唐诗/poet.song.151000.json','["徐郎坐窮無幾請，千里過我身將影。", "未辦還轅梅雪漂，頗憶離家鴈天冷。", "高郎表表今子雲，等閑落筆詩中君。", "學力不爲救饑分，歸從夫子收奇勳。"]'),
('57b5c4b3-de03-4f95-95a6-47279d5e3d82','贈畫士龔子','陳造','宋','宋诗','song-poetry','','[]','古人論畫索畫外，世俗區區較形似。',214,'全唐诗/poet.song.151000.json','["古人論畫索畫外，世俗區區較形似。", "眼明亦有可人者，龔子畫形兼畫意。", "秋蘭春蕙相與芳，梅花照影生暗香。", "倚煙映霧各夸嫮，併作短軸供寶藏。", "斬新雪色三丈壁，勝日煩渠揮淡墨。", "楂牙老樹對醜石，龍騰獸伏起恍惚。", "松底跳波隠隠轟千鼙，石間橫斜風竹相因依。", "長翁雅趣在水竹，新開湖南規辦五畝綠。", "此松此石偕四友，身未出門先在目。", "暮年供給良易足，龔子惠我真絕俗。", "萬錢酬贈不頷頤，新詩渠能飽君腹。", "平生好事吾屢空，龔子好事未後翁。", "藏詩寶畫從人笑，與子把玩無終窮。"]'),
('b9080624-905d-4771-80d9-8c4f23ca0334','呈趙帥','陳造','宋','宋诗','song-poetry','','[]','雨行本自貪風便，四十里程真劈箭。',232,'全唐诗/poet.song.151000.json','["雨行本自貪風便，四十里程真劈箭。", "長年攤錢夸半仙，一炊黍頃風頭轉。", "生世快意多所辱，葉舟瓠壺浪如屋。", "暗樁觸船船版折，船丁籲天船媼哭。", "塗窮儻有哀王孫，腰舖人家緊閉門。", "丁翁祿𨔤捕魚者，向我顧肯顔色溫。", "茅屋新成容寄宿，麻茶初熟仍見分。", "解衣滅燭睡欲死，鄉夢醒時鷄喚晨。", "平時晨餔下南浦，定向揚州聽更鼓。", "飛廉生憂吾敢怨，薄命若爲防市弩。", "今朝河面吹細痕，竹樹不聲人駿奔。", "掣鈴一笑話疇昔，便有樂事酬佳辰。", "鎮淮主人開淥樽，蕙蘭香前簫鼓喧，一盃爲我安驚魂。", "勝談亹亹清耳根，向來憂虞無足言。"]'),
('dd0ef245-2638-42a9-9cc6-1f61fe261f68','山居十首  其一','陳造','宋','宋诗','song-poetry','','[]','山間有好事，時肯問何如。',48,'全唐诗/poet.song.151000.json','["山間有好事，時肯問何如。", "束送筯頭薤，鮮分匙面魚。", "披襟偕我飽，攬髮爲君梳。", "一笑塵勞外，都無病可祛。"]'),
('a9267a4b-073d-4ddd-bfa5-5986be3f9d7f','山居十首  其二','陳造','宋','宋诗','song-poetry','','[]','咀毒橫戈地，財堪博一羞。',48,'全唐诗/poet.song.151000.json','["咀毒橫戈地，財堪博一羞。", "時流正攘臂，老子解抽頭。", "秦楚蝸兩角，跖夷貉一丘。", "向來回晚照，了不見全牛。"]'),
('ce71de86-4d93-4ff7-9ce1-c715496983d6','山居十首  其三','陳造','宋','宋诗','song-poetry','','[]','忽作斷過訪，經旬閑瘦筇。',48,'全唐诗/poet.song.151000.json','["忽作斷過訪，經旬閑瘦筇。", "慵添和詩債，病減灌園功。", "石鼎裊輕碧，庭柯零碎紅。", "竹君如見慰，竟日嘯窗風。"]'),
('cdb6fef0-b9eb-4fc2-a5bb-627a9f7a9c2f','山居十首  其四','陳造','宋','宋诗','song-poetry','','[]','居深自少客，兒輩省譍門。',48,'全唐诗/poet.song.151000.json','["居深自少客，兒輩省譍門。", "日課午鐘飯，生涯三畝園。", "嗜魚親蜑戶，輟果及王孫。", "不惜苔錢破，橫縱步屧痕。"]'),
('3c35b9d0-74d3-43a1-806b-28b9575eaa1e','山居十首  其五','陳造','宋','宋诗','song-poetry','','[]','鳥息我亦倦，行行取徑微。',48,'全唐诗/poet.song.151000.json','["鳥息我亦倦，行行取徑微。", "石稜妨錯足，藤蔓每鉤衣。", "森木各天籟，連山同夕暉。", "推門吟袖冷，滿带野風歸。"]'),
('d72100f1-4f28-46ec-babf-03c1fcbbdeb7','山居十首  其六','陳造','宋','宋诗','song-poetry','','[]','涉世慣多遻，還欣愜此心。',48,'全唐诗/poet.song.151000.json','["涉世慣多遻，還欣愜此心。", "鷄孫當歲稔，竹母值秋陰。", "言配香秔軟，行須綠影深。", "繼今摩腹去，風日更蕭森。"]'),
('9f38e3db-8301-4db2-95eb-86f60970ec7e','山居十首  其七','陳造','宋','宋诗','song-poetry','','[]','萍梗纔餬口，爬沙亦畏塗。',48,'全唐诗/poet.song.151000.json','["萍梗纔餬口，爬沙亦畏塗。", "悠然三徑地，有此百金軀。", "乘興聊吟筆，無絃且槁梧。", "幽居喜客醉，未遣秫田蕪。"]'),
('e9440b79-cf60-437f-abc0-92d9f4240cc5','山居十首  其八','陳造','宋','宋诗','song-poetry','','[]','蕉鹿謝依乘，孤高迺得朋。',48,'全唐诗/poet.song.151000.json','["蕉鹿謝依乘，孤高迺得朋。", "閑談每褐父，清晤或鄰僧。", "止酒玄真子，居家杜伯升。", "此心安隠處，蜩鷽傲鵾鵬。"]'),
('4395356d-6ac4-4dae-b20b-9d5ce03ab9a2','山居十首  其九','陳造','宋','宋诗','song-poetry','','[]','一室市聲外，生經良不孤。',48,'全唐诗/poet.song.151000.json','["一室市聲外，生經良不孤。", "園花非獨笑，風竹巧相娛。", "爲客求鵝母，供家課橘奴。", "殘年溫飽爾，外此亦何須。"]'),
('c3cc4f75-95cf-4537-ba1a-ee81094e9089','山居十首  其一○','陳造','宋','宋诗','song-poetry','','[]','丁年陪友舊，塵霧去駸駸。',48,'全唐诗/poet.song.151000.json','["丁年陪友舊，塵霧去駸駸。", "不頼學問力，終孤雲水心。", "無波真古井，躍冶豈祥金。", "撫己知今是，扁舟釣碧潯。"]'),
('565c30c8-2550-4317-bc2a-b00bda7fca1f','元夜病起二首  其一','陳造','宋','宋诗','song-poetry','','[]','霽色莫澄鮮，和聲入管絃。',48,'全唐诗/poet.song.151000.json','["霽色莫澄鮮，和聲入管絃。", "人家無事日，時節放燈天。", "璧月紅塵外，東風綠酒前。", "强陪兒女笑，病骨得輕便。"]'),
('4c93c05e-fc96-4d54-bc8c-ad664c1ff252','元夜病起二首  其二','陳造','宋','宋诗','song-poetry','','[]','節物撩佳興，浮生盍自寬。',48,'全唐诗/poet.song.151000.json','["節物撩佳興，浮生盍自寬。", "山城如許樂，燈市不多寒。", "微步漂香細，行歌惜夜闌。", "何人欹醉帽，朱袖簇歸鞍。"]'),
('4b85251a-19c3-4d08-9c88-744a4c6af87d','香雲寺','陳造','宋','宋诗','song-poetry','','[]','山月明空隙，庭柯下槁乾。',48,'全唐诗/poet.song.151000.json','["山月明空隙，庭柯下槁乾。", "沈沈僧夜靜，漠漠鴈天寒。", "夢境愁偏隔，詩情老易闌。", "未容辭水厄，聊復踞蒲團。"]'),
('2b279e45-64ca-4a72-9d1b-02d690da210b','丁簿到蕪湖書不至','陳造','宋','宋诗','song-poetry','','[]','幾日到于湖，交情未合疎。',48,'全唐诗/poet.song.151000.json','["幾日到于湖，交情未合疎。", "相望百里地，不寄一行書。", "待此寬相憶，何人念索居。", "朔風吹鴈斷，徙倚正愁予。"]'),
('679a9dfb-98e6-4f5b-8f22-b8d9bc3a2e96','圩上','陳造','宋','宋诗','song-poetry','','[]','小村山影裏，山脚水明沙。',48,'全唐诗/poet.song.151000.json','["小村山影裏，山脚水明沙。", "春事初移柳，人家未摘茶。", "生兒了門戶，饌客有魚蝦。", "笑我塵埃者，奔馳鬢易華。"]'),
('a8c16e5e-02df-49a5-9b02-db271d406e64','丁酉道中暮春','陳造','宋','宋诗','song-poetry','','[]','去家如昨日，節物轉頭非。',48,'全唐诗/poet.song.151000.json','["去家如昨日，節物轉頭非。", "風處綠自舞，雨餘紅頓稀。", "野橋平水過，村路躡花歸。", "趁得酴醾在，箏琶拂舊衣。"]'),
('0c741fd8-1659-4c07-a0c6-b700fd343ba4','秋日','陳造','宋','宋诗','song-poetry','','[]','夢蟻浪多憂，隙駒如許遒。',48,'全唐诗/poet.song.151000.json','["夢蟻浪多憂，隙駒如許遒。", "凄凉一霜早，黄落萬山秋。", "得失古青簡，漂零予白頭。", "不因多病過，始覺此生浮。"]'),
('50de2c9f-abed-491e-85f5-efcadc382979','仁于庵','陳造','宋','宋诗','song-poetry','','[]','䆉䅉圍僧屋，檀欒隔槿籬。',48,'全唐诗/poet.song.151000.json','["䆉䅉圍僧屋，檀欒隔槿籬。", "月池聊濯足，雪壁賸留詩。", "里社皆囷廩，鐘魚亦歲時。", "平生松隠賦，回首十年遲。"]'),
('6d65d564-8060-4d0e-95f5-9c453a0f6e99','次韻翟元卿  其一','陳造','宋','宋诗','song-poetry','','[]','君是儒冠秀，源流况父兄。',48,'全唐诗/poet.song.151000.json','["君是儒冠秀，源流况父兄。", "文堪一戰霸，氣欲五郎卿。", "與世甘多遻，謀生迄未成。", "其誰爲推挽，小試合承明。"]'),
('4bc80cd2-5a7a-472e-8b16-a841eb22e5f0','次韻翟元卿  其二','陳造','宋','宋诗','song-poetry','','[]','我困枘投鑿，君才瓴建高。',48,'全唐诗/poet.song.151000.json','["我困枘投鑿，君才瓴建高。", "要之同臭味，政以借熏陶。", "觴詠聊真樂，媸妍付爾曹。", "能來緩詩頰，芋火薦松醪。"]'),
('b1d2bd4c-b9f4-48d9-a886-1e490d2516b3','得姪消息二首  其一','陳造','宋','宋诗','song-poetry','','[]','甚喜年穀熟，仍聞佳食眠。',48,'全唐诗/poet.song.151000.json','["甚喜年穀熟，仍聞佳食眠。", "郡人新過此，鄉信得真傳。", "社酒浮蛆淥，湖魚割玉鮮。", "平時計安穩，莫靳里胥錢。"]'),
('dff1457a-742b-4601-bbe7-0524c59def78','得姪消息二首  其二','陳造','宋','宋诗','song-poetry','','[]','二頃居耕穫，爲謀未覺非。',48,'全唐诗/poet.song.151000.json','["二頃居耕穫，爲謀未覺非。", "輸租能早計，坐社莫相違。", "念我官將滿，連宵夢只歸。", "團欒老丘壑，肯作食言肥。"]'),
('b39e1c28-9570-46ea-8d12-5d16dd456e83','感興','陳造','宋','宋诗','song-poetry','','[]','如鏡江流去，奔馳合自羞。',48,'全唐诗/poet.song.151000.json','["如鏡江流去，奔馳合自羞。", "病容霜後葉，歸興浪前漚。", "岐路三生債，風埃一飽謀。", "山田饒芋栗，珍重故園秋。"]'),
('d89e5866-a06e-48f7-9c58-48931725b2c1','送人赴試','陳造','宋','宋诗','song-poetry','','[]','之子是荆璞，溫純仍琢磨。',48,'全唐诗/poet.song.151000.json','["之子是荆璞，溫純仍琢磨。", "諸公推大手，壯歲合賢科。", "豹霧三年隠，龍門一躍過。", "得詩應自慰，老子閲人多。"]'),
('80d4d815-2329-4d6e-9153-d3edce39ff50','金地寺','陳造','宋','宋诗','song-poetry','','[]','側徑崎嶇去，飛蘿次第捫。',48,'全唐诗/poet.song.151000.json','["側徑崎嶇去，飛蘿次第捫。", "山橫欲無地，路轉却逢村。", "竹柏圍荒寺，莓苔上繚垣。", "殘僧不知客，芋火老雲根。"]'),
('6ac23141-1097-4364-91d8-c2b8b605e269','留行都','陳造','宋','宋诗','song-poetry','','[]','久飫南來飯，長維北去船。',48,'全唐诗/poet.song.151000.json','["久飫南來飯，長維北去船。", "薰衣子笑韻，入筯望潮鮮。", "意適忘漂泛，吾生計食眠。", "歸期何用數，寬待藕花天。"]'),
('7b2b97e7-94fb-45d1-b6a8-c89c22f89ce2','調官歸','陳造','宋','宋诗','song-poetry','','[]','穰穰衣冠地，眈眈公輔居。',48,'全唐诗/poet.song.151000.json','["穰穰衣冠地，眈眈公輔居。", "雲霄有捷徑，塵土且長裾。", "老去懷歸切，生知與世疎。", "解裝漫刺在，况說子公書。"]'),
('dc84baa3-2876-41b7-ba41-311c6b90f050','陪盱眙王使君東游四首  其一','陳造','宋','宋诗','song-poetry','','[]','錦席浮波影，牙檣轉霧霏。',48,'全唐诗/poet.song.151000.json','["錦席浮波影，牙檣轉霧霏。", "飛花窺碧酒，舞蝶傍紅衣。", "野日歌前淡，雲峯望處微。", "游魚應與樂，啼鳥莫催歸。"]'),
('34b7af65-4a03-488e-bda9-abec5a12558d','陪盱眙王使君東游四首  其二','陳造','宋','宋诗','song-poetry','','[]','纜解鷗飛處，船移柳影中。',48,'全唐诗/poet.song.151000.json','["纜解鷗飛處，船移柳影中。", "林廬桃李月，浦溆蕙蘭風。", "酒淺能無醉，歌長惜有終。", "賦詩聊泚筆，寓意未須工。"]'),
('a2686291-8d5f-4967-9846-2cdda18557ea','陪盱眙王使君東游四首  其三','陳造','宋','宋诗','song-poetry','','[]','紅旗圍皂蓋，離迾碧山隅。',48,'全唐诗/poet.song.151000.json','["紅旗圍皂蓋，離迾碧山隅。", "水色涵雲樹，賓筵著畫圖。", "香溫金鑿落，花亞錦屠蘇。", "醉裏銀絲鱠，漁舟不待呼。"]'),
('072b7439-abbb-42cf-b580-c645f0b71cc8','陪盱眙王使君東游四首  其四','陳造','宋','宋诗','song-poetry','','[]','風林山闕處，茅舍兩三家。',48,'全唐诗/poet.song.151000.json','["風林山闕處，茅舍兩三家。", "小駐回鶻隊，重尋粟玉花。", "疎煙橫暖靄，碧溜漱晴沙。", "野興未渠盡，數峯明晚霞。"]'),
('c634e9c8-a30d-4b1a-aa33-aecdc5b03c72','都梁八首  其一','陳造','宋','宋诗','song-poetry','','[]','淮汴朝宗地，孤埤只眼前。',48,'全唐诗/poet.song.151000.json','["淮汴朝宗地，孤埤只眼前。", "譙樓西日淡，戍鼓北風傳。", "破竹非無計，澆瓜亦自賢。", "客愁渾幾許，撫劍倚吳天。"]'),
('4096950c-a797-4e55-86bf-f813b9663ded','都梁八首  其二','陳造','宋','宋诗','song-poetry','','[]','天外纖雲盡，山巔望眼遥。',48,'全唐诗/poet.song.151000.json','["天外纖雲盡，山巔望眼遥。", "平淮剪綠野，白塔界晴霄。", "客裏風光異，吟邊物象驕。", "功名它日事，回首興蕭條。"]'),
('da238d99-12f9-482c-a62f-926d059340f7','都梁八首  其三','陳造','宋','宋诗','song-poetry','','[]','新居得翠微，景趣自幽奇。',48,'全唐诗/poet.song.151000.json','["新居得翠微，景趣自幽奇。", "白石羣羊卧，脩篁翠葆欹。", "山光銜睥睨，雲影傍藩籬。", "席戶無車馬，禽猿不更疑。"]'),
('f1a366f2-0caf-42d4-8045-644206c662be','都梁八首  其四','陳造','宋','宋诗','song-poetry','','[]','關塞凄凉處，青徐指顧邊。',48,'全唐诗/poet.song.151000.json','["關塞凄凉處，青徐指顧邊。", "如何漢正朔，不盡禹山川。", "將略輕三捷，天威重萬全。", "諸公不愒日，老子判留年。"]'),
('112fd099-6135-48be-a600-35f9d36250a3','都梁八首  其五','陳造','宋','宋诗','song-poetry','','[]','路惡惟沙磧，山回忽市廛。',48,'全唐诗/poet.song.151000.json','["路惡惟沙磧，山回忽市廛。", "樓臺明晚照，花竹暝寒煙。", "生事知無警，歡聲驗有年。", "猶嫌武陵遇，不載割淮鮮。"]'),
('f0b8272d-801b-4f41-8b5c-b6e295f7043d','都梁八首  其六','陳造','宋','宋诗','song-poetry','','[]','犬吠葱青裏，人家竹徑深。',48,'全唐诗/poet.song.151000.json','["犬吠葱青裏，人家竹徑深。", "短籬循石磵，老屋枕煙岑。", "牛瘠知春事，鳩啼認晏陰。", "豐年易爲客，盃酒慰幽尋。"]'),
('c06e4a30-4771-4a0f-a4bd-59ac6be110d0','都梁八首  其七','陳造','宋','宋诗','song-poetry','','[]','向來經世藴，每作負山馳。',48,'全唐诗/poet.song.151000.json','["向來經世藴，每作負山馳。", "鬢髮不留黑，京塵慙舊緇。", "生涯黄卷在，心事白鷗知。", "回首林泉癖，窮吾不爲詩。"]'),
('4c3dbfe7-bf9d-4630-80aa-f7278a8895a3','都梁八首  其八','陳造','宋','宋诗','song-poetry','','[]','年年漢臣節，春鴈與同歸。',48,'全唐诗/poet.song.151000.json','["年年漢臣節，春鴈與同歸。", "番俗尊華服，皇家後武威。", "市中斜毼賤，水外拂廬稀。", "南北皆生息，和親果是非。"]'),
('0a56efbe-35bd-4d79-9482-a4b0aa84c05e','寄姪','陳造','宋','宋诗','song-poetry','','[]','擁衾聽良夜，風葉不餘飛。',48,'全唐诗/poet.song.151000.json','["擁衾聽良夜，風葉不餘飛。", "天地清霜冷，江湖旅鴈歸。", "幽人惜短夢，遊子念征衣。", "窮老人間世，愁城屢合圍。"]'),
('c84b6aac-d04b-4615-bb88-606e2428076c','雨後病起二首  其一','陳造','宋','宋诗','song-poetry','','[]','旱歲仍無麥，淮民食正艱。',48,'全唐诗/poet.song.151000.json','["旱歲仍無麥，淮民食正艱。", "幾時占雨信，今日破天慳。", "盡息田家嘆，聊開病客顔。", "何由長歲稔，金火莫循環。"]'),
('c227c233-604a-46ac-8355-d409d88ba05b','雨後病起二首  其二','陳造','宋','宋诗','song-poetry','','[]','小卧竹間齋，幽懷得好開。',48,'全唐诗/poet.song.151000.json','["小卧竹間齋，幽懷得好開。", "病從凉後減，雨及望時來。", "兩屩山千疊，諸雛飯一杯。", "吾生計此耳，無夢到燕臺。"]'),
('5e26bfb3-86bf-49ce-93cd-98f46cea5f15','歸自湖西','陳造','宋','宋诗','song-poetry','','[]','晨具湖西飯，還家腹果然。',48,'全唐诗/poet.song.151000.json','["晨具湖西飯，還家腹果然。", "怒風長擘席，急浪不鳴船。", "身覺青冥上，情留白鳥邊。", "衰年端一快，整帽向雲天。"]'),
('6f7e647c-0ac5-4396-b646-507aa0165f54','客中','陳造','宋','宋诗','song-poetry','','[]','多夜淮瀕夢，言歸未有期。',48,'全唐诗/poet.song.151000.json','["多夜淮瀕夢，言歸未有期。", "愁禁客舍雨，寒過杏花時。", "酒廢無何飲，春如不自持。", "若爲丹九轉，能黑鏡中絲。"]'),
('300a27aa-c493-49b1-94bb-be2da767e3bc','次韻朱萬卿五首  其一','陳造','宋','宋诗','song-poetry','','[]','陳雷好賓主，亹亹各風流。',48,'全唐诗/poet.song.151000.json','["陳雷好賓主，亹亹各風流。", "末座仍枚叟，捐金得莫愁。", "濃歡兼卜夜，暇日頼銷憂。", "近按梁州譜，何妨一再謳。"]'),
('ea59b9c9-0f70-4d47-b4f5-6a2807a7881f','次韻朱萬卿五首  其二','陳造','宋','宋诗','song-poetry','','[]','風義陶朱裔，斗南無此流。',48,'全唐诗/poet.song.151000.json','["風義陶朱裔，斗南無此流。", "懸知禁厨臠，不賦畔牢愁。", "筆落無千載，談間散百憂。", "盡抄新樂府，惜欠雪兒謳。"]'),
('17abea43-83a2-480f-8285-2c3f5d44d94c','次韻朱萬卿五首  其三','陳造','宋','宋诗','song-poetry','','[]','彼姝綠窗子，歐靚亦其流。',48,'全唐诗/poet.song.151000.json','["彼姝綠窗子，歐靚亦其流。", "裙衩何因瘦，眉梢不貯愁。", "唾花新得意，庭草共忘憂。", "雌鳳求凰曲，人前莫誤謳。"]'),
('38df1717-ca6c-4f6e-b96b-69a0323f0882','次韻朱萬卿五首  其四','陳造','宋','宋诗','song-poetry','','[]','一雨動三日，溝塍皆怒流。',48,'全唐诗/poet.song.151000.json','["一雨動三日，溝塍皆怒流。", "風凉欺酒力，喜色寄詩愁。", "不待桑林禱，俄寬杞國憂。", "豐登知有象，滿聽載塗謳。"]'),
('ddcbee0b-a266-4647-acb7-d6e5e4ece1ca','次韻朱萬卿五首  其五','陳造','宋','宋诗','song-poetry','','[]','平時歌酒伴，雲散與風流。',48,'全唐诗/poet.song.151000.json','["平時歌酒伴，雲散與風流。", "白髮潘懷縣，青衫許散愁。", "生憐自謀拙，人謂不堪憂。", "只擬江湖去，狂吟和棹謳。"]'),
('d697899e-628c-4569-b0b2-ce93e6585510','寄興化徐尉二首  其一','陳造','宋','宋诗','song-poetry','','[]','敬問昭陽尉，餐錢得飽無。',48,'全唐诗/poet.song.151000.json','["敬問昭陽尉，餐錢得飽無。", "時方依絳帳，課謝剪萑苻。", "賓俎仍黄雉，書窗了白駒。", "低回自愛惜，才業正時須。"]'),
('b4deb007-d619-4537-8ff4-f8b5f2309eda','寄興化徐尉二首  其二','陳造','宋','宋诗','song-poetry','','[]','自折河橋柳，何人慰寂寥。',48,'全唐诗/poet.song.151000.json','["自折河橋柳，何人慰寂寥。", "一書寧用靳，兩舍未爲遥。", "瓜戍裝應趣，荆扉興自饒。", "回頭五雲處，猶肯訪漁樵。"]'),
('c6d7b6eb-31ad-495a-84bb-63a6f7f56b85','次韻彭景貺','陳造','宋','宋诗','song-poetry','','[]','鳩杖隨身去，鄉園得自娛。',48,'全唐诗/poet.song.151000.json','["鳩杖隨身去，鄉園得自娛。", "紅鮮終日有，俗物向來無。", "酒所揮椽筆，風前據槁梧。", "逢人休舉似，兒輩笑吾徒。"]'),
('78c5e8cb-f226-4f59-87c8-73f37938c6e3','贈課會諸公','陳造','宋','宋诗','song-poetry','','[]','書社他年事，尋盟未厭煩。',48,'全唐诗/poet.song.151000.json','["書社他年事，尋盟未厭煩。", "須吾執牛耳，助子躍龍門。", "凌厲先諸彥，從容即萬言。", "雋功科舉外，暇日要深論。"]'),
('944aa727-197f-40c9-a0d5-39e132b3b914','次瓜州','陳造','宋','宋诗','song-poetry','','[]','雲曀平山塔，煙明老濞城。',48,'全唐诗/poet.song.151000.json','["雲曀平山塔，煙明老濞城。", "客行判費日，舟泊細論程。", "閘水清兼濁，潮天雨復晴。", "未須歸有夢，午枕愜凉生。"]'),
('3849b4ad-ed77-4f84-8244-53265527c67c','贈高黄二子','陳造','宋','宋诗','song-poetry','','[]','平昔金蘭契，過逢意自饒。',48,'全唐诗/poet.song.151000.json','["平昔金蘭契，過逢意自饒。", "乘閑無窘步，命笑有嘉招。", "翠歛歌眉黛，紅生醉頰潮。", "歸驂從惜夜，小待玉笙調。"]'),
('a15ec0b3-f5cb-4387-bc0f-65dbb5068ed5','贈趙秀才','陳造','宋','宋诗','song-poetry','','[]','衮衮紅塵去，扁舟得挽回。',48,'全唐诗/poet.song.151000.json','["衮衮紅塵去，扁舟得挽回。", "半生障日手，一笑沃愁杯。", "應俗吾衰矣，論文子壯哉。", "明年日邊信，滿冀好懷開。"]'),
('00067a7c-4306-411a-af2a-54e6f9def9ad','約二趙棋集雨不果來','陳造','宋','宋诗','song-poetry','','[]','客子離羣意，蕭齋只睡宜。',48,'全唐诗/poet.song.151000.json','["客子離羣意，蕭齋只睡宜。", "得無新雨嘆，漫有故人期。", "日力須棋局，風凉入酒卮。", "轉頭車婦去，相憶各兒癡。"]'),
('cf113590-d824-4c2e-956a-75013131a0ff','次韻高縉之二首  其一','陳造','宋','宋诗','song-poetry','','[]','能事餘千牘，幽期自一丘。',48,'全唐诗/poet.song.151000.json','["能事餘千牘，幽期自一丘。", "向來書襞積，不療客漂流。", "小挹蘇耽鶴，同歌甯戚牛。", "幾時詩酒社，相屬話天遊。"]'),
('ee7325db-c4ba-4874-9644-5e97167121d2','次韻高縉之二首  其二','陳造','宋','宋诗','song-poetry','','[]','奚囊走湖海，襟度極風流。',48,'全唐诗/poet.song.151000.json','["奚囊走湖海，襟度極風流。", "學力隠一敵，才華追二劉。", "與時君有用，漫仕我非優。", "它日霄霏上，詩成復寄不。"]'),
('182c25a6-fd5f-466d-9815-91a2098c7671','次韻石湖居士瓶中早梅二首  其一','陳造','宋','宋诗','song-poetry','','[]','詩翁靜三昧，筇杖壁間橫。',48,'全唐诗/poet.song.151000.json','["詩翁靜三昧，筇杖壁間橫。", "小閤自清絕，幽芳從瘦生。", "巧當窗影見，時映燭花明。", "底用尋春去，衝寒踏月行。"]'),
('edb01881-de08-495b-b490-d5db7eeb8522','次韻石湖居士瓶中早梅二首  其二','陳造','宋','宋诗','song-poetry','','[]','羅帷護春色，羣木未昭蘇。',48,'全唐诗/poet.song.151000.json','["羅帷護春色，羣木未昭蘇。", "絕勝翻香坐，聊陪琢句臞。", "天資便靜獨，冰影倚空無。", "後夜逢姑射，仙家白玉壺。"]'),
('6fc51c8a-4b6e-472e-a1b4-86644dc475f4','再遊虎丘二首  其一','陳造','宋','宋诗','song-poetry','','[]','闔廬歸骨地，僧宇庇高丘。',48,'全唐诗/poet.song.151000.json','["闔廬歸骨地，僧宇庇高丘。", "又趁能詩伴，來爲弔古遊。", "英雄餘幅紙，歲月莽東流。", "未解山前客，相逢更說愁。"]'),
('f33cb3ff-1110-4615-9842-a432886c3130','再遊虎丘二首  其二','陳造','宋','宋诗','song-poetry','','[]','令節携壺客，當年伏虎山。',48,'全唐诗/poet.song.151000.json','["令節携壺客，當年伏虎山。", "詩成雲氣上，人語畫圖間。", "官作三年住，時須半日閑。", "從今碧眼老，幾送醉中還。"]'),
('776b68b4-4cfb-451d-a79d-7de40e4b7969','謝陳夢錫詩卷二首  其一','陳造','宋','宋诗','song-poetry','','[]','詩法工如此，何時粟一囊。',48,'全唐诗/poet.song.151000.json','["詩法工如此，何時粟一囊。", "渠儂須擁篲，老子欲燒香。", "世論瞢賢否，人家皆稻粱。", "願天開老眼，爲子療饑腸。"]'),
('8ccaf47e-957a-4a29-918c-79b2bd08fc54','謝陳夢錫詩卷二首  其二','陳造','宋','宋诗','song-poetry','','[]','高才萬夫敵，餘事十全醫。',48,'全唐诗/poet.song.151000.json','["高才萬夫敵，餘事十全醫。", "有句撞哀玉，它年飲上池。", "可緣乖世用，政自畏人知。", "當復嫌多口，頻煩說項斯。"]'),
('0c513afe-6e06-42c8-ba23-ca003ed5f228','即事','陳造','宋','宋诗','song-poetry','','[]','側徑苔竹潤，短籬鷄鶩喧。',48,'全唐诗/poet.song.151000.json','["側徑苔竹潤，短籬鷄鶩喧。", "小停障日手，聊憩卧雲村。", "綠影烏皮几，新醅老瓦盆。", "平生農圃計，重與野人論。"]'),
('639082d3-9375-469e-a1ba-d183623389c0','次韻羅春伯提舉','陳造','宋','宋诗','song-poetry','','[]','龍公靳飛雨，盍趁望時來。',48,'全唐诗/poet.song.151000.json','["龍公靳飛雨，盍趁望時來。", "尚及豐年計，真令笑口開。", "池蓮端自若，月地信佳哉。", "倚檻西風夜，題詩判費才。"]'),
('140f16f9-fcc5-4e11-bd91-b0110349d873','送高縉之歸謀武林結課二首  其一','陳造','宋','宋诗','song-poetry','','[]','眼底論人物，如君亦壯哉。',48,'全唐诗/poet.song.151000.json','["眼底論人物，如君亦壯哉。", "作書猶乞米，造物不憐才。", "跋履妨詩筆，祛除近酒盃。", "飛塵棲劍室，歸棹莫遲回。"]'),
('5e363a94-149f-4571-8060-b84896f8126b','送高縉之歸謀武林結課二首  其二','陳造','宋','宋诗','song-poetry','','[]','輻輳羣英地，皇州異別州。',48,'全唐诗/poet.song.151000.json','["輻輳羣英地，皇州異別州。", "能文纔倚馬，作意付焚舟。", "士價知名下，醫門要擔頭。", "明年春鴈足，詢我賀書郵。"]'),
('744301d9-68d0-4019-8b98-6e526d96fba2','歲晚言懷  其一','陳造','宋','宋诗','song-poetry','','[]','病在歲云除，相羊小石渠。',48,'全唐诗/poet.song.151000.json','["病在歲云除，相羊小石渠。", "連朝無出日，進藥止觀書。", "舊苦將迎困，新慙誦說疎。", "官曹不事事，世恐誚相如。"]'),
('9064afc7-c0ba-44af-aaf4-5232fe483d48','歲晚言懷  其二','陳造','宋','宋诗','song-poetry','','[]','紙屋酣春意，霜空凝凍雲。',48,'全唐诗/poet.song.151000.json','["紙屋酣春意，霜空凝凍雲。", "甘違酒伴約，稍策睡鄉勳。", "寂寂觀騰踔，堂堂斂放紛。", "冥心得今我，回首謝前聞。"]'),
('fbe9d23a-4ff4-4546-a7a0-1739a900422d','歲晚言懷  其三','陳造','宋','宋诗','song-poetry','','[]','雀響初防雪，鴉驕恐報晴。',48,'全唐诗/poet.song.151000.json','["雀響初防雪，鴉驕恐報晴。", "徒妨一老夢，莫究二蟲情。", "虛籟吹羣動，洪爐寄短生。", "只今觀物化，未替白鷗盟。"]'),
('52e77d59-cf35-40e7-9a50-c21e9bc2baa7','贈相士蜀張二詩  其一','陳造','宋','宋诗','song-poetry','','[]','博古亦多藝，相形仍論心。',48,'全唐诗/poet.song.151000.json','["博古亦多藝，相形仍論心。", "司南輔名教，左契指升沈。", "好語空千紙，行囊未一簪。", "鄉關劍閣外，鴈足謾歸音。"]'),
('d47b6919-d5c5-4776-9875-df13ec3b938e','贈相士蜀張二詩  其二','陳造','宋','宋诗','song-poetry','','[]','貧病謝人謀，形容覽鏡羞。',48,'全唐诗/poet.song.151000.json','["貧病謝人謀，形容覽鏡羞。", "要隨耕釣往，聊爲斗升留。", "子術誠探妙，吾門恐暗投。", "霜髯文學掾，寧復鄧元侯。"]'),
('1b92f7da-15c4-44d5-855a-d95a911917a2','贈陳錢二別乘  其一','陳造','宋','宋诗','song-poetry','','[]','蜂蝶如相識，窺人却怪生。',48,'全唐诗/poet.song.151000.json','["蜂蝶如相識，窺人却怪生。", "平時被花惱，因病此心輕。", "笑語初疑夢，香紅旋問名。", "杖藜回白首，頹景欻銜城。"]'),
('2eb94ba9-e240-4042-b9a0-d608c6eb9c44','贈陳錢二別乘  其二','陳造','宋','宋诗','song-poetry','','[]','花氣浮遲日，鶑歌佐緩觴。',48,'全唐诗/poet.song.151000.json','["花氣浮遲日，鶑歌佐緩觴。", "肯孤留客意，兼貸著書忙。", "疇昔朋遊樂，扶携醉後狂。", "因君話塵外，清興頓能長。"]'),
('1e5f5b4d-9e1e-4802-aeba-4ae5d9df6fb3','贈陳錢二別乘  其三','陳造','宋','宋诗','song-poetry','','[]','小築縈人夢，詩翁况舊期。',48,'全唐诗/poet.song.151000.json','["小築縈人夢，詩翁况舊期。", "定携桃葉女，猶羨習家池。", "鶑燕聽歌慣，風煙取醉宜。", "餞春餘幾日，一笑更容遲。"]'),
('2c8820bb-ba20-4e72-99e6-0ae70573d0d5','送李元英還常熟從周宰讀書','陳造','宋','宋诗','song-poetry','','[]','久趼尋師足，還家訖受經。',48,'全唐诗/poet.song.151000.json','["久趼尋師足，還家訖受經。", "可容輕日力，政使带朝星。", "高步須堂奧，它年看典刑。", "奉親時得笑，餘事賜袍青。"]'),
('331cf464-ae7b-4937-be60-dedfc09c4b1b','次韻歸路微雪','陳造','宋','宋诗','song-poetry','','[]','卓犖康時略，昂藏報主身。',48,'全唐诗/poet.song.151000.json','["卓犖康時略，昂藏報主身。", "衝風還按轡，飛雪却宜人。", "帝渥先春遍，詩題觸目新。", "行行何樣好，歸路玉爲塵。"]'),
('183f54b8-595e-4bb4-9289-cde3e8ae0630','鹽城阻冰雪贈陳德美三首  其一','陳造','宋','宋诗','song-poetry','','[]','斷港冰初合，窮塗歲欲除。',48,'全唐诗/poet.song.151000.json','["斷港冰初合，窮塗歲欲除。", "臨年仍此悔，議道得無疎。", "撫事空搔首，何人爲寄書。", "海風吹浩蕩，側望正愁予。"]'),
('b57f3f2b-91ad-43b3-a5f9-8fbcc51c1201','鹽城阻冰雪贈陳德美三首  其二','陳造','宋','宋诗','song-poetry','','[]','身口真相累，風霜得備嘗。',48,'全唐诗/poet.song.151000.json','["身口真相累，風霜得備嘗。", "即今歌匪兕，未憗反屠羊。", "辟謗規閑口，因衰再覆觴。", "不知詩酒外，何計逭悲凉。"]'),
('36cd74bc-d18b-4440-a859-835fa22818f2','鹽城阻冰雪贈陳德美三首  其三','陳造','宋','宋诗','song-poetry','','[]','雪意知呈瑞，還欺客鬢星。',48,'全唐诗/poet.song.151000.json','["雪意知呈瑞，還欺客鬢星。", "悲歡隨處異，艱阻向來經。", "夢境翩蝴蝶，宗盟近脊令。", "盤餐更譚麈，足用慰漂零。"]'),
('bf00613b-677c-454e-9bf7-bfde4ebf454a','夜雨','陳造','宋','宋诗','song-poetry','','[]','窗聲呼夢斷，燈影尚微茫。',48,'全唐诗/poet.song.151000.json','["窗聲呼夢斷，燈影尚微茫。", "忽掃蚊專夜，從知雨獻凉。", "佳眠嗟莫續，殘漏耿猶長。", "却憶檠三尺，馮書怯曙光。"]'),
('345a983e-5d0f-4582-929e-e6d91014e23c','次韻何學諭送行二首  其一','陳造','宋','宋诗','song-poetry','','[]','新詩念報答，呫囁未能書。',48,'全唐诗/poet.song.151000.json','["新詩念報答，呫囁未能書。", "落筆羣英右，惟君一敵如。", "窮愁疎翰墨，客路費羲舒。", "延閤青冥上，摩研正望渠。"]'),
('fbafb20e-6033-410a-8c9a-697042b4ca19','次韻何學諭送行二首  其二','陳造','宋','宋诗','song-poetry','','[]','湖山迎客棹，觸目總宜詩。',48,'全唐诗/poet.song.151000.json','["湖山迎客棹，觸目總宜詩。", "回首蓬萊近，平生汗漫期。", "衰年得奇觀，往事屬懷思。", "何日鴟夷去，扁舟共翠眉。"]'),
('b99df2e1-44cc-4b14-85d8-455424d6984a','曹娥廟二首  其一','陳造','宋','宋诗','song-poetry','','[]','處死稽緗素，求名每寂寥。',48,'全唐诗/poet.song.151000.json','["處死稽緗素，求名每寂寥。", "紛紛等枯冢，凜凜獨高標。", "玉刻龜趺字，風驅水伯潮。", "英魂儼如在，楚些未須招。"]'),
('6e8999b6-ade9-470f-a605-2725381f9ae3','曹娥廟二首  其二','陳造','宋','宋诗','song-poetry','','[]','閲世誰無父，渠寧厭久生。',48,'全唐诗/poet.song.151000.json','["閲世誰無父，渠寧厭久生。", "驚波輕一死，森木竟雙塋。", "石壁千尋立，江流萬古清。", "祠宮拜遺像，猶復涕縱橫。"]'),
('6233088e-b799-4058-8d2a-bdd834276f51','寄師文二首  其一','陳造','宋','宋诗','song-poetry','','[]','父子相爲命，淮鄉望海隅。',48,'全唐诗/poet.song.151000.json','["父子相爲命，淮鄉望海隅。", "誰非牛舐犢，心羨燕將雛。", "綵服藏書蠹，青春負隙駒。", "營營溫飽計，猶恐未良圖。"]'),
('5d42d4c6-66cb-466c-853d-1f94219e04d5','寄師文二首  其二','陳造','宋','宋诗','song-poetry','','[]','阿泰知何似，無書坐地偏。',48,'全唐诗/poet.song.151000.json','["阿泰知何似，無書坐地偏。", "未妨歸緩緩，可免意縣縣。", "肖父仍便酒，如翁不蓄錢。", "况須供老眼，欲說已欣然。"]'),
('6a873753-70c0-4157-8f43-1e7ee146d3eb','登招寶山','陳造','宋','宋诗','song-poetry','','[]','一鷲風煙上，三韓指點中。',48,'全唐诗/poet.song.151000.json','["一鷲風煙上，三韓指點中。", "地隨山共盡，天與水無窮。", "夢蟻紛軒冕，騎魚可閬蓬。", "仙曹應拊掌，顧我簿書叢。"]'),
('a13f7ba0-57c9-4216-ba76-18d98bd009f7','定海四首  其一','陳造','宋','宋诗','song-poetry','','[]','縣境拖脩直，人家住土塗。',48,'全唐诗/poet.song.151000.json','["縣境拖脩直，人家住土塗。", "三方鯨浪湧，一島虎頭孤。", "風物猶佳處，絃歌付老夫。", "平生蟲篆意，或許間憂虞。"]'),
('66b8872a-f3e3-4542-98ab-8623ba151df0','定海四首  其二','陳造','宋','宋诗','song-poetry','','[]','齒髮今如此，東來料一寒。',48,'全唐诗/poet.song.151000.json','["齒髮今如此，東來料一寒。", "愛民平日事，宰縣昔人難。", "稍得官租辦，聊容坐席安。", "渠儂趨負輓，疑未厭兒寬。"]'),
('41117f54-520f-4005-a300-30264a3ff23d','定海四首  其三','陳造','宋','宋诗','song-poetry','','[]','穫稻來墝埆，開篘薦碧香。',48,'全唐诗/poet.song.151000.json','["穫稻來墝埆，開篘薦碧香。", "地偏皆斥鹵，汲井得甘芳。", "漫仕今千室，前人陋一鄉。", "民安吾亦飽，相樂亦相忘。"]'),
('02efd104-06a7-4f36-a5ea-515ef5ba3c5f','定海四首  其四','陳造','宋','宋诗','song-poetry','','[]','官廨鹽煙外，居人雜賈胡。',48,'全唐诗/poet.song.151000.json','["官廨鹽煙外，居人雜賈胡。", "聽言須畫字，討海倚輸租。", "習俗何妨陋，鮮肥頗不無。", "已甘三載住，疇昔計乘桴。"]'),
('999e228e-00eb-4a1f-b1b9-120877950fb0','聞師文過錢塘二首  其一','陳造','宋','宋诗','song-poetry','','[]','行役兒無慮，衰懷自不忘。',48,'全唐诗/poet.song.151000.json','["行役兒無慮，衰懷自不忘。", "待潮何處泊，聽雨共更長。", "指俟烏供哺，先容鴈著行。", "更寬三日計，茫蒼下歸艎。"]'),
('0c19b33c-b83e-4f20-bd20-b5566e7ae69b','聞師文過錢塘二首  其二','陳造','宋','宋诗','song-poetry','','[]','九堰三江外，欹帆側柂頻。',48,'全唐诗/poet.song.151000.json','["九堰三江外，欹帆側柂頻。", "海鮮當日筯，雨鵲定隨人。", "椒酒須分歲，江梅巧借春。", "團欒多樂事，未沬物華新。"]'),
('a811c07b-da92-46e1-b2bd-7abb9fb8ebb6','即事','陳造','宋','宋诗','song-poetry','','[]','平昔功名念，如今冷似灰。',48,'全唐诗/poet.song.151000.json','["平昔功名念，如今冷似灰。", "藏書堪樂死，望歲待歸來。", "小宅依城築，虛簷枕水開。", "溪翁詩社侶，有酒賸追陪。"]'),
('477d625e-7202-41b1-a120-fc98ee1c6ed2','官居二首  其一','陳造','宋','宋诗','song-poetry','','[]','磔磔初鳴曉，通通已報衙。',48,'全唐诗/poet.song.151000.json','["磔磔初鳴曉，通通已報衙。", "拙勤知待旦，欺紿未停撾。", "漫役鄉園夢，祇添老眼花。", "屈信庸敢計，斗祿倚生涯。"]'),
('6389418c-f976-49e6-90d7-1086bd626bcf','官居二首  其二','陳造','宋','宋诗','song-poetry','','[]','官居不惜日，宰縣動三年。',48,'全唐诗/poet.song.151000.json','["官居不惜日，宰縣動三年。", "忍事腸欲爛，爲防頭救燃。", "不應一飽計，長受衆人憐。", "俛仰堪供笑，人間海易田。"]'),
('41d094db-646a-42d2-99ea-05dea949f4f9','送學生歸赴秋試因省別業三首  其一','陳造','宋','宋诗','song-poetry','','[]','凉意蘇殘夢，催兒起問塗。',48,'全唐诗/poet.song.151000.json','["凉意蘇殘夢，催兒起問塗。", "功名數前輩，術業舊原夫。", "漫觸煙樓破，應先老驥驅。", "蠲痾吾有待，端不倚岐盧。"]'),
('45c945a4-9864-484f-80ae-b42c917f3ee6','送學生歸赴秋試因省別業三首  其二','陳造','宋','宋诗','song-poetry','','[]','年事真無頼，官曹已憚煩。',48,'全唐诗/poet.song.151000.json','["年事真無頼，官曹已憚煩。", "兒堪付門戶，吾粗有田園。", "遊舊因相問，襟懷爲細論。", "此心歸隠計，日日受風幡。"]'),
('eb00290e-c3c6-49ce-8cd7-fc6ce8110b75','送學生歸赴秋試因省別業三首  其三','陳造','宋','宋诗','song-poetry','','[]','食口幾鵝雁，田收問菜麻。',48,'全唐诗/poet.song.151000.json','["食口幾鵝雁，田收問菜麻。", "寧堪再攬減，又抱兩嘔鴉。", "投老憐漂泊，何時了貸賒。", "終慙陶靖節，歸不計生涯。"]'),
('3ec53384-6eea-4b7f-88d1-b3409d9950ab','冬至','陳造','宋','宋诗','song-poetry','','[]','至節占天意，豐登又必然。',48,'全唐诗/poet.song.151000.json','["至節占天意，豐登又必然。", "相風綠漪靜，賓日矞雲鮮。", "比屋皆生意，窮閻有醉眠。", "端容衰病宰，索句海山前。"]'),
('d1362975-9ec3-495b-ae56-aaedfcd1aede','立春','陳造','宋','宋诗','song-poetry','','[]','春信葭灰動，尋知寒事休。',48,'全唐诗/poet.song.151000.json','["春信葭灰動，尋知寒事休。", "光陰從冉冉，身世判悠悠。", "鬢影看銀勝，官期志土牛。", "羸骸更元命，惜爲斗升留。"]'),
('ec7b1b77-daae-4b10-be19-2a67e6fdf86f','祭龍','陳造','宋','宋诗','song-poetry','','[]','廣殿羅籩豆，脩廓振珮環。',48,'全唐诗/poet.song.151000.json','["廣殿羅籩豆，脩廓振珮環。", "帝觴初拜手，仙馭不違顔。", "瑞霧浮空下，靈風拂袂還。", "定知龍宛宛，千祀拱南山。"]'),
('40316c5a-3255-4917-be8d-504dda1d0b65','答龔炳澤卿','陳造','宋','宋诗','song-poetry','','[]','之子違離久，前宵夢見之。',48,'全唐诗/poet.song.151000.json','["之子違離久，前宵夢見之。", "秋蛇開側理，曉鵲啅疎籬。", "歆秀何時改，郊庠更問爲。", "有言今贅矣，暗裏自應知。"]'),
('0233d462-bf95-40ee-9da0-e77045654a6e','送嚴上舍并寄諸公十首','陳造','宋','宋诗','song-poetry','','[]','嚴子老且健，翩然湖外行。',48,'全唐诗/poet.song.151000.json','["嚴子老且健，翩然湖外行。", "歸來困一跌，悲嘯念餘生。", "幸棄扶衰杖，幾成折足鐺。", "開籠出雙鳥，身已御風輕。"]'),
('b233485a-1315-42af-8083-4cd4dc8198a2','送嚴上舍并寄諸公十首 送嚴 其一','陳造','宋','宋诗','song-poetry','','[]','嘖嘖鴈聲急，稜稜秋意深。',48,'全唐诗/poet.song.151000.json','["嘖嘖鴈聲急，稜稜秋意深。", "行都舊新雨，獨客短長吟。", "子肯憐衰病，時來慰滯淫。", "惜無移日酒，留照蠟燈斟。"]'),
('16076ee9-8041-4f32-b947-22b0c7b202fd','送嚴上舍并寄諸公十首 送嚴 其二','陳造','宋','宋诗','song-poetry','','[]','自昔金陵幕，周旋未盡能。',48,'全唐诗/poet.song.151000.json','["自昔金陵幕，周旋未盡能。", "凄凉論閥閲，突兀擅聲稱。", "直己堪從事，公言不負丞。", "嗣當蜚鶚牘，留眼看依乘。"]'),
('d7b418aa-fb2f-45ac-943a-0dd8882d09e9','送嚴上舍并寄諸公十首 寄張次夔縣丞 其一','陳造','宋','宋诗','song-poetry','','[]','聞道張夫子，還家俗累輕。',48,'全唐诗/poet.song.151000.json','["聞道張夫子，還家俗累輕。", "兩官終短袖，五字屹長城。", "龍斷悲人世，煙雲寫物情。", "只今遥夜月，獨許伴空明。"]'),
('b3b885c8-5dac-4c65-8009-4896e879eeed','送嚴上舍并寄諸公十首 寄張次夔縣丞 其二','陳造','宋','宋诗','song-poetry','','[]','趙子趨吳幕，予偕詠舞雩。',48,'全唐诗/poet.song.151000.json','["趙子趨吳幕，予偕詠舞雩。", "迄今推轂力，不墮拾塵誣。", "鬢脚今全白，車輪欲半朱。", "何階答知己，冰蘗耐窮塗。"]'),
('6ee0f02f-83da-4ea6-a8d6-b09281c60907','送嚴上舍并寄諸公十首 寄趙景安府判 其一','陳造','宋','宋诗','song-poetry','','[]','已種河陽柳，將題晉客輿。',48,'全唐诗/poet.song.151000.json','["已種河陽柳，將題晉客輿。", "論交記曩昔，因使問何如。", "擁燼應多暇，援毫不一書。", "詩成當屬我，拜賜衮褒餘。"]'),
('e2e01a92-20a4-4554-b264-2a84eda73d78','送嚴上舍并寄諸公十首 寄趙景安府判 其二','陳造','宋','宋诗','song-poetry','','[]','憶訪俞夫子，頻煩挽袖留。',48,'全唐诗/poet.song.151000.json','["憶訪俞夫子，頻煩挽袖留。", "酒邊無俗物，塵外有高樓。", "未醉催歌扇，言歸聽漏籌。", "此歡誰與繼，怊悵歲時遒。"]'),
('00fd9668-3f1d-4b9d-bdb9-71fbaa6f0e97','送嚴上舍并寄諸公十首 寄俞君任府判 其一','陳造','宋','宋诗','song-poetry','','[]','暇日詩成集，西來見未曾。',48,'全唐诗/poet.song.151000.json','["暇日詩成集，西來見未曾。", "金徽想流水，玉井定層冰。", "呵護山靈惜，流傳紙價增。", "石湖千載託，密密續前燈。"]'),
('7e3a1c54-086f-40e9-b695-abfc8ed252b8','送嚴上舍并寄諸公十首 寄俞君任府判 其二','陳造','宋','宋诗','song-poetry','','[]','交際論才業，何郎種種長。',48,'全唐诗/poet.song.151000.json','["交際論才業，何郎種種長。", "元推萬人敵，况別四年彊。", "文看青錢中，詩須古錦藏。", "西歸容盥讀，老境借輝光。"]'),
('9855c380-afff-4266-9334-adfb46a4f8e5','送嚴上舍并寄諸公十首 寄何解元','陳造','宋','宋诗','song-poetry','','[]','舊識追風足，低摧坂下車。',48,'全唐诗/poet.song.151000.json','["舊識追風足，低摧坂下車。", "長驅待雲路，小捷已鄉書。", "唾手須科第，差肩有詔除。", "公餘富佳句，記我渾樵漁。"]'),
('cb73df64-1e65-42cb-86c3-65567599e1da','再次韻十首  其一','陳造','宋','宋诗','song-poetry','','[]','重見髮更白，羈棲偕在行。',48,'全唐诗/poet.song.151000.json','["重見髮更白，羈棲偕在行。", "余嗟遽如許，子亦可憐生。", "玉粒書新券，霜蔬煮破鐺。", "詩成莫浪出，或取世儒輕。"]'),
('e75b439e-8c74-4008-becd-24fbf564bc38','再次韻十首  其二','陳造','宋','宋诗','song-poetry','','[]','曲巷纔人跡，泥塗沒屐深。',48,'全唐诗/poet.song.151000.json','["曲巷纔人跡，泥塗沒屐深。", "未妨衝雨到，要伴掉頭吟。", "大巧專亭毒，何時掃疹淫。", "濁醪君莫厭，排悶勉孤斟。"]');
